//! Lowers AST + `ResolvedFile` + `TypedFile` to a backend-neutral
//! [`MirModule`].
//!
//! This pass is the source of all type-aware structural decisions
//! backends rely on. In particular, the `println` intrinsic dispatch is
//! decided here, not in the backend, by recording an `args[0]` type
//! that the backend examines via `MirFunction::locals[arg.0]`.
//!
//! ## What it currently lowers
//!
//! - `fun main()` and similar zero/one-parameter top-level functions
//! - `println(<int|string|local>)` calls
//! - Integer arithmetic
//! - Local `val s = "..."` and `val n = 42`
//! - `greet("...")` style top-level calls between functions in the
//!   same file
//!
//! ## What it explicitly errors on
//!
//! Anything else: classes, when, lambdas, generics, string templates,
//! if-as-expression, top-level vals. Each unsupported construct emits
//! a diagnostic and stops lowering for that function.

use rustc_hash::FxHashMap;
use skotch_diagnostics::{Diagnostic, Diagnostics};
use skotch_intern::{Interner, Symbol};
use skotch_mir::{
    BasicBlock, BinOp as MBinOp, CallKind, ExceptionHandler, FuncId, LiveSpill, LocalId, MirClass,
    MirConst, MirField, MirFunction, MirModule, Rvalue, SpillKind, SpillSlot, Stmt as MStmt,
    SuspendCallSite, SuspendStateMachine, Terminator,
};
use skotch_resolve::{ExternalClassKind, PackageSymbolTable, ResolvedFile};
use skotch_syntax::{BinOp, ConstructorParam, Decl, Expr, FunDecl, KtFile, Stmt, TypeRef, ValDecl};
use skotch_typeck::TypedFile;
use skotch_types::Ty;

use std::cell::RefCell;
use std::collections::HashMap;
use std::sync::Mutex;

use skotch_types::intrinsics;

thread_local! {
    /// Hint set by `lower_val_stmt` while lowering the right-hand side
    /// of a `val name = ...` so an `Expr::ObjectExpr` knows the target
    /// variable name. kotlinc names anonymous object classes
    /// `<Wrapper>$<EnclosingFn>$<varName>$<idx>` — we read this hint to
    /// match the convention. Cleared after the rhs lowers.
    static OBJECT_EXPR_VAR_HINT: RefCell<Option<String>> = const { RefCell::new(None) };
}

// ── Shared class registry ───────────────────────────────────────────────
//
// A single global registry of ClassInfo objects, populated from JDK jmods,
// Kotlin stdlib, and dependency JARs on the CLASSPATH. Both static and
// instance method lookups share this registry.

static CLASS_REGISTRY: Mutex<Option<HashMap<String, skotch_classinfo::ClassInfo>>> =
    Mutex::new(None);

fn with_registry<R>(
    f: impl FnOnce(&mut HashMap<String, skotch_classinfo::ClassInfo>) -> R,
) -> Option<R> {
    let mut guard = CLASS_REGISTRY.lock().ok()?;
    let reg = guard.get_or_insert_with(skotch_classinfo::build_jdk_registry);
    Some(f(reg))
}

/// Pre-load classes from dependency JARs into the shared registry.
/// Call this before compilation so that external methods are resolvable.
pub fn preload_registry_jars(jars: &[std::path::PathBuf]) {
    let scanned = skotch_classinfo::scan_jars(jars);
    if let Ok(mut guard) = CLASS_REGISTRY.lock() {
        let reg = guard.get_or_insert_with(skotch_classinfo::build_jdk_registry);
        for (k, v) in scanned {
            reg.entry(k).or_insert(v);
        }
    }
    // Also seed the shared classpath cache used by `lookup_method_descriptor`
    // so per-call ZIP scanning doesn't blow up multi-module builds.
    skotch_classinfo::preload_classpath_cache(jars);
}

/// Check if a name is a static method on a given class (by JVM path).
/// Used to detect static method imports like `import ...Assertions.assertTrue`.
pub fn is_static_method_on_class(class_jvm_path: &str, method_name: &str) -> bool {
    ensure_class_loaded(class_jvm_path);
    with_registry(|reg| {
        reg.get(class_jvm_path)
            .map(|ci| {
                ci.methods
                    .iter()
                    .any(|m| m.name == method_name && m.is_static() && m.is_public())
            })
            .unwrap_or(false)
    })
    .unwrap_or(false)
}

/// Ensure a class is loaded into the registry (by JVM path).
fn ensure_class_loaded(class_name: &str) {
    let needs_load = with_registry(|reg| !reg.contains_key(class_name)).unwrap_or(true);
    if needs_load {
        let jvm_path = if class_name.contains('/') {
            class_name.to_string()
        } else {
            format!("java/lang/{class_name}")
        };
        if let Ok(info) = skotch_classinfo::load_jdk_class(&jvm_path) {
            if let Ok(mut guard) = CLASS_REGISTRY.lock() {
                if let Some(reg) = guard.as_mut() {
                    reg.insert(class_name.to_string(), info);
                }
            }
        }
    }
}

/// Check if a JVM class is an interface by reading its ACC_INTERFACE flag
/// from the classfile. Falls back to the static registry for known stdlib
/// interfaces. This replaces the hardcoded JVM_INTERFACES list.
pub fn is_jvm_interface(class_name: &str) -> bool {
    // First check the classfile registry (authoritative).
    ensure_class_loaded(class_name);
    let from_classfile =
        with_registry(|reg| reg.get(class_name).map(|ci| ci.is_interface())).flatten();
    if let Some(is_iface) = from_classfile {
        return is_iface;
    }
    // Fallback to static registry for known stdlib interfaces when
    // classfile isn't available (e.g. no JDK installed).
    skotch_stdlib_registry::is_jvm_interface(class_name)
}

/// Convert a `Ty` to its JVM descriptor string fragment (for building
/// method descriptors in the MIR lowerer).
/// Map a `Ty` to a JVM descriptor string for use in parameter positions.
/// `Unit` maps to `Lkotlin/Unit;` (not `V`, which is only valid as return type).
/// Parse the return type out of a JVM method descriptor like
/// `(Landroid/os/Bundle;)V` → `Ty::Unit` or `(I)Z` → `Ty::Bool`. Reference
/// types collapse to `Ty::Any` (callers that need the concrete class can
/// re-parse) — this helper is for picking up Composer-less call-site
/// return types from classinfo.
fn ty_from_descriptor_return(desc: &str) -> Ty {
    let ret = desc.rsplit(')').next().unwrap_or("V");
    let mut chars = ret.chars();
    match chars.next() {
        Some('V') => Ty::Unit,
        Some('Z') => Ty::Bool,
        Some('B') => Ty::Byte,
        Some('S') => Ty::Short,
        Some('C') => Ty::Char,
        Some('I') => Ty::Int,
        Some('J') => Ty::Long,
        Some('F') => Ty::Float,
        Some('D') => Ty::Double,
        Some('L') => {
            // L<name>;
            let inner: String = chars.take_while(|&c| c != ';').collect();
            if inner.is_empty() {
                Ty::Any
            } else {
                Ty::Class(inner)
            }
        }
        Some('[') => Ty::Any, // arrays — caller can refine
        _ => Ty::Any,
    }
}

/// Parse a JVM method descriptor and return the 0-based index of the
/// `Landroidx/compose/runtime/Composer;` parameter. Used to fill in the
/// `$composer` slot at the correct position when patching composable
/// call sites — the simple "second-from-last" heuristic places the
/// Composer wrong when the descriptor ends with a trailing `$default`
/// mask (e.g. `(DrawerValue, Function1, Composer, I, I)`).
fn composer_position_in_descriptor(desc: &str) -> Option<usize> {
    let inside = desc.strip_prefix('(').and_then(|s| s.split_once(')'))?.0;
    let mut idx = 0usize;
    let mut chars = inside.chars();
    while let Some(c) = chars.next() {
        match c {
            'L' => {
                let mut name = String::new();
                for cc in chars.by_ref() {
                    if cc == ';' {
                        break;
                    }
                    name.push(cc);
                }
                if name == "androidx/compose/runtime/Composer" {
                    return Some(idx);
                }
                idx += 1;
            }
            '[' => continue,
            'B' | 'C' | 'D' | 'F' | 'I' | 'J' | 'S' | 'Z' => idx += 1,
            _ => continue,
        }
    }
    None
}

/// If the last param of a JVM method descriptor is an object array
/// (`[Lsome/Class;`), return the JVM internal name of the element class
/// (e.g. `kotlin/Pair`). Used to detect vararg slots so individually-
/// passed args at the call site can be packed into a fresh array.
fn vararg_element_class(desc: &str) -> Option<String> {
    let inside = desc.strip_prefix('(').and_then(|s| s.split_once(')'))?.0;
    // Walk to find the LAST param.
    let mut last_kind: Option<String> = None;
    let mut chars = inside.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            'L' => {
                let mut name = String::from("L");
                for cc in chars.by_ref() {
                    name.push(cc);
                    if cc == ';' {
                        break;
                    }
                }
                last_kind = Some(name);
            }
            '[' => {
                let mut s = String::from("[");
                while let Some(&nc) = chars.peek() {
                    if nc == '[' {
                        s.push('[');
                        chars.next();
                    } else {
                        break;
                    }
                }
                if let Some(&nc) = chars.peek() {
                    if nc == 'L' {
                        chars.next();
                        s.push('L');
                        for cc in chars.by_ref() {
                            s.push(cc);
                            if cc == ';' {
                                break;
                            }
                        }
                    } else {
                        s.push(chars.next().unwrap());
                    }
                }
                last_kind = Some(s);
            }
            'B' | 'C' | 'D' | 'F' | 'I' | 'J' | 'S' | 'Z' => {
                last_kind = Some(c.to_string());
            }
            _ => continue,
        }
    }
    let last = last_kind?;
    // Need exactly `[L<name>;` shape — single-dim object array.
    let stripped = last.strip_prefix("[L")?.strip_suffix(';')?;
    if stripped.contains('[') {
        return None;
    }
    Some(stripped.to_string())
}

/// Parse a JVM method descriptor and return the sequence of param Ty values,
/// one per param slot. Used to pad composable call args with correctly
/// typed placeholders (e.g. Int(0) for `$changed`/`$default`, not null).
fn param_tys_from_descriptor(desc: &str) -> Vec<Ty> {
    let inside = match desc.strip_prefix('(').and_then(|s| s.split_once(')')) {
        Some((i, _)) => i,
        None => return Vec::new(),
    };
    let mut out = Vec::new();
    let mut chars = inside.chars();
    while let Some(c) = chars.next() {
        match c {
            'L' => {
                let mut name = String::new();
                for cc in chars.by_ref() {
                    if cc == ';' {
                        break;
                    }
                    name.push(cc);
                }
                out.push(if name == "java/lang/String" {
                    Ty::String
                } else {
                    Ty::Class(name)
                });
            }
            '[' => {
                let mut depth = 1usize;
                while let Some(cc) = chars.next() {
                    if cc == '[' {
                        depth += 1;
                    } else if cc == 'L' {
                        for ccc in chars.by_ref() {
                            if ccc == ';' {
                                break;
                            }
                        }
                        break;
                    } else {
                        break;
                    }
                }
                let _ = depth;
                out.push(Ty::Any);
            }
            'Z' => out.push(Ty::Bool),
            'B' => out.push(Ty::Byte),
            'S' => out.push(Ty::Short),
            'C' => out.push(Ty::Char),
            'I' => out.push(Ty::Int),
            'J' => out.push(Ty::Long),
            'F' => out.push(Ty::Float),
            'D' => out.push(Ty::Double),
            _ => continue,
        }
    }
    out
}

/// Look up the best method descriptor for a composable function call.
/// Prefers overloads whose descriptor contains "Composer" (composable),
/// trying various param counts to account for default parameters.
fn lookup_composable_descriptor(
    class_path: &str,
    method_name: &str,
    user_arg_count: usize,
) -> Option<String> {
    // Try a range of param counts: the composable overload has at least
    // user_args + 2 ($composer + $changed), potentially more with
    // default params ($default bitmask) and the default params themselves.
    for extra in &[2, 3, 4, 5, 6, 7, 8] {
        if let Some(d) = skotch_classinfo::lookup_method_descriptor(
            class_path,
            method_name,
            user_arg_count + extra,
        ) {
            if d.contains("Composer") {
                return Some(d);
            }
        }
    }
    // No composable overload found — try exact match first.
    if let Some(d) =
        skotch_classinfo::lookup_method_descriptor(class_path, method_name, user_arg_count)
    {
        return Some(d);
    }
    // Then try non-composable overloads with extra params — this catches
    // Kotlin defaults like `mutableStateOf(value, policy = null)` whose
    // descriptor has user_args + 1 params but the user only provided
    // the value. The caller's per-slot padding will fill missing
    // reference args with null and primitives with 0 based on the
    // descriptor's character at each slot.
    for extra in &[1usize, 2, 3, 4] {
        if let Some(d) = skotch_classinfo::lookup_method_descriptor(
            class_path,
            method_name,
            user_arg_count + extra,
        ) {
            return Some(d);
        }
    }
    None
}

/// Parse a JVM method descriptor into a vec of per-slot "kind" characters:
/// 'I' for int-shaped primitives, 'J' for long, 'F' for float, 'D' for double,
/// 'L' for reference types (including arrays). Returns one entry per
/// parameter slot. Used by call-site arg-padding to pick the right default
/// value (0 for primitives, null for refs).
fn parse_descriptor_param_chars(desc: &str) -> Vec<char> {
    let inner = desc
        .strip_prefix('(')
        .and_then(|s| s.split(')').next())
        .unwrap_or("");
    let mut out = Vec::new();
    let mut chars = inner.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            'B' | 'C' | 'I' | 'S' | 'Z' => out.push('I'),
            'J' => out.push('J'),
            'F' => out.push('F'),
            'D' => out.push('D'),
            'L' => {
                for sc in chars.by_ref() {
                    if sc == ';' {
                        break;
                    }
                }
                out.push('L');
            }
            '[' => {
                // Array: skip the element descriptor entirely (including any nested L...;)
                while let Some(&sc) = chars.peek() {
                    if sc == '[' {
                        chars.next();
                    } else {
                        break;
                    }
                }
                if let Some(elem) = chars.next() {
                    if elem == 'L' {
                        for sc in chars.by_ref() {
                            if sc == ';' {
                                break;
                            }
                        }
                    }
                }
                out.push('L');
            }
            _ => {}
        }
    }
    out
}

fn jvm_type_string_for_ty(ty: &Ty) -> String {
    match ty {
        Ty::Bool => "Z".to_string(),
        Ty::Byte => "B".to_string(),
        Ty::Short => "S".to_string(),
        Ty::Char => "C".to_string(),
        Ty::Int => "I".to_string(),
        Ty::Float => "F".to_string(),
        Ty::Long => "J".to_string(),
        Ty::Double => "D".to_string(),
        Ty::String => "Ljava/lang/String;".to_string(),
        Ty::Unit => "Lkotlin/Unit;".to_string(),
        Ty::Function {
            params,
            is_composable,
            is_suspend,
            ..
        } => {
            // `@Composable () -> R` lowers to `Function{N+2}<...Composer,
            // Int, R>`, `suspend () -> R` lowers to `Function{N+1}<...,
            // Continuation, R>`. Without the composable bump, callers
            // of a function declared with `content: @Composable () ->
            // Unit` end up with the wrong Function arity in the
            // descriptor (Function0 vs Function2), and the runtime
            // checkcast at the call site fails — see JetChat's
            // JetchatDrawer.
            let n =
                params.len() + if *is_composable { 2 } else { 0 } + if *is_suspend { 1 } else { 0 };
            format!("Lkotlin/jvm/functions/Function{};", n)
        }
        // Apply kotlinc's JavaToKotlinClassMap erasure so the MIR
        // putstatic/getstatic descriptor matches the field declaration
        // emitted by the backend (which applies the same mapping). An
        // inferred type may still carry the Kotlin-side name
        // (`kotlin/collections/List`) where the JVM descriptor must use
        // `Ljava/util/List;`.
        Ty::Class(name) => {
            let mapped = intrinsics::jvm_builtin_class_erasure(name).unwrap_or(name);
            format!("L{mapped};")
        }
        // Generic types erase to their base class's descriptor on the JVM
        // (`List<Foo>` → `Ljava/util/List;`). Without this, a top-level
        // `val xs = listOf(...)` field declared `List` got a putstatic
        // descriptor of `Ljava/lang/Object;`, so the `<clinit>` store and
        // any read pushed an Object the verifier rejected when the value
        // flowed into a `List`-typed parameter.
        Ty::Generic { base, .. } => jvm_type_string_for_ty(base),
        _ => "Ljava/lang/Object;".to_string(),
    }
}

/// Resolve a type name to a `Ty`, checking built-in types first, then
/// Resolve a full TypeRef to a Ty, handling function types and nullable.
fn resolve_type_ref(tr: &skotch_syntax::TypeRef, interner: &Interner, module: &MirModule) -> Ty {
    if let Some(ref fparams) = tr.func_params {
        // Function type: (P1, P2, ...) -> R
        let params: Vec<Ty> = fparams
            .iter()
            .map(|p| resolve_type_ref(p, interner, module))
            .collect();
        let ret = resolve_type(interner.resolve(tr.name), module);
        let base = Ty::Function {
            params,
            ret: Box::new(ret),
            is_suspend: tr.is_suspend,
            is_composable: tr.is_composable,
        };
        if tr.nullable {
            Ty::Nullable(Box::new(base))
        } else {
            base
        }
    } else {
        let base = resolve_type(interner.resolve(tr.name), module);
        if tr.nullable {
            Ty::Nullable(Box::new(base))
        } else {
            base
        }
    }
}

/// user-defined classes/enums in the module.
/// Check whether `ty` represents a callable lambda — either a
/// synthetic `<Outer>$Lambda$N` class generated for capturing lambdas
/// or a `kotlin/jvm/functions/FunctionN` interface produced by the
/// LambdaMetafactory-based lowering. Used to gate scope-function
/// lowering, lambda invocation dispatch, and `$Lambda$`-specific
/// checks throughout MIR-lower.
fn is_lambda_or_function_ty(ty: &Ty, module: &MirModule) -> bool {
    matches!(
        ty,
        Ty::Class(n)
            if module.is_lambda_class(n)
                || n.starts_with("kotlin/jvm/functions/Function")
    ) || matches!(ty, Ty::Function { .. })
}

/// Look up a lambda's `invoke` return type. For synthetic `$Lambda$N`
/// classes, finds the actual return on the class's `invoke` method.
/// For `FunctionN` interface types, returns `Ty::Any` (the erased
/// `Object` return). Caller fallback is `Ty::Any`.
fn lambda_invoke_return_ty(ty: &Ty, module: &MirModule) -> Ty {
    if let Ty::Class(n) = ty {
        if n.starts_with("kotlin/jvm/functions/Function") {
            return Ty::Any;
        }
        if module.is_lambda_class(n) {
            return module
                .classes
                .iter()
                .find(|c| &c.name == n)
                .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                .map(|m| m.return_ty.clone())
                .unwrap_or(Ty::Any);
        }
    }
    if let Ty::Function { ret, .. } = ty {
        return (**ret).clone();
    }
    Ty::Any
}

fn resolve_type(name: &str, module: &MirModule) -> Ty {
    // Resolve type aliases before anything else.
    let resolved_name = if let Some(target) = module.type_aliases.get(name) {
        target.as_str()
    } else {
        name
    };
    if let Some(ty) = skotch_types::ty_from_name(resolved_name) {
        return ty;
    }
    // User-defined types take priority over well-known mappings so
    // that e.g. a user-defined `Pair` class isn't silently mapped
    // to `kotlin/Pair`.
    // Enums are real classes now.
    if module.enum_names.contains(resolved_name) {
        // Use the FQ name from the module's class list if available.
        let fq = fq_class_name(resolved_name, module);
        return Ty::Class(fq);
    }
    // User-defined class or interface.
    if module.classes.iter().any(|c| c.name == resolved_name) {
        let fq = fq_class_name(resolved_name, module);
        return Ty::Class(fq);
    }
    // Map well-known Kotlin collection/stdlib type names to their
    // fully-qualified JVM internal names.
    if let Some(jvm_name) = well_known_class_name(resolved_name) {
        return Ty::Class(jvm_name.to_string());
    }
    // Cross-file class (from PackageSymbolTable).
    if let Some((jvm_name, _, _)) = module.cross_file_classes.get(resolved_name) {
        return Ty::Class(jvm_name.clone());
    }
    // Imported external types (Java SDK classes brought in via `import`
    // statements, e.g. `import android.os.Bundle` → `android/os/Bundle`).
    // Without this lookup, types from the Android SDK fall through to
    // `Ty::Any`, which then descriptor-encodes nullable params as
    // `Ljava/lang/Object;` instead of the proper class reference — and
    // the runtime override check sees a signature mismatch and fails to
    // bind the override (e.g. `onCreate(Bundle?)` getting emitted as
    // `onCreate(Object)` makes the activity unloadable).
    if let Some(jvm_path) = module.import_map.get(resolved_name) {
        return Ty::Class(jvm_path.clone());
    }
    Ty::Any
}

/// Get the fully-qualified JVM name for a user-defined class.
/// If the class name already contains '/', it's already FQ.
/// Otherwise, derive from the module's wrapper_class package prefix.
fn fq_class_name(simple_name: &str, module: &MirModule) -> String {
    if simple_name.contains('/') {
        return simple_name.to_string();
    }
    // Check if any class in the module has this name and a FQ path.
    for c in &module.classes {
        if c.name == simple_name && c.name.contains('/') {
            return c.name.clone();
        }
    }
    // Derive from wrapper_class: "com/example/FooKt" → "com/example/"
    let prefix = module
        .wrapper_class
        .rfind('/')
        .map(|i| &module.wrapper_class[..=i])
        .unwrap_or("");
    format!("{prefix}{simple_name}")
}

/// Infer the type of a class property from its init expression.
/// Used when no explicit type annotation is provided.
fn infer_property_type(init: &skotch_syntax::Expr, interner: &Interner, module: &MirModule) -> Ty {
    use skotch_syntax::Expr;
    match init {
        Expr::IntLit(_, _) => Ty::Int,
        Expr::LongLit(_, _) => Ty::Long,
        Expr::DoubleLit(_, _) => Ty::Double,
        Expr::FloatLit(_, _) => Ty::Float,
        Expr::BoolLit(_, _) => Ty::Bool,
        Expr::CharLit(_, _) => Ty::Char,
        Expr::NullLit(_) => Ty::Any,
        // String literals and templates → String type.
        Expr::StringTemplate(_, _) => Ty::String,
        // Constructor calls: `ClassName(args)` → Ty::Class(ClassName)
        Expr::Call { callee, .. } => {
            if let Expr::Ident(name, _) = callee.as_ref() {
                let name_str = interner.resolve(*name);
                // If name starts with uppercase, it's likely a constructor.
                if name_str.starts_with(|c: char| c.is_uppercase()) {
                    let resolved = resolve_type(name_str, module);
                    if !matches!(resolved, Ty::Int) {
                        return resolved;
                    }
                    // If resolve_type returned Int (unknown), treat as Any
                    // since constructors always return reference types.
                    return Ty::Any;
                }
                // For function calls (lowercase), the return type is unknown
                // without type inference — use Any as a safe default.
                Ty::Any
            } else {
                Ty::Any
            }
        }
        // Field access like `_flow.asStateFlow()` → Any (reference)
        Expr::Field { .. } | Expr::SafeCall { .. } => Ty::Any,
        // Lambda expression → function type (reference)
        Expr::Lambda { .. } => Ty::Any,
        // Identifier reference → Any (could be anything)
        Expr::Ident(_, _) => Ty::Any,
        // Default for anything else
        _ => Ty::Any,
    }
}

/// Map well-known Kotlin source-level class names to their JVM internal names
/// so that type descriptors use `Ljava/util/List;` rather than `LList;`.
fn well_known_class_name(name: &str) -> Option<&'static str> {
    match name {
        "List" | "MutableList" => Some("java/util/List"),
        "Map" | "MutableMap" => Some("java/util/Map"),
        "Set" | "MutableSet" => Some("java/util/Set"),
        "Collection" => Some("java/util/Collection"),
        "Iterable" => Some("java/lang/Iterable"),
        "Iterator" => Some("java/util/Iterator"),
        "Pair" => Some("kotlin/Pair"),
        "Triple" => Some("kotlin/Triple"),
        _ => None,
    }
}

/// Return the Kotlin stdlib `Function{N}` interface name for the given
/// arity. Lambda classes implement this real stdlib interface so they can
/// be passed to Kotlin stdlib HOFs (map, filter, etc.) which expect
/// `kotlin/jvm/functions/Function1` and friends.
///
/// Unlike the old `$FunctionN` approach, we do NOT create a synthetic
/// interface class — the real interface lives in kotlin-stdlib.jar on
/// the runtime classpath.
fn stdlib_function_interface(arity: usize) -> String {
    format!("kotlin/jvm/functions/Function{arity}")
}

/// Check if a method call on a receiver type is a Kotlin stdlib
/// Convert AST annotations to MIR annotations.
/// Annotations with `SOURCE` retention are not emitted to bytecode. This
/// matches kotlinc's behavior for built-in source-only annotations like
/// `@Suppress`, `@SinceKotlin`, etc. Note that `@Deprecated` IS emitted
/// (as both a JVM `Deprecated` attribute and a `RuntimeVisibleAnnotations`).
fn is_source_retention_annotation(name: &str) -> bool {
    matches!(
        name,
        "Suppress"
            | "SinceKotlin"
            | "OptIn"
            | "RequiresOptIn"
            | "SubclassOptInRequired"
            | "BuilderInference"
            | "Experimental"
            | "kotlin/Suppress"
            | "kotlin/SinceKotlin"
            | "kotlin/OptIn"
            | "kotlin/RequiresOptIn"
            | "kotlin/BuilderInference"
            | "kotlin/Experimental"
    )
}

fn lower_annotations(
    annotations: &[skotch_syntax::Annotation],
    interner: &Interner,
    import_map: Option<&FxHashMap<String, String>>,
) -> Vec<skotch_mir::MirAnnotation> {
    annotations
        .iter()
        .filter(|a| !is_source_retention_annotation(interner.resolve(a.name)))
        .map(|a| {
            let name = interner.resolve(a.name);
            // First try the well-known annotation registry (JvmStatic, etc.).
            let mut descriptor = skotch_stdlib_registry::annotation_descriptor(name);
            // If the registry returned a simple-name descriptor (no package),
            // try to resolve via the file's import_map. E.g. `import
            // org.junit.jupiter.api.Test` maps "Test" → "org/junit/jupiter/api/Test",
            // giving descriptor "Lorg/junit/jupiter/api/Test;".
            if !descriptor.contains('/') {
                if let Some(map) = import_map {
                    if let Some(jvm_path) = map.get(name) {
                        descriptor = format!("L{jvm_path};");
                    }
                }
            }
            let args: Vec<skotch_mir::MirAnnotationArg> = a
                .args
                .iter()
                .enumerate()
                .map(|(i, arg)| {
                    let arg_name = format!("value{i}");
                    let value = match arg {
                        skotch_syntax::AnnotationArg::StringLit(s) => {
                            skotch_mir::MirAnnotationValue::String(s.clone())
                        }
                        skotch_syntax::AnnotationArg::IntLit(v) => {
                            skotch_mir::MirAnnotationValue::Int(*v as i32)
                        }
                        skotch_syntax::AnnotationArg::BoolLit(v) => {
                            skotch_mir::MirAnnotationValue::Bool(*v)
                        }
                        skotch_syntax::AnnotationArg::Ident(sym) => {
                            skotch_mir::MirAnnotationValue::String(
                                interner.resolve(*sym).to_string(),
                            )
                        }
                        skotch_syntax::AnnotationArg::QualifiedName(parts) => {
                            let joined: Vec<&str> =
                                parts.iter().map(|s| interner.resolve(*s)).collect();
                            skotch_mir::MirAnnotationValue::String(joined.join("."))
                        }
                        skotch_syntax::AnnotationArg::Array(items) => {
                            let arr: Vec<skotch_mir::MirAnnotationValue> = items
                                .iter()
                                .map(|item| match item {
                                    skotch_syntax::AnnotationArg::StringLit(s) => {
                                        skotch_mir::MirAnnotationValue::String(s.clone())
                                    }
                                    _ => skotch_mir::MirAnnotationValue::String(String::new()),
                                })
                                .collect();
                            skotch_mir::MirAnnotationValue::Array(arr)
                        }
                    };
                    skotch_mir::MirAnnotationArg {
                        name: if a.args.len() == 1 {
                            "value".to_string()
                        } else {
                            arg_name
                        },
                        value,
                    }
                })
                .collect();
            // Default to Runtime, but flip to Binary for annotations
            // declared with @Retention(AnnotationRetention.BINARY) by
            // common stdlib / Compose / Kotlin types. kotlinc emits
            // these via RuntimeInvisibleAnnotations; matching the
            // retention keeps the attribute placement byte-identical.
            let retention = if is_binary_retention_annotation(&descriptor) {
                skotch_mir::AnnotationRetention::Binary
            } else {
                skotch_mir::AnnotationRetention::Runtime
            };
            skotch_mir::MirAnnotation {
                descriptor,
                args,
                retention,
            }
        })
        .collect()
}

fn is_binary_retention_annotation(descriptor: &str) -> bool {
    // Common @Composable / Kotlin compiler-plugin annotations whose
    // canonical declaration uses `@Retention(AnnotationRetention.BINARY)`.
    matches!(
        descriptor,
        "Landroidx/compose/runtime/Composable;"
            | "Landroidx/compose/runtime/ReadOnlyComposable;"
            | "Landroidx/compose/runtime/Stable;"
            | "Landroidx/compose/runtime/Immutable;"
            | "Landroidx/compose/runtime/NonRestartableComposable;"
    )
}

/// Look up a Kotlin extension function compiled as a static method in
/// a `*Kt` facade class. Data is in the `skotch-stdlib-registry` crate.
fn stdlib_extension(
    receiver_ty: &str,
    method: &str,
) -> Option<(&'static str, &'static str, &'static str, Ty)> {
    skotch_stdlib_registry::lookup_stdlib_extension(receiver_ty, method).map(|ext| {
        (
            ext.facade_class,
            ext.jvm_method,
            ext.descriptor,
            (ext.return_ty)(),
        )
    })
}

/// Dynamically discovered stdlib extension cache. Populated on first use
/// by scanning kotlin-stdlib.jar for all *Kt facade classes.
static DISCOVERED_EXTENSIONS: Mutex<Option<Vec<skotch_classinfo::DiscoveredExtension>>> =
    Mutex::new(None);

/// Look up an extension function dynamically from kotlin-stdlib.jar.
/// Falls back to this when the static STDLIB_EXTENSIONS table has no match.
fn dynamic_stdlib_extension(
    receiver_ty: &str,
    method: &str,
) -> Option<(String, String, String, Ty)> {
    let mut guard = DISCOVERED_EXTENSIONS.lock().ok()?;
    let extensions = guard.get_or_insert_with(skotch_classinfo::discover_stdlib_extensions);

    // Map Skotch receiver type names to JVM descriptor prefixes.
    let receiver_descriptors: Vec<&str> = match receiver_ty {
        "java/lang/Iterable"
        | "java/util/List"
        | "java/util/Collection"
        | "List"
        | "MutableList"
        | "Collection"
        | "Iterable" => {
            vec![
                "Ljava/lang/Iterable;",
                "Ljava/util/Collection;",
                "Ljava/util/List;",
            ]
        }
        "java/util/Map" | "Map" | "MutableMap" => vec!["Ljava/util/Map;"],
        "java/util/Set" | "Set" | "MutableSet" => vec!["Ljava/util/Set;", "Ljava/lang/Iterable;"],
        "java/lang/String" | "String" => vec!["Ljava/lang/CharSequence;", "Ljava/lang/String;"],
        "java/lang/CharSequence" | "CharSequence" => vec!["Ljava/lang/CharSequence;"],
        "kotlin/sequences/Sequence" | "Sequence" => vec!["Lkotlin/sequences/Sequence;"],
        _ if receiver_ty.starts_with("java/") || receiver_ty.starts_with("kotlin/") => {
            vec![] // Return empty for specific JVM types we don't handle yet
        }
        _ => vec!["Ljava/lang/Iterable;", "Ljava/lang/Object;"], // Try common supertypes
    };

    // Also try the receiver's own fully-qualified descriptor, so extensions on
    // concrete dep-jar classes (e.g. `kotlinx/coroutines/flow/MutableStateFlow`
    // → `FlowKt.asStateFlow`) resolve — the hardcoded map above only covers the
    // stdlib collection/string aliases.
    let mut candidates: Vec<String> = receiver_descriptors.iter().map(|s| s.to_string()).collect();
    if receiver_ty.contains('/') {
        candidates.push(format!("L{receiver_ty};"));
    }

    for ext in extensions.iter() {
        if ext.method_name != method {
            continue;
        }
        for recv_desc in &candidates {
            if &ext.receiver_descriptor == recv_desc {
                let return_ty = match ext.return_descriptor.as_str() {
                    "V" => Ty::Unit,
                    "Z" => Ty::Bool,
                    "I" => Ty::Int,
                    "J" => Ty::Long,
                    "D" => Ty::Double,
                    d if d.starts_with("Ljava/lang/String;") => Ty::String,
                    d if d.starts_with("Ljava/util/List;") => {
                        Ty::Class("java/util/List".to_string())
                    }
                    d if d.starts_with("Ljava/util/Set;") => Ty::Class("java/util/Set".to_string()),
                    d if d.starts_with("Ljava/util/Map;") => Ty::Class("java/util/Map".to_string()),
                    // Any other reference type: recover the nominal class (e.g.
                    // `Lkotlinx/coroutines/flow/StateFlow;` → StateFlow) so the
                    // result isn't erased to `Any`.
                    d if d.starts_with('L') && d.ends_with(';') => {
                        Ty::Class(d[1..d.len() - 1].to_string())
                    }
                    _ => Ty::Any,
                };
                return Some((
                    ext.facade_class.clone(),
                    ext.method_name.clone(),
                    ext.descriptor.clone(),
                    return_ty,
                ));
            }
        }
    }
    None
}

/// Remap a `LocalId` via the given `map`, defaulting to the original
/// id if no entry exists. Used by the inline-fn body splicer.
fn remap_local(map: &FxHashMap<u32, LocalId>, l: LocalId) -> LocalId {
    map.get(&l.0).copied().unwrap_or(l)
}

/// Clone an `Rvalue`, remapping every `LocalId` it contains via `map`.
/// String fields (class names, descriptors) are cloned verbatim.
fn remap_rvalue(map: &FxHashMap<u32, LocalId>, rv: &Rvalue) -> Rvalue {
    match rv {
        Rvalue::Const(c) => Rvalue::Const(c.clone()),
        Rvalue::Local(l) => Rvalue::Local(remap_local(map, *l)),
        Rvalue::BinOp { op, lhs, rhs } => Rvalue::BinOp {
            op: *op,
            lhs: remap_local(map, *lhs),
            rhs: remap_local(map, *rhs),
        },
        Rvalue::GetStaticField {
            class_name,
            field_name,
            descriptor,
        } => Rvalue::GetStaticField {
            class_name: class_name.clone(),
            field_name: field_name.clone(),
            descriptor: descriptor.clone(),
        },
        Rvalue::NewInstance(n) => Rvalue::NewInstance(n.clone()),
        Rvalue::GetField {
            receiver,
            class_name,
            field_name,
        } => Rvalue::GetField {
            receiver: remap_local(map, *receiver),
            class_name: class_name.clone(),
            field_name: field_name.clone(),
        },
        Rvalue::PutField {
            receiver,
            class_name,
            field_name,
            value,
        } => Rvalue::PutField {
            receiver: remap_local(map, *receiver),
            class_name: class_name.clone(),
            field_name: field_name.clone(),
            value: remap_local(map, *value),
        },
        Rvalue::PutStaticField {
            class_name,
            field_name,
            descriptor,
            value,
        } => Rvalue::PutStaticField {
            class_name: class_name.clone(),
            field_name: field_name.clone(),
            descriptor: descriptor.clone(),
            value: remap_local(map, *value),
        },
        Rvalue::Call { kind, args } => Rvalue::Call {
            kind: kind.clone(),
            args: args.iter().map(|l| remap_local(map, *l)).collect(),
        },
        Rvalue::InstanceOf {
            obj,
            type_descriptor,
        } => Rvalue::InstanceOf {
            obj: remap_local(map, *obj),
            type_descriptor: type_descriptor.clone(),
        },
        Rvalue::NewIntArray(s) => Rvalue::NewIntArray(remap_local(map, *s)),
        Rvalue::ArrayLoad { array, index } => Rvalue::ArrayLoad {
            array: remap_local(map, *array),
            index: remap_local(map, *index),
        },
        Rvalue::ArrayStore {
            array,
            index,
            value,
        } => Rvalue::ArrayStore {
            array: remap_local(map, *array),
            index: remap_local(map, *index),
            value: remap_local(map, *value),
        },
        Rvalue::ArrayLength(a) => Rvalue::ArrayLength(remap_local(map, *a)),
        Rvalue::NewObjectArray(s) => Rvalue::NewObjectArray(remap_local(map, *s)),
        Rvalue::NewTypedObjectArray {
            size,
            element_class,
        } => Rvalue::NewTypedObjectArray {
            size: remap_local(map, *size),
            element_class: element_class.clone(),
        },
        Rvalue::ObjectArrayStore {
            array,
            index,
            value,
        } => Rvalue::ObjectArrayStore {
            array: remap_local(map, *array),
            index: remap_local(map, *index),
            value: remap_local(map, *value),
        },
        Rvalue::CheckCast { obj, target_class } => Rvalue::CheckCast {
            obj: remap_local(map, *obj),
            target_class: target_class.clone(),
        },
    }
}

/// Try to inline a call to a user-declared `inline fun` by splicing the
/// callee's body into the caller's current basic block. Returns
/// `Some(result_local)` when inlining succeeded, `None` to fall through
/// to the regular static-call path.
///
/// **Conservative gating:** only inlines callees that are
/// - marked `is_inline = true`,
/// - have exactly one basic block (no internal branches),
/// - have no exception handlers,
/// - are not `suspend`,
/// - have no lambda-typed parameters (HOF inline fns like `let`/`with`
///   are intrinsified separately and not handled here),
/// - terminate with `Return` or `ReturnValue(local)`.
///
/// `target_idx` is the index into `caller_module.functions` of the inline
/// callee. `arg_locals` are the caller's locals holding the lowered args.
/// The function clones the callee's body, builds a `param → arg` plus
/// `other → fresh caller local` remap, then pushes each remapped stmt
/// onto the caller's `fb` and returns the remapped return local.
fn try_inline_call_into_fb(
    target_idx: usize,
    arg_locals: &[LocalId],
    fb: &mut FnBuilder,
    module: &MirModule,
) -> Option<LocalId> {
    let target = &module.functions[target_idx];

    if !target.is_inline
        || target.is_suspend
        || target.is_abstract
        || target.blocks.len() != 1
        || !target.exception_handlers.is_empty()
        || target.suspend_state_machine.is_some()
    {
        return None;
    }
    // Skip HOF inline fns — the intrinsics path handles them.
    if target
        .params
        .iter()
        .any(|p| matches!(target.locals[p.0 as usize], Ty::Function { .. }))
    {
        return None;
    }
    // The arg count must match the param count. Default-param dispatch
    // wraps calls in a synthetic wrapper that we don't try to unwind
    // here — fall through to the normal static-call path.
    if arg_locals.len() != target.params.len() {
        return None;
    }

    let block = &target.blocks[0];

    // Build the LocalId remap: every callee local maps to a fresh local
    // in the caller. Param locals map to the caller's arg locals
    // *directly* — re-using the arg's existing slot avoids an extra
    // copy and matches kotlinc's inline-fn lowering, which uses the
    // arg slot for the corresponding param read.
    let mut remap: FxHashMap<u32, LocalId> = FxHashMap::default();
    for (i, &param_local) in target.params.iter().enumerate() {
        remap.insert(param_local.0, arg_locals[i]);
    }
    for (i, ty) in target.locals.iter().enumerate() {
        let id = LocalId(i as u32);
        remap
            .entry(id.0)
            .or_insert_with(|| fb.new_local(ty.clone()));
    }

    // Splice each statement, remapping all LocalIds.
    for stmt in &block.stmts {
        match stmt {
            MStmt::Assign { dest, value } => {
                fb.push_stmt(MStmt::Assign {
                    dest: remap_local(&remap, *dest),
                    value: remap_rvalue(&remap, value),
                });
            }
        }
    }

    // Capture the return value.
    match &block.terminator {
        Terminator::ReturnValue(l) => Some(remap_local(&remap, *l)),
        Terminator::Return => {
            // Unit-typed inline fn — synthesize a Unit-valued dest.
            let dest = fb.new_local(Ty::Unit);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Null),
            });
            Some(dest)
        }
        // Branch/Goto/Throw in a single-block fn means we gated wrong
        // (single block can't goto another, and Throw/Branch don't
        // terminate cleanly here). Fall through.
        _ => None,
    }
}

/// Lower a parsed/resolved/typed file to MIR.
pub fn lower_file(
    file: &KtFile,
    resolved: &ResolvedFile,
    typed: &TypedFile,
    interner: &mut Interner,
    diags: &mut Diagnostics,
    wrapper_class: &str,
    package_symbols: Option<&PackageSymbolTable>,
) -> MirModule {
    let mut module = MirModule {
        wrapper_class: wrapper_class.to_string(),
        ..MirModule::default()
    };

    // ─── Pass 0: collect type aliases ─────────────────────────────────
    for decl in &file.decls {
        if let Decl::TypeAlias(ta) = decl {
            let alias_name = interner.resolve(ta.name).to_string();
            let target_name = interner.resolve(ta.target.name).to_string();
            module.type_aliases.insert(alias_name, target_name);
        }
    }

    // ─── Pass 1: register top-level functions ───────────────────────────
    //
    // Pre-allocate a `FuncId` for every top-level `fun` in source order
    // so call sites between them resolve consistently regardless of
    // declaration order.
    let mut name_to_func: FxHashMap<Symbol, FuncId> = FxHashMap::default();
    let mut fn_pass1_idx: usize = 0;
    for decl in &file.decls {
        if let Decl::Fun(f) = decl {
            let id = FuncId(module.functions.len() as u32);
            name_to_func.insert(f.name, id);
            // Extension properties (`val X.foo`) are emitted as `getFoo`
            // methods to match kotlinc's accessor naming. Keep the
            // original symbol bound in `name_to_func` so source-level
            // references still resolve to this `FuncId`.
            let raw_name = interner.resolve(f.name).to_string();
            let name_str = if f.is_ext_property {
                let mut chars = raw_name.chars();
                let first = chars.next().map(|c| c.to_ascii_uppercase());
                match first {
                    Some(c) => format!("get{}{}", c, chars.as_str()),
                    None => raw_name.clone(),
                }
            } else {
                raw_name
            };
            // Use the typechecker's return type so recursive calls and
            // forward references get the correct type, not Ty::Unit.
            let declared_ret = typed
                .functions
                .get(fn_pass1_idx)
                .map(|t| t.return_ty.clone())
                .unwrap_or(Ty::Unit);
            // Coroutine transform: rewrite the
            // return type of every `suspend fun` to `Any` (which
            // lowers to `Ljava/lang/Object;` on JVM). The actual
            // `$completion: Continuation` parameter is appended in
            // `lower_function`; we only record the signature change
            // here so call sites resolving through `name_to_func`
            // see the post-transform return type.
            let return_ty = if f.is_suspend { Ty::Any } else { declared_ret };
            let mut required = f.params.iter().filter(|p| p.default.is_none()).count();
            let mut param_defaults: Vec<Option<MirConst>> = f
                .params
                .iter()
                .map(|p| {
                    p.default
                        .as_ref()
                        .and_then(|d| lower_const_init(d, &mut module))
                })
                .collect();
            let mut param_names: Vec<String> = f
                .params
                .iter()
                .map(|p| interner.resolve(p.name).to_string())
                .collect();
            // Extension functions / properties have an implicit
            // receiver param prepended at codegen. kotlinc names it
            // `<this>` so the checkNotNullParameter prologue emits the
            // right intrinsic message.
            if f.receiver_ty.is_some() {
                param_names.insert(0, "<this>".to_string());
            }
            let vararg_index = f.params.iter().position(|p| p.is_vararg);
            // Coroutine transform: every `suspend
            // fun` grows a trailing `$completion: Continuation`
            // parameter. The call site knows to synthesize an
            // argument for it from the target's `is_suspend` flag.
            if f.is_suspend {
                param_names.push("$completion".to_string());
                param_defaults.push(None);
                required += 1;
            }
            // Set up placeholder params so extension function detection
            // (is_extension = params.len() == args.len() + 1) works for
            // recursive calls before the function is fully lowered.
            let placeholder_param_count = f.params.len()
                + if f.receiver_ty.is_some() { 1 } else { 0 }
                + if f.is_suspend { 1 } else { 0 };
            let placeholder_params: Vec<LocalId> =
                (0..placeholder_param_count as u32).map(LocalId).collect();
            // Populate the placeholder param types from the typechecker so
            // recursive calls see the real param types (not `Any`) and skip
            // autoboxing primitive arguments.
            let mut placeholder_locals: Vec<Ty> = vec![Ty::Any; placeholder_param_count];
            if !f.is_suspend {
                let receiver_offset = if f.receiver_ty.is_some() { 1 } else { 0 };
                if let Some(tf) = typed.functions.get(fn_pass1_idx) {
                    for (i, ty) in tf.param_tys.iter().enumerate() {
                        let pos = receiver_offset + i;
                        if pos < placeholder_locals.len() {
                            placeholder_locals[pos] = ty.clone();
                        }
                    }
                }
            }
            let fn_annotations = lower_annotations(&f.annotations, interner, None);
            module.functions.push(MirFunction {
                id,
                name: name_str,
                params: placeholder_params,
                locals: placeholder_locals,
                blocks: Vec::new(),
                return_ty,
                required_params: required,
                param_names,
                param_defaults,
                param_receiver_types: Vec::new(),
                is_abstract: false,
                exception_handlers: Vec::new(),
                vararg_index,
                is_suspend: f.is_suspend,
                is_inline: f.is_inline,
                has_type_params: !f.type_params.is_empty(),
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: fn_annotations,
                named_locals: Vec::new(),
                is_private: matches!(f.visibility, skotch_syntax::Visibility::Private),
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            });
            fn_pass1_idx += 1;
        }
    }

    // ── Pre-register external suspend function stubs ──────
    //
    // External suspend functions like `delay` (from kotlinx-coroutines)
    // must be registered before any function bodies are lowered, so that
    // `body_contains_suspend_call` can detect them during suspend-lambda
    // analysis. These stubs are never emitted as JVM methods (they're
    // marked `is_abstract`); the real implementations live in library JARs.
    {
        let delay_sym = interner.intern("delay");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&delay_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "delay".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Unit),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_ms = stub.new_local(Ty::Long);
            stub.params.push(p_ms);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(delay_sym, fid);
        }
    }

    // ── Pre-register additional suspend function stubs ──────
    //
    // `withContext`, `coroutineScope`, `supervisorScope`, `withTimeout`,
    // `withTimeoutOrNull`, and `yield` are all suspend functions from
    // kotlinx-coroutines that appear as direct calls in user code.
    // Register stubs so `body_contains_suspend_call` can detect them
    // inside trailing lambdas passed to coroutine builders.
    //
    // withContext(CoroutineContext, Function2, Continuation) → Object
    // coroutineScope(Function2, Continuation) → Object
    // supervisorScope(Function2, Continuation) → Object
    // withTimeout(Long, Function2, Continuation) → Object
    // withTimeoutOrNull(Long, Function2, Continuation) → Object
    // yield(Continuation) → Object
    {
        // yield — suspend fun yield()
        let yield_sym = interner.intern("yield");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&yield_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "yield".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Unit),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(yield_sym, fid);
        }

        // withContext — suspend fun <T> withContext(context, block): T
        let wc_sym = interner.intern("withContext");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&wc_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "withContext".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Any),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_ctx = stub.new_local(Ty::Class("kotlin/coroutines/CoroutineContext".to_string()));
            stub.params.push(p_ctx);
            let p_block = stub.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
            stub.params.push(p_block);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(wc_sym, fid);
        }

        // coroutineScope — suspend fun <R> coroutineScope(block): R
        let cs_sym = interner.intern("coroutineScope");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&cs_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "coroutineScope".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Any),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_block = stub.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
            stub.params.push(p_block);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(cs_sym, fid);
        }

        // supervisorScope — suspend fun <R> supervisorScope(block): R
        let ss_sym = interner.intern("supervisorScope");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&ss_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "supervisorScope".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Any),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_block = stub.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
            stub.params.push(p_block);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(ss_sym, fid);
        }

        // withTimeout — suspend fun <T> withTimeout(timeMillis: Long, block): T
        let wt_sym = interner.intern("withTimeout");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&wt_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "withTimeout".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Any),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_ms = stub.new_local(Ty::Long);
            stub.params.push(p_ms);
            let p_block = stub.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
            stub.params.push(p_block);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(wt_sym, fid);
        }

        // withTimeoutOrNull — suspend fun <T> withTimeoutOrNull(timeMillis: Long, block): T?
        let wton_sym = interner.intern("withTimeoutOrNull");
        #[allow(clippy::map_entry)]
        if !name_to_func.contains_key(&wton_sym) {
            let mut stub = MirFunction {
                id: FuncId(0),
                name: "withTimeoutOrNull".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Any,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: true,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: Some(Ty::Nullable(Box::new(Ty::Any))),
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let p_ms = stub.new_local(Ty::Long);
            stub.params.push(p_ms);
            let p_block = stub.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
            stub.params.push(p_block);
            let p_cont = stub.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
            stub.params.push(p_cont);
            let fid = module.add_function(stub);
            name_to_func.insert(wton_sym, fid);
        }
    }

    // Collect enum names so they can be recognized as types (mapped to String).
    let enum_names: rustc_hash::FxHashSet<String> = file
        .decls
        .iter()
        .filter_map(|d| {
            if let Decl::Enum(e) = d {
                Some(interner.resolve(e.name).to_string())
            } else {
                None
            }
        })
        .collect();
    module.enum_names = enum_names;

    // ─── Collect reified inline function bodies for call-site inlining ──
    // Functions with `reified` type params must be inlined at call sites
    // so the type check can use the concrete type argument.
    let mut reified_fns: FxHashMap<Symbol, &FunDecl> = FxHashMap::default();
    for decl in &file.decls {
        if let Decl::Fun(f) = decl {
            if f.type_params.iter().any(|tp| tp.is_reified) {
                reified_fns.insert(f.name, f);
            }
        }
    }

    // ─── Pass 2: collect top-level val constants ────────────────────────
    //
    // Top-level vals with literal initializers are lowered as
    // **inlined constants**: every reference site emits a
    // `Rvalue::Const(<value>)` directly. This avoids the complexity of
    // emitting JVM static fields + `<clinit>` and DEX `static_values_off`
    // for the common case where the user wrote a literal. Compile speed
    // and output accuracy both win — there's no extra method to compile
    // and the runtime behavior is identical (the JIT would inline these
    // anyway).
    //
    // Non-literal initializers are already rejected by `skotch-typeck`
    // ("top-level val initializers must be a literal"), so we
    // skip silently here when we can't extract a `MirConst`.
    let mut name_to_global: FxHashMap<Symbol, MirConst> = FxHashMap::default();
    // Track non-const top-level vals whose initializers couldn't be const-
    // folded. After all functions are lowered (and thus all call sites
    // resolvable), we synthesize a `<clinit>` MirFunction that lowers each
    // saved init expression and stores the result via PutStaticField.
    let mut deferred_val_inits: Vec<(String, &skotch_syntax::Expr)> = Vec::new();
    for decl in &file.decls {
        if let Decl::Val(v) = decl {
            let name_str = interner.resolve(v.name).to_string();
            if let Some(c) = lower_const_init(&v.init, &mut module) {
                let ty = const_ty(&c);
                if v.is_const {
                    // `const val` → `public static final` field with
                    // ConstantValue attribute. Use sites inline the
                    // literal directly.
                    name_to_global.insert(v.name, c.clone());
                    module.top_level_consts.push((name_str, ty, c));
                } else {
                    // Regular `val` → `private static final` field plus
                    // `<clinit>` initializer plus public getter. Use
                    // sites must NOT inline; they read via `getstatic`.
                    // Track in `top_level_prop_names` (as a string set on
                    // the module) so the Ident lookup can recognize and
                    // emit `Rvalue::GetStaticField` instead of inlining.
                    module.top_level_props.push((name_str.clone(), ty, c));
                    module.top_level_prop_names.insert(name_str);
                }
            } else if !v.is_const {
                // Non-const val whose initializer is a function call,
                // construction, or other non-trivial expression. Register
                // the field with the inferred initializer type (falls back
                // to `Ty::Any` for unrecognized init shapes) so the
                // synthesized `get<Name>()` accessor's return descriptor
                // matches what cross-file call sites read from the same-
                // package `ExternalValDecl` (which goes through resolve.rs's
                // `infer_val_type_from_init`). The actual value is still
                // computed in the synthetic <clinit> emitted below.
                let inferred_ty = infer_top_level_val_ty(&v.init, file, interner);
                module
                    .top_level_props
                    .push((name_str.clone(), inferred_ty, MirConst::Null));
                module.top_level_prop_names.insert(name_str.clone());
                deferred_val_inits.push((name_str, &v.init));
            }
        }
    }

    // ─── Build import map ────────────────────────────────────────────────
    // Maps simple class names → JVM class paths from import statements.
    // Also includes default java.lang.* imports (Kotlin implicitly imports java.lang.*).
    let mut import_map: FxHashMap<String, String> = FxHashMap::default();
    // Default java.lang.* imports (from registry).
    for name in skotch_stdlib_registry::DEFAULT_IMPORTS {
        import_map.insert(name.to_string(), format!("java/lang/{name}"));
    }
    // Process explicit imports
    for imp in &file.imports {
        let segments: Vec<&str> = imp.path.iter().map(|s| interner.resolve(*s)).collect();
        if imp.is_wildcard {
            // Star imports: enumerate user classes/functions from
            // PackageSymbolTable for the matching package prefix.
            if let Some(pkg) = package_symbols {
                let pkg_prefix = segments.join("/");
                for (name, ext_class) in &pkg.classes {
                    if ext_class.jvm_name.starts_with(&pkg_prefix) {
                        import_map
                            .entry(name.clone())
                            .or_insert_with(|| ext_class.jvm_name.clone());
                    }
                }
            }
        } else if !segments.is_empty() {
            // Use alias if present, otherwise use the simple name.
            let key = if let Some(alias_sym) = imp.alias {
                interner.resolve(alias_sym).to_string()
            } else {
                segments.last().unwrap().to_string()
            };
            let jvm_path = segments.join("/");

            // Check if this is a static method import (e.g. Assertions.assertTrue).
            // If the last segment is a static method on the class formed by the
            // rest of the segments, store it as a static method import.
            if segments.len() >= 2 {
                let method_name = *segments.last().unwrap();
                let class_segments = &segments[..segments.len() - 1];
                let class_path = class_segments.join("/");
                if is_static_method_on_class(&class_path, method_name) {
                    module
                        .static_method_imports
                        .insert(key.clone(), (class_path.clone(), method_name.to_string()));
                    // Also add the class to import_map so annotations etc. resolve.
                    let class_simple = class_segments.last().unwrap().to_string();
                    import_map.entry(class_simple).or_insert(class_path);
                    continue;
                }
            }

            import_map.insert(key, jvm_path);
        }
    }

    module.import_map = import_map;

    // Register cross-file declarations so they're accessible from lower_expr.
    if let Some(pkg) = package_symbols {
        // Classes → import_map + cross_file_classes + stub MirClass entries.
        // The stub MirClass allows field access (`p.x`) and method dispatch
        // (`g.greet()`) to work on cross-file class instances.
        for (name, ext_class) in &pkg.classes {
            if !module.import_map.contains_key(name) {
                module
                    .import_map
                    .insert(name.clone(), ext_class.jvm_name.clone());
            }
            let is_data = matches!(ext_class.kind, ExternalClassKind::DataClass);
            module.cross_file_classes.insert(
                name.clone(),
                (
                    ext_class.jvm_name.clone(),
                    format!("{:?}", ext_class.kind),
                    is_data,
                ),
            );

            // Only add a stub MirClass if one with this name doesn't
            // already exist (the class might be defined in this file too).
            let already_exists = module.classes.iter().any(|c| c.name == ext_class.jvm_name);
            if !already_exists {
                use skotch_mir::{BasicBlock, FuncId, MirClass, MirField, MirFunction, Terminator};
                let fields: Vec<MirField> = ext_class
                    .fields
                    .iter()
                    .map(|(fname, fty)| MirField {
                        name: fname.clone(),
                        ty: fty.clone(),
                        is_jvm_field: false,
                    })
                    .collect();
                let stub_fn = |mname: &str, param_tys: &[Ty], ret_ty: &Ty| -> MirFunction {
                    let mut locals = vec![Ty::Class(ext_class.jvm_name.clone())];
                    for pt in param_tys {
                        locals.push(pt.clone());
                    }
                    let params: Vec<LocalId> = (0..locals.len() as u32).map(LocalId).collect();
                    MirFunction {
                        id: FuncId(0),
                        name: mname.to_string(),
                        params,
                        locals,
                        blocks: vec![BasicBlock {
                            stmts: Vec::new(),
                            terminator: Terminator::Return,
                        }],
                        return_ty: ret_ty.clone(),
                        required_params: 0,
                        param_names: Vec::new(),
                        param_receiver_types: Vec::new(),
                        param_defaults: Vec::new(),
                        is_abstract: false,
                        vararg_index: None,
                        exception_handlers: Vec::new(),
                        is_suspend: false,
                        is_inline: false,
                        has_type_params: false,
                        suspend_original_return_ty: None,
                        suspend_state_machine: None,
                        annotations: Vec::new(),
                        named_locals: Vec::new(),
                        is_private: false,
                        is_static: false,
                        default_call_masks: Vec::new(),
                        needs_leading_nop: false,
                        local_generic_args: rustc_hash::FxHashMap::default(),
                    }
                };
                let methods: Vec<MirFunction> = ext_class
                    .methods
                    .iter()
                    .map(|(mname, param_tys, ret_ty)| stub_fn(mname, param_tys, ret_ty))
                    .collect();
                // Populate the cross-file stub constructor with the
                // class's full primary-ctor param types (val/var or not).
                // Without this, every call site that crosses files sees
                // a zero-arg `<init>` stub, the JVM backend infers the
                // descriptor from only the user-supplied args, and the
                // emitted `<init>` descriptor gets truncated — for
                // example `Message("a","b","c")` (where Message declares
                // 5 params, 2 with defaults) emits
                // `<init>(String,String,String)V` instead of the real
                // 5-arg signature, and the runtime can't find it.
                //
                // Prefer the full `ctor_params` list (declaration order,
                // includes plain non-field params like
                // `class ConversationUiState(channelName: String,
                // channelMembers: Int, initialMessages: List<Message>)`)
                // and only fall back to `fields` when the resolver
                // didn't record it.
                let ctor_param_tys: Vec<Ty> = if ext_class.ctor_params.is_empty() {
                    ext_class.fields.iter().map(|(_, t)| t.clone()).collect()
                } else {
                    ext_class
                        .ctor_params
                        .iter()
                        .map(|(_, t)| t.clone())
                        .collect()
                };
                let ctor_param_names: Vec<String> = if ext_class.ctor_params.is_empty() {
                    ext_class.fields.iter().map(|(n, _)| n.clone()).collect()
                } else {
                    ext_class
                        .ctor_params
                        .iter()
                        .map(|(n, _)| n.clone())
                        .collect()
                };
                let mut empty_ctor = stub_fn("<init>", &ctor_param_tys, &Ty::Unit);
                // Populate `param_names` so named-arg reordering at the
                // call site can map `Foo(name = ..., other = ...)` to the
                // constructor's positional slots.
                empty_ctor.param_names = ctor_param_names;
                // If this cross-file class has a companion object, also
                // push a stub MirClass for it so the call-site companion
                // dispatcher (`OuterClass.method(...)`) at lib.rs:7746
                // can resolve `OuterClass$Companion.method` virtually.
                let companion_jvm_name = if ext_class.companion_methods.is_empty() {
                    None
                } else {
                    let comp_name = format!("{}$Companion", ext_class.jvm_name);
                    let comp_methods: Vec<MirFunction> = ext_class
                        .companion_methods
                        .iter()
                        .map(|(mname, param_tys, ret_ty)| stub_fn(mname, param_tys, ret_ty))
                        .collect();
                    let comp_ctor = stub_fn("<init>", &[], &Ty::Unit);
                    module.classes.push(MirClass {
                        name: comp_name.clone(),
                        super_class: None,
                        is_open: false,
                        is_abstract: false,
                        is_interface: false,
                        interfaces: Vec::new(),
                        fields: Vec::new(),
                        methods: comp_methods,
                        constructor: comp_ctor,
                        secondary_constructors: Vec::new(),
                        is_lambda: false,
                        is_suspend_lambda: false,
                        is_cross_file_stub: true,
                        annotations: Vec::new(),
                        has_type_params: false,
                        is_object_singleton: true,
                        companion_class_name: None,
                        static_fields: Vec::new(),
                        clinit: None,
                    });
                    Some(comp_name)
                };
                module.classes.push(MirClass {
                    name: ext_class.jvm_name.clone(),
                    super_class: ext_class.super_class.clone(),
                    is_open: ext_class.is_open,
                    is_abstract: ext_class.is_abstract,
                    is_interface: matches!(ext_class.kind, ExternalClassKind::Interface),
                    interfaces: Vec::new(),
                    fields,
                    methods,
                    constructor: empty_ctor,
                    secondary_constructors: Vec::new(),
                    is_lambda: false,
                    is_suspend_lambda: false,
                    is_cross_file_stub: true,
                    annotations: Vec::new(),
                    has_type_params: false,
                    is_object_singleton: false,
                    companion_class_name: companion_jvm_name,
                    static_fields: Vec::new(),
                    clinit: None,
                });
            }
        }
        // Functions → cross_file_fns so bare calls resolve.
        for (name, decls) in &pkg.functions {
            if let Some(ext) = decls.first() {
                module.cross_file_fns.insert(
                    name.clone(),
                    (
                        ext.owner_class.clone(),
                        ext.descriptor.clone(),
                        ext.return_ty.clone(),
                    ),
                );
            }
        }
        // Top-level vals → cross_file_vals so `topLevelVal.someMethod()`
        // resolves via the wrapper class's static getter rather than
        // treating the val name as a class.
        for (name, ext_val) in &pkg.vals {
            module.cross_file_vals.insert(
                name.clone(),
                (ext_val.owner_class.clone(), ext_val.ty.clone()),
            );
        }
    }

    // ── Register a synthetic $Callable interface so all lambda classes
    //    can share a common dispatch target for invokevirtual. ────────
    //    This interface declares `invoke` with Object params/return so
    //    any lambda can be called through it.
    // Pre-register a synthetic $Callable abstract class that all lambda
    // classes will extend. This allows invokevirtual $Callable.invoke(...)
    // to dispatch correctly for function-typed parameters.
    // $Callable has no invoke method itself (it's added per-lambda with
    // the correct signature), but the JVM can resolve invokevirtual on
    // a parent class reference if the runtime subclass has the method.
    // Actually — the JVM requires the methodref class to DECLARE the
    // method. So we won't use $Callable for dispatch. Instead, we'll
    // record lambda class names during lowering and use a two-pass
    // approach: lower all declarations first, then patch invoke targets.
    //
    // For now, function-typed parameters that receive lambdas work ONLY
    // when the lambda is defined in the same scope (local variable).
    // Passing through a function parameter (higher-order) needs the
    // $Callable interface, which is tracked as a v0.3.0 follow-up.

    // ─── Pass 3: lower each function body ───────────────────────────────
    let mut fn_idx: usize = 0;
    for decl in &file.decls {
        match decl {
            Decl::Fun(f) => {
                let typed_fn = typed.functions.get(fn_idx);
                lower_function(
                    f,
                    fn_idx,
                    typed_fn,
                    &mut name_to_func,
                    &name_to_global,
                    &mut module,
                    interner,
                    diags,
                );
                fn_idx += 1;
            }
            Decl::Val(_) => {
                // Already handled in pass 2.
            }
            Decl::Class(c) => {
                lower_class(
                    c,
                    &mut name_to_func,
                    &mut name_to_global,
                    &mut module,
                    interner,
                    diags,
                );
            }
            Decl::Object(o) => {
                lower_object(
                    o,
                    &mut name_to_func,
                    &name_to_global,
                    &mut module,
                    interner,
                    diags,
                );
            }
            Decl::Enum(e) => {
                lower_enum(
                    e,
                    &mut name_to_func,
                    &mut name_to_global,
                    &mut module,
                    interner,
                );
            }
            Decl::Interface(iface) => {
                lower_interface(
                    iface,
                    &mut name_to_func,
                    &name_to_global,
                    &mut module,
                    interner,
                    diags,
                );
            }
            Decl::TypeAlias(_) => {
                // Type aliases are resolved at parse/type-check time;
                // no MIR lowering needed.
            }
            Decl::Unsupported { what, span } => {
                diags.push(Diagnostic::error(
                    *span,
                    format!("`{what}` declarations are not yet supported"),
                ));
            }
        }
    }
    let _ = resolved;

    // ─── Pass 3b: synthesize `<clinit>` for non-const val initializers ──
    //
    // The Null placeholders registered in pass 2 keep the static fields
    // and getters from disappearing, but reads return `null` — which is
    // wrong for Compose theme constants like
    // `val JetchatLightColorScheme = lightColorScheme(...)`. Synthesize a
    // proper `<clinit>` that runs each deferred initializer and stores
    // the result via `Rvalue::PutStaticField`. Also handles the
    // const-foldable props (was previously the auto-clinit's job), so
    // both kinds end up in a single <clinit> as the JVM requires.
    if !deferred_val_inits.is_empty() {
        let clinit_idx = module.functions.len();
        let mut fb = FnBuilder::new(clinit_idx, "<clinit>".to_string(), Ty::Unit);
        let mut scope: Vec<(Symbol, LocalId)> = Vec::new();
        let wrapper_class = module.wrapper_class.clone();
        let deferred_names: rustc_hash::FxHashSet<String> =
            deferred_val_inits.iter().map(|(n, _)| n.clone()).collect();
        // Const-foldable props go first — same order as the auto-clinit.
        // We snapshot them so we don't borrow `module.top_level_props`
        // while calling lower_expr (which mutates module).
        let const_props: Vec<(String, Ty, MirConst)> = module
            .top_level_props
            .iter()
            .filter(|(n, _, _)| !deferred_names.contains(n))
            .cloned()
            .collect();
        for (val_name, ty, value) in const_props {
            let local = fb.new_local(ty.clone());
            fb.push_stmt(MStmt::Assign {
                dest: local,
                value: Rvalue::Const(value),
            });
            let dummy = fb.new_local(Ty::Unit);
            let descriptor = jvm_type_string_for_ty(&ty);
            fb.push_stmt(MStmt::Assign {
                dest: dummy,
                value: Rvalue::PutStaticField {
                    class_name: wrapper_class.clone(),
                    field_name: val_name,
                    descriptor,
                    value: local,
                },
            });
        }
        // Now the deferred initializers — each lowers its real init
        // expression and stores the result via PutStaticField.
        for (val_name, init_expr) in deferred_val_inits {
            if let Some(value_local) = lower_expr(
                init_expr,
                &mut fb,
                &mut scope,
                &mut module,
                &mut name_to_func,
                &name_to_global,
                interner,
                diags,
                None,
            ) {
                // Use the descriptor that matches the static field's actual
                // declared type (populated from `infer_top_level_val_ty`
                // above). Hardcoding `Ljava/lang/Object;` here produced
                // putstatic ops with descriptors that didn't match the
                // field declaration — the JVM rejects this at <clinit>
                // load time with `NoSuchFieldError: No static field <N>
                // of type Ljava/lang/Object;` even when a same-named field
                // with a different descriptor exists.
                let field_ty = module
                    .top_level_props
                    .iter()
                    .find(|(n, _, _)| n == &val_name)
                    .map(|(_, t, _)| t.clone())
                    .unwrap_or(Ty::Any);
                let descriptor = jvm_type_string_for_ty(&field_ty);
                let dummy = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: dummy,
                    value: Rvalue::PutStaticField {
                        class_name: wrapper_class.clone(),
                        field_name: val_name,
                        descriptor,
                        value: value_local,
                    },
                });
            }
        }
        let mut clinit_mf = fb.finish();
        clinit_mf.return_ty = Ty::Unit;
        // `<clinit>` is implicitly static. kotlinc emits ACC_STATIC only —
        // no visibility flag and no ACC_FINAL. The JVM backend special-
        // cases the `<clinit>` name in the access-flag computation.
        module.functions.push(clinit_mf);
    }

    // ─── Apply package prefix ──────────────────────────────────────────
    //
    // If the source file has a `package` declaration, prepend the
    // package path (with `/` separators) to the wrapper class and all
    // user-defined class names so that the JVM sees the correct
    // fully-qualified internal names (e.g. `com/example/InputKt`).
    if let Some(pkg) = &file.package {
        let segments: Vec<&str> = pkg.path.iter().map(|s| interner.resolve(*s)).collect();
        if !segments.is_empty() {
            let prefix = segments.join("/");

            // Collect the set of simple (un-prefixed) user class names
            // so we can rewrite internal references. Exclude cross-file
            // stubs — they already have the correct fully-qualified name.
            let user_classes: rustc_hash::FxHashSet<String> = module
                .classes
                .iter()
                .filter(|c| !c.is_cross_file_stub)
                .map(|c| c.name.clone())
                .collect();

            // Capture the un-prefixed wrapper class name so step 4 can
            // also rewrite class refs that point at the wrapper itself
            // (e.g. same-file `Rvalue::GetStaticField` for a top-level
            // val: `ThemesKt.JetchatDarkColorScheme` → `com/example/.../
            // ThemesKt.JetchatDarkColorScheme`). Without this, JetChat's
            // JetchatTheme reads its own `JetchatLightColorScheme` field
            // through `LThemesKt;` and ClassLoader can't resolve it.
            let unprefixed_wrapper = module.wrapper_class.clone();

            // 1. Prefix the wrapper class.
            module.wrapper_class = format!("{prefix}/{}", module.wrapper_class);

            // 2. Prefix every user-defined class name.
            for class in &mut module.classes {
                if user_classes.contains(&class.name) {
                    class.name = format!("{prefix}/{}", class.name);
                }
                // Also prefix the companion-class pointer if it
                // refers to a user-defined class. Without this, the
                // outer class's `Companion` static field gets the
                // wrong descriptor (`LContentMainBinding$Companion;`
                // instead of the FQ form) and `NoSuchFieldError`
                // surfaces at runtime.
                if let Some(comp) = class.companion_class_name.clone() {
                    let comp_simple = comp.split('$').next().unwrap_or(&comp);
                    if user_classes.contains(comp_simple) {
                        class.companion_class_name = Some(format!("{prefix}/{comp}"));
                    }
                }
            }

            // 3. Prefix enum names.
            let old_enum_names: Vec<String> = module.enum_names.iter().cloned().collect();
            module.enum_names.clear();
            for name in old_enum_names {
                module.enum_names.insert(format!("{prefix}/{name}"));
            }

            // 4. Rewrite class-name references inside all MIR functions.
            let rewrite = |name: &mut String| {
                if user_classes.contains(name.as_str()) || name.as_str() == unprefixed_wrapper {
                    *name = format!("{prefix}/{name}");
                }
            };
            let rewrite_fn = |f: &mut MirFunction| {
                // Rewrite Ty::Class in locals.
                for ty in &mut f.locals {
                    if let Ty::Class(ref mut n) = ty {
                        if user_classes.contains(n.as_str()) {
                            *n = format!("{prefix}/{n}");
                        }
                    }
                }
                // Rewrite Rvalue references.
                for block in &mut f.blocks {
                    for stmt in &mut block.stmts {
                        let MStmt::Assign { value, .. } = stmt;
                        match value {
                            Rvalue::NewInstance(ref mut n) if user_classes.contains(n.as_str()) => {
                                *n = format!("{prefix}/{n}");
                            }
                            Rvalue::GetField {
                                ref mut class_name, ..
                            } => rewrite(class_name),
                            Rvalue::PutField {
                                ref mut class_name, ..
                            } => rewrite(class_name),
                            Rvalue::GetStaticField {
                                ref mut class_name, ..
                            } => rewrite(class_name),
                            Rvalue::PutStaticField {
                                ref mut class_name, ..
                            } => rewrite(class_name),
                            Rvalue::InstanceOf {
                                ref mut type_descriptor,
                                ..
                            } if user_classes.contains(type_descriptor.as_str()) => {
                                *type_descriptor = format!("{prefix}/{type_descriptor}");
                            }
                            // CheckCast must be prefixed in lockstep with
                            // InstanceOf — the synthesized data-class
                            // `equals` does `instanceof Foo` followed by
                            // `(Foo) other`. If only InstanceOf gets the
                            // package prefix, the JVM verifier flags the
                            // checkcast as targeting an unresolved
                            // simple-named class and rejects field access
                            // against it ("cannot access instance field
                            // <T>.<field> from object of type Unresolved
                            // Reference: <simple>").
                            Rvalue::CheckCast {
                                ref mut target_class,
                                ..
                            } if user_classes.contains(target_class.as_str()) => {
                                *target_class = format!("{prefix}/{target_class}");
                            }
                            Rvalue::Call { ref mut kind, .. } => match kind {
                                CallKind::Constructor(ref mut n)
                                    if user_classes.contains(n.as_str()) =>
                                {
                                    *n = format!("{prefix}/{n}");
                                }
                                CallKind::Virtual {
                                    ref mut class_name, ..
                                } => rewrite(class_name),
                                CallKind::Super {
                                    ref mut class_name, ..
                                } => rewrite(class_name),
                                CallKind::LambdaMetafactory {
                                    ref mut impl_class, ..
                                } => rewrite(impl_class),
                                _ => {}
                            },
                            _ => {}
                        }
                    }
                }
            };
            // Top-level functions.
            for f in &mut module.functions {
                rewrite_fn(f);
            }
            // Class methods and constructors.
            for class in &mut module.classes {
                rewrite_fn(&mut class.constructor);
                for ctor in &mut class.secondary_constructors {
                    rewrite_fn(ctor);
                }
                for method in &mut class.methods {
                    rewrite_fn(method);
                }
            }
        }
    }

    // ─── Coroutine transform: continuation classes ────────
    //
    // Every suspend function the MIR lowerer marked with a
    // `SuspendStateMachine` needs a synthetic
    // `{Wrapper}${fn}$1 extends ContinuationImpl` alongside it.
    // We generate the class shape here so that the JVM backend
    // can emit both the caller's state machine and the companion
    // class in a single pass. The fields (`result: Object`,
    // `label: int`), the one-arg `<init>(Continuation)` super
    // call, and the `invokeSuspend(Object)` method that stashes
    // `$result`, flips the `label` sign bit, and re-invokes the
    // original `run(Continuation)` are all fixed shapes — the
    // only per-function inputs are the wrapper class name and
    // the suspend function's name.
    let continuation_classes: Vec<MirClass> = module
        .functions
        .iter()
        .filter_map(|f| {
            f.suspend_state_machine
                .as_ref()
                .map(|sm| build_continuation_class(sm, &module.wrapper_class, &f.name))
        })
        .collect();
    module.classes.extend(continuation_classes);

    // Also generate continuation classes for suspend
    // methods on user-defined classes. Skip SuspendLambda classes
    // (they ARE their own continuation — no separate companion).
    let class_cont_classes: Vec<MirClass> = module
        .classes
        .iter()
        .filter(|cls| !cls.is_suspend_lambda)
        .flat_map(|cls| {
            cls.methods.iter().filter_map(|m| {
                m.suspend_state_machine
                    .as_ref()
                    .map(|sm| build_continuation_class(sm, &cls.name, &m.name))
            })
        })
        .collect();
    module.classes.extend(class_cont_classes);

    // Post-process: fully-qualify short class names in all Ty::Class values.
    // This ensures descriptors use valid JVM internal names (e.g.,
    // "com/example/Message" instead of "Message") which d8 requires.
    fq_qualify_module_types(&mut module);

    skotch_mir::dump::maybe_dump_module(&module, "mir-lower");

    module
}

/// Fully-qualify all short class names in the module's types.
/// Short names (without '/') are resolved using the module's wrapper_class
/// package prefix and cross_file_classes lookup.
fn fq_qualify_module_types(module: &mut MirModule) {
    let prefix = module
        .wrapper_class
        .rfind('/')
        .map(|i| module.wrapper_class[..=i].to_string())
        .unwrap_or_default();

    // Collect known same-file class names for quick lookup.
    let same_file_classes: rustc_hash::FxHashSet<String> =
        module.classes.iter().map(|c| c.name.clone()).collect();

    // Collect cross-file class FQ names.
    let cross_fq: rustc_hash::FxHashMap<String, String> = module
        .cross_file_classes
        .iter()
        .map(|(k, (jvm, _, _))| (k.clone(), jvm.clone()))
        .collect();

    // Snapshot the file's import map so an explicitly-imported external type
    // keeps its import FQ instead of being package-prefixed (cloned to avoid
    // borrowing `module` while the closure also mutates `module.functions`).
    let import_map: rustc_hash::FxHashMap<String, String> = module.import_map.clone();

    let resolve = |name: &str| -> String {
        if name.contains('/') || name.is_empty() {
            return name.to_string();
        }
        // Check cross-file classes first (higher priority).
        if let Some(fq) = cross_fq.get(name) {
            return fq.clone();
        }
        // Same-file class: prefix with package.
        if same_file_classes.contains(name) {
            return format!("{prefix}{name}");
        }
        // An explicitly-imported external type keeps its import FQ — do NOT
        // package-prefix it. e.g. a param/return whose type is `Modifier`
        // (`import androidx.compose.ui.Modifier`) must stay
        // `androidx/compose/ui/Modifier`, not `<pkg>/Modifier`; otherwise the
        // emitted declaration descriptor disagrees with call sites (which
        // resolve via the import map) and the JVM raises NoSuchMethodError —
        // JetChat's `ConversationContent(…, modifier: Modifier, …)`.
        if let Some(fq) = import_map.get(name) {
            return fq.clone();
        }
        // Unknown short name: prefix with package (best effort).
        format!("{prefix}{name}")
    };

    // Fix types in all functions.
    for func in &mut module.functions {
        for ty in &mut func.locals {
            if let Ty::Class(name) = ty {
                if !name.contains('/') && !name.is_empty() {
                    *name = resolve(name);
                }
            }
        }
        if let Ty::Class(name) = &mut func.return_ty {
            if !name.contains('/') && !name.is_empty() {
                *name = resolve(name);
            }
        }
    }
    /// Fully-qualify class names inside a JVM descriptor string.
    /// Replaces `LFoo;` with `Lcom/example/.../Foo;` for short names.
    fn fq_descriptor(desc: &mut String, resolve: &dyn Fn(&str) -> String) {
        let mut result = String::with_capacity(desc.len());
        let bytes = desc.as_bytes();
        let mut i = 0;
        while i < bytes.len() {
            if bytes[i] == b'L' {
                let start = i + 1;
                let end = desc[start..]
                    .find(';')
                    .map(|p| start + p)
                    .unwrap_or(bytes.len());
                let class_name = &desc[start..end];
                if !class_name.contains('/')
                    && !class_name.is_empty()
                    && class_name.as_bytes()[0].is_ascii_uppercase()
                {
                    let resolved = resolve(class_name);
                    result.push('L');
                    result.push_str(&resolved);
                    result.push(';');
                } else {
                    result.push_str(&desc[i..end + 1]);
                }
                i = end + 1;
            } else {
                result.push(bytes[i] as char);
                i += 1;
            }
        }
        *desc = result;
    }

    // Also fix class names in Rvalue values (GetField, PutField, NewInstance, CallKind).
    #[allow(clippy::collapsible_if, clippy::collapsible_match)]
    fn fq_rvalues(func: &mut MirFunction, resolve: &dyn Fn(&str) -> String) {
        use skotch_mir::{CallKind as CK, Rvalue as R};
        for block in &mut func.blocks {
            for stmt in &mut block.stmts {
                let skotch_mir::Stmt::Assign { value, .. } = stmt;
                match value {
                    R::GetField { class_name, .. } | R::PutField { class_name, .. } => {
                        if !class_name.contains('/') && !class_name.is_empty() {
                            *class_name = resolve(class_name);
                        }
                    }
                    R::NewInstance(name) => {
                        if !name.contains('/') && !name.is_empty() {
                            *name = resolve(name);
                        }
                    }
                    R::Call { kind, .. } => match kind {
                        CK::Constructor(name) => {
                            if !name.contains('/') && !name.is_empty() {
                                *name = resolve(name);
                            }
                        }
                        CK::Virtual { class_name, .. } => {
                            if !class_name.contains('/') && !class_name.is_empty() {
                                *class_name = resolve(class_name);
                            }
                        }
                        CK::StaticJava {
                            class_name,
                            descriptor,
                            ..
                        }
                        | CK::VirtualJava {
                            class_name,
                            descriptor,
                            ..
                        }
                        | CK::ConstructorJava {
                            class_name,
                            descriptor,
                            ..
                        } => {
                            if !class_name.contains('/') && !class_name.is_empty() {
                                *class_name = resolve(class_name);
                            }
                            // Also FQ-resolve class names inside the descriptor string.
                            // Pattern: L<ShortName>; where ShortName starts uppercase and has no /.
                            fq_descriptor(descriptor, resolve);
                        }
                        _ => {}
                    },
                    _ => {}
                }
            }
        }
    }

    // Fix Rvalues in top-level functions.
    for func in &mut module.functions {
        fq_rvalues(func, &resolve);
    }

    // Fix types in all class constructors, methods, and fields.
    for class in &mut module.classes {
        for field in &mut class.fields {
            if let Ty::Class(name) = &mut field.ty {
                if !name.contains('/') && !name.is_empty() {
                    *name = resolve(name);
                }
            }
        }
        // Constructor locals
        for ty in &mut class.constructor.locals {
            if let Ty::Class(name) = ty {
                if !name.contains('/') && !name.is_empty() {
                    *name = resolve(name);
                }
            }
        }
        // Secondary constructors
        for ctor in &mut class.secondary_constructors {
            for ty in &mut ctor.locals {
                if let Ty::Class(name) = ty {
                    if !name.contains('/') && !name.is_empty() {
                        *name = resolve(name);
                    }
                }
            }
        }
        // Methods
        for method in &mut class.methods {
            for ty in &mut method.locals {
                if let Ty::Class(name) = ty {
                    if !name.contains('/') && !name.is_empty() {
                        *name = resolve(name);
                    }
                }
            }
            if let Ty::Class(name) = &mut method.return_ty {
                if !name.contains('/') && !name.is_empty() {
                    *name = resolve(name);
                }
            }
            fq_rvalues(method, &resolve);
        }
        // Constructor Rvalues
        fq_rvalues(&mut class.constructor, &resolve);
        for ctor in &mut class.secondary_constructors {
            fq_rvalues(ctor, &resolve);
        }
    }
}

/// Build the synthetic `ContinuationImpl` subclass for a single-
/// suspension-point state machine.
///
/// Shape (for `run()`):
///
/// ```text
/// final class InputKt$run$1 extends ContinuationImpl {
///     Object result;
///     int    label;
///     <init>(Continuation completion) {
///         super(completion);
///     }
///     public final Object invokeSuspend(Object $result) {
///         this.result = $result;
///         this.label |= 0x80000000;
///         return InputKt.run((Continuation) this);
///     }
/// }
/// ```
fn build_continuation_class(
    sm: &SuspendStateMachine,
    _wrapper_class: &str,
    _fn_name: &str,
) -> MirClass {
    // ── <init>(Continuation) { super(Continuation); return; } ──
    let mut ctor = MirFunction {
        id: FuncId(0),
        name: "<init>".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::Unit,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    let this_local = ctor.new_local(Ty::Class(sm.continuation_class.clone()));
    let completion_local = ctor.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
    ctor.params.push(this_local);
    ctor.params.push(completion_local);
    let super_dest = ctor.new_local(Ty::Unit);
    ctor.blocks[0].stmts.push(MStmt::Assign {
        dest: super_dest,
        value: Rvalue::Call {
            kind: CallKind::Constructor(
                "kotlin/coroutines/jvm/internal/ContinuationImpl".to_string(),
            ),
            args: vec![this_local, completion_local],
        },
    });

    // ── invokeSuspend(Object $result): Object ──
    let mut invoke = MirFunction {
        id: FuncId(0),
        name: "invokeSuspend".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::Any,
        required_params: 0,
        param_names: vec!["$result".to_string()],
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        // The `invokeSuspend` body is a fixed pattern the backend
        // emits directly: there's no MIR-level equivalent for the
        // `this.label |= 0x80000000` bitwise-OR step. We reuse the
        // same marker the top-level `run` function carries so the
        // JVM backend knows to substitute its canonical emitter.
        suspend_state_machine: Some(sm.clone()),
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    let invoke_this = invoke.new_local(Ty::Class(sm.continuation_class.clone()));
    let result_param = invoke.new_local(Ty::Any);
    invoke.params.push(invoke_this);
    invoke.params.push(result_param);

    // Every local that lives across a suspend call
    // becomes a synthetic field on the continuation class. Fields
    // are emitted in `spill_layout` order so the backend's
    // getfield/putfield descriptors line up with what kotlinc
    // produces (and so two skotch runs are bit-stable).
    let mut fields: Vec<MirField> = Vec::new();
    for slot in &sm.spill_layout {
        fields.push(MirField {
            name: slot.name.clone(),
            ty: match slot.kind {
                SpillKind::Int => Ty::Int,
                SpillKind::Long => Ty::Long,
                SpillKind::Float => Ty::Int, // unused in this session
                SpillKind::Double => Ty::Double,
                SpillKind::Ref => Ty::Any,
            },
            is_jvm_field: false,
        });
    }
    fields.push(MirField {
        name: "result".to_string(),
        ty: Ty::Any,
        is_jvm_field: false,
    });
    fields.push(MirField {
        name: "label".to_string(),
        ty: Ty::Int,
        is_jvm_field: false,
    });

    MirClass {
        name: sm.continuation_class.clone(),
        super_class: Some("kotlin/coroutines/jvm/internal/ContinuationImpl".to_string()),
        is_open: false,
        is_abstract: false,
        is_interface: false,
        interfaces: Vec::new(),
        fields,
        methods: vec![invoke],
        constructor: ctor,
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: false,
        is_object_singleton: false,
        companion_class_name: None,
        static_fields: Vec::new(),
        clinit: None,
    }
}

/// Try to extract a compile-time-constant value from a top-level
/// `val` initializer. Returns `None` for non-literal initializers
/// (which the type checker has already rejected).
///
/// String literals are interned into the module's string pool here so
/// that the same `StringId` is shared with any inline `println("...")`
/// uses of the same text — backends dedupe constant-pool entries
/// across the whole module, and inlining the global through the same
/// string pool keeps that dedup correct.
/// Emit MIR-level autoboxing for a primitive value.  Returns a new
/// local holding the boxed reference (e.g. `Integer.valueOf(int)`) or
/// the original local unchanged if it is already a reference type.
/// Autobox helper for suspend function returns. kotlinc routes the
/// boxing through `kotlin/coroutines/jvm/internal/Boxing.boxXxx`
/// rather than `Xxx.valueOf` for these. The Boxing helpers exist for
/// Bool, Byte, Char, Short, Int, Long, Float, Double — we cover the
/// numeric set we use.
fn mir_autobox_suspend(fb: &mut FnBuilder, val: LocalId, ty: &Ty) -> LocalId {
    let (method, descriptor) = match ty {
        Ty::Int => ("boxInt", "(I)Ljava/lang/Integer;"),
        Ty::Long => ("boxLong", "(J)Ljava/lang/Long;"),
        Ty::Double => ("boxDouble", "(D)Ljava/lang/Double;"),
        Ty::Bool => ("boxBoolean", "(Z)Ljava/lang/Boolean;"),
        Ty::Byte => ("boxByte", "(B)Ljava/lang/Byte;"),
        Ty::Short => ("boxShort", "(S)Ljava/lang/Short;"),
        Ty::Char => ("boxChar", "(C)Ljava/lang/Character;"),
        Ty::Float => ("boxFloat", "(F)Ljava/lang/Float;"),
        _ => return val,
    };
    let boxed = fb.new_local(Ty::Any);
    fb.push_stmt(MStmt::Assign {
        dest: boxed,
        value: Rvalue::Call {
            kind: CallKind::StaticJava {
                class_name: "kotlin/coroutines/jvm/internal/Boxing".to_string(),
                method_name: method.to_string(),
                descriptor: descriptor.to_string(),
            },
            args: vec![val],
        },
    });
    boxed
}

fn mir_autobox(fb: &mut FnBuilder, val: LocalId, ty: &Ty) -> LocalId {
    match ty {
        Ty::Int => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Integer".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(I)Ljava/lang/Integer;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Long => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Long".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(J)Ljava/lang/Long;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Double => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Double".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(D)Ljava/lang/Double;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Bool => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Boolean".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(Z)Ljava/lang/Boolean;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Char => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Character".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(C)Ljava/lang/Character;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Byte => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Byte".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(B)Ljava/lang/Byte;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Short => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Short".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(S)Ljava/lang/Short;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        Ty::Float => {
            let boxed = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: boxed,
                value: Rvalue::Call {
                    kind: CallKind::StaticJava {
                        class_name: "java/lang/Float".to_string(),
                        method_name: "valueOf".to_string(),
                        descriptor: "(F)Ljava/lang/Float;".to_string(),
                    },
                    args: vec![val],
                },
            });
            boxed
        }
        _ => val,
    }
}

/// Emit MIR to create a new exception and throw it.
/// If `message` is Some, invokes the lambda to get a String and passes it
/// to the exception's `(Ljava/lang/Object;)V` constructor. Otherwise uses
/// the no-arg constructor.
/// Emit MIR to create a new exception and throw it.
/// If `message` is Some, invokes the lambda to get a String and passes it
/// to the exception constructor. Uses `lookup_constructor` to find the
/// correct descriptor.
fn emit_throw_new(
    fb: &mut FnBuilder,
    module: &MirModule,
    exception_class: &str,
    message: Option<LocalId>,
) {
    let exc = fb.new_local(Ty::Class(exception_class.to_string()));
    fb.push_stmt(MStmt::Assign {
        dest: exc,
        value: Rvalue::NewInstance(exception_class.to_string()),
    });
    if let Some(msg_local) = message {
        // The message argument may be a lambda (require(cond) { "msg" }).
        // If it's a lambda class, invoke it to get the String. Otherwise
        // use it directly.
        let msg_ty = fb.mf.locals[msg_local.0 as usize].clone();
        let msg = if is_lambda_or_function_ty(&msg_ty, module) {
            let result = fb.new_local(Ty::Any);
            fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Call {
                    kind: CallKind::Virtual {
                        class_name: if let Ty::Class(n) = &msg_ty {
                            n.clone()
                        } else {
                            unreachable!()
                        },
                        method_name: "invoke".to_string(),
                    },
                    args: vec![msg_local],
                },
            });
            result
        } else {
            msg_local
        };
        // Find the correct constructor descriptor via ClasspathIndex.
        let descriptor = lookup_constructor(exception_class, 1, &[Ty::String])
            .unwrap_or_else(|| "(Ljava/lang/String;)V".to_string());
        fb.push_stmt(MStmt::Assign {
            dest: exc,
            value: Rvalue::Call {
                kind: CallKind::ConstructorJava {
                    class_name: exception_class.to_string(),
                    descriptor,
                },
                args: vec![msg],
            },
        });
    } else {
        fb.push_stmt(MStmt::Assign {
            dest: exc,
            value: Rvalue::Call {
                kind: CallKind::ConstructorJava {
                    class_name: exception_class.to_string(),
                    descriptor: "()V".to_string(),
                },
                args: vec![],
            },
        });
    }
    fb.set_terminator(Terminator::Throw(exc));
}

/// Parse a JVM method descriptor and return the param classes/primitives
/// as `Ty`s. Used to recover expected types for external static fn calls
/// where we don't have a MirFunction.
fn descriptor_arg_tys(desc: &str) -> Vec<Ty> {
    let inner = match desc.split(')').next().and_then(|s| s.strip_prefix('(')) {
        Some(s) => s,
        None => return Vec::new(),
    };
    let mut out = Vec::new();
    let mut chars = inner.chars().peekable();
    while let Some(c) = chars.next() {
        let ty = match c {
            'B' => Ty::Byte,
            'C' => Ty::Char,
            'D' => Ty::Double,
            'F' => Ty::Float,
            'I' => Ty::Int,
            'J' => Ty::Long,
            'S' => Ty::Short,
            'Z' => Ty::Bool,
            'L' => {
                let mut s = String::new();
                for sc in chars.by_ref() {
                    if sc == ';' {
                        break;
                    }
                    s.push(sc);
                }
                Ty::Class(s)
            }
            '[' => {
                // Skip the array descriptor and return Any — we don't
                // need precise array typing for callable-ref expansion.
                while let Some(&n) = chars.peek() {
                    if n == '[' {
                        chars.next();
                    } else {
                        break;
                    }
                }
                if let Some(&n) = chars.peek() {
                    if n == 'L' {
                        chars.next();
                        for sc in chars.by_ref() {
                            if sc == ';' {
                                break;
                            }
                        }
                    } else {
                        chars.next();
                    }
                }
                Ty::Any
            }
            _ => continue,
        };
        out.push(ty);
    }
    out
}

/// Look up the JVM descriptor for an external static function call. Walks
/// `static_method_imports` then `import_map`, and tries Pascal-cased Kt
/// facade variants for package-level top-level functions like
/// `AndroidViewBinding` (which actually lives in `AndroidViewBindingKt`).
fn find_external_static_descriptor(
    callee_str: &str,
    module: &MirModule,
    user_arg_count: usize,
) -> Option<String> {
    let try_lookup = |class_path: &str, method: &str| -> Option<String> {
        // Try a range of arities — composable adds +2 ($composer +
        // $changed), $default adds another +1 plus default placeholders.
        for extra in 0..=8 {
            if let Some(d) = skotch_classinfo::lookup_method_descriptor(
                class_path,
                method,
                user_arg_count + extra,
            ) {
                return Some(d);
            }
        }
        None
    };
    if let Some((class_path, method_name)) = module.static_method_imports.get(callee_str) {
        if let Some(d) = try_lookup(class_path, method_name) {
            return Some(d);
        }
    }
    if let Some(jvm_class) = module.import_map.get(callee_str) {
        let last_segment = jvm_class.rsplit('/').next().unwrap_or(jvm_class);
        // Pascal-cased identifier means it's either a real class (rare)
        // or a top-level Kotlin function whose owner is the file's Kt
        // facade. Lowercase = package-level fn already named after the
        // function.
        if last_segment.starts_with(|c: char| c.is_lowercase()) {
            let package_path = jvm_class
                .rsplit_once('/')
                .map(|(p, _)| p)
                .unwrap_or(jvm_class);
            if let Some(wrapper) =
                skotch_classinfo::find_wrapper_class_for_function(package_path, callee_str)
            {
                if let Some(d) = try_lookup(&wrapper, callee_str) {
                    return Some(d);
                }
            }
        } else {
            // Try direct first (real-class import), then fall back to
            // the parent package's Kt facade.
            if let Some(d) = try_lookup(jvm_class, callee_str) {
                return Some(d);
            }
            let package_path = jvm_class
                .rsplit_once('/')
                .map(|(p, _)| p)
                .unwrap_or(jvm_class);
            if let Some(wrapper) =
                skotch_classinfo::find_wrapper_class_for_function(package_path, callee_str)
            {
                if let Some(d) = try_lookup(&wrapper, callee_str) {
                    return Some(d);
                }
            }
        }
    }
    None
}

/// If `arg` is a desugared callable-reference lambda (parser produces
/// `{ $ref_arg -> Foo.member($ref_arg) }` for `Foo::member`) and the
/// surrounding call expects a `FunctionN` with N != 1, expand the lambda
/// to N params calling the underlying function with N args. This lets a
/// method reference resolve against the N-arity overload (kotlinc does
/// this via bidirectional inference at the use site).
fn maybe_expand_callable_ref(
    arg: &Expr,
    expected_ty: &Ty,
    interner: &mut Interner,
) -> Option<Expr> {
    let expected_arity = match expected_ty {
        Ty::Function { params, .. } => params.len(),
        Ty::Class(n) => {
            let prefix = "kotlin/jvm/functions/Function";
            let n_str = n.strip_prefix(prefix)?;
            n_str.parse::<usize>().ok()?
        }
        Ty::Nullable(inner) => return maybe_expand_callable_ref(arg, inner, interner),
        _ => return None,
    };
    if expected_arity == 1 {
        return None;
    }
    let (params, body, is_suspend, lambda_span) = match arg {
        Expr::Lambda {
            params,
            body,
            is_suspend,
            span,
        } => (params, body, *is_suspend, *span),
        _ => return None,
    };
    if params.len() != 1 {
        return None;
    }
    let ref_arg_sym = interner.intern("$ref_arg");
    if params[0].name != ref_arg_sym {
        return None;
    }
    if body.stmts.len() != 1 {
        return None;
    }
    let (inner_call, body_uses_return) = match &body.stmts[0] {
        Stmt::Expr(e) => (e, false),
        Stmt::Return { value: Some(e), .. } => (e, true),
        _ => return None,
    };
    let (call_callee, call_args, call_type_args, call_span) = match inner_call {
        Expr::Call {
            callee,
            args,
            type_args,
            span,
        } => (callee, args, type_args, *span),
        _ => return None,
    };
    if call_args.len() != 1 {
        return None;
    }
    let single_arg_sym = match &call_args[0].expr {
        Expr::Ident(s, _) => *s,
        _ => return None,
    };
    if single_arg_sym != ref_arg_sym {
        return None;
    }
    let any_sym = interner.intern("Any");
    let any_ty = skotch_syntax::TypeRef {
        name: any_sym,
        nullable: false,
        func_params: None,
        type_args: Vec::new(),
        is_suspend: false,
        is_composable: false,
        has_receiver: false,
        span: params[0].span,
    };
    let mut new_params = Vec::with_capacity(expected_arity);
    let mut new_call_args = Vec::with_capacity(expected_arity);
    for i in 0..expected_arity {
        let name_str = if i == 0 {
            "$ref_arg".to_string()
        } else {
            format!("$ref_arg{}", i + 1)
        };
        let sym = interner.intern(&name_str);
        new_params.push(skotch_syntax::Param {
            name: sym,
            ty: any_ty.clone(),
            default: None,
            is_vararg: false,
            span: params[0].span,
        });
        new_call_args.push(skotch_syntax::CallArg {
            name: None,
            expr: Expr::Ident(sym, params[0].span),
        });
    }
    let new_call = Expr::Call {
        callee: call_callee.clone(),
        args: new_call_args,
        type_args: call_type_args.clone(),
        span: call_span,
    };
    let new_stmt = if body_uses_return {
        Stmt::Return {
            value: Some(new_call),
            label: None,
            span: body.span,
        }
    } else {
        Stmt::Expr(new_call)
    };
    Some(Expr::Lambda {
        params: new_params,
        body: skotch_syntax::Block {
            stmts: vec![new_stmt],
            span: body.span,
        },
        is_suspend,
        span: lambda_span,
    })
}

/// Detect whether a lambda body contains a call to a suspend function.
/// Used to mark the lambda as a suspend lambda so future codegen can
/// generate a `SuspendLambda`-extending class.
///
/// Currently this is detection-only. The flag flows
/// through MIR but full codegen is a follow-up.
fn body_contains_suspend_call(
    body: &skotch_syntax::Block,
    module: &MirModule,
    interner: &Interner,
    name_to_func: &FxHashMap<Symbol, FuncId>,
) -> bool {
    fn scan_expr(
        e: &Expr,
        module: &MirModule,
        interner: &Interner,
        name_to_func: &FxHashMap<Symbol, FuncId>,
    ) -> bool {
        match e {
            Expr::Call { callee, args, .. } => {
                // Check if callee is a known suspend function
                if let Expr::Ident(name, _) = callee.as_ref() {
                    if let Some(&fid) = name_to_func.get(name) {
                        if let Some(f) = module.functions.get(fid.0 as usize) {
                            if f.is_suspend {
                                return true;
                            }
                        }
                    }
                }
                scan_expr(callee, module, interner, name_to_func)
                    || args
                        .iter()
                        .any(|a| scan_expr(&a.expr, module, interner, name_to_func))
            }
            Expr::Binary { lhs, rhs, .. } => {
                scan_expr(lhs, module, interner, name_to_func)
                    || scan_expr(rhs, module, interner, name_to_func)
            }
            Expr::If {
                cond,
                then_block,
                else_block,
                ..
            } => {
                scan_expr(cond, module, interner, name_to_func)
                    || scan_block(then_block, module, interner, name_to_func)
                    || else_block
                        .as_ref()
                        .is_some_and(|b| scan_block(b, module, interner, name_to_func))
            }
            Expr::Paren(inner, _) => scan_expr(inner, module, interner, name_to_func),
            _ => false,
        }
    }
    fn scan_block(
        b: &skotch_syntax::Block,
        module: &MirModule,
        interner: &Interner,
        name_to_func: &FxHashMap<Symbol, FuncId>,
    ) -> bool {
        for stmt in &b.stmts {
            match stmt {
                Stmt::Expr(e) if scan_expr(e, module, interner, name_to_func) => {
                    return true;
                }
                Stmt::Val(v) if scan_expr(&v.init, module, interner, name_to_func) => {
                    return true;
                }
                Stmt::Return { value: Some(e), .. }
                    if scan_expr(e, module, interner, name_to_func) =>
                {
                    return true;
                }
                _ => {}
            }
        }
        false
    }
    scan_block(body, module, interner, name_to_func)
}

/// Detect whether a 0-arg lambda body has unqualified calls that don't
/// resolve to anything in scope — a signal that the lambda is a
/// receiver lambda (e.g. `StringBuilder.() -> Unit`) whose unqualified
/// calls (`append("x")`) need a captured receiver to dispatch against.
/// The metafactory path lowers to a static helper with no `this`, so
/// any such lambda must take the explicit-class path instead.
fn body_has_unresolved_unqualified_call(
    body: &skotch_syntax::Block,
    scope: &[(Symbol, LocalId)],
    module: &MirModule,
    name_to_func: &FxHashMap<Symbol, FuncId>,
    interner: &mut Interner,
) -> bool {
    let println_sym = interner.intern("println");
    let print_sym = interner.intern("print");
    fn is_resolved(
        name: Symbol,
        scope: &[(Symbol, LocalId)],
        module: &MirModule,
        name_to_func: &FxHashMap<Symbol, FuncId>,
        println_sym: Symbol,
        print_sym: Symbol,
        interner: &Interner,
    ) -> bool {
        if name == println_sym || name == print_sym {
            return true;
        }
        if name_to_func.contains_key(&name) {
            return true;
        }
        if scope.iter().any(|(s, _)| *s == name) {
            return true;
        }
        let name_str = interner.resolve(name);
        if module.classes.iter().any(|c| c.name == name_str) {
            return true;
        }
        false
    }
    fn scan_expr(
        e: &Expr,
        scope: &[(Symbol, LocalId)],
        module: &MirModule,
        name_to_func: &FxHashMap<Symbol, FuncId>,
        println_sym: Symbol,
        print_sym: Symbol,
        interner: &Interner,
    ) -> bool {
        match e {
            Expr::Call { callee, args, .. } => {
                if let Expr::Ident(name, _) = callee.as_ref() {
                    if !is_resolved(
                        *name,
                        scope,
                        module,
                        name_to_func,
                        println_sym,
                        print_sym,
                        interner,
                    ) {
                        return true;
                    }
                }
                scan_expr(
                    callee,
                    scope,
                    module,
                    name_to_func,
                    println_sym,
                    print_sym,
                    interner,
                ) || args.iter().any(|a| {
                    scan_expr(
                        &a.expr,
                        scope,
                        module,
                        name_to_func,
                        println_sym,
                        print_sym,
                        interner,
                    )
                })
            }
            Expr::Binary { lhs, rhs, .. } => {
                scan_expr(
                    lhs,
                    scope,
                    module,
                    name_to_func,
                    println_sym,
                    print_sym,
                    interner,
                ) || scan_expr(
                    rhs,
                    scope,
                    module,
                    name_to_func,
                    println_sym,
                    print_sym,
                    interner,
                )
            }
            Expr::Field { receiver, .. } | Expr::SafeCall { receiver, .. } => scan_expr(
                receiver,
                scope,
                module,
                name_to_func,
                println_sym,
                print_sym,
                interner,
            ),
            Expr::Paren(inner, _) => scan_expr(
                inner,
                scope,
                module,
                name_to_func,
                println_sym,
                print_sym,
                interner,
            ),
            _ => false,
        }
    }
    fn scan_block(
        b: &skotch_syntax::Block,
        scope: &[(Symbol, LocalId)],
        module: &MirModule,
        name_to_func: &FxHashMap<Symbol, FuncId>,
        println_sym: Symbol,
        print_sym: Symbol,
        interner: &Interner,
    ) -> bool {
        for stmt in &b.stmts {
            match stmt {
                Stmt::Expr(e) | Stmt::Return { value: Some(e), .. } => {
                    if scan_expr(
                        e,
                        scope,
                        module,
                        name_to_func,
                        println_sym,
                        print_sym,
                        interner,
                    ) {
                        return true;
                    }
                }
                Stmt::Val(v)
                    if scan_expr(
                        &v.init,
                        scope,
                        module,
                        name_to_func,
                        println_sym,
                        print_sym,
                        interner,
                    ) =>
                {
                    return true;
                }
                _ => {}
            }
        }
        false
    }
    scan_block(
        body,
        scope,
        module,
        name_to_func,
        println_sym,
        print_sym,
        interner,
    )
}

/// Collect free variables in a lambda body: names that are referenced
/// but not defined as lambda parameters or known top-level functions.
fn collect_free_vars(
    body: &skotch_syntax::Block,
    param_names: &[Symbol],
    outer_scope: &[(Symbol, LocalId)],
    fb: &FnBuilder,
    _interner: &Interner,
) -> Vec<(Symbol, LocalId, Ty)> {
    let mut free = Vec::new();
    let mut seen = rustc_hash::FxHashSet::default();
    collect_free_in_block(body, param_names, outer_scope, fb, &mut free, &mut seen);
    free
}

/// Check whether a block references a given identifier (Symbol) anywhere
/// in its expression positions. Used to detect when a lambda body uses
/// the implicit `it` parameter, so the lowering can add the invoke
/// method param even when the surrounding caller-arity heuristic
/// doesn't predict it.
fn body_references_ident(body: &skotch_syntax::Block, target: Symbol) -> bool {
    let mut found = false;
    scan_block_for_ident(body, target, &mut found);
    found
}

fn scan_block_for_ident(block: &skotch_syntax::Block, target: Symbol, found: &mut bool) {
    for stmt in &block.stmts {
        if *found {
            return;
        }
        match stmt {
            skotch_syntax::Stmt::Expr(e) | skotch_syntax::Stmt::Return { value: Some(e), .. } => {
                scan_expr_for_ident(e, target, found);
            }
            skotch_syntax::Stmt::Val(v) => {
                scan_expr_for_ident(&v.init, target, found);
            }
            skotch_syntax::Stmt::Assign { value, .. } => {
                scan_expr_for_ident(value, target, found);
            }
            _ => {}
        }
    }
}

fn scan_expr_for_ident(e: &skotch_syntax::Expr, target: Symbol, found: &mut bool) {
    if *found {
        return;
    }
    use skotch_syntax::Expr;
    match e {
        Expr::Ident(name, _) if *name == target => {
            *found = true;
        }
        Expr::Call { callee, args, .. } => {
            scan_expr_for_ident(callee, target, found);
            for a in args {
                scan_expr_for_ident(&a.expr, target, found);
            }
        }
        Expr::Binary { lhs, rhs, .. } => {
            scan_expr_for_ident(lhs, target, found);
            scan_expr_for_ident(rhs, target, found);
        }
        Expr::Unary { operand, .. } => scan_expr_for_ident(operand, target, found),
        Expr::Field { receiver, .. } | Expr::SafeCall { receiver, .. } => {
            scan_expr_for_ident(receiver, target, found);
        }
        Expr::Index {
            receiver, index, ..
        } => {
            scan_expr_for_ident(receiver, target, found);
            scan_expr_for_ident(index, target, found);
        }
        Expr::If {
            cond,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_ident(cond, target, found);
            scan_block_for_ident(then_block, target, found);
            if let Some(eb) = else_block {
                scan_block_for_ident(eb, target, found);
            }
        }
        Expr::When {
            subject,
            branches,
            else_body,
            ..
        } => {
            scan_expr_for_ident(subject, target, found);
            for br in branches {
                scan_expr_for_ident(&br.pattern, target, found);
                if let Some(re) = &br.range_end {
                    scan_expr_for_ident(re, target, found);
                }
                scan_expr_for_ident(&br.body, target, found);
            }
            if let Some(eb) = else_body {
                scan_expr_for_ident(eb, target, found);
            }
        }
        _ => {}
    }
}

/// Detect whether a lambda body has unqualified method calls (or property
/// accesses) that resolve to members of the enclosing class. Used to
/// decide if the lambda needs to capture outer `this` so those calls
/// can dispatch via the captured field instead of using the lambda's
/// own `this`.
fn body_needs_outer_this(
    body: &skotch_syntax::Block,
    outer_class_name: &str,
    module: &MirModule,
    interner: &mut Interner,
) -> bool {
    let mut method_syms: rustc_hash::FxHashSet<Symbol> = rustc_hash::FxHashSet::default();
    // Walk the class plus its superclass chain and implemented interfaces
    // so that calls to inherited extension methods (e.g. `dp.roundToPx()`
    // on `Density`-extension inherited by a `MyDensity : Density` outer
    // class) are detected.
    let mut to_visit: Vec<String> = vec![outer_class_name.to_string()];
    let mut visited: rustc_hash::FxHashSet<String> = rustc_hash::FxHashSet::default();
    while let Some(cn) = to_visit.pop() {
        if !visited.insert(cn.clone()) {
            continue;
        }
        if let Some(cls) = module.classes.iter().find(|c| c.name == cn) {
            for m in &cls.methods {
                method_syms.insert(interner.intern(&m.name));
            }
            for iname in &cls.interfaces {
                to_visit.push(iname.clone());
            }
            if let Some(sc) = &cls.super_class {
                to_visit.push(sc.clone());
            }
        }
    }
    if method_syms.is_empty() {
        return false;
    }
    let mut found = false;
    scan_block_for_outer_calls(body, &method_syms, &mut found);
    found
}

fn scan_block_for_outer_calls(
    block: &skotch_syntax::Block,
    method_syms: &rustc_hash::FxHashSet<Symbol>,
    found: &mut bool,
) {
    for stmt in &block.stmts {
        if *found {
            return;
        }
        match stmt {
            skotch_syntax::Stmt::Expr(e) | skotch_syntax::Stmt::Return { value: Some(e), .. } => {
                scan_expr_for_outer_calls(e, method_syms, found);
            }
            skotch_syntax::Stmt::Val(v) => {
                scan_expr_for_outer_calls(&v.init, method_syms, found);
            }
            skotch_syntax::Stmt::Assign { value, .. } => {
                scan_expr_for_outer_calls(value, method_syms, found);
            }
            _ => {}
        }
    }
}

fn scan_expr_for_outer_calls(
    e: &skotch_syntax::Expr,
    method_syms: &rustc_hash::FxHashSet<Symbol>,
    found: &mut bool,
) {
    if *found {
        return;
    }
    use skotch_syntax::Expr;
    match e {
        Expr::Call { callee, args, .. } => {
            if let Expr::Ident(name, _) = callee.as_ref() {
                if method_syms.contains(name) {
                    *found = true;
                    return;
                }
            }
            // Receiver dot-call form: `dp.roundToPx()`. If `roundToPx` is
            // an extension method on the outer `this`'s class (which is
            // what method_syms reflects), kotlinc lowers this as
            // `outer.roundToPx(dp)`, requiring the lambda to capture
            // the outer `this`.
            if let Expr::Field { name, .. } = callee.as_ref() {
                if method_syms.contains(name) {
                    *found = true;
                    return;
                }
            }
            scan_expr_for_outer_calls(callee, method_syms, found);
            for a in args {
                scan_expr_for_outer_calls(&a.expr, method_syms, found);
            }
        }
        Expr::Binary { lhs, rhs, .. } => {
            scan_expr_for_outer_calls(lhs, method_syms, found);
            scan_expr_for_outer_calls(rhs, method_syms, found);
        }
        Expr::Unary { operand, .. } => scan_expr_for_outer_calls(operand, method_syms, found),
        Expr::Field { receiver, .. } | Expr::SafeCall { receiver, .. } => {
            scan_expr_for_outer_calls(receiver, method_syms, found);
        }
        Expr::Index {
            receiver, index, ..
        } => {
            scan_expr_for_outer_calls(receiver, method_syms, found);
            scan_expr_for_outer_calls(index, method_syms, found);
        }
        Expr::If {
            cond,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_outer_calls(cond, method_syms, found);
            scan_block_for_outer_calls(then_block, method_syms, found);
            if let Some(eb) = else_block {
                scan_block_for_outer_calls(eb, method_syms, found);
            }
        }
        _ => {}
    }
}

fn collect_free_in_block(
    block: &skotch_syntax::Block,
    param_names: &[Symbol],
    outer_scope: &[(Symbol, LocalId)],
    fb: &FnBuilder,
    free: &mut Vec<(Symbol, LocalId, Ty)>,
    seen: &mut rustc_hash::FxHashSet<Symbol>,
) {
    for stmt in &block.stmts {
        match stmt {
            Stmt::Expr(e) | Stmt::Return { value: Some(e), .. } => {
                collect_free_in_expr(e, param_names, outer_scope, fb, free, seen);
            }
            Stmt::Val(v) => {
                collect_free_in_expr(&v.init, param_names, outer_scope, fb, free, seen);
            }
            Stmt::Assign { value, .. } => {
                collect_free_in_expr(value, param_names, outer_scope, fb, free, seen);
            }
            Stmt::IndexAssign {
                receiver,
                index,
                value,
                ..
            } => {
                collect_free_in_expr(receiver, param_names, outer_scope, fb, free, seen);
                collect_free_in_expr(index, param_names, outer_scope, fb, free, seen);
                collect_free_in_expr(value, param_names, outer_scope, fb, free, seen);
            }
            _ => {}
        }
    }
}

fn collect_free_in_expr(
    e: &Expr,
    param_names: &[Symbol],
    outer_scope: &[(Symbol, LocalId)],
    fb: &FnBuilder,
    free: &mut Vec<(Symbol, LocalId, Ty)>,
    seen: &mut rustc_hash::FxHashSet<Symbol>,
) {
    match e {
        Expr::Ident(name, _) if !param_names.contains(name) && !seen.contains(name) => {
            if let Some((_, local_id)) = outer_scope.iter().rev().find(|(s, _)| s == name) {
                let ty = fb.mf.locals[local_id.0 as usize].clone();
                free.push((*name, *local_id, ty));
                seen.insert(*name);
            }
        }
        Expr::Binary { lhs, rhs, .. } => {
            collect_free_in_expr(lhs, param_names, outer_scope, fb, free, seen);
            collect_free_in_expr(rhs, param_names, outer_scope, fb, free, seen);
        }
        Expr::Unary { operand, .. } => {
            collect_free_in_expr(operand, param_names, outer_scope, fb, free, seen);
        }
        Expr::Call { callee, args, .. } => {
            collect_free_in_expr(callee, param_names, outer_scope, fb, free, seen);
            for a in args {
                collect_free_in_expr(&a.expr, param_names, outer_scope, fb, free, seen);
            }
        }
        Expr::Field { receiver, .. } | Expr::SafeCall { receiver, .. } => {
            collect_free_in_expr(receiver, param_names, outer_scope, fb, free, seen);
        }
        Expr::Index {
            receiver, index, ..
        } => {
            collect_free_in_expr(receiver, param_names, outer_scope, fb, free, seen);
            collect_free_in_expr(index, param_names, outer_scope, fb, free, seen);
        }
        Expr::If {
            cond,
            then_block,
            else_block,
            ..
        } => {
            collect_free_in_expr(cond, param_names, outer_scope, fb, free, seen);
            collect_free_in_block(then_block, param_names, outer_scope, fb, free, seen);
            if let Some(eb) = else_block {
                collect_free_in_block(eb, param_names, outer_scope, fb, free, seen);
            }
        }
        Expr::StringTemplate(parts, _) => {
            for p in parts {
                match p {
                    skotch_syntax::TemplatePart::Expr(inner) => {
                        collect_free_in_expr(inner, param_names, outer_scope, fb, free, seen);
                    }
                    skotch_syntax::TemplatePart::IdentRef(sym, _)
                        if !param_names.contains(sym) && !seen.contains(sym) =>
                    {
                        if let Some((_, local_id)) =
                            outer_scope.iter().rev().find(|(s, _)| s == sym)
                        {
                            let ty = fb.mf.locals[local_id.0 as usize].clone();
                            free.push((*sym, *local_id, ty));
                            seen.insert(*sym);
                        }
                    }
                    _ => {}
                }
            }
        }
        Expr::Paren(inner, _)
        | Expr::NotNullAssert { expr: inner, .. }
        | Expr::IsCheck { expr: inner, .. }
        | Expr::AsCast { expr: inner, .. }
        | Expr::Throw { expr: inner, .. } => {
            collect_free_in_expr(inner, param_names, outer_scope, fb, free, seen);
        }
        Expr::ElvisOp { lhs, rhs, .. } => {
            collect_free_in_expr(lhs, param_names, outer_scope, fb, free, seen);
            collect_free_in_expr(rhs, param_names, outer_scope, fb, free, seen);
        }
        Expr::When {
            subject,
            branches,
            else_body,
            ..
        } => {
            collect_free_in_expr(subject, param_names, outer_scope, fb, free, seen);
            for br in branches {
                collect_free_in_expr(&br.pattern, param_names, outer_scope, fb, free, seen);
                if let Some(re) = &br.range_end {
                    collect_free_in_expr(re, param_names, outer_scope, fb, free, seen);
                }
                collect_free_in_expr(&br.body, param_names, outer_scope, fb, free, seen);
            }
            if let Some(eb) = else_body {
                collect_free_in_expr(eb, param_names, outer_scope, fb, free, seen);
            }
        }
        Expr::Try {
            body,
            catch_body,
            extra_catches,
            finally_body,
            ..
        } => {
            collect_free_in_block(body, param_names, outer_scope, fb, free, seen);
            if let Some(cb) = catch_body {
                collect_free_in_block(cb, param_names, outer_scope, fb, free, seen);
            }
            for (_, _, eb) in extra_catches {
                collect_free_in_block(eb, param_names, outer_scope, fb, free, seen);
            }
            if let Some(fb_blk) = finally_body {
                collect_free_in_block(fb_blk, param_names, outer_scope, fb, free, seen);
            }
        }
        Expr::Lambda {
            params: inner_params,
            body: inner_body,
            ..
        } => {
            // A nested lambda may reference variables from the enclosing
            // scope.  We must recurse into its body so that those
            // references are surfaced as free variables of the *outer*
            // lambda.  The nested lambda's own parameters shadow outer
            // names, so extend `param_names` with them before recursing.
            let mut extended_params: Vec<Symbol> = param_names.to_vec();
            for p in inner_params {
                extended_params.push(p.name);
            }
            collect_free_in_block(inner_body, &extended_params, outer_scope, fb, free, seen);
        }
        _ => {}
    }
}

/// Mirror of `skotch-resolve`'s `infer_val_type_from_init`, but consulting
/// `file.imports` directly (the module-level `import_map` isn't built yet
/// at this point in the lowering pipeline). Limited to the one-level
/// pattern matches the resolver also recognizes — anything else returns
/// `Ty::Any` so the existing fallback behavior is preserved.
fn infer_top_level_val_ty(init: &Expr, file: &KtFile, interner: &Interner) -> Ty {
    use skotch_syntax::ast::Expr as E;
    let lookup_import = |simple: &str| -> Option<String> {
        for imp in &file.imports {
            if imp.is_wildcard {
                continue;
            }
            if let Some(last) = imp.path.last() {
                if interner.resolve(*last) == simple {
                    let path: Vec<&str> = imp.path.iter().map(|s| interner.resolve(*s)).collect();
                    return Some(path.join("/"));
                }
            }
        }
        None
    };
    match init {
        E::Call { callee, args, .. } => match callee.as_ref() {
            E::Ident(sym, _) => {
                let name = interner.resolve(*sym);
                // Kotlin stdlib collection builders. Centralized in
                // `intrinsics::fallback_collection_builder_class`. Mirror of
                // `skotch-resolve::infer_val_type_from_init` so the
                // mir-lower side and the cross-file side agree.
                if intrinsics::fallback_collection_builder_class(name).is_some() {
                    let elem_ty = args
                        .first()
                        .map(|a| infer_top_level_val_ty(&a.expr, file, interner))
                        .unwrap_or(Ty::Any);
                    return intrinsics::collection_builder_result_ty(name, elem_ty)
                        .unwrap_or(Ty::Any);
                }
                // Kotlin convention: type names start uppercase, function
                // names start lowercase. Only treat the call as a class
                // construction when the callee follows the type-name rule;
                // otherwise we have no way to know the function's actual
                // return type from this position and `Ty::Any` is correct.
                let starts_upper = name.chars().next().is_some_and(|c| c.is_ascii_uppercase());
                if !starts_upper {
                    return Ty::Any;
                }
                if let Some(fq) = lookup_import(name) {
                    Ty::Class(fq)
                } else if file.decls.iter().any(|d| {
                    if let Decl::Class(c) = d {
                        interner.resolve(c.name) == name
                    } else {
                        false
                    }
                }) {
                    Ty::Class(name.to_string())
                } else {
                    Ty::Any
                }
            }
            _ => Ty::Any,
        },
        E::StringLit(_, _) | E::StringTemplate(_, _) => Ty::String,
        E::IntLit(_, _) => Ty::Int,
        E::LongLit(_, _) => Ty::Long,
        E::FloatLit(_, _) => Ty::Float,
        E::DoubleLit(_, _) => Ty::Double,
        E::BoolLit(_, _) => Ty::Bool,
        E::CharLit(_, _) => Ty::Char,
        // `56.dp` / `8.sp` / `2.em` — compose unit-property extensions on a
        // numeric receiver. skotch lowers `.dp`/`.sp`/`.em` to `.toFloat()`,
        // so the value is a primitive float; the field must be typed Float to
        // match (kotlinc emits the `Dp`/`TextUnit` value class, erased to `F`
        // on the JVM). Without this the top-level-val field is `Object` and
        // the `<clinit>` `putstatic` of a float fails d8/the verifier — this
        // is ConversationKt's `private val JumpToBottomThreshold = 56.dp`.
        E::Field { name, .. } if intrinsics::is_compose_unit_prop(interner.resolve(*name)) => {
            Ty::Float
        }
        _ => Ty::Any,
    }
}

fn lower_const_init(e: &Expr, module: &mut MirModule) -> Option<MirConst> {
    match e {
        Expr::IntLit(v, _) => Some(MirConst::Int(*v as i32)),
        Expr::LongLit(v, _) => Some(MirConst::Long(*v)),
        Expr::FloatLit(v, _) => Some(MirConst::Float(*v as f32)),
        Expr::DoubleLit(v, _) => Some(MirConst::Double(*v)),
        Expr::BoolLit(v, _) => Some(MirConst::Bool(*v)),
        Expr::NullLit(_) => Some(MirConst::Null),
        Expr::StringLit(s, _) => {
            let sid = module.intern_string(s);
            Some(MirConst::String(sid))
        }
        // Wrapper around a literal (`val X = (1)`) — recurse so the
        // user's harmless parens don't break const-folding.
        Expr::Paren(inner, _) => lower_const_init(inner, module),
        _ => None,
    }
}

/// Surface type of a `MirConst`. Used by the inline-global lowering
/// in `Expr::Ident` so the local that holds the inlined value gets
/// the right type for the JVM/DEX/LLVM backends to dispatch on.
fn const_ty(c: &MirConst) -> Ty {
    match c {
        MirConst::Unit => Ty::Unit,
        MirConst::Bool(_) => Ty::Bool,
        MirConst::Int(_) => Ty::Int,
        MirConst::Long(_) => Ty::Long,
        MirConst::Float(_) => Ty::Float,
        MirConst::Double(_) => Ty::Double,
        MirConst::Null => Ty::Nullable(Box::new(Ty::Any)),
        MirConst::String(_) => Ty::String,
    }
}

/// Builder for a multi-block MIR function. Tracks the "current
/// block" so statements are appended to the right place, and lets
/// `lower_expr` create new basic blocks for `if`-expressions without
/// threading a mutable block-list through every function.
struct FnBuilder {
    mf: MirFunction,
    /// Index of the block we're currently emitting into.
    cur_block: u32,
    /// Symbols declared as `var` (mutable) in this function scope.
    var_syms: rustc_hash::FxHashSet<Symbol>,
    /// MIR locals that correspond to suspend-typed function
    /// parameters (e.g. `block: suspend () -> String`). When such a
    /// local is invoked as a callable, the MIR lowerer must append the
    /// enclosing function's `$completion` continuation as the trailing
    /// argument and skip the normal Int-unbox on the Object result.
    suspend_callable_locals: rustc_hash::FxHashSet<u32>,
    /// Reified type parameter substitutions for the current inline scope.
    /// Maps type param names (e.g. "A", "B") to concrete types (e.g. "String").
    reified_types: FxHashMap<String, String>,
    /// Per-enclosing-function lambda counter (1-based at first use).
    /// Used to build kotlinc-style names `<wrapper>$<fn>$<idx>` so the
    /// emitted class names match kotlinc byte-for-byte.
    lambda_count: u32,
    // (has_unresolved detection moved to JVM backend's has_null_stubs())
}

impl FnBuilder {
    fn new(fn_idx: usize, name: String, return_ty: Ty) -> Self {
        let mf = MirFunction {
            id: FuncId(fn_idx as u32),
            name,
            params: Vec::new(),
            locals: Vec::new(),
            blocks: vec![BasicBlock {
                stmts: Vec::new(),
                terminator: Terminator::Return,
            }],
            return_ty,
            required_params: 0,
            param_names: Vec::new(),
            param_defaults: Vec::new(),
            param_receiver_types: Vec::new(),
            is_abstract: false,
            exception_handlers: Vec::new(),
            vararg_index: None,
            is_suspend: false,
            is_inline: false,
            has_type_params: false,
            suspend_original_return_ty: None,
            suspend_state_machine: None,
            annotations: Vec::new(),
            named_locals: Vec::new(),
            is_private: false,
            is_static: false,
            default_call_masks: Vec::new(),
            needs_leading_nop: false,
            local_generic_args: rustc_hash::FxHashMap::default(),
        };
        FnBuilder {
            mf,
            cur_block: 0,
            var_syms: rustc_hash::FxHashSet::default(),
            suspend_callable_locals: rustc_hash::FxHashSet::default(),
            reified_types: FxHashMap::default(),
            lambda_count: 0,
        }
    }

    fn new_local(&mut self, ty: Ty) -> LocalId {
        self.mf.new_local(ty)
    }

    fn push_stmt(&mut self, stmt: MStmt) {
        self.mf.blocks[self.cur_block as usize].stmts.push(stmt);
    }

    /// Create a fresh empty block and return its index. Does NOT
    /// switch `cur_block` — the caller decides when to switch.
    fn new_block(&mut self) -> u32 {
        let idx = self.mf.blocks.len() as u32;
        self.mf.blocks.push(BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return, // patched later
        });
        idx
    }

    /// Set the terminator of the current block and switch to
    /// `next_block`.
    fn terminate_and_switch(&mut self, terminator: Terminator, next_block: u32) {
        self.mf.blocks[self.cur_block as usize].terminator = terminator;
        self.cur_block = next_block;
    }

    /// Set the terminator of the current block without switching.
    #[allow(dead_code)]
    fn set_terminator(&mut self, terminator: Terminator) {
        self.mf.blocks[self.cur_block as usize].terminator = terminator;
    }

    fn finish(self) -> MirFunction {
        self.mf
    }
}

/// Outcome of [`extract_suspend_state_machine`] — the three cases
/// the coroutine lowering passes branch on.
enum SuspendSitesResult {
    /// No inner suspend calls; the signature rewrite is
    /// all we need.
    Zero,
    /// At least one inner suspend call; we emit the state-machine
    /// shape with the supplied marker. Single-
    /// suspension (string-literal tail) and N-
    /// suspension (real expression tail) cases both surface here — the
    /// marker's `sites` vector distinguishes them for the backend.
    Found(SuspendStateMachine),
    /// The function has suspend calls, but the body shape is
    /// outside the current scope. Reserved for future use.
    #[allow(dead_code)]
    Unsupported(String),
}

/// Scan a freshly-lowered suspend function for calls to other
/// suspend functions and, if they're present, build a
/// [`SuspendStateMachine`] marker describing the coroutine
/// dispatcher the JVM backend should emit.
///
/// Two shapes are recognized:
///
/// - **Single-suspension.** A single suspend call with no arguments beyond
///   the synthesized `$completion`, followed by a literal-string
///   return terminator. Produces the historic marker shape
///   (`sites` empty, `resume_return_text` populated).
/// - **Multi-suspension.** Any number of suspend calls with no args beyond
///   `$completion`, in a straight-line single-block body. Produces
///   a marker with populated `sites` and `spill_layout` and lets
///   the JVM backend walk the real MIR for the resume tail.
///
/// Anything richer (suspend calls with user args, branches across
/// suspend sites) becomes [`SuspendSitesResult::Unsupported`] so the
/// caller can emit a precise diagnostic. Future work will lift
/// these restrictions.
fn extract_suspend_state_machine(
    mf: &MirFunction,
    module: &MirModule,
    wrapper_class: &str,
    fn_name: &str,
) -> SuspendSitesResult {
    // The state machine class shape is `<wrapper>$<fn>$<idx>` where idx
    // is 1-based. If a lambda inside this function has already claimed
    // `<wrapper>$<fn>$1`, bump until we find a free index — same scheme
    // as the lambda-lifter's uniqueness loop.
    let mut idx = 1usize;
    let cont_name = loop {
        let candidate = format!("{wrapper_class}${fn_name}${idx}");
        if !module.classes.iter().any(|c| c.name == candidate) {
            break candidate;
        }
        idx += 1;
    };
    extract_suspend_state_machine_with_cont(mf, module, wrapper_class, fn_name, cont_name)
}

/// Variant of [`extract_suspend_state_machine`] that lets the caller
/// override the continuation class name. Suspend lambdas use this
/// because the lambda class IS the continuation (it
/// extends `SuspendLambda`), so there is no separate `InputKt$fn$1`
/// companion — the state machine stored on the lambda's invoke
/// method points at the lambda class itself.
fn extract_suspend_state_machine_with_cont(
    mf: &MirFunction,
    module: &MirModule,
    wrapper_class: &str,
    fn_name: &str,
    continuation_class: String,
) -> SuspendSitesResult {
    // Walk every block collecting (block_idx, stmt_idx, callee FuncId, argc)
    // for each suspend-fn static call. The MIR lowerer routes these
    // through `invokestatic` with the trailing `$completion`
    // already appended, so they're easy to recognize structurally.
    // Suspend call sites come in two flavors:
    // 1. Static calls to known suspend functions (CallKind::Static)
    // 2. Virtual/interface calls to suspend methods (VirtualJava)
    //    — e.g., Deferred.await(), Function1.invoke() on suspend types
    //
    // We track both with a sentinel FuncId(u32::MAX) for virtual calls
    // since they don't have a real FuncId in our module.
    let virtual_suspend_fid = FuncId(u32::MAX);
    let mut sites_raw: Vec<(u32, u32, FuncId, usize)> = Vec::new();
    for (bi, block) in mf.blocks.iter().enumerate() {
        for (si, stmt) in block.stmts.iter().enumerate() {
            let MStmt::Assign { value, .. } = stmt;
            match value {
                Rvalue::Call {
                    kind: CallKind::Static(fid),
                    args,
                } => {
                    let target = &module.functions[fid.0 as usize];
                    if target.is_suspend {
                        sites_raw.push((bi as u32, si as u32, *fid, args.len()));
                    }
                }
                Rvalue::Call {
                    kind:
                        CallKind::VirtualJava {
                            class_name,
                            method_name,
                            descriptor,
                        },
                    args,
                } => {
                    // Known suspend interface/virtual methods.
                    // Any VirtualJava call whose descriptor ends with
                    // `Continuation;)Ljava/lang/Object;` is a suspend
                    // method call (user-defined or library).
                    let is_suspend_virtual = (class_name == "kotlinx/coroutines/Deferred"
                        && method_name == "await")
                        || (class_name == "kotlinx/coroutines/Job" && method_name == "join")
                        || (class_name.starts_with("kotlin/jvm/functions/Function")
                            && method_name == "invoke"
                            && descriptor.contains("Continuation"))
                        || (descriptor
                            .contains("Lkotlin/coroutines/Continuation;)Ljava/lang/Object;"));
                    if is_suspend_virtual {
                        sites_raw.push((bi as u32, si as u32, virtual_suspend_fid, args.len()));
                    }
                }
                _ => {}
            }
        }
    }
    if sites_raw.is_empty() {
        return SuspendSitesResult::Zero;
    }

    // Tail-call optimization: a suspend fn whose body is a single
    // suspend call returned directly (no other instructions, no
    // arg-loading temps between the call and the return) gets emitted
    // as a plain `aload $completion; invokestatic …; areturn` — no
    // state machine needed because no suspension boundary needs to
    // restore local state. kotlinc applies this to bodies like
    // `suspend fun caller() = x()`.
    if sites_raw.len() == 1 {
        let (call_bi, call_si, _, _) = sites_raw[0];
        let block = &mf.blocks[call_bi as usize];
        // Identify the call's destination local.
        let call_dest = match &block.stmts[call_si as usize] {
            MStmt::Assign { dest, .. } => *dest,
        };
        // Check that the call is the last (only) statement and the
        // terminator is `ReturnValue(call_dest)`.
        let is_only_stmt = block.stmts.len() == (call_si as usize + 1);
        let returns_call_dest = matches!(
            &block.terminator,
            Terminator::ReturnValue(l) if *l == call_dest
        );
        // The call's args must all be forwarded from the outer fn's
        // params in the same order. That is, the call's i-th arg must
        // be the outer fn's i-th param (where the last param is
        // $completion). This covers `caller() = x()` AND
        // `caller(a, b) = x(a, b)` — both compile to a straight
        // load-args-and-call shape with no state machine.
        let args_forward_params = match &block.stmts[call_si as usize] {
            MStmt::Assign {
                value: Rvalue::Call { args, .. },
                ..
            } => {
                args.len() == mf.params.len()
                    && args.iter().zip(mf.params.iter()).all(|(a, p)| a == p)
            }
            _ => false,
        };
        let prior_stmts_trivial = (0..call_si as usize).all(|i| {
            matches!(
                &block.stmts[i],
                MStmt::Assign {
                    value: Rvalue::Const(_),
                    ..
                }
            )
        });
        if is_only_stmt
            && returns_call_dest
            && args_forward_params
            && prior_stmts_trivial
            && call_bi == 0
            && mf.blocks.len() == 1
        {
            return SuspendSitesResult::Zero;
        }
    }

    // Compute the outer function's user param types (everything
    // except the last param which is the $completion Continuation).
    let outer_user_param_tys: Vec<Ty> = if mf.params.len() > 1 {
        mf.params[..mf.params.len() - 1]
            .iter()
            .map(|pid| mf.locals[pid.0 as usize].clone())
            .collect()
    } else {
        Vec::new()
    };

    // Single-suspension path: if the body also has a string-literal
    // return tail we keep the single-suspension shape byte-for-byte (the
    // committed 391 fixture depends on it). This only applies when
    // the sole suspend call has just the implicit `$completion` — a
    // user-arg call can't be expressed in the legacy marker
    // (there is no way to thread arg values into the legacy emitter).
    if sites_raw.len() == 1 && sites_raw[0].3 == 1 {
        if let Some(resume_return_text) = extract_trailing_string(mf, module) {
            let (_, _, fid, _) = sites_raw[0];
            let target = &module.functions[fid.0 as usize];
            return SuspendSitesResult::Found(SuspendStateMachine {
                continuation_class,
                outer_class: wrapper_class.to_string(),
                outer_method: fn_name.to_string(),
                outer_user_param_tys: outer_user_param_tys.clone(),
                suspend_call_class: wrapper_class.to_string(),
                suspend_call_method: target.name.clone(),
                resume_return_text,
                sites: Vec::new(),
                spill_layout: Vec::new(),
                is_instance_method: false,
            });
        }
    }

    // Multi-block state machines are now supported.
    // Build per-site callee info and the conservative spill layout.
    let (sites, spill_layout) = build_sites_and_spills(mf, module, &sites_raw);

    SuspendSitesResult::Found(SuspendStateMachine {
        continuation_class,
        outer_class: wrapper_class.to_string(),
        outer_method: fn_name.to_string(),
        outer_user_param_tys,
        // Legacy compatibility fields stay populated (with the
        // FIRST callee) purely so MIR consumers that peek at them
        // don't see empty strings; the backend ignores them in the
        // multi-suspension path.
        suspend_call_class: wrapper_class.to_string(),
        suspend_call_method: {
            let (_, _, fid, _) = sites_raw[0];
            if fid.0 == u32::MAX {
                // Virtual suspend call — name is in the SuspendCallSite
                String::new()
            } else {
                module.functions[fid.0 as usize].name.clone()
            }
        },
        resume_return_text: String::new(),
        sites,
        spill_layout,
        is_instance_method: false,
    })
}

/// Given the raw suspend-call sites (block, stmt, callee, argc), in
/// source order, compute:
///
/// 1. the per-site callee info the backend needs to emit
///    `invokestatic`,
/// 2. the set of MIR locals live across each suspend call (over-
///    conservative — every local assigned earlier in the block and
///    referenced later is included), and
/// 3. the continuation-class spill layout (`I$0`, `L$0`, …) those
///    locals map to.
///
/// This is the straight-line-body specialization of a standard
/// liveness analysis: for each call site we just scan prior stmts
/// for writes and later stmts (+ the terminator) for reads. That
/// over-spills dead locals, but is always correct — a more precise
/// analysis is a future follow-up.
fn build_sites_and_spills(
    mf: &MirFunction,
    module: &MirModule,
    sites_raw: &[(u32, u32, FuncId, usize)],
) -> (Vec<SuspendCallSite>, Vec<SpillSlot>) {
    // Per-kind running counters for slot name suffixes (I$0, I$1, …).
    let mut kind_counters: [u32; 5] = [0; 5];
    fn kind_idx(k: SpillKind) -> usize {
        match k {
            SpillKind::Int => 0,
            SpillKind::Long => 1,
            SpillKind::Float => 2,
            SpillKind::Double => 3,
            SpillKind::Ref => 4,
        }
    }

    // Maps MIR local -> index in spill_layout, so repeated uses of
    // the same local across multiple suspend sites share one field.
    let mut local_to_slot: FxHashMap<u32, u32> = FxHashMap::default();
    let mut spill_layout: Vec<SpillSlot> = Vec::new();

    // Multi-block support. If all sites are in the same
    // block, use the original single-block analysis. Otherwise use
    // a conservative inter-block analysis.
    // Single-block only when ALL sites are in the SAME block
    // AND no other blocks have executable statements. Empty blocks with
    // just Goto/Return terminators are fine (common in lambda bodies).
    let is_single_block = {
        let first = sites_raw[0].0;
        let all_same = sites_raw.iter().all(|(b, _, _, _)| *b == first);
        let site_blocks: rustc_hash::FxHashSet<u32> =
            sites_raw.iter().map(|(b, _, _, _)| *b).collect();
        let has_code_blocks = mf
            .blocks
            .iter()
            .enumerate()
            .any(|(i, b)| !site_blocks.contains(&(i as u32)) && !b.stmts.is_empty());
        all_same && !has_code_blocks
    };

    let mut sites_out: Vec<SuspendCallSite> = Vec::with_capacity(sites_raw.len());
    for (bi, si, fid, _) in sites_raw {
        let block = &mf.blocks[*bi as usize];

        // Collect locals WRITTEN before this site.
        // Include function parameters (they're live from
        // function entry). Exclude the last param ($completion).
        let mut written: Vec<LocalId> = Vec::new();
        let n_params = mf.params.len();
        for &pid in mf.params.iter().take(n_params.saturating_sub(1)) {
            written.push(pid);
        }
        if is_single_block {
            // Original path: only scan within the single block.
            for (idx, stmt) in block.stmts.iter().enumerate() {
                if (idx as u32) >= *si {
                    break;
                }
                let MStmt::Assign { dest, .. } = stmt;
                written.push(*dest);
            }
        } else {
            // Multi-block: include locals from block 0 (entry — always
            // dominates all other blocks) + the site's own block
            // before the suspend call. Don't include other NON-entry
            // blocks — locals from other branches may not be
            // initialized on this execution path.
            if *bi != 0 {
                for stmt in &mf.blocks[0].stmts {
                    let MStmt::Assign { dest, .. } = stmt;
                    written.push(*dest);
                }
            }
            for (idx, stmt) in block.stmts.iter().enumerate() {
                if (idx as u32) >= *si {
                    break;
                }
                let MStmt::Assign { dest, .. } = stmt;
                written.push(*dest);
            }
        }

        // Collect locals READ after this site.
        let mut read: rustc_hash::FxHashSet<u32> = rustc_hash::FxHashSet::default();
        if is_single_block {
            for (idx, stmt) in block.stmts.iter().enumerate() {
                if (idx as u32) <= *si {
                    continue;
                }
                collect_reads(stmt, &mut read);
            }
            collect_terminator_reads(&block.terminator, &mut read);
        } else {
            // Multi-block: only scan reads AFTER the suspend site in
            // the same block + terminator. Only these stmts run in the
            // resume path for this specific branch.
            for (idx, stmt) in block.stmts.iter().enumerate() {
                if (idx as u32) <= *si {
                    continue;
                }
                collect_reads(stmt, &mut read);
            }
            collect_terminator_reads(&block.terminator, &mut read);
        }

        // Skip locals that are the suspend-call's own dest.
        let own_dest = {
            let MStmt::Assign { dest, .. } = &block.stmts[*si as usize];
            *dest
        };

        // For instance suspend methods, `this` (first param)
        // must always be spilled so `invokeSuspend` can use it as the
        // invokevirtual receiver. Force it into the read set.
        if !mf.params.is_empty() {
            let first_param = mf.params[0];
            let first_ty = &mf.locals[first_param.0 as usize];
            if matches!(first_ty, Ty::Class(_)) && mf.is_suspend {
                read.insert(first_param.0);
            }
        }

        let mut live_spills: Vec<LiveSpill> = Vec::new();
        for w in written {
            if w == own_dest {
                continue;
            }
            if !read.contains(&w.0) {
                continue;
            }
            let ty = &mf.locals[w.0 as usize];
            // Don't try to spill `Unit` — it's not a real value on
            // JVM. (Shouldn't arise in our scope, but guard.)
            if matches!(ty, Ty::Unit) {
                continue;
            }
            let kind = SpillKind::for_ty(ty);
            let slot_idx = *local_to_slot.entry(w.0).or_insert_with(|| {
                let n = kind_counters[kind_idx(kind)];
                kind_counters[kind_idx(kind)] = n + 1;
                let name = format!("{}{}", kind.prefix(), n);
                let idx = spill_layout.len() as u32;
                spill_layout.push(SpillSlot { name, kind });
                idx
            });
            live_spills.push(LiveSpill {
                local: w,
                slot: slot_idx,
            });
        }
        // Sort by slot index so the emitted spill/restore order is
        // stable across runs.
        live_spills.sort_by_key(|ls| ls.slot);

        // Extract the user-argument locals (everything
        // except the trailing `$completion`) plus their types, and
        // surface the callee's declared return type so the JVM
        // backend can emit a post-invoke `checkcast`. Older
        // single-suspension call shapes have no user args and a
        // `Unit`-typed callee, which keeps `args`/`arg_tys` empty
        // and the legacy emit path byte-stable.
        let stmt = &block.stmts[*si as usize];
        let MStmt::Assign {
            dest: call_dest,
            value: call_value,
        } = stmt;
        let Rvalue::Call {
            args: call_args, ..
        } = call_value
        else {
            unreachable!("suspend-call site is always a Call rvalue");
        };
        // The last arg is the implicit $completion the MIR lowerer
        // appends; everything before it is a user argument.
        let user_arg_count = call_args.len().saturating_sub(1);
        let args: Vec<LocalId> = call_args[..user_arg_count].to_vec();
        // Use the target function's declared parameter
        // types (not the call-site argument types) so that the
        // callee descriptor uses the correct interface types. For
        // example, when passing an `InputKt$Lambda$0` to a param
        // typed as `Function1`, the descriptor must say `Function1`.
        // Handle both Static and VirtualJava suspend calls.
        // Virtual calls use a sentinel FuncId(u32::MAX).
        let is_virtual = fid.0 == u32::MAX;
        let (arg_tys, return_ty, callee_class, callee_method_name): (Vec<Ty>, Ty, String, String) =
            if is_virtual {
                // Extract info from the VirtualJava call rvalue directly
                let stmt = &block.stmts[*si as usize];
                let MStmt::Assign { value, .. } = stmt;
                match value {
                    Rvalue::Call {
                        kind:
                            CallKind::VirtualJava {
                                class_name,
                                method_name,
                                ..
                            },
                        ..
                    } => {
                        // For await(), there are no user args — just receiver + continuation
                        // The receiver is the first arg, continuation is last
                        let at: Vec<Ty> = args
                            .iter()
                            .map(|a| mf.locals[a.0 as usize].clone())
                            .collect();
                        (at, Ty::Any, class_name.clone(), method_name.clone())
                    }
                    _ => unreachable!("virtual suspend site must be VirtualJava"),
                }
            } else {
                let target = &module.functions[fid.0 as usize];
                let at: Vec<Ty> = args
                    .iter()
                    .enumerate()
                    .map(|(i, a)| {
                        target
                            .params
                            .get(i)
                            .and_then(|p| target.locals.get(p.0 as usize))
                            .cloned()
                            .unwrap_or_else(|| mf.locals[a.0 as usize].clone())
                    })
                    .collect();
                let rt = target
                    .suspend_original_return_ty
                    .clone()
                    .unwrap_or(Ty::Unit);
                let cc = match target.name.as_str() {
                    "delay" => "kotlinx/coroutines/DelayKt".to_string(),
                    "yield" => "kotlinx/coroutines/YieldKt".to_string(),
                    "withContext" => "kotlinx/coroutines/BuildersKt".to_string(),
                    "coroutineScope" => "kotlinx/coroutines/CoroutineScopeKt".to_string(),
                    "supervisorScope" => "kotlinx/coroutines/SupervisorKt".to_string(),
                    "withTimeout" | "withTimeoutOrNull" => {
                        "kotlinx/coroutines/TimeoutKt".to_string()
                    }
                    _ => module.wrapper_class.clone(),
                };
                (at, rt, cc, target.name.clone())
            };

        sites_out.push(SuspendCallSite {
            block_idx: *bi,
            stmt_idx: *si,
            callee_class,
            callee_method: callee_method_name,
            args,
            arg_tys,
            return_ty,
            is_virtual,
            result_local: *call_dest,
            live_spills,
        });
    }

    (sites_out, spill_layout)
}

/// Collect every `LocalId` read (as a source operand) by an
/// `MStmt::Assign`. Writes to `dest` are intentionally excluded.
fn collect_reads(stmt: &MStmt, out: &mut rustc_hash::FxHashSet<u32>) {
    let MStmt::Assign { value, .. } = stmt;
    collect_rvalue_reads(value, out);
}

fn collect_rvalue_reads(v: &Rvalue, out: &mut rustc_hash::FxHashSet<u32>) {
    match v {
        Rvalue::Const(_) | Rvalue::NewInstance(_) | Rvalue::GetStaticField { .. } => {}
        Rvalue::Local(l) => {
            out.insert(l.0);
        }
        Rvalue::BinOp { lhs, rhs, .. } => {
            out.insert(lhs.0);
            out.insert(rhs.0);
        }
        Rvalue::GetField { receiver, .. } => {
            out.insert(receiver.0);
        }
        Rvalue::PutField {
            receiver, value, ..
        } => {
            out.insert(receiver.0);
            out.insert(value.0);
        }
        Rvalue::PutStaticField { value, .. } => {
            out.insert(value.0);
        }
        Rvalue::Call { args, .. } => {
            for a in args {
                out.insert(a.0);
            }
        }
        Rvalue::InstanceOf { obj, .. } => {
            out.insert(obj.0);
        }
        Rvalue::NewIntArray(l) | Rvalue::ArrayLength(l) | Rvalue::NewObjectArray(l) => {
            out.insert(l.0);
        }
        Rvalue::NewTypedObjectArray { size, .. } => {
            out.insert(size.0);
        }
        Rvalue::ArrayLoad { array, index } => {
            out.insert(array.0);
            out.insert(index.0);
        }
        Rvalue::ArrayStore {
            array,
            index,
            value,
        }
        | Rvalue::ObjectArrayStore {
            array,
            index,
            value,
        } => {
            out.insert(array.0);
            out.insert(index.0);
            out.insert(value.0);
        }
        Rvalue::CheckCast { obj, .. } => {
            out.insert(obj.0);
        }
    }
}

fn collect_terminator_reads(t: &Terminator, out: &mut rustc_hash::FxHashSet<u32>) {
    match t {
        Terminator::Return | Terminator::Goto(_) => {}
        Terminator::ReturnValue(l) => {
            out.insert(l.0);
        }
        Terminator::Branch { cond, .. } => {
            out.insert(cond.0);
        }
        Terminator::Throw(exc) => {
            out.insert(exc.0);
        }
    }
}

/// Walk the function's last block and, if its terminator is
/// `ReturnValue(local)` where `local` was assigned a
/// `Rvalue::Const(MirConst::String(...))`, resolve the string
/// id back to its text via the module's string pool. Used by
/// the single-suspension path to recognize the "return \"done\"" post-suspend
/// tail pattern and thread the literal through to the JVM
/// backend's constant pool.
fn extract_trailing_string(mf: &MirFunction, module: &MirModule) -> Option<String> {
    let last = mf.blocks.last()?;
    let Terminator::ReturnValue(local) = &last.terminator else {
        return None;
    };
    // Scan the last block's stmts for the assignment to this local.
    // The CPS rewrite path wraps the return in a `mir_autobox` call
    // followed by a `Call` to `Integer.valueOf` etc., so the value
    // we care about might be several assignments back. Walk
    // backwards and stop at the first `Const(String(sid))` we see
    // referencing the terminator's local, either directly or via
    // a single `Rvalue::Local(...)` alias.
    let mut tracked = *local;
    for stmt in last.stmts.iter().rev() {
        let MStmt::Assign { dest, value } = stmt;
        if *dest != tracked {
            continue;
        }
        match value {
            Rvalue::Const(MirConst::String(sid)) => {
                return Some(module.lookup_string(*sid).to_string());
            }
            Rvalue::Local(src) => {
                tracked = *src;
            }
            _ => return None,
        }
    }
    None
}

#[allow(clippy::too_many_arguments)]
/// True if `body` is a single statement of one of the shapes for which
/// kotlinc emits a leading `nop` at offset 0 (so the function-declaration
/// line gets its own `LineNumberTable` entry distinct from the body's
/// first instruction line). The recognized shapes are:
///
/// - `when { ... }` (no subject — lowers to an if-else chain)
/// - `if (cond) ... else if (...) ... else ...` (chain of else-ifs)
/// - `try { ... } catch (...) { ... }` (with or without finally)
/// - any of the above wrapped in a `return`
fn function_body_needs_leading_nop(body: &skotch_syntax::Block) -> bool {
    use skotch_syntax::{Expr, Stmt};
    if body.stmts.len() != 1 {
        return false;
    }
    // Try-as-statement is its own variant; match it directly first.
    if matches!(body.stmts[0], Stmt::TryStmt { .. }) {
        return true;
    }
    let expr = match &body.stmts[0] {
        Stmt::Expr(e) => e,
        Stmt::Return { value: Some(e), .. } => e,
        _ => return false,
    };
    fn is_else_if_chain(e: &Expr) -> bool {
        match e {
            Expr::If {
                else_block: Some(eb),
                ..
            } => {
                if eb.stmts.len() != 1 {
                    return false;
                }
                if let Stmt::Expr(inner) = &eb.stmts[0] {
                    matches!(inner, Expr::If { .. })
                } else {
                    false
                }
            }
            _ => false,
        }
    }
    match expr {
        Expr::When { subject, .. } => matches!(subject.as_ref(), Expr::BoolLit(true, _)),
        Expr::Try { .. } => true,
        Expr::If { .. } => is_else_if_chain(expr) && !is_simple_string_chain(expr),
        _ => false,
    }
}

/// True if every leaf branch of the if-else-if chain is a simple expression
/// like a string literal — kotlinc doesn't add a LineNumberTable nop for
/// those (the values themselves carry the line info via the call site).
fn is_simple_string_chain(e: &Expr) -> bool {
    match e {
        Expr::If {
            then_block,
            else_block,
            ..
        } => {
            let then_simple = block_is_simple_value(then_block);
            let else_simple = match else_block {
                Some(eb) => {
                    if eb.stmts.len() == 1 {
                        match &eb.stmts[0] {
                            skotch_syntax::Stmt::Expr(inner) => match inner {
                                Expr::If { .. } => is_simple_string_chain(inner),
                                Expr::StringLit(..)
                                | Expr::IntLit(..)
                                | Expr::BoolLit(..)
                                | Expr::Ident(..) => true,
                                _ => false,
                            },
                            _ => false,
                        }
                    } else {
                        block_is_simple_value(eb)
                    }
                }
                None => true,
            };
            then_simple && else_simple
        }
        _ => false,
    }
}

fn block_is_simple_value(b: &skotch_syntax::Block) -> bool {
    if b.stmts.len() != 1 {
        return false;
    }
    match &b.stmts[0] {
        skotch_syntax::Stmt::Expr(e) => matches!(
            e,
            Expr::StringLit(..) | Expr::IntLit(..) | Expr::BoolLit(..) | Expr::Ident(..)
        ),
        _ => false,
    }
}

#[allow(clippy::too_many_arguments)]
fn lower_function(
    f: &FunDecl,
    fn_idx: usize,
    typed: Option<&skotch_typeck::TypedFunction>,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    module: &mut MirModule,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) {
    let raw_name = interner.resolve(f.name).to_string();
    let name = if f.is_ext_property {
        let mut chars = raw_name.chars();
        let first = chars.next().map(|c| c.to_ascii_uppercase());
        match first {
            Some(c) => format!("get{}{}", c, chars.as_str()),
            None => raw_name.clone(),
        }
    } else {
        raw_name
    };
    let declared_ret = typed
        .map(|t| t.return_ty.clone())
        .or_else(|| {
            f.return_ty.as_ref().map(|tr| {
                let resolved = resolve_type(interner.resolve(tr.name), module);
                resolved
            })
        })
        .unwrap_or(Ty::Unit);
    // Upgrade simple class names from typeck to fully-qualified names
    // via the file's import map. Without this, return types like
    // `AnnotatedString` end up as `Ty::Class("AnnotatedString")`,
    // emitted as the malformed JVM descriptor `LAnnotatedString;` —
    // d8 rejects it because the class doesn't exist at that path.
    // Mirrors the param-type upgrade further down.
    let declared_ret = match declared_ret {
        Ty::Class(name) if !name.contains('/') => {
            if let Some(fq) = module.import_map.get(&name) {
                Ty::Class(fq.clone())
            } else {
                Ty::Class(name)
            }
        }
        Ty::Nullable(inner) => match *inner {
            Ty::Class(name) if !name.contains('/') => {
                if let Some(fq) = module.import_map.get(&name) {
                    Ty::Nullable(Box::new(Ty::Class(fq.clone())))
                } else {
                    Ty::Nullable(Box::new(Ty::Class(name)))
                }
            }
            other => Ty::Nullable(Box::new(other)),
        },
        other => other,
    };
    // Coroutine transform: a `suspend fun`'s
    // JVM return type becomes `Object` (we use `Ty::Any`). The
    // original declared return type is still needed below so we
    // can box primitive `return` expressions before the
    // `areturn`. See milestones.yaml v0.9.0.
    let return_ty = if f.is_suspend {
        Ty::Any
    } else {
        declared_ret.clone()
    };
    let mut fb = FnBuilder::new(fn_idx, name.clone(), return_ty);
    fb.mf.is_suspend = f.is_suspend;
    fb.mf.is_private = matches!(f.visibility, skotch_syntax::Visibility::Private);
    // Coroutine transform: remember the source-
    // level declared return type of every suspend fun before the
    // CPS rewrite promotes it to `Object`. Callers that invoke
    // this suspend fun need it to emit the correct `checkcast` on
    // resume. Non-suspend funs leave this as `None`.
    if f.is_suspend {
        fb.mf.suspend_original_return_ty = Some(declared_ret.clone());
    }

    // Allocate parameter locals first so they get LocalId 0..N.
    let mut scope: Vec<(Symbol, LocalId)> = Vec::new();

    // For extension functions: add the receiver as the first parameter.
    // It's accessible as `this` in the function body.
    if let Some(recv) = &f.receiver_ty {
        let recv_ty = resolve_type(interner.resolve(recv.name), module);
        let id = fb.new_local(recv_ty);
        fb.mf.params.push(id);
        let this_sym = interner.intern("this");
        scope.push((this_sym, id));
    }

    for (pi, p) in f.params.iter().enumerate() {
        let ty = if p.is_vararg {
            // vararg Int → IntArray (JVM `int[]`)
            Ty::IntArray
        } else {
            typed
                .and_then(|t| {
                    t.param_tys
                        .get(pi + if f.receiver_ty.is_some() { 1 } else { 0 })
                        .cloned()
                })
                .unwrap_or_else(|| resolve_type(interner.resolve(p.ty.name), module))
        };
        // Typeck returns simple-name `Ty::Class("DrawerState")` for any
        // uppercase name not in its env. Downstream the JVM emitter
        // prefixes simple names with the file's wrapper-class package,
        // producing descriptors like `Lcom/example/.../DrawerState;`
        // that don't match the actual class location. Use the file's
        // import map (which holds `DrawerState ->
        // androidx/compose/material3/DrawerState` etc.) to upgrade
        // simple names to FQ so producer and caller agree on the
        // descriptor. (Caller side already FQ-resolves via the import
        // map in skotch-resolve.)
        let ty = match ty {
            Ty::Class(name) if !name.contains('/') => {
                if let Some(fq) = module.import_map.get(&name) {
                    Ty::Class(fq.clone())
                } else {
                    Ty::Class(name)
                }
            }
            Ty::Nullable(inner) => match *inner {
                Ty::Class(name) if !name.contains('/') => {
                    if let Some(fq) = module.import_map.get(&name) {
                        Ty::Nullable(Box::new(Ty::Class(fq.clone())))
                    } else {
                        Ty::Nullable(Box::new(Ty::Class(name)))
                    }
                }
                other => Ty::Nullable(Box::new(other)),
            },
            other => other,
        };
        // Detect extension function type parameters. The parser sets
        // `has_receiver = true` on types like `StringBuilder.() -> Unit`
        // and encodes the receiver as func_params[0]. Record the
        // receiver class name for call-site lambda-with-receiver dispatch.
        if p.ty.has_receiver {
            if let Some(ref fparams) = p.ty.func_params {
                if !fparams.is_empty() {
                    let recv_name = interner.resolve(fparams[0].name).to_string();
                    let jvm_class = match recv_name.as_str() {
                        "StringBuilder" => "java/lang/StringBuilder".to_string(),
                        "String" => "java/lang/String".to_string(),
                        other => other.to_string(),
                    };
                    fb.mf.param_receiver_types.push((pi, jvm_class));
                }
            }
        }
        // Function-typed parameters → kotlin/jvm/functions/FunctionN interface.
        // Suspend function types bump arity by +1 for the
        // implicit Continuation parameter — `suspend () -> T` maps to
        // `Function1<Continuation, Object>`, not `Function0`.
        let is_suspend_callable = matches!(
            ty,
            Ty::Function {
                is_suspend: true,
                ..
            }
        );
        // Preserve the structured Function param types before erasing to
        // `Ty::Class(FunctionN)` — call sites need the original param Tys
        // to pick the right lambda-helper descriptor (`(I)I` not `(Object)I`).
        let preserved_fn_params: Option<Vec<Ty>> = if let Ty::Function { ref params, .. } = ty {
            Some(params.clone())
        } else {
            None
        };
        let ty = if let Ty::Function {
            ref params,
            is_suspend: fn_suspend,
            is_composable: fn_composable,
            ..
        } = ty
        {
            // `@Composable () -> R` bumps arity by 2 (Composer + Int).
            // Without this, a function declared with
            // `content: @Composable () -> Unit` ends up with
            // `Function0` in its JVM descriptor and the call site
            // fails a `checkcast Function2` at runtime.
            let arity =
                params.len() + if fn_suspend { 1 } else { 0 } + if fn_composable { 2 } else { 0 };
            let iface = stdlib_function_interface(arity);
            Ty::Class(iface)
        } else {
            ty
        };
        // Override enum class types to String (enums are string-based).
        let id = fb.new_local(ty);
        fb.mf.params.push(id);
        if let Some(fn_params) = preserved_fn_params {
            fb.mf.local_generic_args.insert(id.0, fn_params);
        }
        // Record suspend-typed callable parameters so that
        // when they're invoked the MIR lowerer threads the continuation.
        if is_suspend_callable {
            fb.suspend_callable_locals.insert(id.0);
        }
        scope.push((p.name, id));
    }

    // Coroutine transform: a `suspend fun`'s
    // last parameter is an implicit `$completion: Continuation`.
    // We append it AFTER the explicit user parameters so the
    // source-visible parameter positions are unchanged.
    if f.is_suspend {
        let cont_ty = Ty::Class("kotlin/coroutines/Continuation".to_string());
        let cont_id = fb.new_local(cont_ty);
        fb.mf.params.push(cont_id);
        let cont_sym = interner.intern("$completion");
        scope.push((cont_sym, cont_id));
    }

    // Set the leading-nop flag for bodies whose only stmt is a when-without-
    // subject, an explicit if-else-if chain, or a try-catch (or `return` of
    // such expressions). kotlinc emits a `nop` at offset 0 for these so the
    // LineNumberTable has a slot for the function-declaration line.
    fb.mf.needs_leading_nop = function_body_needs_leading_nop(&f.body);

    let mut ok = true;
    for s in &f.body.stmts {
        if !lower_stmt(
            s,
            &mut fb,
            &mut scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
            None, // no loop context at function body level
        ) {
            // Abort lowering — see v42 note in project_jetchat_progress
            // memory. Trying to "preserve partial bodies on stmt failure"
            // produces malformed bytecode that fails JVM verification
            // (e.g. half-lowered `LocalContext.current` reads on a null
            // receiver). An empty placeholder body with the correct
            // descriptor is strictly safer than a partial one with junk.
            ok = false;
            break;
        }
    }
    // The current block's terminator stays `Return` (set by the
    // FnBuilder constructor and never overwritten for the last block).

    // Coroutine transform: rewrite every
    // return in this suspend function so that the returned value
    // is a reference (the method descriptor now promises
    // `Object`). `ReturnValue` terminators get autoboxed; bare
    // `Return` terminators (suspend fun with a `Unit` declared
    // return type) become `return null`, which is a valid
    // `Object`. Emitting `kotlin.Unit.INSTANCE` instead is the
    // semantically correct thing and will land together with the
    // full CPS state-machine.
    if f.is_suspend {
        for bi in 0..fb.mf.blocks.len() {
            match fb.mf.blocks[bi].terminator.clone() {
                Terminator::ReturnValue(local) => {
                    let ty = fb.mf.locals[local.0 as usize].clone();
                    let prev_block = fb.cur_block;
                    fb.cur_block = bi as u32;
                    // For suspend functions kotlinc uses
                    // `kotlin/coroutines/jvm/internal/Boxing.boxInt/Long/...`
                    // helpers rather than `Integer.valueOf` etc.
                    let boxed = mir_autobox_suspend(&mut fb, local, &ty);
                    fb.cur_block = prev_block;
                    fb.mf.blocks[bi].terminator = Terminator::ReturnValue(boxed);
                }
                Terminator::Return => {
                    let prev_block = fb.cur_block;
                    fb.cur_block = bi as u32;
                    let null_local = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest: null_local,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    fb.cur_block = prev_block;
                    fb.mf.blocks[bi].terminator = Terminator::ReturnValue(null_local);
                }
                _ => {}
            }
        }
    }

    // Coroutine transform: if this suspend
    // function contains any suspension points, attach a
    // [`SuspendStateMachine`] marker so the JVM backend emits the
    // canonical dispatcher + tableswitch pattern. Zero suspension
    // points falls through to the signature-rewrite-only shape. The extractor
    // rejects shapes outside the current scope (suspend calls with
    // user args, branches across suspend sites) as hard errors
    // rather than silently miscompiling.
    if f.is_suspend && ok {
        let sm = extract_suspend_state_machine(&fb.mf, module, &module.wrapper_class, &name);
        match sm {
            SuspendSitesResult::Zero => {}
            SuspendSitesResult::Found(state_machine) => {
                fb.mf.suspend_state_machine = Some(state_machine);
            }
            SuspendSitesResult::Unsupported(reason) => {
                diags.push(Diagnostic::error(
                    f.span,
                    format!(
                        "suspend function `{name}` has an unsupported shape: {reason}; the skotch \
                         CPS transform currently supports straight-line bodies with suspend calls \
                         that take only the implicit `$completion`"
                    ),
                ));
                ok = false;
            }
        }
    }

    // When a non-suspend function returns Unit but the body
    // ends with `ReturnValue(local)` whose type is non-Unit (e.g.
    // `fun main() = runBlocking { ... }` where runBlocking returns Object),
    // drop the value and emit plain `Return`. The JVM backend would
    // otherwise emit `areturn` from a `void` method, failing verification.
    if !f.is_suspend && declared_ret == Ty::Unit {
        for block in &mut fb.mf.blocks {
            if let Terminator::ReturnValue(local) = &block.terminator {
                let ty = &fb.mf.locals[local.0 as usize];
                if !matches!(ty, Ty::Unit) {
                    block.terminator = Terminator::Return;
                }
            }
        }
    }

    if ok {
        // Preserve param metadata from Pass 1.
        let saved_defaults = module.functions[fn_idx].param_defaults.clone();
        let saved_required = module.functions[fn_idx].required_params;
        let saved_names = module.functions[fn_idx].param_names.clone();
        let saved_vararg = module.functions[fn_idx].vararg_index;
        let saved_suspend = module.functions[fn_idx].is_suspend;
        let saved_inline = module.functions[fn_idx].is_inline;
        let saved_annotations = module.functions[fn_idx].annotations.clone();
        let saved_has_type_params = module.functions[fn_idx].has_type_params;
        let saved_suspend_orig_ret = module.functions[fn_idx].suspend_original_return_ty.clone();
        module.functions[fn_idx] = fb.finish();
        module.functions[fn_idx].param_defaults = saved_defaults;
        module.functions[fn_idx].required_params = saved_required;
        module.functions[fn_idx].param_names = saved_names;
        module.functions[fn_idx].vararg_index = saved_vararg;
        module.functions[fn_idx].is_suspend = saved_suspend;
        module.functions[fn_idx].is_inline = saved_inline;
        module.functions[fn_idx].annotations = saved_annotations;
        module.functions[fn_idx].has_type_params = saved_has_type_params;
        if module.functions[fn_idx]
            .suspend_original_return_ty
            .is_none()
        {
            module.functions[fn_idx].suspend_original_return_ty = saved_suspend_orig_ret;
        }
    } else {
        // Body lowering failed (some inner statement returned false).
        // Replace the body with a single `return` terminator, but PRESERVE
        // the params/locals/signature from Pass 1's placeholder so callers
        // see the correct descriptor. Without this, top-level @Composable
        // functions with bodies that hit unresolved identifiers end up
        // emitted as `()V` (no params) even though source declared params
        // — breaking every cross-file call site that pushes args expecting
        // the typed descriptor.
        let placeholder = &mut module.functions[fn_idx];
        placeholder.blocks = vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }];
        // Reset terminator type to match return_ty: for non-Unit return
        // types the stub emitter pushes a default value, so the body's
        // empty `Return` terminator is fine — the JVM `emit_stub_method`
        // path keys off return_ty, not the terminator.
    }
}

/// Loop context for `break` and `continue`: (continue_target, break_target).
type LoopCtx = Option<(u32, u32)>;

#[allow(clippy::too_many_arguments)]
fn lower_stmt(
    stmt: &Stmt,
    fb: &mut FnBuilder,
    scope: &mut Vec<(Symbol, LocalId)>,
    module: &mut MirModule,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    interner: &mut Interner,
    diags: &mut Diagnostics,
    loop_ctx: LoopCtx,
) -> bool {
    match stmt {
        Stmt::Expr(e) => lower_expr(
            e,
            fb,
            scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
            loop_ctx,
        )
        .is_some(),
        Stmt::Val(v) => lower_val_stmt(
            v,
            fb,
            scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
        ),
        Stmt::Return { value, .. } => {
            if let Some(v) = value {
                if let Some(local) = lower_expr(
                    v,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                ) {
                    fb.set_terminator(Terminator::ReturnValue(local));
                }
            } else {
                // `return` (or `return@label`) with no value — exits the
                // current function/lambda returning Unit/void.
                fb.set_terminator(Terminator::Return);
            }
            true
        }
        Stmt::While { cond, body, .. } => {
            // Special-case `while (true) { body }`: no cond block, body
            // is the loop header; continue/break wire to body/exit
            // directly. kotlinc emits the body inline with `break` as
            // the only exit path (fixture 143).
            if matches!(cond, Expr::BoolLit(true, _)) {
                let body_block = fb.new_block();
                let exit_block = fb.new_block();
                fb.terminate_and_switch(Terminator::Goto(body_block), body_block);
                let lctx = Some((body_block, exit_block));
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        lctx,
                    );
                }
                fb.terminate_and_switch(Terminator::Goto(body_block), exit_block);
                return true;
            }
            // while (cond) { body }
            //   → current → goto cond_block
            //     cond_block: eval cond → Branch(cond, body_block, exit_block)
            //     body_block: eval body → goto cond_block
            //     exit_block: continue
            let cond_block = fb.new_block();
            let body_block = fb.new_block();
            let exit_block = fb.new_block();
            fb.terminate_and_switch(Terminator::Goto(cond_block), cond_block);
            if let Some(cond_local) = lower_expr(
                cond,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) {
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: cond_local,
                        then_block: body_block,
                        else_block: exit_block,
                    },
                    body_block,
                );
            }
            let lctx = Some((cond_block, exit_block));
            for s in &body.stmts {
                lower_stmt(
                    s,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    lctx,
                );
            }
            fb.terminate_and_switch(Terminator::Goto(cond_block), exit_block);
            true
        }
        Stmt::DoWhile { body, cond, .. } => {
            // do { body } while (cond)
            //   → body_block: body → cond_block: eval cond → Branch(cond, body_block, exit_block)
            let body_block = fb.new_block();
            let cond_block = fb.new_block();
            let exit_block = fb.new_block();
            fb.terminate_and_switch(Terminator::Goto(body_block), body_block);
            let lctx = Some((cond_block, exit_block));
            for s in &body.stmts {
                lower_stmt(
                    s,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    lctx,
                );
            }
            fb.terminate_and_switch(Terminator::Goto(cond_block), cond_block);
            if let Some(cond_local) = lower_expr(
                cond,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) {
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: cond_local,
                        then_block: body_block,
                        else_block: exit_block,
                    },
                    exit_block,
                );
            }
            true
        }
        Stmt::Assign { target, value, .. } => {
            // var reassignment: look up the existing local, lower the
            // value, and assign to the same local ID.
            if let Some(rhs) = lower_expr(
                value,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) {
                // Check if this var is ref-boxed (captured mutable var).
                let ref_holder_name =
                    interner.intern(&format!("$ref${}", interner.resolve(*target)));
                if let Some((_, ref_lid)) = scope
                    .iter()
                    .rev()
                    .find(|(name, _)| *name == ref_holder_name)
                {
                    let ref_lid = *ref_lid;
                    // Find the $Ref class name from the local's type.
                    let ref_class = match &fb.mf.locals[ref_lid.0 as usize] {
                        Ty::Class(name) => name.clone(),
                        _ => String::new(),
                    };
                    if !ref_class.is_empty() {
                        // Write through the $Ref: ref.element = rhs
                        fb.push_stmt(MStmt::Assign {
                            dest: ref_lid,
                            value: Rvalue::PutField {
                                receiver: ref_lid,
                                class_name: ref_class.clone(),
                                field_name: "element".to_string(),
                                value: rhs,
                            },
                        });
                        // In the lambda invoke scope, also update the
                        // element-typed local copy so subsequent reads
                        // see the new value.  Skip this in the outer scope
                        // where the target local IS the $Ref object.
                        if let Some((_, local_id)) =
                            scope.iter().rev().find(|(name, _)| *name == *target)
                        {
                            let dest = *local_id;
                            let dest_ty = &fb.mf.locals[dest.0 as usize];
                            if !matches!(dest_ty, Ty::Class(n) if n.starts_with("$Ref$")) {
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Local(rhs),
                                });
                            }
                        }
                    }
                } else {
                    // Normal (non-ref-boxed) assignment.
                    if let Some((_name, local_id)) =
                        scope.iter().rev().find(|(name, _)| *name == *target)
                    {
                        let dest = *local_id;
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Local(rhs),
                        });
                    }
                }
            }
            true
        }
        Stmt::IndexAssign {
            receiver,
            index,
            value,
            ..
        } => {
            let arr = lower_expr(
                receiver,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            );
            let idx = lower_expr(
                index,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            );
            let val = lower_expr(
                value,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            );
            if let (Some(a), Some(i), Some(v)) = (arr, idx, val) {
                let arr_ty = fb.mf.locals[a.0 as usize].clone();
                // Check for operator fun set() on user-defined classes.
                let has_set = if let Ty::Class(ref cn) = arr_ty {
                    module
                        .classes
                        .iter()
                        .find(|c| &c.name == cn)
                        .is_some_and(|cls| cls.methods.iter().any(|m| m.name == "set"))
                } else {
                    false
                };
                if has_set {
                    if let Ty::Class(cn) = &arr_ty {
                        let dest = fb.new_local(Ty::Unit);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: cn.clone(),
                                    method_name: "set".to_string(),
                                },
                                args: vec![a, i, v],
                            },
                        });
                    }
                } else {
                    let dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::ArrayStore {
                            array: a,
                            index: i,
                            value: v,
                        },
                    });
                }
            }
            true
        }
        Stmt::FieldAssign {
            receiver,
            field,
            value,
            ..
        } => {
            let Some(recv_local) = lower_expr(
                receiver,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) else {
                return false;
            };
            let Some(val_local) = lower_expr(
                value,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) else {
                return false;
            };
            let recv_ty = fb.mf.locals[recv_local.0 as usize].clone();
            let class_name = if let Ty::Class(cn) = &recv_ty {
                cn.clone()
            } else {
                "java/lang/Object".to_string()
            };
            let field_name = interner.resolve(*field).to_string();
            // Check for a custom setter method on the class (user-defined).
            let setter_name = format!("set{}{}", &field_name[..1].to_uppercase(), &field_name[1..]);
            let user_has_setter = if let Ty::Class(ref cn) = recv_ty {
                module
                    .classes
                    .iter()
                    .find(|c| &c.name == cn)
                    .is_some_and(|cls| cls.methods.iter().any(|m| m.name == setter_name))
            } else {
                false
            };
            // For external classes (Kotlin/JDK interfaces and classes that
            // expose properties as setter methods), check classinfo for an
            // instance `set<Field>(Type)V` method. Without this, code like
            // `mutableStateFlow.value = true` lowers to
            // `putfield MutableStateFlow.value:Z` — but MutableStateFlow is
            // an interface with no field, only `setValue(Object)V`. The
            // resulting bytecode passes verification (kotlin/jvm
            // checking is structural) but crashes with
            // IncompatibleClassChangeError at the first call.
            let external_setter_desc: Option<String> =
                if !user_has_setter && class_name.contains('/') {
                    skotch_classinfo::lookup_method_descriptor(&class_name, &setter_name, 1)
                } else {
                    None
                };
            if user_has_setter {
                let dummy = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: dummy,
                    value: Rvalue::Call {
                        kind: CallKind::Virtual {
                            class_name,
                            method_name: setter_name,
                        },
                        args: vec![recv_local, val_local],
                    },
                });
            } else if let Some(setter_desc) = external_setter_desc {
                // Box primitives if the descriptor expects an Object
                // (Kotlin generic-erased property setters take Object).
                let val_ty = fb.mf.locals[val_local.0 as usize].clone();
                let boxed_val = if setter_desc.contains("Ljava/lang/Object;") {
                    mir_autobox(fb, val_local, &val_ty)
                } else {
                    val_local
                };
                let dummy = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: dummy,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name,
                            method_name: setter_name,
                            descriptor: setter_desc,
                        },
                        args: vec![recv_local, boxed_val],
                    },
                });
            } else {
                let dummy = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: dummy,
                    value: Rvalue::PutField {
                        receiver: recv_local,
                        class_name,
                        field_name,
                        value: val_local,
                    },
                });
            }
            true
        }
        Stmt::For {
            var_name,
            start: range_start,
            end: range_end,
            exclusive,
            descending,
            step: step_expr,
            body,
            ..
        } => {
            // Desugar: for (i in a..b) { body }
            //   → var i = a
            //     val _end = b
            //     while (i <= _end) { body; i = i + 1 }
            //
            // For inclusive (`..`), non-descending ranges with a literal-int
            // end, kotlinc folds `i <= K` to `i < K+1`. We mirror that here.
            let inclusive_const_end_plus_one: Option<i32> = if !*exclusive && !*descending {
                if let Expr::IntLit(v, _) = range_end {
                    let plus_one = *v + 1;
                    if plus_one >= i32::MIN as i64 && plus_one <= i32::MAX as i64 {
                        Some(plus_one as i32)
                    } else {
                        None
                    }
                } else {
                    None
                }
            } else {
                None
            };
            // For descending (`downTo`) ranges with a literal-int end K,
            // kotlinc rewrites `i >= K` as `K-1 < i`. The constant K-1 is
            // on the LHS and the loop variable on the RHS (operand order
            // swapped), and the cmp is `CmpLt`. Matches kotlinc's
            // `iconst <K-1>; iload <i>; if_icmpge EXIT` pattern.
            let descending_const_end_minus_one: Option<i32> = if *descending && step_expr.is_none()
            {
                if let Expr::IntLit(v, _) = range_end {
                    let minus_one = *v - 1;
                    if minus_one >= i32::MIN as i64 && minus_one <= i32::MAX as i64 {
                        Some(minus_one as i32)
                    } else {
                        None
                    }
                } else {
                    None
                }
            } else {
                None
            };
            let Some(start_val) = lower_expr(
                range_start,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) else {
                return false;
            };
            let end_val = if let Some(plus_one) = inclusive_const_end_plus_one {
                let local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: local,
                    value: Rvalue::Const(MirConst::Int(plus_one)),
                });
                local
            } else if let Some(minus_one) = descending_const_end_minus_one {
                let local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: local,
                    value: Rvalue::Const(MirConst::Int(minus_one)),
                });
                local
            } else {
                let Some(v) = lower_expr(
                    range_end,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                ) else {
                    return false;
                };
                v
            };

            // Create the loop variable.
            let loop_var = fb.new_local(Ty::Int);
            fb.push_stmt(MStmt::Assign {
                dest: loop_var,
                value: Rvalue::Local(start_val),
            });
            scope.push((*var_name, loop_var));

            // while (loop_var <= end_val)
            let cond_block = fb.new_block();
            let body_block = fb.new_block();
            let variable_end_termination = !*exclusive
                && !*descending
                && step_expr.is_none()
                && inclusive_const_end_plus_one.is_none()
                && descending_const_end_minus_one.is_none();
            // Allocate term_check_block between body and incr, so its bytecode
            // lands right after body (enabling fall-through for the no-sub-
            // block body case). For bodies with internal sub-blocks (if/else,
            // when), those sub-blocks come after term_check in MIR order
            // anyway; the goto chain from body→tcb is unavoidable.
            let term_check_block = if variable_end_termination {
                Some(fb.new_block())
            } else {
                None
            };
            let incr_block = fb.new_block(); // increment step
            let exit_block = fb.new_block();

            fb.terminate_and_switch(Terminator::Goto(cond_block), cond_block);

            // Condition depends on range kind:
            // ..     → loop_var <= end_val   (folded to `<` against end+1
            //          when end is a literal — see above)
            // until  → loop_var <  end_val
            // downTo → loop_var >= end_val   (folded to `end-1 < loop_var`
            //          with operands swapped when end is a literal — see
            //          above; matches kotlinc's reversed-operand emission)
            let descending_swap = descending_const_end_minus_one.is_some();
            let cmp_op = if descending_swap {
                MBinOp::CmpLt
            } else if *descending {
                MBinOp::CmpGe
            } else if *exclusive || inclusive_const_end_plus_one.is_some() {
                MBinOp::CmpLt
            } else {
                MBinOp::CmpLe
            };
            let (cmp_lhs, cmp_rhs) = if descending_swap {
                (end_val, loop_var)
            } else {
                (loop_var, end_val)
            };
            let cmp = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: cmp,
                value: Rvalue::BinOp {
                    op: cmp_op,
                    lhs: cmp_lhs,
                    rhs: cmp_rhs,
                },
            });
            fb.terminate_and_switch(
                Terminator::Branch {
                    cond: cmp,
                    then_block: body_block,
                    else_block: exit_block,
                },
                body_block,
            );

            // Body — break goes to exit_block. Continue goes to term_check
            // block when variable-end termination is active.
            let continue_target = term_check_block.unwrap_or(incr_block);
            let lctx = Some((continue_target, exit_block));
            for s in &body.stmts {
                lower_stmt(
                    s,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    lctx,
                );
            }

            if let Some(tcb) = term_check_block {
                // After body's last block: goto term-check block.
                fb.terminate_and_switch(Terminator::Goto(tcb), tcb);
                let term_cmp = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: term_cmp,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpNe,
                        lhs: loop_var,
                        rhs: end_val,
                    },
                });
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: term_cmp,
                        then_block: incr_block,
                        else_block: exit_block,
                    },
                    incr_block,
                );
            } else {
                // After body: goto increment block
                fb.terminate_and_switch(Terminator::Goto(incr_block), incr_block);
            }

            // Step block: i = i + step (ascending) or i = i - step (descending)
            // When a `step` expression is provided, always ADD (the step
            // value itself is always positive in Kotlin; for downTo the
            // step is still added as subtraction).
            let step_op = if *descending {
                MBinOp::SubI
            } else {
                MBinOp::AddI
            };
            let step_val = if let Some(step_e) = step_expr {
                lower_expr(
                    step_e,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )
                .unwrap_or_else(|| {
                    let tmp = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: tmp,
                        value: Rvalue::Const(MirConst::Int(1)),
                    });
                    tmp
                })
            } else {
                let one = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: one,
                    value: Rvalue::Const(MirConst::Int(1)),
                });
                one
            };
            let incremented = fb.new_local(Ty::Int);
            fb.push_stmt(MStmt::Assign {
                dest: incremented,
                value: Rvalue::BinOp {
                    op: step_op,
                    lhs: loop_var,
                    rhs: step_val,
                },
            });
            fb.push_stmt(MStmt::Assign {
                dest: loop_var,
                value: Rvalue::Local(incremented),
            });

            // Back-edge target: variable-end termination check loops back
            // to body (skipping the now-redundant initial check). Other
            // shapes loop back to cond as before.
            let back_edge = if variable_end_termination {
                body_block
            } else {
                cond_block
            };
            fb.terminate_and_switch(Terminator::Goto(back_edge), exit_block);
            true
        }
        Stmt::ForIn {
            var_name,
            destructure_names,
            iterable,
            body,
            ..
        } => {
            // Desugar: for (x in collection) { body }
            let Some(collection_local) = lower_expr(
                iterable,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) else {
                return false;
            };

            let collection_ty = fb.mf.locals[collection_local.0 as usize].clone();

            if matches!(
                collection_ty,
                Ty::IntArray | Ty::LongArray | Ty::DoubleArray | Ty::BooleanArray | Ty::ByteArray
            ) {
                // IntArray iteration: desugar to index-based loop
                //   var i = 0
                //   while (i < array.size) { val x = array[i]; body; i++ }
                let idx_var = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: idx_var,
                    value: Rvalue::Const(MirConst::Int(0)),
                });

                let arr_len = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: arr_len,
                    value: Rvalue::ArrayLength(collection_local),
                });

                let cond_block = fb.new_block();
                let body_block = fb.new_block();
                let exit_block = fb.new_block();

                fb.terminate_and_switch(Terminator::Goto(cond_block), cond_block);

                // Condition: i < array.size
                let cmp = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: cmp,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpLt,
                        lhs: idx_var,
                        rhs: arr_len,
                    },
                });
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: cmp,
                        then_block: body_block,
                        else_block: exit_block,
                    },
                    body_block,
                );

                // Body: val x = array[i]
                let element = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: element,
                    value: Rvalue::ArrayLoad {
                        array: collection_local,
                        index: idx_var,
                    },
                });
                if let Some(names) = destructure_names {
                    // Destructure the element via componentN() calls.
                    for (i, dn) in names.iter().enumerate() {
                        let method_name = format!("component{}", i + 1);
                        let comp = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest: comp,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "kotlin/Pair".to_string(),
                                    method_name: method_name.clone(),
                                    descriptor: "()Ljava/lang/Object;".to_string(),
                                },
                                args: vec![element],
                            },
                        });
                        scope.push((*dn, comp));
                    }
                } else {
                    scope.push((*var_name, element));
                }

                let lctx = Some((cond_block, exit_block));
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        lctx,
                    );
                }

                // i++
                let incremented = fb.new_local(Ty::Int);
                let one = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: one,
                    value: Rvalue::Const(MirConst::Int(1)),
                });
                fb.push_stmt(MStmt::Assign {
                    dest: incremented,
                    value: Rvalue::BinOp {
                        op: MBinOp::AddI,
                        lhs: idx_var,
                        rhs: one,
                    },
                });
                fb.push_stmt(MStmt::Assign {
                    dest: idx_var,
                    value: Rvalue::Local(incremented),
                });

                fb.terminate_and_switch(Terminator::Goto(cond_block), exit_block);
            } else {
                // Check if we're iterating a Map — need entrySet().iterator()
                // instead of just .iterator().
                let is_map = matches!(&collection_ty, Ty::Class(cn)
                    if cn.contains("Map"));

                // Collection iteration via iterator()
                //   val iter = collection.iterator()
                //   while (iter.hasNext()) { val x = iter.next(); body }
                let iter_local = fb.new_local(Ty::Class("java/util/Iterator".to_string()));
                if is_map && destructure_names.is_some() {
                    // Map destructuring: map.entrySet().iterator()
                    let entry_set = fb.new_local(Ty::Class("java/util/Set".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: entry_set,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/util/Map".to_string(),
                                method_name: "entrySet".to_string(),
                                descriptor: "()Ljava/util/Set;".to_string(),
                            },
                            args: vec![collection_local],
                        },
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest: iter_local,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/util/Set".to_string(),
                                method_name: "iterator".to_string(),
                                descriptor: "()Ljava/util/Iterator;".to_string(),
                            },
                            args: vec![entry_set],
                        },
                    });
                } else {
                    fb.push_stmt(MStmt::Assign {
                        dest: iter_local,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/Iterable".to_string(),
                                method_name: "iterator".to_string(),
                                descriptor: "()Ljava/util/Iterator;".to_string(),
                            },
                            args: vec![collection_local],
                        },
                    });
                }

                let cond_block = fb.new_block();
                let body_block = fb.new_block();
                let exit_block = fb.new_block();

                fb.terminate_and_switch(Terminator::Goto(cond_block), cond_block);

                // Condition: iter.hasNext()
                let has_next = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: has_next,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "java/util/Iterator".to_string(),
                            method_name: "hasNext".to_string(),
                            descriptor: "()Z".to_string(),
                        },
                        args: vec![iter_local],
                    },
                });
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: has_next,
                        then_block: body_block,
                        else_block: exit_block,
                    },
                    body_block,
                );

                // Body: val x = iter.next(); <body stmts>
                let element = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: element,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "java/util/Iterator".to_string(),
                            method_name: "next".to_string(),
                            descriptor: "()Ljava/lang/Object;".to_string(),
                        },
                        args: vec![iter_local],
                    },
                });
                if let Some(names) = destructure_names {
                    if is_map {
                        // Map.Entry destructuring: checkcast + getKey()/getValue()
                        let entry = fb.new_local(Ty::Class("java/util/Map$Entry".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: entry,
                            value: Rvalue::CheckCast {
                                obj: element,
                                target_class: "java/util/Map$Entry".to_string(),
                            },
                        });
                        for (i, dn) in names.iter().enumerate() {
                            let method_name = if i == 0 { "getKey" } else { "getValue" };
                            let comp = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: comp,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "java/util/Map$Entry".to_string(),
                                        method_name: method_name.to_string(),
                                        descriptor: "()Ljava/lang/Object;".to_string(),
                                    },
                                    args: vec![entry],
                                },
                            });
                            scope.push((*dn, comp));
                        }
                    } else {
                        // Pair/data class destructuring: checkcast + componentN()
                        let pair = fb.new_local(Ty::Class("kotlin/Pair".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: pair,
                            value: Rvalue::CheckCast {
                                obj: element,
                                target_class: "kotlin/Pair".to_string(),
                            },
                        });
                        for (i, dn) in names.iter().enumerate() {
                            let method_name = format!("component{}", i + 1);
                            let comp = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: comp,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "kotlin/Pair".to_string(),
                                        method_name,
                                        descriptor: "()Ljava/lang/Object;".to_string(),
                                    },
                                    args: vec![pair],
                                },
                            });
                            scope.push((*dn, comp));
                        }
                    }
                } else {
                    scope.push((*var_name, element));
                }

                let lctx = Some((cond_block, exit_block));
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        lctx,
                    );
                }

                fb.terminate_and_switch(Terminator::Goto(cond_block), exit_block);
            }
            true
        }
        Stmt::LocalFun(f) => {
            // Lower local function as a synthetic top-level function.
            // Captured outer variables are passed as extra parameters.
            // kotlinc names nested local functions as `outer$inner` and
            // marks them private — match that here for parity.
            let fn_idx = module.functions.len();
            let inner_simple = interner.resolve(f.name).to_string();
            let fn_name = format!("{}${}", fb.mf.name, inner_simple);
            let return_ty = f
                .return_ty
                .as_ref()
                .map(|tr| resolve_type_ref(tr, interner, module))
                .unwrap_or(Ty::Unit);

            // Collect free variables in the local function body.
            let param_names: Vec<Symbol> = f.params.iter().map(|p| p.name).collect();
            let free_vars: Vec<(Symbol, LocalId, Ty)> =
                collect_free_vars(&f.body, &param_names, scope, fb, interner);
            let captures = free_vars;

            // Push placeholder and register in name_to_func BEFORE lowering
            // so recursive calls from inside the body can resolve.
            let total_params = captures.len() + f.params.len();
            let placeholder_params: Vec<LocalId> = (0..total_params as u32).map(LocalId).collect();
            let placeholder_locals: Vec<Ty> = vec![Ty::Any; total_params];
            module.functions.push(MirFunction {
                id: FuncId(fn_idx as u32),
                name: fn_name.clone(),
                params: placeholder_params,
                locals: placeholder_locals,
                blocks: Vec::new(),
                return_ty: return_ty.clone(),
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: false,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: true,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            });
            name_to_func.insert(f.name, FuncId(fn_idx as u32));

            // Build the function with captures as extra leading params.
            let mut inner_fb = FnBuilder::new(fn_idx, fn_name.clone(), return_ty.clone());
            inner_fb.mf.is_private = true;

            // Add capture params first.
            let mut inner_scope: Vec<(Symbol, LocalId)> = Vec::new();
            for (sym, _, ty) in &captures {
                let pid = inner_fb.new_local(ty.clone());
                inner_fb.mf.params.push(pid);
                inner_scope.push((*sym, pid));
            }

            // Add explicit function params.
            for p in &f.params {
                let ty = resolve_type_ref(&p.ty, interner, module);
                let pid = inner_fb.new_local(ty);
                inner_fb.mf.params.push(pid);
                inner_scope.push((p.name, pid));
            }

            // Lower the body with inner scope.
            for s in &f.body.stmts {
                lower_stmt(
                    s,
                    &mut inner_fb,
                    &mut inner_scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            // If the body didn't terminate, add a default return.
            if !matches!(
                inner_fb.mf.blocks[inner_fb.cur_block as usize].terminator,
                Terminator::ReturnValue(_) | Terminator::Return
            ) {
                inner_fb.set_terminator(Terminator::Return);
            }

            let inner_fn = inner_fb.finish();
            // Replace the placeholder with the real lowered function.
            module.functions[fn_idx] = inner_fn;

            // When calling this local function, the caller must prepend
            // capture args. Store capture info for the call site.
            // We encode this by making the function's params count include
            // captures, so the call site knows to pass them.
            // Store the capture local IDs for later use at call sites.
            for (sym, outer_lid, _) in &captures {
                // Register a synthetic name→local mapping so the call site
                // can find the outer locals to pass as capture args.
                let key =
                    interner.intern(&format!("$capture${}${}", fn_name, interner.resolve(*sym)));
                scope.push((key, *outer_lid));
            }

            true
        }
        Stmt::Break { .. } => {
            if let Some((_continue_blk, break_blk)) = loop_ctx {
                fb.set_terminator(Terminator::Goto(break_blk));
            }
            true
        }
        Stmt::Continue { .. } => {
            if let Some((continue_blk, _break_blk)) = loop_ctx {
                fb.set_terminator(Terminator::Goto(continue_blk));
            }
            true
        }
        Stmt::TryStmt {
            body,
            catch_param,
            catch_type,
            catch_body,
            extra_catches,
            finally_body,
            ..
        } => {
            if body.stmts.is_empty() {
                // An empty try body cannot throw, so any catch clauses are
                // unreachable and the protected region would be zero-length.
                // A zero-length exception-table entry (start_pc == end_pc) is
                // malformed: d8 crashes with an AIOOBE and the JVM verifier
                // rejects it. kotlinc emits no handler for an empty try. So
                // drop the try/catch scaffolding entirely and emit only the
                // finally body (which still always runs) inline.
                if let Some(fb_block) = finally_body {
                    for s in &fb_block.stmts {
                        let terminated = lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        if terminated {
                            break;
                        }
                    }
                }
            } else if catch_body.is_some() {
                // ── try-catch lowering ──────────────────────────────────
                //
                // Layout:
                //   current_block → goto try_block
                //   try_block: <try body stmts> → goto after_block
                //   catch_block: astore catch_param; <catch body> → goto after_block
                //   after_block: <continues>
                //
                // Exception handler: [try_block .. catch_block) → catch_block
                let try_block = fb.new_block();
                let catch_block = fb.new_block();
                // Pre-allocate one block per extra catch clause BEFORE
                // after_block so MIR emission order is try, catch1,
                // catch2, ..., after — matching kotlinc's layout for
                // multi-catch (510).
                let extra_catch_blocks: Vec<u32> =
                    extra_catches.iter().map(|_| fb.new_block()).collect();
                let after_block = fb.new_block();

                // Jump from current block into the try body.
                fb.terminate_and_switch(Terminator::Goto(try_block), try_block);

                // Lower the try body.
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    );
                }
                // If the try body ends with an explicit
                // `return`, the current block already has a ReturnValue
                // terminator. Don't overwrite it with Goto(after_block)
                // — the block returns directly. Only add the Goto if
                // the block has the default Return terminator.
                {
                    let cur = fb.cur_block as usize;
                    let cur_term = &fb.mf.blocks[cur].terminator;
                    if matches!(cur_term, Terminator::ReturnValue(_) | Terminator::Throw(_)) {
                        // Block already returns or throws. Don't overwrite
                        // with Goto — just switch to catch_block.
                        fb.cur_block = catch_block;
                    } else {
                        fb.terminate_and_switch(Terminator::Goto(after_block), catch_block);
                    }
                }

                // The catch handler block receives the exception on the
                // JVM operand stack. We allocate a local to store it,
                // typed as the declared catch type for smart-cast dispatch.
                if let Some(param_sym) = catch_param {
                    let exc_ty = catch_type
                        .as_ref()
                        .map(|ct| {
                            // Known stdlib exceptions resolve to their JVM
                            // class via the central table; user exception
                            // types pass through unchanged (identity).
                            let name = interner.resolve(*ct);
                            let jvm = intrinsics::kotlin_to_jvm_class(name).unwrap_or(name);
                            Ty::Class(jvm.to_string())
                        })
                        .unwrap_or(Ty::Error);
                    let exc_local = fb.new_local(exc_ty);
                    scope.push((*param_sym, exc_local));
                    // Placeholder assignment — the JVM backend will emit
                    // astore at handler entry instead of aconst_null.
                    fb.push_stmt(MStmt::Assign {
                        dest: exc_local,
                        value: Rvalue::Const(MirConst::Null),
                    });
                }

                // Lower the catch body.
                if let Some(cb) = catch_body {
                    for s in &cb.stmts {
                        lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                }
                // Same check for catch body: don't overwrite explicit return.
                {
                    let cur = fb.cur_block as usize;
                    let cur_term = &fb.mf.blocks[cur].terminator;
                    if !matches!(cur_term, Terminator::ReturnValue(_)) {
                        fb.terminate_and_switch(Terminator::Goto(after_block), after_block);
                    } else {
                        fb.cur_block = after_block;
                    }
                }

                // Record exception handler.
                let jvm_catch_type =
                    catch_type.map(|sym| intrinsics::catch_type_to_jvm(interner.resolve(sym)));

                fb.mf.exception_handlers.push(ExceptionHandler {
                    try_start_block: try_block,
                    try_end_block: catch_block,
                    handler_block: catch_block,
                    catch_type: jvm_catch_type,
                });

                // Process additional catch clauses (multi-catch).
                // Each gets its own block + exception handler. All share
                // the same try region [try_start, first_catch_start).
                for (idx, (extra_param, extra_type, extra_body)) in extra_catches.iter().enumerate()
                {
                    let extra_catch_block = extra_catch_blocks[idx];
                    // Resolve declared exception type.
                    let extra_name = interner.resolve(*extra_type);
                    // Known stdlib exceptions resolve via the central
                    // table; user types pass through unchanged (identity).
                    let extra_exc_ty = Ty::Class(
                        intrinsics::kotlin_to_jvm_class(extra_name)
                            .unwrap_or(extra_name)
                            .to_string(),
                    );
                    fb.cur_block = extra_catch_block;
                    let extra_exc_local = fb.new_local(extra_exc_ty);
                    let scope_entry = (*extra_param, extra_exc_local);
                    scope.push(scope_entry);
                    fb.push_stmt(MStmt::Assign {
                        dest: extra_exc_local,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    for s in &extra_body.stmts {
                        lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                    // Pop the catch param's scope entry so subsequent
                    // catches don't see it.
                    if let Some(pos) = scope
                        .iter()
                        .rposition(|(s, l)| *s == scope_entry.0 && *l == scope_entry.1)
                    {
                        scope.remove(pos);
                    }
                    let cur = fb.cur_block as usize;
                    let cur_term = &fb.mf.blocks[cur].terminator;
                    if !matches!(cur_term, Terminator::ReturnValue(_) | Terminator::Throw(_)) {
                        fb.terminate_and_switch(Terminator::Goto(after_block), after_block);
                    } else {
                        fb.cur_block = after_block;
                    }
                    // Map declared type name to FQN for exception table.
                    let jvm_extra_type =
                        intrinsics::catch_type_to_jvm(interner.resolve(*extra_type));
                    fb.mf.exception_handlers.push(ExceptionHandler {
                        try_start_block: try_block,
                        try_end_block: catch_block,
                        handler_block: extra_catch_block,
                        catch_type: Some(jvm_extra_type),
                    });
                }

                // Finally block (if present) is inlined after the catch.
                if let Some(fb_block) = finally_body {
                    for s in &fb_block.stmts {
                        let terminated = lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        if terminated {
                            break;
                        }
                    }
                }
            } else if let Some(fb_block) = finally_body {
                // try-finally (no catch). kotlinc emits:
                //   try_block: <body>
                //   after_block: <normal-path finally> ; goto exit
                //   handler_block (catch any Throwable):
                //     astore exc; <exception-path finally>; aload exc; athrow
                //   exit_block: <continue>
                // We allocate after_block BEFORE handler_block so MIR-iteration
                // order matches kotlinc's bytecode layout.
                let try_block = fb.new_block();
                let after_block = fb.new_block();
                let handler_block = fb.new_block();
                let exit_block = fb.new_block();
                fb.terminate_and_switch(Terminator::Goto(try_block), try_block);
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    );
                }
                {
                    let cur = fb.cur_block as usize;
                    let cur_term = &fb.mf.blocks[cur].terminator;
                    if matches!(cur_term, Terminator::ReturnValue(_) | Terminator::Throw(_)) {
                        fb.cur_block = after_block;
                    } else {
                        fb.terminate_and_switch(Terminator::Goto(after_block), after_block);
                    }
                }
                // Normal-path finally first (kotlinc bytecode order).
                for s in &fb_block.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    );
                }
                fb.terminate_and_switch(Terminator::Goto(exit_block), handler_block);
                // Exception-path handler: receives Throwable on stack.
                let exc_local = fb.new_local(Ty::Class("java/lang/Throwable".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: exc_local,
                    value: Rvalue::Const(MirConst::Null),
                });
                for s in &fb_block.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    );
                }
                fb.set_terminator(Terminator::Throw(exc_local));
                fb.mf.exception_handlers.push(ExceptionHandler {
                    try_start_block: try_block,
                    try_end_block: after_block,
                    handler_block,
                    catch_type: None, // null = catch any (Throwable)
                });
                fb.cur_block = exit_block;
            } else {
                // try without catch and without finally — just lower the body.
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    );
                }
            }
            true
        }
        Stmt::ThrowStmt { expr, .. } => {
            // Lower the exception expression and terminate with Throw.
            if let Some(exc_local) = lower_expr(
                expr,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) {
                fb.set_terminator(Terminator::Throw(exc_local));
            }
            true
        }
        Stmt::Destructure { names, init, .. } => {
            // Lower the init expression to get the composite value.
            let Some(init_local) = lower_expr(
                init,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) else {
                return false;
            };
            // Determine the class name from the init local's type.
            // For non-class types (Ty::Any, Ty::Error), fall back to
            // "java/lang/Object" so componentN() calls still compile.
            let init_ty = fb.mf.locals[init_local.0 as usize].clone();
            let class_name = match &init_ty {
                Ty::Class(name) => name.clone(),
                _ => "java/lang/Object".to_string(),
            };
            // For each name at position i, emit a virtual call to component{i+1}().
            for (i, name) in names.iter().enumerate() {
                let method_name = format!("component{}", i + 1);
                // Determine the return type from the class fields.
                let field_ty = module
                    .classes
                    .iter()
                    .find(|c| c.name == class_name)
                    .and_then(|c| c.fields.get(i))
                    .map(|f| f.ty.clone())
                    .unwrap_or(Ty::Any);
                let result = fb.new_local(field_ty);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::Virtual {
                            class_name: class_name.clone(),
                            method_name,
                        },
                        args: vec![init_local],
                    },
                });
                // Each destructuring binding (`val (x, y) = ...`) is a
                // named local — kotlinc materializes them to slots even
                // when their first use is the next instruction.
                fb.mf.named_locals.push(result);
                scope.push((*name, result));
            }
            true
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn lower_val_stmt(
    v: &ValDecl,
    fb: &mut FnBuilder,
    scope: &mut Vec<(Symbol, LocalId)>,
    module: &mut MirModule,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) -> bool {
    // Tell `Expr::ObjectExpr` lowering the target variable name so it
    // can name the anonymous class `Wrapper$Fn$Var$N` (kotlinc style).
    let var_name = interner.resolve(v.name).to_string();
    OBJECT_EXPR_VAR_HINT.with(|cell| *cell.borrow_mut() = Some(var_name));
    let Some(rhs) = lower_expr(
        &v.init,
        fb,
        scope,
        module,
        name_to_func,
        name_to_global,
        interner,
        diags,
        None,
    ) else {
        OBJECT_EXPR_VAR_HINT.with(|cell| *cell.borrow_mut() = None);
        return false;
    };
    OBJECT_EXPR_VAR_HINT.with(|cell| *cell.borrow_mut() = None);
    let rhs_ty = fb.mf.locals[rhs.0 as usize].clone();
    // Respect the nullable annotation when present.  In particular,
    // `val x: String? = "hello"` should give x type Nullable(String),
    // not plain String (the RHS type).  We only use the annotation to
    // add the Nullable wrapper; for everything else (including function
    // types like `(Int) -> Int`) we keep the RHS-inferred type.
    let ty = if let Some(tr) = &v.ty {
        if tr.nullable && tr.func_params.is_none() {
            let base = resolve_type(interner.resolve(tr.name), module);
            Ty::Nullable(Box::new(base))
        } else if tr.nullable {
            // Function-type annotation: wrap the RHS type.
            if matches!(rhs_ty, Ty::Nullable(_)) {
                rhs_ty
            } else {
                Ty::Nullable(Box::new(rhs_ty))
            }
        } else {
            // Narrow integer/float literals to the annotated type.
            // e.g. `val b: Byte = 42` → Ty::Byte, `val s: Short = 1000` → Ty::Short
            // Reference widening: prefer the annotated class type when
            // it differs from the RHS class, so dispatch goes through
            // the declared interface/superclass (kotlinc behaviour).
            let annotated = resolve_type(interner.resolve(tr.name), module);
            match (&annotated, &rhs_ty) {
                (Ty::Byte | Ty::Short, Ty::Int) | (Ty::Float, Ty::Double) => annotated,
                (Ty::Class(target), Ty::Class(actual)) if target != actual => annotated,
                _ => rhs_ty,
            }
        }
    } else {
        rhs_ty
    };
    // Reference widening: if the annotated type is a different class
    // from the RHS class, emit a CheckCast and use the casted local.
    // kotlinc emits `checkcast Greeter` for `val g: Greeter =
    // FormalGreeter()` so subsequent virtual dispatch goes through the
    // interface.
    let actual_rhs_ty = fb.mf.locals[rhs.0 as usize].clone();
    let rhs = if let (Ty::Class(target), Ty::Class(actual)) = (&ty, &actual_rhs_ty) {
        if target != actual {
            let cast = fb.new_local(Ty::Class(target.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: cast,
                value: Rvalue::CheckCast {
                    obj: rhs,
                    target_class: target.clone(),
                },
            });
            cast
        } else {
            rhs
        }
    } else {
        rhs
    };

    // When narrowing from Int→Byte/Short or Double→Float, patch the
    // RHS local's type in-place so backends emit the right opcodes
    // for load/store. This is safe because the RHS local is a
    // freshly-created temporary that is only consumed here.
    if ty != fb.mf.locals[rhs.0 as usize] {
        fb.mf.locals[rhs.0 as usize] = ty.clone();
    }
    // For `val` (immutable), we can reuse the rhs local directly,
    // avoiding an unnecessary copy. For `var`, we must create a fresh
    // local because writes to the var should not affect the rhs source
    // (e.g., `var x = y; x = ...` should not change y).
    let dest = if v.is_var {
        let d = fb.new_local(ty);
        fb.push_stmt(MStmt::Assign {
            dest: d,
            value: Rvalue::Local(rhs),
        });
        d
    } else {
        rhs
    };
    fb.mf.named_locals.push(dest);
    scope.push((v.name, dest));
    if v.is_var {
        fb.var_syms.insert(v.name);
    }
    true
}

/// Try to evaluate an integer constant expression at compile time.
/// Handles integer literals and nested binary arithmetic on integers.
fn try_eval_int(e: &Expr) -> Option<i32> {
    match e {
        Expr::IntLit(v, _) => Some(*v as i32),
        Expr::Binary { op, lhs, rhs, .. } => {
            let l = try_eval_int(lhs)?;
            let r = try_eval_int(rhs)?;
            match op {
                BinOp::Add => Some(l.wrapping_add(r)),
                BinOp::Sub => Some(l.wrapping_sub(r)),
                BinOp::Mul => Some(l.wrapping_mul(r)),
                BinOp::Div if r != 0 => Some(l.wrapping_div(r)),
                BinOp::Mod if r != 0 => Some(l.wrapping_rem(r)),
                _ => None,
            }
        }
        Expr::Unary {
            op: skotch_syntax::UnaryOp::Neg,
            operand,
            ..
        } => {
            let v = try_eval_int(operand)?;
            Some(v.wrapping_neg())
        }
        Expr::Paren(inner, _) => try_eval_int(inner),
        _ => None,
    }
}

/// Try to constant-fold a binary expression with Int operands.
fn try_const_fold_int(lhs: &Expr, rhs: &Expr, op: &BinOp) -> Option<i32> {
    if !matches!(
        op,
        BinOp::Add | BinOp::Sub | BinOp::Mul | BinOp::Div | BinOp::Mod
    ) {
        return None;
    }
    let l = try_eval_int(lhs)?;
    let r = try_eval_int(rhs)?;
    match op {
        BinOp::Add => Some(l.wrapping_add(r)),
        BinOp::Sub => Some(l.wrapping_sub(r)),
        BinOp::Mul => Some(l.wrapping_mul(r)),
        BinOp::Div if r != 0 => Some(l.wrapping_div(r)),
        BinOp::Mod if r != 0 => Some(l.wrapping_rem(r)),
        _ => None,
    }
}

/// Try to evaluate a long constant expression at compile time.
fn try_eval_long(e: &Expr) -> Option<i64> {
    match e {
        Expr::LongLit(v, _) => Some(*v),
        Expr::Binary { op, lhs, rhs, .. } => {
            let l = try_eval_long(lhs)?;
            let r = try_eval_long(rhs)?;
            match op {
                BinOp::Add => Some(l.wrapping_add(r)),
                BinOp::Sub => Some(l.wrapping_sub(r)),
                BinOp::Mul => Some(l.wrapping_mul(r)),
                BinOp::Div if r != 0 => Some(l.wrapping_div(r)),
                BinOp::Mod if r != 0 => Some(l.wrapping_rem(r)),
                _ => None,
            }
        }
        Expr::Paren(inner, _) => try_eval_long(inner),
        _ => None,
    }
}

/// Try to constant-fold a binary expression with Long operands.
fn try_const_fold_long(lhs: &Expr, rhs: &Expr, op: &BinOp) -> Option<i64> {
    if !matches!(
        op,
        BinOp::Add | BinOp::Sub | BinOp::Mul | BinOp::Div | BinOp::Mod
    ) {
        return None;
    }
    // Only fold if at least one operand is a Long literal (otherwise it's an Int expression)
    let has_long = matches!(lhs, Expr::LongLit(..)) || matches!(rhs, Expr::LongLit(..));
    if !has_long {
        return None;
    }
    let l = try_eval_long(lhs)?;
    let r = try_eval_long(rhs)?;
    match op {
        BinOp::Add => Some(l.wrapping_add(r)),
        BinOp::Sub => Some(l.wrapping_sub(r)),
        BinOp::Mul => Some(l.wrapping_mul(r)),
        BinOp::Div if r != 0 => Some(l.wrapping_div(r)),
        BinOp::Mod if r != 0 => Some(l.wrapping_rem(r)),
        _ => None,
    }
}

/// Try to evaluate an expression as a compile-time string constant.
/// Returns the string value if the expression is a constant string,
/// or a string representation of a constant int/long/double/bool.
fn try_eval_string(e: &Expr) -> Option<String> {
    match e {
        Expr::StringLit(s, _) => Some(s.clone()),
        Expr::IntLit(v, _) => Some(v.to_string()),
        Expr::LongLit(v, _) => Some(v.to_string()),
        Expr::DoubleLit(v, _) => Some(format_double_kotlin(*v)),
        Expr::BoolLit(v, _) => Some(v.to_string()),
        Expr::Paren(inner, _) => try_eval_string(inner),
        Expr::Binary { op, lhs, rhs, .. } => {
            // Allow folding of `intExpr + intExpr` etc. inside templates.
            if let Some(v) = try_eval_int(e) {
                return Some(v.to_string());
            }
            if let Some(v) = try_eval_long(e) {
                return Some(v.to_string());
            }
            // String concatenation via +
            if matches!(op, BinOp::Add) {
                let l = try_eval_string(lhs)?;
                let r = try_eval_string(rhs)?;
                return Some(format!("{l}{r}"));
            }
            None
        }
        Expr::Unary { .. } => {
            if let Some(v) = try_eval_int(e) {
                return Some(v.to_string());
            }
            None
        }
        _ => None,
    }
}

/// Format a double the way Kotlin's `toString()` does (e.g., `1.0` not `1`).
fn format_double_kotlin(v: f64) -> String {
    if v.is_nan() {
        return "NaN".to_string();
    }
    if v.is_infinite() {
        return if v > 0.0 {
            "Infinity".to_string()
        } else {
            "-Infinity".to_string()
        };
    }
    if v == v.trunc() && v.abs() < 1e16 {
        // Integer-valued double: kotlin toString prints "1.0"
        return format!("{v:.1}");
    }
    format!("{v}")
}

/// Try to evaluate a string template at compile time. Returns the
/// concatenated string if every part is a compile-time constant.
fn try_const_fold_template(
    parts: &[skotch_syntax::TemplatePart],
    _interner: &Interner,
) -> Option<String> {
    let mut out = String::new();
    for p in parts {
        match p {
            skotch_syntax::TemplatePart::Text(s, _) => out.push_str(s),
            skotch_syntax::TemplatePart::Expr(e) => {
                let s = try_eval_string(e)?;
                out.push_str(&s);
            }
            // Ident references aren't compile-time constants in general.
            skotch_syntax::TemplatePart::IdentRef(..) => return None,
        }
    }
    Some(out)
}

/// Lower an expression and return the local that holds its value.
/// Returns `None` if lowering hit an unsupported construct.
#[allow(clippy::too_many_arguments)]
fn lower_expr(
    e: &Expr,
    fb: &mut FnBuilder,
    scope: &mut Vec<(Symbol, LocalId)>,
    module: &mut MirModule,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    interner: &mut Interner,
    diags: &mut Diagnostics,
    loop_ctx: LoopCtx,
) -> Option<LocalId> {
    match e {
        Expr::IntLit(v, _) => {
            let dest = fb.new_local(Ty::Int);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Int(*v as i32)),
            });
            Some(dest)
        }
        Expr::CharLit(v, _) => {
            // Char literal: store as Ty::Char with the code point value.
            // On JVM this is a 16-bit unsigned value stored in an int local.
            let dest = fb.new_local(Ty::Char);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Int(*v as i32)),
            });
            Some(dest)
        }
        Expr::LongLit(v, _) => {
            let dest = fb.new_local(Ty::Long);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Long(*v)),
            });
            Some(dest)
        }
        Expr::DoubleLit(v, _) => {
            let dest = fb.new_local(Ty::Double);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Double(*v)),
            });
            Some(dest)
        }
        Expr::FloatLit(v, _) => {
            let dest = fb.new_local(Ty::Float);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Float(*v as f32)),
            });
            Some(dest)
        }
        Expr::NullLit(_) => {
            let dest = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Null),
            });
            Some(dest)
        }
        Expr::BoolLit(v, _) => {
            let dest = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::Bool(*v)),
            });
            Some(dest)
        }
        Expr::StringLit(s, _) => {
            let sid = module.intern_string(s);
            let dest = fb.new_local(Ty::String);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::String(sid)),
            });
            Some(dest)
        }
        Expr::Ident(name, _span) => {
            if let Some((_, id)) = scope.iter().rev().find(|(n, _)| *n == *name) {
                let src = *id;
                let ty = fb.mf.locals[src.0 as usize].clone();
                // Auto-dereference $Ref-boxed vars: read .element field.
                if let Ty::Class(ref cls) = ty {
                    if cls.starts_with("$Ref$") {
                        let elem_ty = module
                            .classes
                            .iter()
                            .find(|c| &c.name == cls)
                            .and_then(|c| c.fields.first())
                            .map(|f| f.ty.clone())
                            .unwrap_or(Ty::Error);
                        let dest = fb.new_local(elem_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::GetField {
                                receiver: src,
                                class_name: cls.clone(),
                                field_name: "element".to_string(),
                            },
                        });
                        return Some(dest);
                    }
                }
                // Identity copy elision: when reading a non-mutable val,
                // we can return the source local directly. For vars, the
                // value could change later, so we must copy. This matches
                // kotlinc's behavior of using val values directly from
                // their source slots.
                if !fb.var_syms.contains(name) {
                    let _ = ty;
                    return Some(src);
                }
                let dest = fb.new_local(ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Local(src),
                });
                Some(dest)
            } else if let Some(constant) = name_to_global.get(name) {
                let ty = const_ty(constant);
                let dest = fb.new_local(ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(constant.clone()),
                });
                Some(dest)
            } else if module
                .top_level_prop_names
                .contains(interner.resolve(*name))
            {
                // Non-`const val` top-level property: kotlinc emits a
                // `getstatic <wrapper>.<name>:<descriptor>` rather than
                // inlining the literal.
                let name_str = interner.resolve(*name).to_string();
                let prop = module
                    .top_level_props
                    .iter()
                    .find(|(n, _, _)| n == &name_str)
                    .cloned();
                let ty = prop.as_ref().map(|p| p.1.clone()).unwrap_or(Ty::Any);
                let descriptor = jvm_type_string_for_ty(&ty);
                let class_name = module.wrapper_class.clone();
                let dest = fb.new_local(ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::GetStaticField {
                        class_name,
                        field_name: name_str,
                        descriptor,
                    },
                });
                Some(dest)
            } else if let Some((owner_class, val_ty)) =
                module.cross_file_vals.get(interner.resolve(*name)).cloned()
            {
                // Cross-file top-level val: emit a call to the
                // synthesized `get<Name>()` accessor on the owning
                // wrapper class. kotlinc generates both a static field
                // and a getter; we use the getter for parity.
                let ident_str = interner.resolve(*name).to_string();
                let getter_name =
                    format!("get{}{}", ident_str[..1].to_uppercase(), &ident_str[1..]);
                let descriptor = format!("(){}", jvm_type_string_for_ty(&val_ty));
                let dest = fb.new_local(val_ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: owner_class,
                            method_name: getter_name,
                            descriptor,
                        },
                        args: vec![],
                    },
                });
                Some(dest)
            } else if let Some(jvm_class) = module.import_map.get(interner.resolve(*name)) {
                // Imported class/object reference (e.g. MaterialTheme, Modifier, R)
                // OR an imported enum constant / static field (e.g.
                // `import androidx.compose.material3.DrawerValue.Closed`
                // makes `Closed` resolve to the JVM path
                // `androidx/compose/material3/DrawerValue/Closed`).
                //
                // Detect the static-field case by splitting at the last
                // `/` and asking classinfo whether the prefix is a class
                // that declares this name as a static field. If so, emit
                // a `GetStaticField` of the enum's declared type; this
                // produces `getstatic DrawerValue.Closed:LDrawerValue;`
                // instead of the previous `aconst_null` placeholder that
                // crashed `rememberDrawerState`'s `initialValue.ordinal()`.
                let ident_str = interner.resolve(*name).to_string();
                let static_field = jvm_class.rsplit_once('/').and_then(|(owner, field_name)| {
                    skotch_classinfo::lookup_static_field_descriptor(owner, field_name)
                        .map(|desc| (owner.to_string(), field_name.to_string(), desc))
                });
                if let Some((owner, field_name, desc)) = static_field {
                    let field_ty = ty_from_descriptor_return(&desc);
                    let dest = fb.new_local(field_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::GetStaticField {
                            class_name: owner,
                            field_name,
                            descriptor: desc,
                        },
                    });
                    Some(dest)
                } else if let Some(desc) =
                    skotch_classinfo::lookup_static_field_descriptor(jvm_class, "INSTANCE")
                {
                    // Kotlin `object` singleton: `MaterialTheme` →
                    // getstatic MaterialTheme.INSTANCE:LMaterialTheme;
                    let field_ty = ty_from_descriptor_return(&desc);
                    let dest = fb.new_local(field_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::GetStaticField {
                            class_name: jvm_class.clone(),
                            field_name: "INSTANCE".to_string(),
                            descriptor: desc,
                        },
                    });
                    Some(dest)
                } else if let Some(desc) =
                    skotch_classinfo::lookup_static_field_descriptor(jvm_class, "Companion")
                {
                    // Class/interface with companion object: `Modifier` →
                    // getstatic Modifier.Companion:LModifier$Companion;
                    // The companion field is the conventional access path
                    // for the companion singleton, which IS-A the outer
                    // type when the companion has the right supertype
                    // (e.g. Modifier.Companion : Modifier).
                    let field_ty = ty_from_descriptor_return(&desc);
                    let dest = fb.new_local(field_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::GetStaticField {
                            class_name: jvm_class.clone(),
                            field_name: "Companion".to_string(),
                            descriptor: desc,
                        },
                    });
                    Some(dest)
                } else {
                    let _ = ident_str;
                    let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Const(MirConst::Null), // placeholder — class reference
                    });
                    Some(dest)
                }
            } else if let Some((owner, _desc, ret_ty)) =
                module.cross_file_fns.get(interner.resolve(*name))
            {
                // Cross-file top-level val accessed as a getter call.
                let ret = ret_ty.clone();
                let dest = fb.new_local(ret);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::GetStaticField {
                        class_name: owner.clone(),
                        field_name: interner.resolve(*name).to_string(),
                        descriptor: "Ljava/lang/Object;".to_string(),
                    },
                });
                Some(dest)
            } else {
                // Special case: `this` not in scope — use the function's
                // first parameter, which is `this` for class methods and
                // lambda invoke methods.
                let name_str = interner.resolve(*name);
                if name_str == "this" && !fb.mf.params.is_empty() {
                    let this_local = fb.mf.params[0];
                    let ty = fb.mf.locals[this_local.0 as usize].clone();
                    let dest = fb.new_local(ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Local(this_local),
                    });
                    return Some(dest);
                }
                // Same-file class reference used as a value expression. For
                // a Kotlin `object Foo`, `Foo` evaluates to its INSTANCE
                // singleton; for a class with a `companion object`, the
                // bare class name evaluates to its Companion singleton.
                // Both are static fields on the (outer) class.
                if let Some(cls) = module.classes.iter().find(|c| c.name == name_str) {
                    if cls.is_object_singleton {
                        let desc = format!("L{};", cls.name);
                        let dest = fb.new_local(Ty::Class(cls.name.clone()));
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::GetStaticField {
                                class_name: cls.name.clone(),
                                field_name: "INSTANCE".to_string(),
                                descriptor: desc,
                            },
                        });
                        return Some(dest);
                    }
                    if let Some(comp_class) = &cls.companion_class_name {
                        let desc = format!("L{};", comp_class);
                        let dest = fb.new_local(Ty::Class(comp_class.clone()));
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::GetStaticField {
                                class_name: cls.name.clone(),
                                field_name: "Companion".to_string(),
                                descriptor: desc,
                            },
                        });
                        return Some(dest);
                    }
                }
                // Implicit-`this` instance field: a bare `name` that matches a
                // field of the enclosing class (param[0] = `this`) → `this.name`,
                // typed by the field's declared type. Without this, references to
                // sibling properties inside a property initializer — e.g.
                // `_x.asStateFlow()` where `val x = _x.asStateFlow()` — fall
                // through to the null placeholder below and lose their type (the
                // receiver becomes `Any`, so the call can't resolve). Instance
                // methods don't reach here because their bodies pre-populate
                // `scope` with the fields, so this stays golden-neutral for them.
                if let Some(this_local) = fb.mf.params.first().copied() {
                    if let Ty::Class(this_cls) = fb.mf.locals[this_local.0 as usize].clone() {
                        let field_info = module
                            .classes
                            .iter()
                            .find(|c| c.name == this_cls)
                            .and_then(|c| c.fields.iter().find(|f| f.name == name_str))
                            .map(|f| (f.name.clone(), f.ty.clone()));
                        if let Some((field_name, field_ty)) = field_info {
                            let dest = fb.new_local(field_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::GetField {
                                    receiver: this_local,
                                    class_name: this_cls,
                                    field_name,
                                },
                            });
                            return Some(dest);
                        }
                    }
                }
                // Unknown identifier — emit a null placeholder to avoid cascading errors.
                let dest = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(MirConst::Null),
                });
                Some(dest)
            }
        }
        Expr::Paren(inner, _) => lower_expr(
            inner,
            fb,
            scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
            loop_ctx,
        ),
        Expr::Binary {
            op,
            lhs,
            rhs,
            span: _,
        } => {
            // Short-circuit && and || — these lower to branches.
            if matches!(op, BinOp::And | BinOp::Or) {
                let result = fb.new_local(Ty::Bool);
                let rhs_block = fb.new_block();
                let merge_block = fb.new_block();
                let l = lower_expr(
                    lhs,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )?;
                if *op == BinOp::And {
                    // lhs && rhs: if lhs is false, result = false; else eval rhs
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Const(MirConst::Bool(false)),
                    });
                    fb.terminate_and_switch(
                        Terminator::Branch {
                            cond: l,
                            then_block: rhs_block,
                            else_block: merge_block,
                        },
                        rhs_block,
                    );
                } else {
                    // lhs || rhs: if lhs is true, result = true; else eval rhs
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Const(MirConst::Bool(true)),
                    });
                    fb.terminate_and_switch(
                        Terminator::Branch {
                            cond: l,
                            then_block: merge_block,
                            else_block: rhs_block,
                        },
                        rhs_block,
                    );
                }
                // Smart cast with &&: if lhs is `x is Type`, narrow x
                // in the rhs_block scope (reached only when lhs is true).
                let and_smart_cast = if *op == BinOp::And {
                    if let Expr::IsCheck {
                        expr: checked,
                        type_name,
                        negated: false,
                        ..
                    } = lhs.as_ref()
                    {
                        if let Expr::Ident(var_name, _) = checked.as_ref() {
                            let type_str = interner.resolve(*type_name);
                            let narrowed_ty =
                                skotch_types::ty_from_name(type_str).unwrap_or_else(|| {
                                    if module.classes.iter().any(|c| c.name == type_str) {
                                        Ty::Class(type_str.to_string())
                                    } else {
                                        Ty::Any
                                    }
                                });
                            if let Some((_, old_local)) =
                                scope.iter().rev().find(|(s, _)| s == var_name)
                            {
                                let cast_local = fb.new_local(narrowed_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest: cast_local,
                                    value: Rvalue::Local(*old_local),
                                });
                                scope.push((*var_name, cast_local));
                                1usize
                            } else {
                                0
                            }
                        } else {
                            0
                        }
                    } else {
                        0
                    }
                } else {
                    0
                };
                let r = lower_expr(
                    rhs,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )?;
                // Pop smart cast scope entries from && narrowing.
                for _ in 0..and_smart_cast {
                    scope.pop();
                }
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Local(r),
                });
                fb.terminate_and_switch(Terminator::Goto(merge_block), merge_block);
                return Some(result);
            }

            // ── String-concat chain fusion ─────────────────────────────
            // `"a" + x + ", b=" + y + ", c=" + z` parses as nested
            // `BinOp::Add`. kotlinc collapses the entire chain into a
            // single `invokedynamic makeConcatWithConstants` with one
            // recipe and one arg per dynamic operand. We mirror that:
            // when the outer op is `+` and any operand is a String,
            // walk the chain into a flat list, build a recipe, and
            // emit one `MakeConcatWithConstants` call.
            if matches!(op, BinOp::Add) {
                let mut chain: Vec<&Expr> = Vec::new();
                fn collect_add<'a>(e: &'a Expr, out: &mut Vec<&'a Expr>) {
                    if let Expr::Binary {
                        op: BinOp::Add,
                        lhs,
                        rhs,
                        ..
                    } = e
                    {
                        collect_add(lhs, out);
                        collect_add(rhs, out);
                    } else {
                        out.push(e);
                    }
                }
                collect_add(lhs, &mut chain);
                collect_add(rhs, &mut chain);
                if chain.len() >= 3 {
                    // Heuristic: walk the chain, peek each operand's
                    // shape. If the FIRST operand looks String-like
                    // (literal/template/known-string Ident), commit to
                    // the fused emission.
                    let first_is_stringy = matches!(
                        chain.first(),
                        Some(Expr::StringLit(_, _) | Expr::StringTemplate(_, _))
                    );
                    if first_is_stringy {
                        let mut recipe = String::new();
                        let mut args: Vec<LocalId> = Vec::new();
                        let mut descriptor = String::from("(");
                        let mut recipe_safe = true;
                        for op_expr in &chain {
                            if let Expr::StringLit(s, _) = op_expr {
                                if s.contains('\u{1}') || s.contains('\u{2}') {
                                    recipe_safe = false;
                                    break;
                                }
                                recipe.push_str(s);
                                continue;
                            }
                            let Some(local) = lower_expr(
                                op_expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            ) else {
                                recipe_safe = false;
                                break;
                            };
                            let ty = fb.mf.locals[local.0 as usize].clone();
                            let desc = match &ty {
                                Ty::String => "Ljava/lang/String;".to_string(),
                                Ty::Int | Ty::Byte | Ty::Short | Ty::Char => "I".to_string(),
                                Ty::Long => "J".to_string(),
                                Ty::Float => "F".to_string(),
                                Ty::Double => "D".to_string(),
                                Ty::Bool => "Z".to_string(),
                                _ => {
                                    recipe_safe = false;
                                    break;
                                }
                            };
                            descriptor.push_str(&desc);
                            args.push(local);
                            recipe.push('\u{1}');
                        }
                        if recipe_safe && !args.is_empty() {
                            descriptor.push_str(")Ljava/lang/String;");
                            let dest = fb.new_local(Ty::String);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::MakeConcatWithConstants { recipe, descriptor },
                                    args,
                                },
                            });
                            return Some(dest);
                        }
                    }
                }
            }

            // ── Constant folding for integer arithmetic ──────────────
            // If both operands are compile-time integer constants, evaluate
            // at compile time (matching kotlinc's behavior).
            if let Some(folded) = try_const_fold_int(lhs, rhs, op) {
                let dest = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(MirConst::Int(folded)),
                });
                return Some(dest);
            }
            if let Some(folded) = try_const_fold_long(lhs, rhs, op) {
                let dest = fb.new_local(Ty::Long);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(MirConst::Long(folded)),
                });
                return Some(dest);
            }

            let l = lower_expr(
                lhs,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let r = lower_expr(
                rhs,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let lhs_ty = &fb.mf.locals[l.0 as usize];
            let rhs_ty = &fb.mf.locals[r.0 as usize];

            // ── Operator overloading for class types ────────────────
            // When the LHS is a class instance, check if it has an
            // operator method (plus, minus, times, compareTo) and
            // desugar to a virtual call instead of a primitive op.
            if let Ty::Class(class_name) = lhs_ty {
                let op_method = match op {
                    BinOp::Add => Some("plus"),
                    BinOp::Sub => Some("minus"),
                    BinOp::Mul => Some("times"),
                    BinOp::Div => Some("div"),
                    BinOp::Mod => Some("rem"),
                    BinOp::Lt | BinOp::Gt | BinOp::LtEq | BinOp::GtEq => Some("compareTo"),
                    _ => None,
                };
                if let Some(method_name) = op_method {
                    let mut found: Option<(String, Ty)> = None;
                    let mut search = Some(class_name.clone());
                    while let Some(ref cname) = search {
                        if let Some(cls) = module.classes.iter().find(|c| &c.name == cname) {
                            if let Some(m) = cls.methods.iter().find(|m| m.name == method_name) {
                                found = Some((cname.clone(), m.return_ty.clone()));
                                break;
                            }
                            search = cls.super_class.clone();
                        } else {
                            break;
                        }
                    }
                    if let Some((found_class, ret_ty)) = found {
                        if method_name == "compareTo" {
                            let cmp_result = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: cmp_result,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: found_class,
                                        method_name: "compareTo".to_string(),
                                    },
                                    args: vec![l, r],
                                },
                            });
                            let zero = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: zero,
                                value: Rvalue::Const(MirConst::Int(0)),
                            });
                            let cmp_op = match op {
                                BinOp::Lt => MBinOp::CmpLt,
                                BinOp::Gt => MBinOp::CmpGt,
                                BinOp::LtEq => MBinOp::CmpLe,
                                BinOp::GtEq => MBinOp::CmpGe,
                                _ => unreachable!(),
                            };
                            let dest = fb.new_local(Ty::Bool);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::BinOp {
                                    op: cmp_op,
                                    lhs: cmp_result,
                                    rhs: zero,
                                },
                            });
                            return Some(dest);
                        } else {
                            // Use the method's declared return type when
                            // available; fall back to the receiver's class
                            // type so chained operators (a + b + c) keep the
                            // correct type even when the method stub has not
                            // yet been replaced with the fully-inferred body.
                            let effective_ret = if ret_ty == Ty::Unit {
                                Ty::Class(class_name.clone())
                            } else {
                                ret_ty
                            };
                            let dest = fb.new_local(effective_ret);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: found_class,
                                        method_name: method_name.to_string(),
                                    },
                                    args: vec![l, r],
                                },
                            });
                            return Some(dest);
                        }
                    }
                }
            }

            // Auto-unbox Ty::Any operands for arithmetic: Object → Integer.intValue()
            // Skip when either side is String — that's string concatenation, not arithmetic,
            // and the Any operand is likely a String at runtime.
            let lhs_ty = lhs_ty.clone();
            let rhs_ty = rhs_ty.clone();
            let needs_unbox = matches!(
                op,
                BinOp::Add
                    | BinOp::Sub
                    | BinOp::Mul
                    | BinOp::Div
                    | BinOp::Mod
                    | BinOp::Lt
                    | BinOp::Gt
                    | BinOp::LtEq
                    | BinOp::GtEq
            ) && (matches!(lhs_ty, Ty::Any) || matches!(rhs_ty, Ty::Any))
                && !matches!(lhs_ty, Ty::String)
                && !matches!(rhs_ty, Ty::String);
            let (l, lhs_ty) = if needs_unbox && matches!(lhs_ty, Ty::Any) {
                let unboxed = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: unboxed,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "java/lang/Integer".to_string(),
                            method_name: "intValue".to_string(),
                            descriptor: "()I".to_string(),
                        },
                        args: vec![l],
                    },
                });
                (unboxed, Ty::Int)
            } else {
                (l, lhs_ty)
            };
            let (r, rhs_ty) = if needs_unbox && matches!(rhs_ty, Ty::Any) {
                let unboxed = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: unboxed,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "java/lang/Integer".to_string(),
                            method_name: "intValue".to_string(),
                            descriptor: "()I".to_string(),
                        },
                        args: vec![r],
                    },
                });
                (unboxed, Ty::Int)
            } else {
                (r, rhs_ty)
            };

            let is_double = matches!(lhs_ty, Ty::Double) || matches!(rhs_ty, Ty::Double);
            let is_float =
                !is_double && (matches!(lhs_ty, Ty::Float) || matches!(rhs_ty, Ty::Float));
            let is_long = !is_double
                && !is_float
                && (matches!(lhs_ty, Ty::Long) || matches!(rhs_ty, Ty::Long));
            // Widen Int→Double when comparing/operating with a Double operand.
            let (l, lhs_ty) = if is_double && matches!(lhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Double);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2d".to_string(),
                            descriptor: "(I)D".to_string(),
                        },
                        args: vec![l],
                    },
                });
                (widened, Ty::Double)
            } else {
                (l, lhs_ty)
            };
            let (r, rhs_ty) = if is_double && matches!(rhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Double);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2d".to_string(),
                            descriptor: "(I)D".to_string(),
                        },
                        args: vec![r],
                    },
                });
                (widened, Ty::Double)
            } else {
                (r, rhs_ty)
            };
            // Widen Int→Long when comparing/operating with a Long operand.
            let (l, lhs_ty) = if is_long && matches!(lhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Long);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2l".to_string(),
                            descriptor: "(I)J".to_string(),
                        },
                        args: vec![l],
                    },
                });
                (widened, Ty::Long)
            } else {
                (l, lhs_ty)
            };
            let (r, rhs_ty) = if is_long && matches!(rhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Long);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2l".to_string(),
                            descriptor: "(I)J".to_string(),
                        },
                        args: vec![r],
                    },
                });
                (widened, Ty::Long)
            } else {
                (r, rhs_ty)
            };
            // Widen Int→Float when operating with a Float operand.
            let (l, lhs_ty) = if is_float && matches!(lhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Float);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2f".to_string(),
                            descriptor: "(I)F".to_string(),
                        },
                        args: vec![l],
                    },
                });
                (widened, Ty::Float)
            } else {
                (l, lhs_ty)
            };
            #[allow(unused_variables)]
            let (r, rhs_ty) = if is_float && matches!(rhs_ty, Ty::Int) {
                let widened = fb.new_local(Ty::Float);
                fb.push_stmt(MStmt::Assign {
                    dest: widened,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$convert".to_string(),
                            method_name: "i2f".to_string(),
                            descriptor: "(I)F".to_string(),
                        },
                        args: vec![r],
                    },
                });
                (widened, Ty::Float)
            } else {
                (r, rhs_ty)
            };
            let (mop, result_ty) = match op {
                BinOp::Add if matches!(lhs_ty, Ty::String) || matches!(rhs_ty, Ty::String) => {
                    (MBinOp::ConcatStr, Ty::String)
                }
                BinOp::Add if is_double => (MBinOp::AddD, Ty::Double),
                BinOp::Sub if is_double => (MBinOp::SubD, Ty::Double),
                BinOp::Mul if is_double => (MBinOp::MulD, Ty::Double),
                BinOp::Div if is_double => (MBinOp::DivD, Ty::Double),
                BinOp::Mod if is_double => (MBinOp::ModD, Ty::Double),
                BinOp::Add if is_long => (MBinOp::AddL, Ty::Long),
                BinOp::Sub if is_long => (MBinOp::SubL, Ty::Long),
                BinOp::Mul if is_long => (MBinOp::MulL, Ty::Long),
                BinOp::Div if is_long => (MBinOp::DivL, Ty::Long),
                BinOp::Mod if is_long => (MBinOp::ModL, Ty::Long),
                BinOp::Add if is_float => (MBinOp::AddF, Ty::Float),
                BinOp::Sub if is_float => (MBinOp::SubF, Ty::Float),
                BinOp::Mul if is_float => (MBinOp::MulF, Ty::Float),
                BinOp::Div if is_float => (MBinOp::DivF, Ty::Float),
                BinOp::Mod if is_float => (MBinOp::ModF, Ty::Float),
                BinOp::Add => (MBinOp::AddI, Ty::Int),
                BinOp::Sub => (MBinOp::SubI, Ty::Int),
                BinOp::Mul => (MBinOp::MulI, Ty::Int),
                BinOp::Div => (MBinOp::DivI, Ty::Int),
                BinOp::Mod => (MBinOp::ModI, Ty::Int),
                BinOp::Eq => (MBinOp::CmpEq, Ty::Bool),
                BinOp::NotEq => (MBinOp::CmpNe, Ty::Bool),
                BinOp::Lt => (MBinOp::CmpLt, Ty::Bool),
                BinOp::Gt => (MBinOp::CmpGt, Ty::Bool),
                BinOp::LtEq => (MBinOp::CmpLe, Ty::Bool),
                BinOp::GtEq => (MBinOp::CmpGe, Ty::Bool),
                BinOp::And | BinOp::Or => unreachable!("handled above"),
            };
            let dest = fb.new_local(result_ty);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::BinOp {
                    op: mop,
                    lhs: l,
                    rhs: r,
                },
            });
            Some(dest)
        }
        Expr::If {
            cond,
            then_block,
            else_block,
            ..
        } => {
            // Constant-fold `if (boolean_literal) ... else ...`. kotlinc
            // emits only the chosen branch with no Branch terminator and
            // no StackMapTable, which we mirror here to keep parity.
            if let Expr::BoolLit(b, _) = cond.as_ref() {
                let chosen: Option<&skotch_syntax::Block> = if *b {
                    Some(then_block.as_ref())
                } else {
                    else_block.as_ref().map(|bx| bx.as_ref())
                };
                if let Some(blk) = chosen {
                    let mut last_val: Option<LocalId> = None;
                    for s in &blk.stmts {
                        match s {
                            skotch_syntax::Stmt::Expr(e) => {
                                last_val = lower_expr(
                                    e,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                );
                            }
                            _ => {
                                let _ = lower_stmt(
                                    s,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                );
                            }
                        }
                    }
                    return last_val.or_else(|| {
                        let dest = fb.new_local(Ty::Unit);
                        Some(dest)
                    });
                }
                let dest = fb.new_local(Ty::Unit);
                return Some(dest);
            }

            // ── Multi-block lowering for if-as-expression ────────
            //
            // 1. Lower the condition in the current block
            // 2. Create then, else, and merge blocks
            // 3. Terminate current block with Branch
            // 4. Lower then branch → writes result to shared local → Goto merge
            // 5. Lower else branch (if present) → writes result → Goto merge
            // 6. Merge block becomes the new current block
            //
            // The shared result local is pre-allocated here. Both
            // branches write to it via `Rvalue::Local(their_val)`.
            // The merge block can read it directly.

            let cond_local = lower_expr(
                cond,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;

            let then_blk = fb.new_block();
            let else_blk = fb.new_block();
            let merge_blk = fb.new_block();

            // The result local's type is inferred from the then-branch
            // after lowering it. We use a placeholder here that gets
            // replaced once the then-branch produces a value.
            // For now, start with Ty::Int as default (overridden below).
            let result = fb.new_local(Ty::Int); // type may be patched

            fb.terminate_and_switch(
                Terminator::Branch {
                    cond: cond_local,
                    then_block: then_blk,
                    else_block: else_blk,
                },
                then_blk,
            );

            // Smart cast: if cond is `x is Type`, narrow x's type in then-branch.
            // Create a new local with the narrowed type and rebind x in scope.
            let smart_cast_count = if let Expr::Binary {
                op: BinOp::NotEq,
                lhs,
                rhs,
                ..
            } = cond.as_ref()
            {
                // Null-check smart cast: `x != null` → narrow x from T? to T.
                if let (Expr::Ident(var_name, _), Expr::NullLit(_))
                | (Expr::NullLit(_), Expr::Ident(var_name, _)) = (lhs.as_ref(), rhs.as_ref())
                {
                    if let Some((_, old_local)) = scope.iter().rev().find(|(s, _)| s == var_name) {
                        let old_ty = fb.mf.locals[old_local.0 as usize].clone();
                        let narrowed = if let Ty::Nullable(inner) = old_ty {
                            *inner
                        } else {
                            old_ty
                        };
                        let cast_local = fb.new_local(narrowed);
                        fb.push_stmt(MStmt::Assign {
                            dest: cast_local,
                            value: Rvalue::Local(*old_local),
                        });
                        scope.push((*var_name, cast_local));
                        1
                    } else {
                        0
                    }
                } else {
                    0
                }
            } else {
                // Check for IsCheck directly, or IsCheck as LHS of &&.
                let is_check_info: Option<(&Expr, Symbol)> = if let Expr::IsCheck {
                    expr: checked,
                    type_name,
                    negated: false,
                    ..
                } = cond.as_ref()
                {
                    Some((checked.as_ref(), *type_name))
                } else if let Expr::Binary {
                    op: BinOp::And,
                    lhs: and_lhs,
                    ..
                } = cond.as_ref()
                {
                    if let Expr::IsCheck {
                        expr: checked,
                        type_name,
                        negated: false,
                        ..
                    } = and_lhs.as_ref()
                    {
                        Some((checked.as_ref(), *type_name))
                    } else {
                        None
                    }
                } else {
                    None
                };
                if let Some((Expr::Ident(var_name, _), type_name)) = is_check_info {
                    let type_str = interner.resolve(type_name);
                    let narrowed_ty = skotch_types::ty_from_name(type_str).unwrap_or_else(|| {
                        // Check same-file user classes first…
                        if module.classes.iter().any(|c| c.name == type_str) {
                            Ty::Class(type_str.to_string())
                        }
                        // …then file-level imports (parser strips the
                        // module path; `import a.b.Foo` lands in
                        // `module.import_map` as `Foo -> a/b/Foo`).
                        // Without this, `if (x is Bar)` where Bar is
                        // an imported class narrows to `Ty::Any` and
                        // the smart-cast loses all useful information.
                        else if let Some(fq) = module.import_map.get(type_str) {
                            Ty::Class(fq.clone())
                        } else {
                            Ty::Any
                        }
                    });
                    // Find the variable's current local.
                    if let Some((_, old_local)) = scope.iter().rev().find(|(s, _)| s == var_name) {
                        // Create a new local with the narrowed type.
                        let cast_local = fb.new_local(narrowed_ty);
                        // Emit a copy from old to new (identity cast for now).
                        fb.push_stmt(MStmt::Assign {
                            dest: cast_local,
                            value: Rvalue::Local(*old_local),
                        });
                        // Push new binding that shadows the original.
                        scope.push((*var_name, cast_local));
                        1
                    } else {
                        0
                    }
                } else {
                    0
                }
            };

            // Then branch.
            let mut then_val: Option<LocalId> = None;
            let mut then_terminates = false;
            for s in &then_block.stmts {
                match s {
                    skotch_syntax::Stmt::Expr(e) => {
                        then_val = lower_expr(
                            e,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                    skotch_syntax::Stmt::Return { .. } => {
                        let _ = lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        then_terminates = true;
                    }
                    skotch_syntax::Stmt::Break { .. } | skotch_syntax::Stmt::Continue { .. } => {
                        let _ = lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        then_terminates = true;
                    }
                    _ => {
                        let _ = lower_stmt(
                            s,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                }
            }
            // Remove smart cast scope entry.
            for _ in 0..smart_cast_count {
                scope.pop();
            }
            // Check if the block already terminated (throw expression,
            // return expression, etc.) — don't overwrite with Goto.
            let already_terminated = matches!(
                fb.mf.blocks[fb.cur_block as usize].terminator,
                Terminator::Throw(_) | Terminator::ReturnValue(_)
            );
            // Only skip result assignment for Throw — the val from
            // Expr::Throw is an uninitialized Nothing local (aload of
            // Top triggers VerifyError). ReturnValue blocks still need
            // their preceding assignments for coroutine state machines.
            let throw_terminated = matches!(
                fb.mf.blocks[fb.cur_block as usize].terminator,
                Terminator::Throw(_)
            );
            if let Some(val) = then_val {
                if !throw_terminated {
                    let inferred_ty = fb.mf.locals[val.0 as usize].clone();
                    fb.mf.locals[result.0 as usize] = inferred_ty;
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(val),
                    });
                }
            }
            if then_terminates || already_terminated {
                fb.cur_block = else_blk;
            } else {
                fb.terminate_and_switch(Terminator::Goto(merge_blk), else_blk);
            }

            // Else branch.
            let mut else_terminates = false;
            if let Some(eb) = else_block {
                for s in &eb.stmts {
                    match s {
                        skotch_syntax::Stmt::Expr(e) => {
                            if let Some(val) = lower_expr(
                                e,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            ) {
                                // Guard: don't assign result from a
                                // throw expression (uninitialized Nothing local).
                                let blk_term = &fb.mf.blocks[fb.cur_block as usize].terminator;
                                let dead = matches!(blk_term, Terminator::Throw(_));
                                if !dead {
                                    fb.push_stmt(MStmt::Assign {
                                        dest: result,
                                        value: Rvalue::Local(val),
                                    });
                                }
                            }
                        }
                        skotch_syntax::Stmt::Return { .. }
                        | skotch_syntax::Stmt::Break { .. }
                        | skotch_syntax::Stmt::Continue { .. } => {
                            let _ = lower_stmt(
                                s,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                            else_terminates = true;
                        }
                        _ => {
                            let _ = lower_stmt(
                                s,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        }
                    }
                }
            }
            let else_already_terminated = matches!(
                fb.mf.blocks[fb.cur_block as usize].terminator,
                Terminator::Throw(_) | Terminator::ReturnValue(_)
            );
            // For if-without-else, the else branch reaches the merge block
            // without assigning to `result`. The JVM verifier then sees an
            // uninitialized local read by the merge's return — emitted as
            // `areturn` with empty stack. Assign null so both paths produce
            // a value.
            if else_block.is_none() && !else_terminates && !else_already_terminated {
                let null_local = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: null_local,
                    value: Rvalue::Const(MirConst::Null),
                });
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Local(null_local),
                });
            }
            if else_terminates || else_already_terminated {
                fb.cur_block = merge_blk;
            } else {
                fb.terminate_and_switch(Terminator::Goto(merge_blk), merge_blk);
            }

            Some(result)
        }
        Expr::Call {
            callee,
            args,
            type_args,
            span,
        } => {
            // Handle method calls on a receiver: `receiver.method(args)`
            if let Expr::Field { receiver, name, .. } = callee.as_ref() {
                let method_name = *name;

                // Check for enum static methods: Color.values(), Color.valueOf("RED").
                if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                    let recv_name = interner.resolve(*recv_sym).to_string();
                    if module.enum_names.contains(&recv_name) {
                        let method_str = interner.resolve(method_name).to_string();
                        if method_str == "values" || method_str == "valueOf" {
                            let compound = format!("{}${}", recv_name, method_str);
                            let compound_sym = interner.intern(&compound);
                            if let Some(&fid) = name_to_func.get(&compound_sym) {
                                let ret_ty = module.functions[fid.0 as usize].return_ty.clone();
                                let mut arg_locals = Vec::new();
                                for a in args {
                                    let id = lower_expr(
                                        &a.expr,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    )?;
                                    arg_locals.push(id);
                                }
                                let dest = fb.new_local(ret_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::Static(fid),
                                        args: arg_locals,
                                    },
                                });
                                return Some(dest);
                            }
                        }
                    }
                }

                // Object singleton method call: `ObjectName.method(args)`.
                // Emits `getstatic ObjectName.INSTANCE; invokevirtual
                // ObjectName.method(args)`. This is the kotlinc shape
                // for `object X { fun y() }` calls.
                //
                // Companion object method call: `OuterClass.method(args)`
                // where `OuterClass` has a `companion object { fun method }`.
                // Emits `getstatic OuterClass.Companion; invokevirtual
                // OuterClass$Companion.method(args)`.
                if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                    let recv_name = interner.resolve(*recv_sym).to_string();
                    let method_str = interner.resolve(method_name).to_string();
                    let singleton_match: Option<(String, Ty)> = module
                        .classes
                        .iter()
                        .find(|c| c.is_object_singleton && c.name == recv_name)
                        .and_then(|c| {
                            c.methods
                                .iter()
                                .find(|m| m.name == method_str)
                                .map(|m| (c.name.clone(), m.return_ty.clone()))
                        });
                    if let Some((class_name, ret_ty)) = singleton_match {
                        let instance_local = fb.new_local(Ty::Class(class_name.clone()));
                        fb.push_stmt(MStmt::Assign {
                            dest: instance_local,
                            value: Rvalue::GetStaticField {
                                class_name: class_name.clone(),
                                field_name: "INSTANCE".to_string(),
                                descriptor: format!("L{};", class_name),
                            },
                        });
                        let mut arg_locals = vec![instance_local];
                        for a in args {
                            let id = lower_expr(
                                &a.expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            )?;
                            arg_locals.push(id);
                        }
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name,
                                    method_name: method_str,
                                },
                                args: arg_locals,
                            },
                        });
                        return Some(dest);
                    }
                    // Companion-object dispatch: receiver is an outer
                    // class name and the method lives on its companion.
                    // In-module classes are stored by simple name
                    // (`ContentMainBinding`); cross-file stubs by full
                    // JVM name (`com/.../ContentMainBinding`). Match
                    // either form so this fires for both call kinds.
                    let companion_match: Option<(String, String, Ty)> = module
                        .classes
                        .iter()
                        .find(|c| {
                            c.companion_class_name.is_some()
                                && (c.name == recv_name
                                    || c.name.rsplit('/').next() == Some(recv_name.as_str()))
                        })
                        .and_then(|outer| {
                            let comp_name = outer.companion_class_name.clone().unwrap();
                            let comp = module.classes.iter().find(|c| c.name == comp_name)?;
                            let m = comp.methods.iter().find(|m| m.name == method_str)?;
                            Some((outer.name.clone(), comp_name, m.return_ty.clone()))
                        });
                    if let Some((outer_name, comp_name, ret_ty)) = companion_match {
                        let instance_local = fb.new_local(Ty::Class(comp_name.clone()));
                        fb.push_stmt(MStmt::Assign {
                            dest: instance_local,
                            value: Rvalue::GetStaticField {
                                class_name: outer_name,
                                field_name: "Companion".to_string(),
                                descriptor: format!("L{};", comp_name),
                            },
                        });
                        let mut arg_locals = vec![instance_local];
                        for a in args {
                            let id = lower_expr(
                                &a.expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            )?;
                            arg_locals.push(id);
                        }
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: comp_name,
                                    method_name: method_str,
                                },
                                args: arg_locals,
                            },
                        });
                        return Some(dest);
                    }
                }

                // Check if this is an object method call (Singleton.method())
                // or an extension function call (receiver.extFun()).
                // Object methods and extension functions are registered as
                // top-level functions. Extension functions have params.len() > args.len()
                // because the receiver is the first param.
                if let Some(&fid) = name_to_func.get(&method_name) {
                    let target = &module.functions[fid.0 as usize];
                    let ret_ty = target.return_ty.clone();
                    let is_extension = target.params.len() == args.len() + 1;
                    let mut arg_locals = Vec::new();
                    if is_extension {
                        // Extension function: lower the receiver and pass
                        // it as the first argument.
                        let recv_local = lower_expr(
                            receiver,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )?;
                        arg_locals.push(recv_local);
                    }
                    for a in args {
                        let id = lower_expr(
                            &a.expr,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )?;
                        arg_locals.push(id);
                    }
                    let dest = fb.new_local(ret_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Static(fid),
                            args: arg_locals,
                        },
                    });
                    return Some(dest);
                }

                // Check if the receiver is a known Java class name for static calls.
                if let Some(static_call) = try_java_static_call(
                    receiver,
                    method_name,
                    args,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                ) {
                    return Some(static_call);
                }

                // Check for enum dispatch functions. When an enum has
                // abstract methods, the lowerer registers dispatch
                // functions as "EnumName$methodName". We detect this
                // for chains like `Op.PLUS.apply(3, 2)` by extracting
                // the class name from the receiver field access.
                {
                    let method_str = interner.resolve(method_name).to_string();
                    // Try to determine the enum class name from the
                    // receiver. For `Op.PLUS.apply()`, the receiver is
                    // `Field { Ident("Op"), "PLUS" }`. Check if the
                    // receiver's outermost ident is an enum class.
                    let enum_class = if let Expr::Field {
                        receiver: inner_recv,
                        ..
                    } = receiver.as_ref()
                    {
                        if let Expr::Ident(sym, _) = inner_recv.as_ref() {
                            let name = interner.resolve(*sym).to_string();
                            if module.enum_names.contains(&name) {
                                Some(name)
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    } else if let Expr::Ident(sym, _) = receiver.as_ref() {
                        // `op.apply()` where op is a local variable —
                        // look up its type from scope.
                        let found = scope
                            .iter()
                            .rev()
                            .find(|(s, _)| s == sym)
                            .map(|(_, lid)| &fb.mf.locals[lid.0 as usize]);
                        if let Some(Ty::Class(cname)) = found {
                            if module.enum_names.contains(cname.as_str()) {
                                Some(cname.clone())
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    } else {
                        None
                    };
                    if let Some(cls_name) = enum_class {
                        let dispatch_name = format!("{}${}", cls_name, method_str);
                        let dispatch_sym = interner.intern(&dispatch_name);
                        if let Some(&fid) = name_to_func.get(&dispatch_sym) {
                            // Lower the receiver (the enum instance)
                            let recv_local = lower_expr(
                                receiver,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            )?;
                            let mut all_args = vec![recv_local];
                            for a in args {
                                let id = lower_expr(
                                    &a.expr,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                )?;
                                all_args.push(id);
                            }
                            let ret_ty = module.functions[fid.0 as usize].return_ty.clone();
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::Static(fid),
                                    args: all_args,
                                },
                            });
                            return Some(dest);
                        }
                    }
                }

                // Check for nested class constructor: `Outer.Nested(args)`.
                // The parser sees this as receiver=Ident("Outer"),
                // name="Nested". We look for a MirClass named "Outer$Nested".
                if let Some(qname) = extract_qualified_name(receiver, interner) {
                    let method_str = interner.resolve(method_name).to_string();
                    let nested_class_name = format!("{}${}", qname, method_str);
                    let is_nested = module.classes.iter().any(|c| c.name == nested_class_name);
                    if is_nested {
                        let mut arg_locals = Vec::new();
                        for a in args {
                            let id = lower_expr(
                                &a.expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            )?;
                            arg_locals.push(id);
                        }
                        let dest = fb.new_local(Ty::Class(nested_class_name.clone()));
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::NewInstance(nested_class_name.clone()),
                        });
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Constructor(nested_class_name),
                                args: arg_locals,
                            },
                        });
                        return Some(dest);
                    }
                }

                // Inner class construction: `outer.Inner(args)` where `outer`
                // is an instance variable. Resolve as `new Outer$Inner(outer, args)`.
                {
                    let method_str = interner.resolve(method_name).to_string();
                    // Check if receiver is a local variable with a class type.
                    if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                        if let Some((_, recv_local)) =
                            scope.iter().rev().find(|(s, _)| s == recv_sym)
                        {
                            let recv_ty = fb.mf.locals[recv_local.0 as usize].clone();
                            if let Ty::Class(ref outer_class) = recv_ty {
                                let inner_class_name = format!("{}${}", outer_class, method_str);
                                let is_inner =
                                    module.classes.iter().any(|c| c.name == inner_class_name);
                                if is_inner {
                                    let mut arg_locals = vec![*recv_local]; // outer ref
                                    for a in args {
                                        let id = lower_expr(
                                            &a.expr,
                                            fb,
                                            scope,
                                            module,
                                            name_to_func,
                                            name_to_global,
                                            interner,
                                            diags,
                                            loop_ctx,
                                        )?;
                                        arg_locals.push(id);
                                    }
                                    let dest = fb.new_local(Ty::Class(inner_class_name.clone()));
                                    fb.push_stmt(MStmt::Assign {
                                        dest,
                                        value: Rvalue::NewInstance(inner_class_name.clone()),
                                    });
                                    fb.push_stmt(MStmt::Assign {
                                        dest,
                                        value: Rvalue::Call {
                                            kind: CallKind::Constructor(inner_class_name),
                                            args: arg_locals,
                                        },
                                    });
                                    return Some(dest);
                                }
                            }
                        }
                    }
                }

                // If try_java_static_call returned None, check if the
                // "receiver.method" is actually a fully-qualified
                // constructor: `java.net.URI()` → receiver="java.net",
                // method="URI" → class="java/net/URI", call <init>.
                if let Some(qname) = extract_qualified_name(receiver, interner) {
                    let method_str = interner.resolve(method_name).to_string();

                    if method_str.starts_with(|c: char| c.is_uppercase()) && qname.contains('.') {
                        let full_class = format!("{qname}.{method_str}");
                        let jvm_class = full_class.replace('.', "/");
                        if let Ok(_info) = skotch_classinfo::load_jdk_class(&jvm_class) {
                            let mut arg_locals = Vec::new();
                            for a in args {
                                let id = lower_expr(
                                    &a.expr,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                )?;
                                arg_locals.push(id);
                            }
                            let dest = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::NewInstance(jvm_class.clone()),
                            });
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::Constructor(jvm_class),
                                    args: arg_locals,
                                },
                            });
                            return Some(dest);
                        }
                    }

                    if qname.starts_with(|c: char| c.is_uppercase()) || qname.contains('.') {
                        // Lower args first (for side effects), then return a
                        // null placeholder. This keeps compilation going for
                        // the rest of the function body.
                        for a in args {
                            let _ = lower_expr(
                                &a.expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        }
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        return Some(dest);
                    }
                }

                // Check for super.method() BEFORE lowering the receiver.
                {
                    let super_sym = interner.intern("super");
                    if let Expr::Ident(ident_name, _) = receiver.as_ref() {
                        if *ident_name == super_sym {
                            let this_sym = interner.intern("this");
                            // Extract parent class name and return type without
                            // holding an immutable borrow across lower_expr.
                            let super_info: Option<(LocalId, String, String, Ty)> = scope
                                .iter()
                                .rev()
                                .find(|(s, _)| *s == this_sym)
                                .and_then(|(_, this_local)| {
                                    let this_ty = &fb.mf.locals[this_local.0 as usize];
                                    if let Ty::Class(cn) = this_ty {
                                        let cls = module.classes.iter().find(|c| &c.name == cn)?;
                                        let parent = cls.super_class.as_ref()?.clone();
                                        let mname = interner.resolve(method_name).to_string();
                                        let mut ret_ty = Ty::Unit;
                                        let mut found = false;
                                        let mut search = Some(parent.clone());
                                        while let Some(ref cname) = search {
                                            if let Some(pcls) =
                                                module.classes.iter().find(|c| &c.name == cname)
                                            {
                                                if let Some(m) =
                                                    pcls.methods.iter().find(|m| m.name == mname)
                                                {
                                                    ret_ty = m.return_ty.clone();
                                                    found = true;
                                                    break;
                                                }
                                                search = pcls.super_class.clone();
                                            } else {
                                                break;
                                            }
                                        }
                                        // Fallback: parent class is external
                                        // (Android SDK / JDK). Resolve the
                                        // method descriptor via classinfo —
                                        // without this, `super.foo()` on a
                                        // foreign supertype loses its return
                                        // type and the call becomes `()V`,
                                        // breaking `||`/boolean chains and
                                        // any expression that consumes the
                                        // result.
                                        if !found {
                                            // Probe a small range of arg
                                            // counts (overloads). user args
                                            // = args.len(); receiver `this`
                                            // is implicit.
                                            let user_argc = args.len();
                                            if let Some(d) =
                                                skotch_classinfo::lookup_method_descriptor(
                                                    &parent, &mname, user_argc,
                                                )
                                            {
                                                ret_ty = ty_from_descriptor_return(&d);
                                            }
                                        }
                                        Some((*this_local, parent, mname, ret_ty))
                                    } else {
                                        None
                                    }
                                });
                            if let Some((this_local, parent, mname, ret_ty)) = super_info {
                                let mut all_args = vec![this_local];
                                for a in args {
                                    let id = lower_expr(
                                        &a.expr,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    )?;
                                    all_args.push(id);
                                }
                                let dest = fb.new_local(ret_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::Super {
                                            class_name: parent,
                                            method_name: mname,
                                        },
                                        args: all_args,
                                    },
                                });
                                return Some(dest);
                            }
                        }
                    }
                }

                // Lower the receiver as the first argument (instance method or extension).
                let recv_local = lower_expr(
                    receiver,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )?;
                let recv_ty = fb.mf.locals[recv_local.0 as usize].clone();
                let method_name_str = interner.resolve(method_name).to_string();

                // For value scope functions (apply, run, also, let),
                // set the receiver type so the lambda body can bind
                // `this` to the receiver for implicit dispatch.
                if intrinsics::is_value_scope_fn(method_name_str.as_str()) {
                    if let Ty::Class(ref cn) = recv_ty {
                        module.lambda_receiver_type = Some(cn.clone());
                    }
                }

                // For `.let`, `.also`, `.takeIf`, `.takeUnless`, the
                // implicit `it` parameter is the receiver itself.
                // Propagate the receiver's nominal type so the lambda
                // body's references to `it.<field>` / `it.<method>`
                // resolve correctly. `.apply` and `.run` bind the
                // receiver as `this`, not `it`, so they get the
                // receiver-type channel above but not this one.
                //
                // Common JetChat pattern (Profile.kt):
                //   `userData.timeZone?.let { ProfileProperty(it) }`
                // — `it` here is `String` (the type of `timeZone`)
                // and the call site for `ProfileProperty(it)` needs
                // that to type-check.
                if intrinsics::scope_fn_binds_it(method_name_str.as_str()) {
                    // Strip the outer `Nullable` wrapper if the
                    // receiver is `T?` — inside the safe-call lambda
                    // body, `it` has been null-narrowed to `T`.
                    let it_ty = intrinsics::strip_nullable(&recv_ty);
                    if !matches!(it_ty, Ty::Any | Ty::Error | Ty::Unit) {
                        module.lambda_param_type = Some(it_ty);
                    }
                }

                // For collection methods that take a `(T) -> R` lambda,
                // propagate the receiver's element type to the lambda's
                // `it` parameter so `list.filter { it.foo }` correctly
                // resolves `.foo` against the element class. Without
                // this, the lambda's `it` falls back to `Ty::Any` and
                // any member access on it gets silently dropped during
                // MIR lowering (the source bug behind task #319).
                //
                // `Iterable<T>`-style methods: lambda is `(T) -> R`.
                // `Map<K,V>`-style methods: lambda is `(Map.Entry<K,V>) -> R`
                // (we don't yet model Map.Entry — leave as a follow-up).
                if intrinsics::is_iterable_t_lambda_method(method_name_str.as_str()) {
                    // Element type may be recorded in the receiver's
                    // `Ty::Generic` args OR in the side-channel
                    // `local_generic_args` map (used when the local's
                    // nominal type stays as the erased class so
                    // downstream pattern matches keep working). Prefer
                    // the Generic form, fall back to the side channel.
                    let element_ty = recv_ty.generic_args().first().cloned().or_else(|| {
                        fb.mf
                            .local_generic_args
                            .get(&recv_local.0)
                            .and_then(|args| args.first().cloned())
                    });
                    if let Some(elem) = element_ty {
                        if !matches!(elem, Ty::Any) {
                            module.lambda_param_type = Some(elem);
                        }
                    }
                }

                let mut all_args = vec![recv_local];
                for a in args {
                    let id = lower_expr(
                        &a.expr,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    all_args.push(id);
                }
                module.lambda_receiver_type = None; // clear after use
                module.lambda_param_type = None; // clear after use

                // ── data class copy() with default-fill ──────────
                // `p.copy(y = 3)` fills unspecified params from receiver fields.
                if method_name_str == "copy" {
                    if let Ty::Class(ref class_name) = recv_ty {
                        // Clone fields to release the borrow on `module`.
                        let copy_fields: Option<Vec<_>> = module
                            .classes
                            .iter()
                            .find(|c| &c.name == class_name)
                            .filter(|cls| {
                                cls.methods.iter().any(|m| m.name == "copy")
                                    && !cls.fields.is_empty()
                            })
                            .map(|cls| {
                                cls.fields
                                    .iter()
                                    .map(|f| (f.name.clone(), f.ty.clone()))
                                    .collect()
                            });
                        if let Some(fields_info) = copy_fields {
                            let mut copy_args = vec![recv_local]; // this
                            for (fname, fty) in &fields_info {
                                // Check if there's a named arg for this field.
                                let named_arg_expr = args
                                    .iter()
                                    .find(|a| a.name.is_some_and(|n| interner.resolve(n) == fname));
                                let val = if let Some(a) = named_arg_expr {
                                    lower_expr(
                                        &a.expr,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    )?
                                } else {
                                    // Load default from receiver.
                                    let fv = fb.new_local(fty.clone());
                                    fb.push_stmt(MStmt::Assign {
                                        dest: fv,
                                        value: Rvalue::GetField {
                                            receiver: recv_local,
                                            class_name: class_name.clone(),
                                            field_name: fname.clone(),
                                        },
                                    });
                                    fv
                                };
                                copy_args.push(val);
                            }
                            let dest = fb.new_local(Ty::Class(class_name.clone()));
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: class_name.clone(),
                                        method_name: "copy".to_string(),
                                    },
                                    args: copy_args,
                                },
                            });
                            return Some(dest);
                        }
                    }
                }

                // ── Infix `to`: `a to b` → `Pair(a, b)` ─────────
                if method_name_str == "to" && args.len() == 1 {
                    let a = recv_local;
                    let b = all_args[1]; // all_args = [receiver, arg]
                    let a_ty = fb.mf.locals[a.0 as usize].clone();
                    let b_ty = fb.mf.locals[b.0 as usize].clone();
                    let a_boxed = mir_autobox(fb, a, &a_ty);
                    let b_boxed = mir_autobox(fb, b, &b_ty);
                    let dest = fb.new_local(Ty::Class("kotlin/Pair".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::NewInstance("kotlin/Pair".to_string()),
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::ConstructorJava {
                                class_name: "kotlin/Pair".to_string(),
                                descriptor: "(Ljava/lang/Object;Ljava/lang/Object;)V".to_string(),
                            },
                            args: vec![a_boxed, b_boxed],
                        },
                    });
                    return Some(dest);
                }

                // ── Int.rangeTo(Int) → new IntRange(start, end) ─────
                if method_name_str == "rangeTo" && args.len() == 1 {
                    let start = recv_local;
                    let end = all_args[1];
                    let dest = fb.new_local(Ty::Class("kotlin/ranges/IntRange".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::NewInstance("kotlin/ranges/IntRange".to_string()),
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::ConstructorJava {
                                class_name: "kotlin/ranges/IntRange".to_string(),
                                descriptor: "(II)V".to_string(),
                            },
                            args: vec![start, end],
                        },
                    });
                    return Some(dest);
                }

                // ── IntRange.contains(Int) → boolean check ──────────
                if method_name_str == "contains"
                    && args.len() == 1
                    && matches!(&recv_ty, Ty::Class(n) if n.contains("IntRange"))
                {
                    let dest = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlin/ranges/IntRange".to_string(),
                                method_name: "contains".to_string(),
                                descriptor: "(I)Z".to_string(),
                            },
                            args: all_args,
                        },
                    });
                    return Some(dest);
                }

                // ── Scope functions (let, also, run, apply) ─────────
                // Lowered as inline intrinsics: the trailing lambda arg
                // is invoked with the receiver, and the result depends
                // on the scope function semantics.
                if intrinsics::is_value_scope_fn(method_name_str.as_str()) && args.len() == 1 {
                    // The single argument should be a lambda.
                    let lambda_local = all_args.last().copied().unwrap();
                    let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                    let is_lambda = is_lambda_or_function_ty(&lambda_ty, module)
                        || matches!(lambda_ty, Ty::Any);
                    if is_lambda {
                        // Invoke the lambda with the receiver as its argument.
                        let invoke_class = match &lambda_ty {
                            Ty::Class(cn) => cn.clone(),
                            Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                            _ => "java/lang/Object".to_string(),
                        };
                        let invoke_ret = lambda_invoke_return_ty(&lambda_ty, module);

                        // Widen the receiver arg to Ty::Any for the erased
                        // invoke signature, and autobox primitives.
                        let recv_arg = {
                            let recv_arg_ty = fb.mf.locals[recv_local.0 as usize].clone();
                            match recv_arg_ty {
                                Ty::Int => {
                                    let boxed = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: boxed,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: "java/lang/Integer".to_string(),
                                                method_name: "valueOf".to_string(),
                                                descriptor: "(I)Ljava/lang/Integer;".to_string(),
                                            },
                                            args: vec![recv_local],
                                        },
                                    });
                                    boxed
                                }
                                Ty::Any => recv_local,
                                _ => {
                                    // Reference type — widen to Ty::Any.
                                    let widened = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: widened,
                                        value: Rvalue::Local(recv_local),
                                    });
                                    widened
                                }
                            }
                        };
                        let call_args = vec![lambda_local, recv_arg];
                        let call_result = fb.new_local(invoke_ret.clone());
                        fb.push_stmt(MStmt::Assign {
                            dest: call_result,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: invoke_class,
                                    method_name: "invoke".to_string(),
                                },
                                args: call_args,
                            },
                        });

                        // `apply`/`also` return the original receiver;
                        // `run`/`let` return the lambda's result.
                        // (Predicates are excluded by is_value_scope_fn.)
                        let returns_receiver = intrinsics::scope_fn(method_name_str.as_str())
                            .is_some_and(intrinsics::ScopeFn::returns_receiver);
                        return if returns_receiver {
                            Some(recv_local)
                        } else {
                            Some(call_result)
                        };
                    }
                }

                // ── `.use { block }` — try-with-resources ──────────
                // Simplified desugaring (no exception handler — just inline
                // the lambda body and call close() afterward):
                //   val result = block(resource)
                //   resource.close()
                //   result
                // Full exception-safe version would need try-finally, but
                // this covers the common case and avoids StackMapTable
                // complexity for exception handlers.
                if method_name_str == "use" && args.len() == 1 {
                    let lambda_local = all_args.last().copied().unwrap();
                    let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                    let is_lambda = is_lambda_or_function_ty(&lambda_ty, module)
                        || matches!(lambda_ty, Ty::Any);
                    if is_lambda {
                        // Invoke the lambda with the resource as argument.
                        let invoke_class = match &lambda_ty {
                            Ty::Class(cn) => cn.clone(),
                            Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                            _ => "java/lang/Object".to_string(),
                        };
                        let invoke_ret = lambda_invoke_return_ty(&lambda_ty, module);

                        // Check if the lambda takes a parameter (Function1)
                        // or is parameterless (Function0).
                        let lambda_param_count = if let Ty::Class(ref cn) = lambda_ty {
                            module
                                .classes
                                .iter()
                                .find(|c| &c.name == cn)
                                .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                                .map(|m| m.params.len().saturating_sub(1)) // subtract `this`
                                .unwrap_or(0)
                        } else {
                            0
                        };

                        let call_args = if lambda_param_count > 0 {
                            // Function1: invoke(receiver)
                            let recv_arg = {
                                let recv_arg_ty = fb.mf.locals[recv_local.0 as usize].clone();
                                if matches!(recv_arg_ty, Ty::Int | Ty::Long | Ty::Double | Ty::Bool)
                                {
                                    mir_autobox(fb, recv_local, &recv_arg_ty)
                                } else if matches!(recv_arg_ty, Ty::Any) {
                                    recv_local
                                } else {
                                    let widened = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: widened,
                                        value: Rvalue::Local(recv_local),
                                    });
                                    widened
                                }
                            };
                            vec![lambda_local, recv_arg]
                        } else {
                            // Function0: invoke() — no receiver arg
                            vec![lambda_local]
                        };
                        let call_result = fb.new_local(invoke_ret);
                        fb.push_stmt(MStmt::Assign {
                            dest: call_result,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: invoke_class,
                                    method_name: "invoke".to_string(),
                                },
                                args: call_args,
                            },
                        });

                        // Call resource.close() after the lambda.
                        // Use the receiver's actual class for dispatch.
                        let close_class = match &recv_ty {
                            Ty::Class(cn) => cn.clone(),
                            _ => "java/lang/AutoCloseable".to_string(),
                        };
                        // Check if close() is on the receiver's own class
                        // (user-defined) or needs to go through an interface.
                        let has_own_close = module.classes.iter().any(|c| {
                            c.name == close_class && c.methods.iter().any(|m| m.name == "close")
                        });
                        let close_result = fb.new_local(Ty::Unit);
                        if has_own_close {
                            fb.push_stmt(MStmt::Assign {
                                dest: close_result,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: close_class,
                                        method_name: "close".to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                        } else {
                            fb.push_stmt(MStmt::Assign {
                                dest: close_result,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "java/lang/AutoCloseable".to_string(),
                                        method_name: "close".to_string(),
                                        descriptor: "()V".to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                        }

                        return Some(call_result);
                    }
                }

                // ── `.forEach { }` on ArrayList/List collections ──────
                if method_name_str == "forEach"
                    && args.len() == 1
                    && matches!(&recv_ty, Ty::Class(n) if n.contains("ArrayList") || n.contains("List"))
                {
                    let lambda_local = all_args[1]; // all_args = [receiver, lambda]
                    let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                    if is_lambda_or_function_ty(&lambda_ty, module) {
                        let cn = match &lambda_ty {
                            Ty::Class(n) => n.clone(),
                            Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                            _ => unreachable!(),
                        };
                        // val iter = collection.iterator()
                        let iter_local = fb.new_local(Ty::Class("java/util/Iterator".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: iter_local,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Iterable".to_string(),
                                    method_name: "iterator".to_string(),
                                    descriptor: "()Ljava/util/Iterator;".to_string(),
                                },
                                args: vec![recv_local],
                            },
                        });
                        // while (iter.hasNext())
                        let cond_blk = fb.new_block();
                        let body_blk = fb.new_block();
                        let exit_blk = fb.new_block();
                        fb.terminate_and_switch(Terminator::Goto(cond_blk), cond_blk);
                        let has_next = fb.new_local(Ty::Bool);
                        fb.push_stmt(MStmt::Assign {
                            dest: has_next,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/util/Iterator".to_string(),
                                    method_name: "hasNext".to_string(),
                                    descriptor: "()Z".to_string(),
                                },
                                args: vec![iter_local],
                            },
                        });
                        fb.terminate_and_switch(
                            Terminator::Branch {
                                cond: has_next,
                                then_block: body_blk,
                                else_block: exit_blk,
                            },
                            body_blk,
                        );
                        // val element = iter.next()
                        let element_obj = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest: element_obj,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/util/Iterator".to_string(),
                                    method_name: "next".to_string(),
                                    descriptor: "()Ljava/lang/Object;".to_string(),
                                },
                                args: vec![iter_local],
                            },
                        });
                        // Look up the lambda's invoke param type. If it's a
                        // primitive, unbox the Object returned by next() so the
                        // invokevirtual descriptor matches the real method.
                        let invoke_param_ty = module
                            .classes
                            .iter()
                            .find(|c| c.name == cn)
                            .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                            .and_then(|m| m.params.get(1)) // skip `this`
                            .map(|p| {
                                module
                                    .classes
                                    .iter()
                                    .find(|c| c.name == cn)
                                    .unwrap()
                                    .methods
                                    .iter()
                                    .find(|m| m.name == "invoke")
                                    .unwrap()
                                    .locals[p.0 as usize]
                                    .clone()
                            })
                            .unwrap_or(Ty::Any);
                        let element = match &invoke_param_ty {
                            Ty::Int => {
                                let unboxed = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: unboxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::VirtualJava {
                                            class_name: "java/lang/Integer".to_string(),
                                            method_name: "intValue".to_string(),
                                            descriptor: "()I".to_string(),
                                        },
                                        args: vec![element_obj],
                                    },
                                });
                                unboxed
                            }
                            Ty::Long => {
                                let unboxed = fb.new_local(Ty::Long);
                                fb.push_stmt(MStmt::Assign {
                                    dest: unboxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::VirtualJava {
                                            class_name: "java/lang/Long".to_string(),
                                            method_name: "longValue".to_string(),
                                            descriptor: "()J".to_string(),
                                        },
                                        args: vec![element_obj],
                                    },
                                });
                                unboxed
                            }
                            Ty::Double => {
                                let unboxed = fb.new_local(Ty::Double);
                                fb.push_stmt(MStmt::Assign {
                                    dest: unboxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::VirtualJava {
                                            class_name: "java/lang/Double".to_string(),
                                            method_name: "doubleValue".to_string(),
                                            descriptor: "()D".to_string(),
                                        },
                                        args: vec![element_obj],
                                    },
                                });
                                unboxed
                            }
                            Ty::Bool => {
                                let unboxed = fb.new_local(Ty::Bool);
                                fb.push_stmt(MStmt::Assign {
                                    dest: unboxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::VirtualJava {
                                            class_name: "java/lang/Boolean".to_string(),
                                            method_name: "booleanValue".to_string(),
                                            descriptor: "()Z".to_string(),
                                        },
                                        args: vec![element_obj],
                                    },
                                });
                                unboxed
                            }
                            // For String, Any, Class, etc. — pass the Object
                            // directly without unboxing.
                            _ => element_obj,
                        };
                        // lambda.invoke(element)
                        let _call_result = fb.new_local(Ty::Unit);
                        fb.push_stmt(MStmt::Assign {
                            dest: _call_result,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: cn,
                                    method_name: "invoke".to_string(),
                                },
                                args: vec![lambda_local, element],
                            },
                        });
                        fb.terminate_and_switch(Terminator::Goto(cond_blk), exit_blk);
                        let result = fb.new_local(Ty::Unit);
                        return Some(result);
                    }
                }

                // ── MutableList .add() / .remove() / .removeAt() / .clear() ───
                if matches!(&recv_ty, Ty::Class(cn) if cn.contains("ArrayList") || cn.contains("List"))
                {
                    let list_method: Option<(&str, &str, &str, Ty)> =
                        match (method_name_str.as_str(), args.len()) {
                            ("add", 1) => {
                                // Autobox the argument before passing to add(Object).
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some(("java/util/List", "add", "(Ljava/lang/Object;)Z", Ty::Bool))
                            }
                            ("remove", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/List",
                                    "remove",
                                    "(Ljava/lang/Object;)Z",
                                    Ty::Bool,
                                ))
                            }
                            ("removeAt", 1) => {
                                Some(("java/util/List", "remove", "(I)Ljava/lang/Object;", Ty::Any))
                            }
                            ("clear", 0) => Some(("java/util/List", "clear", "()V", Ty::Unit)),
                            ("get", 1) => {
                                Some(("java/util/List", "get", "(I)Ljava/lang/Object;", Ty::Any))
                            }
                            ("contains", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/List",
                                    "contains",
                                    "(Ljava/lang/Object;)Z",
                                    Ty::Bool,
                                ))
                            }
                            _ => None,
                        };
                    if let Some((jvm_class, jvm_method, descriptor, ret_ty)) = list_method {
                        // When the receiver is a concrete class (e.g.
                        // ArrayList) rather than the generic List
                        // interface, dispatch on the concrete class —
                        // kotlinc emits `invokevirtual ArrayList.add`
                        // not `invokeinterface List.add`.
                        let dispatch_class = if let Ty::Class(cn) = &recv_ty {
                            if cn.contains("ArrayList") {
                                cn.clone()
                            } else {
                                jvm_class.to_string()
                            }
                        } else {
                            jvm_class.to_string()
                        };
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: dispatch_class,
                                    method_name: jvm_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                // ── Map .containsKey() / .get() / .put() / .remove() ───
                if matches!(&recv_ty, Ty::Class(cn) if cn.contains("Map")) {
                    let map_method: Option<(&str, &str, &str, Ty)> =
                        match (method_name_str.as_str(), args.len()) {
                            ("containsKey", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/Map",
                                    "containsKey",
                                    "(Ljava/lang/Object;)Z",
                                    Ty::Bool,
                                ))
                            }
                            ("containsValue", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/Map",
                                    "containsValue",
                                    "(Ljava/lang/Object;)Z",
                                    Ty::Bool,
                                ))
                            }
                            ("get", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/Map",
                                    "get",
                                    "(Ljava/lang/Object;)Ljava/lang/Object;",
                                    Ty::Any,
                                ))
                            }
                            ("put", 2) => {
                                let k = all_args[1];
                                let k_ty = fb.mf.locals[k.0 as usize].clone();
                                all_args[1] = mir_autobox(fb, k, &k_ty);
                                let v = all_args[2];
                                let v_ty = fb.mf.locals[v.0 as usize].clone();
                                all_args[2] = mir_autobox(fb, v, &v_ty);
                                Some((
                                    "java/util/Map",
                                    "put",
                                    "(Ljava/lang/Object;Ljava/lang/Object;)Ljava/lang/Object;",
                                    Ty::Any,
                                ))
                            }
                            ("remove", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/Map",
                                    "remove",
                                    "(Ljava/lang/Object;)Ljava/lang/Object;",
                                    Ty::Any,
                                ))
                            }
                            ("isEmpty", 0) => Some(("java/util/Map", "isEmpty", "()Z", Ty::Bool)),
                            ("clear", 0) => Some(("java/util/Map", "clear", "()V", Ty::Unit)),
                            _ => None,
                        };
                    if let Some((jvm_class, jvm_method, descriptor, ret_ty)) = map_method {
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: jvm_class.to_string(),
                                    method_name: jvm_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                // ── Set .contains() / .add() / .remove() / .isEmpty() ───
                if matches!(&recv_ty, Ty::Class(cn) if cn.contains("Set")) {
                    let set_method: Option<(&str, &str, &str, Ty)> =
                        match (method_name_str.as_str(), args.len()) {
                            ("contains", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some((
                                    "java/util/Set",
                                    "contains",
                                    "(Ljava/lang/Object;)Z",
                                    Ty::Bool,
                                ))
                            }
                            ("add", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some(("java/util/Set", "add", "(Ljava/lang/Object;)Z", Ty::Bool))
                            }
                            ("remove", 1) => {
                                let arg = all_args[1];
                                let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                                let boxed = mir_autobox(fb, arg, &arg_ty);
                                all_args[1] = boxed;
                                Some(("java/util/Set", "remove", "(Ljava/lang/Object;)Z", Ty::Bool))
                            }
                            ("isEmpty", 0) => Some(("java/util/Set", "isEmpty", "()Z", Ty::Bool)),
                            ("clear", 0) => Some(("java/util/Set", "clear", "()V", Ty::Unit)),
                            _ => None,
                        };
                    if let Some((jvm_class, jvm_method, descriptor, ret_ty)) = set_method {
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: jvm_class.to_string(),
                                    method_name: jvm_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                // ── Pair .toString() — on kotlin/Pair instances ─────
                if matches!(&recv_ty, Ty::Class(cn) if cn == "kotlin/Pair")
                    && method_name_str == "toString"
                {
                    let dest = fb.new_local(Ty::String);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlin/Pair".to_string(),
                                method_name: "toString".to_string(),
                                descriptor: "()Ljava/lang/String;".to_string(),
                            },
                            args: all_args,
                        },
                    });
                    return Some(dest);
                }

                // ── Kotlin stdlib extension functions ─────────────────
                // Extension functions like `List.map {}` are compiled as
                // static methods in `*Kt` facade classes. The receiver
                // becomes the first argument and lambdas must implement
                // `kotlin/jvm/functions/FunctionN`.
                {
                    let recv_ty_str = match &recv_ty {
                        Ty::Class(cn) => cn.as_str(),
                        Ty::String => "java/lang/String",
                        Ty::Int => "java/lang/Integer",
                        Ty::Any => "java/lang/Object",
                        _ => "",
                    };
                    // Try static table first. Dynamic discovery is
                    // deferred until after Java instance method lookup
                    // to avoid shadowing String.substring, String.trim, etc.
                    // Prefer the arity-matching overload (e.g. `none()`
                    // vs `none(predicate)`) so 1-arg calls don't pick
                    // the 2-arg descriptor and trip d8 with "desc expects 2,
                    // got 1 args".
                    let arity = all_args.len();
                    let ext_result = skotch_stdlib_registry::lookup_stdlib_extension_arity(
                        recv_ty_str,
                        &method_name_str,
                        arity,
                    )
                    .map(|ext| {
                        (
                            ext.facade_class.to_string(),
                            ext.jvm_method.to_string(),
                            ext.descriptor.to_string(),
                            (ext.return_ty)(),
                        )
                    })
                    .or_else(|| {
                        stdlib_extension(recv_ty_str, &method_name_str)
                            .map(|(a, b, c, d)| (a.to_string(), b.to_string(), c.to_string(), d))
                    });
                    if let Some((facade_class, facade_method, descriptor, ret_ty)) = ext_result {
                        // For `fold`, the second arg (initial accumulator,
                        // index 1 in all_args) is `Object` on the JVM so
                        // any primitive must be boxed.
                        if facade_method == "fold" && all_args.len() > 1 {
                            let init = all_args[1];
                            let init_ty = fb.mf.locals[init.0 as usize].clone();
                            all_args[1] = mir_autobox(fb, init, &init_ty);
                        }
                        // joinToString$default needs all 9 params even when
                        // the user only supplies the separator.  Cast the
                        // String separator to CharSequence, pad nulls for
                        // prefix/postfix/truncated/transform, 0 for limit,
                        // set the bitmask, and add the trailing marker null.
                        if facade_method == "joinToString$default" {
                            // all_args[0] = receiver (Iterable)
                            // all_args[1] = separator (user-supplied String)
                            // Cast separator to CharSequence descriptor match
                            // (no-op on JVM, types are compatible)

                            // Build full arg list:
                            //   Iterable, CharSequence, CharSequence, CharSequence, int, CharSequence, Function1, int, Object
                            let receiver = all_args[0];
                            let separator = if all_args.len() > 1 {
                                all_args[1]
                            } else {
                                // default separator ", "
                                let sid = module.intern_string(", ");
                                let s = fb.new_local(Ty::String);
                                fb.push_stmt(MStmt::Assign {
                                    dest: s,
                                    value: Rvalue::Const(MirConst::String(sid)),
                                });
                                s
                            };
                            let null_cs = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                            fb.push_stmt(MStmt::Assign {
                                dest: null_cs,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            let null_cs2 = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                            fb.push_stmt(MStmt::Assign {
                                dest: null_cs2,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            let zero = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: zero,
                                value: Rvalue::Const(MirConst::Int(0)),
                            });
                            let null_cs3 = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                            fb.push_stmt(MStmt::Assign {
                                dest: null_cs3,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            let null_fn = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                            fb.push_stmt(MStmt::Assign {
                                dest: null_fn,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            // Bitmask: 62 = 0b111110 — all params except separator use defaults
                            let bitmask = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: bitmask,
                                value: Rvalue::Const(MirConst::Int(62)),
                            });
                            let null_marker = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                            fb.push_stmt(MStmt::Assign {
                                dest: null_marker,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            all_args = vec![
                                receiver,
                                separator,
                                null_cs,
                                null_cs2,
                                zero,
                                null_cs3,
                                null_fn,
                                bitmask,
                                null_marker,
                            ];
                        }
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: facade_class.to_string(),
                                    method_name: facade_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                // Check if receiver is a class instance for virtual dispatch.

                // Override table for methods with ambiguous JVM overloads.
                // These need explicit descriptors because the JVM class has
                // multiple overloads that can't be distinguished by arg count.
                // Disambiguation table for JVM methods with multiple overloads
                // that share the same argument count. These cases can't be
                // resolved by class-file lookup alone without full type
                // inference on the argument expressions.
                // `s.repeat(n)` is a Kotlin stdlib extension on
                // `CharSequence` — kotlinc compiles it to
                // `StringsKt.repeat(s as CharSequence, n)`.
                // `<String>.isEmpty()` is `inline fun CharSequence.isEmpty()
                // : Boolean = length == 0` — kotlinc inlines as:
                //   aload s
                //   checkcast CharSequence
                //   invokeinterface CharSequence.length()
                //   ifne <skip>; iconst_1; goto <end>; <skip>: iconst_0
                if matches!(&recv_ty, Ty::String) && method_name_str == "isEmpty" && args.is_empty()
                {
                    let recv = all_args[0];
                    // Cast s to CharSequence.
                    let cast_local = fb.new_local(Ty::Class("java/lang/CharSequence".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: cast_local,
                        value: Rvalue::CheckCast {
                            obj: recv,
                            target_class: "java/lang/CharSequence".to_string(),
                        },
                    });
                    // Call CharSequence.length() via invokeinterface.
                    let length_local = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: length_local,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/CharSequence".to_string(),
                                method_name: "length".to_string(),
                                descriptor: "()I".to_string(),
                            },
                            args: vec![cast_local],
                        },
                    });
                    // length == 0 → Bool result.
                    let zero_local = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: zero_local,
                        value: Rvalue::Const(MirConst::Int(0)),
                    });
                    let dest = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpEq,
                            lhs: length_local,
                            rhs: zero_local,
                        },
                    });
                    return Some(dest);
                }

                if matches!(&recv_ty, Ty::String) && method_name_str == "repeat" && args.len() == 1
                {
                    let dest = fb.new_local(Ty::String);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlin/text/StringsKt".to_string(),
                                method_name: "repeat".to_string(),
                                descriptor: "(Ljava/lang/CharSequence;I)Ljava/lang/String;"
                                    .to_string(),
                            },
                            args: all_args,
                        },
                    });
                    return Some(dest);
                }
                // `s.startsWith("prefix")` is a Kotlin stdlib extension
                // that compiles to `StringsKt.startsWith$default(s,
                // prefix, ignoreCase=false, defaultMask=2, handler=null)`.
                // Match kotlinc's routing here.
                if matches!(&recv_ty, Ty::String)
                    && method_name_str == "startsWith"
                    && args.len() == 1
                {
                    let zero_local = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: zero_local,
                        value: Rvalue::Const(MirConst::Bool(false)),
                    });
                    let mask_local = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: mask_local,
                        value: Rvalue::Const(MirConst::Int(2)),
                    });
                    let null_local = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest: null_local,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    let mut full_args = all_args.clone();
                    full_args.push(zero_local);
                    full_args.push(mask_local);
                    full_args.push(null_local);
                    let dest = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlin/text/StringsKt".to_string(),
                                method_name: "startsWith$default".to_string(),
                                descriptor:
                                    "(Ljava/lang/String;Ljava/lang/String;ZILjava/lang/Object;)Z"
                                        .to_string(),
                            },
                            args: full_args,
                        },
                    });
                    return Some(dest);
                }
                // String method overload disambiguation (from registry).
                let overload_override: Option<(&str, &str, &str, Ty)> =
                    if matches!(&recv_ty, Ty::String) {
                        skotch_stdlib_registry::lookup_string_overload(&method_name_str, args.len())
                            .map(|o| (o.jvm_class, o.jvm_method, o.descriptor, (o.return_ty)()))
                    } else {
                        None
                    };
                if let Some((jvm_class, jvm_method, descriptor, ret_ty)) = overload_override {
                    let is_instance = !matches!(
                        &recv_ty,
                        Ty::Int | Ty::Long | Ty::Float | Ty::Double | Ty::Bool
                    );
                    let dest = fb.new_local(ret_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: if is_instance {
                                CallKind::VirtualJava {
                                    class_name: jvm_class.to_string(),
                                    method_name: jvm_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                }
                            } else {
                                CallKind::StaticJava {
                                    class_name: jvm_class.to_string(),
                                    method_name: jvm_method.to_string(),
                                    descriptor: descriptor.to_string(),
                                }
                            },
                            args: all_args,
                        },
                    });
                    return Some(dest);
                }

                // ── `deferred.await()` ─────────────────
                //
                // `Deferred.await()` is a suspend function on the
                // `kotlinx/coroutines/Deferred` interface. At the JVM
                // level it becomes:
                //   aload <deferred>
                //   aload <continuation>
                //   invokeinterface Deferred.await(Continuation)Object
                //
                // This is a suspension point — it may return
                // COROUTINE_SUSPENDED. We emit it as
                // a VirtualJava call; the JVM backend recognizes
                // `Deferred` as an interface and emits `invokeinterface`.
                if method_name_str == "await"
                    && args.is_empty()
                    && matches!(&recv_ty, Ty::Class(cn) if cn == "kotlinx/coroutines/Deferred")
                {
                    // The continuation is the enclosing suspend fn's
                    // $completion or, for suspend lambdas, `this`.
                    let cont_local = if fb.mf.is_suspend {
                        *fb.mf
                            .params
                            .last()
                            .expect("suspend fn must have $completion")
                    } else {
                        let c =
                            fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: c,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        c
                    };
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlinx/coroutines/Deferred".to_string(),
                                method_name: "await".to_string(),
                                descriptor: "(Lkotlin/coroutines/Continuation;)Ljava/lang/Object;"
                                    .to_string(),
                            },
                            args: vec![recv_local, cont_local],
                        },
                    });
                    return Some(dest);
                }

                // ── `job.join()` ────────────────────────
                //
                // `Job.join()` is a suspend function on the
                // `kotlinx/coroutines/Job` interface. At JVM level:
                //   aload <job>
                //   aload <continuation>
                //   invokeinterface Job.join(Continuation)V
                //
                // It returns Unit (void), but on JVM it's Object because
                // the CPS transform erases the return type.
                if method_name_str == "join"
                    && args.is_empty()
                    && matches!(&recv_ty, Ty::Class(cn) if cn == "kotlinx/coroutines/Job")
                {
                    let cont_local = if fb.mf.is_suspend {
                        *fb.mf
                            .params
                            .last()
                            .expect("suspend fn must have $completion")
                    } else {
                        let c =
                            fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: c,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        c
                    };
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlinx/coroutines/Job".to_string(),
                                method_name: "join".to_string(),
                                descriptor: "(Lkotlin/coroutines/Continuation;)Ljava/lang/Object;"
                                    .to_string(),
                            },
                            args: vec![recv_local, cont_local],
                        },
                    });
                    return Some(dest);
                }

                // ── `job.cancel()` ──────────────────────
                //
                // `Job.cancel()` is a non-suspend function on Job.
                // It cancels the job (non-blocking).
                if method_name_str == "cancel"
                    && args.is_empty()
                    && matches!(&recv_ty, Ty::Class(cn) if cn == "kotlinx/coroutines/Job"
                        || cn == "kotlinx/coroutines/Deferred")
                {
                    let dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlinx/coroutines/Job".to_string(),
                                method_name: "cancel".to_string(),
                                descriptor: "()V".to_string(),
                            },
                            args: vec![recv_local],
                        },
                    });
                    return Some(dest);
                }

                // ── `job.isActive` property ─────────────
                //
                // `Job.isActive` is a property (getter: isActive()Z).
                if method_name_str == "isActive"
                    && args.is_empty()
                    && matches!(&recv_ty, Ty::Class(cn) if cn == "kotlinx/coroutines/Job"
                        || cn == "kotlinx/coroutines/Deferred")
                {
                    let dest = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "kotlinx/coroutines/Job".to_string(),
                                method_name: "isActive".to_string(),
                                descriptor: "()Z".to_string(),
                            },
                            args: vec![recv_local],
                        },
                    });
                    return Some(dest);
                }

                // Resolve methods dynamically from JDK class files.
                let class_name_buf;
                let jvm_class_for_ty = match &recv_ty {
                    Ty::String => Some("java/lang/String"),
                    Ty::Int => Some("java/lang/Integer"),
                    Ty::Long => Some("java/lang/Long"),
                    Ty::Float => Some("java/lang/Float"),
                    Ty::Double => Some("java/lang/Double"),
                    Ty::Bool => Some("java/lang/Boolean"),
                    Ty::Class(cn) if cn.contains('/') => {
                        class_name_buf = cn.clone();
                        Some(class_name_buf.as_str())
                    }
                    _ => None,
                };

                // Kotlin extension functions map to JVM method names.
                // These are stable ABI translations documented by JetBrains.
                let jvm_method_name = match (method_name_str.as_str(), jvm_class_for_ty) {
                    ("uppercase", Some("java/lang/String")) => "toUpperCase",
                    ("lowercase", Some("java/lang/String")) => "toLowerCase",
                    ("get", Some("java/lang/String")) => "charAt",
                    ("toInt", Some("java/lang/String")) => "parseInt__on__java/lang/Integer",
                    ("toDouble", Some("java/lang/String")) => "parseDouble__on__java/lang/Double",
                    ("toLong", Some("java/lang/String")) => "parseLong__on__java/lang/Long",
                    ("toFloat", Some("java/lang/String")) => "parseFloat__on__java/lang/Float",
                    // Kotlin compiles `<primitive>.toString()` to
                    // `String.valueOf(<primitive>)` for parity with Java.
                    ("toString", Some("java/lang/Integer")) => "valueOf__on__java/lang/String",
                    ("toString", Some("java/lang/Long")) => "valueOf__on__java/lang/String",
                    ("toString", Some("java/lang/Float")) => "valueOf__on__java/lang/String",
                    ("toString", Some("java/lang/Double")) => "valueOf__on__java/lang/String",
                    ("toString", Some("java/lang/Boolean")) => "valueOf__on__java/lang/String",
                    _ => method_name_str.as_str(),
                };

                // Handle cross-class redirections (e.g., String.toInt() → Integer.parseInt)
                let (effective_class, effective_method) =
                    if let Some(pos) = jvm_method_name.find("__on__") {
                        let method = &jvm_method_name[..pos];
                        let class = &jvm_method_name[pos + 6..];
                        (Some(class), method)
                    } else {
                        (jvm_class_for_ty, jvm_method_name)
                    };

                // Constant-fold `<literal>.toString()` — kotlinc emits a
                // literal `ldc "<value>"` rather than calling
                // `String.valueOf(...)` when the receiver is a literal in
                // the source. Skip when the receiver is a named local
                // (val/var) since kotlinc keeps the runtime call there.
                if args.is_empty()
                    && method_name_str == "toString"
                    && !fb.mf.named_locals.contains(&recv_local)
                {
                    let folded: Option<String> = (|| {
                        let last_stmt = fb.mf.blocks[fb.cur_block as usize].stmts.last()?;
                        let MStmt::Assign { dest: d, value } = last_stmt;
                        if d.0 != recv_local.0 {
                            return None;
                        }
                        let Rvalue::Const(c) = value else { return None };
                        match c {
                            MirConst::Int(v) => Some(v.to_string()),
                            MirConst::Long(v) => Some(v.to_string()),
                            MirConst::Bool(v) => Some(v.to_string()),
                            // Doubles/floats use Kotlin's special formatter, skip.
                            _ => None,
                        }
                    })();
                    if let Some(s) = folded {
                        let sid = module.intern_string(&s);
                        let dest = fb.new_local(Ty::String);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::String(sid)),
                        });
                        return Some(dest);
                    }
                }

                // Primitive type conversion methods: toInt(), toDouble(), toLong(), toChar()
                if args.is_empty() {
                    let conversion: Option<(Ty, &str)> = match (method_name_str.as_str(), &recv_ty)
                    {
                        ("toDouble", Ty::Int) => Some((Ty::Double, "i2d")),
                        ("toDouble", Ty::Long) => Some((Ty::Double, "l2d")),
                        ("toLong", Ty::Int) => Some((Ty::Long, "i2l")),
                        ("toLong", Ty::Double) => Some((Ty::Long, "d2l")),
                        ("toInt", Ty::Double) => Some((Ty::Int, "d2i")),
                        ("toInt", Ty::Long) => Some((Ty::Int, "l2i")),
                        ("toInt", Ty::Float) => Some((Ty::Int, "f2i")),
                        ("toInt", Ty::Char) => Some((Ty::Int, "nop")),
                        ("toChar", Ty::Int) => Some((Ty::Char, "i2c")),
                        ("toLong", Ty::Float) => Some((Ty::Long, "f2l")),
                        ("toDouble", Ty::Float) => Some((Ty::Double, "f2d")),
                        ("toFloat", Ty::Int) => Some((Ty::Float, "i2f")),
                        ("toFloat", Ty::Long) => Some((Ty::Float, "l2f")),
                        ("toFloat", Ty::Double) => Some((Ty::Float, "d2f")),
                        ("toFloat", Ty::Float) => Some((Ty::Float, "nop")),
                        _ => None,
                    };
                    if let Some((ret_ty, opcode_name)) = conversion {
                        // Constant fold when the receiver is a literal —
                        // kotlinc emits the converted value directly
                        // (e.g. `42.toDouble()` → `ldc2_w double(42)`).
                        // Skip when the receiver is a named local
                        // (val/var); kotlinc keeps the runtime conversion.
                        let folded: Option<MirConst> = if fb.mf.named_locals.contains(&recv_local) {
                            None
                        } else {
                            (|| {
                                let last_stmt = fb.mf.blocks[fb.cur_block as usize].stmts.last()?;
                                let MStmt::Assign { dest: d, value } = last_stmt;
                                if d.0 != recv_local.0 {
                                    return None;
                                }
                                let Rvalue::Const(c) = value else { return None };
                                match (c, opcode_name) {
                                    (MirConst::Int(v), "i2d") => Some(MirConst::Double(*v as f64)),
                                    (MirConst::Int(v), "i2l") => Some(MirConst::Long(*v as i64)),
                                    (MirConst::Int(v), "i2c") => Some(MirConst::Int(*v & 0xFFFF)),
                                    (MirConst::Long(v), "l2i") => Some(MirConst::Int(*v as i32)),
                                    (MirConst::Long(v), "l2d") => Some(MirConst::Double(*v as f64)),
                                    (MirConst::Double(v), "d2i") => Some(MirConst::Int(*v as i32)),
                                    (MirConst::Double(v), "d2l") => Some(MirConst::Long(*v as i64)),
                                    _ => None,
                                }
                            })()
                        };
                        let dest = fb.new_local(ret_ty);
                        if let Some(folded_const) = folded {
                            // Replace the receiver's Const stmt by
                            // reassigning the dest directly. The original
                            // receiver Const becomes dead and is skipped
                            // by the unused-locals pass.
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Const(folded_const),
                            });
                        } else if opcode_name == "nop" {
                            // Identity conversion — just copy.
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Local(recv_local),
                            });
                        } else {
                            // JVM type conversion opcode — emitted as a
                            // special StaticJava call that the backend
                            // recognizes. The descriptor must match the
                            // opcode's (src)ret JVM signature so
                            // `has_null_stubs_why` doesn't flag an
                            // arg/param mismatch and stub the whole method.
                            let convert_desc = match opcode_name {
                                "i2d" => "(I)D",
                                "i2l" => "(I)J",
                                "i2c" => "(I)C",
                                "i2f" => "(I)F",
                                "l2i" => "(J)I",
                                "l2d" => "(J)D",
                                "l2f" => "(J)F",
                                "d2i" => "(D)I",
                                "d2l" => "(D)J",
                                "d2f" => "(D)F",
                                "f2i" => "(F)I",
                                "f2l" => "(F)J",
                                "f2d" => "(F)D",
                                _ => "(I)V",
                            };
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: "$convert".to_string(),
                                        method_name: opcode_name.to_string(),
                                        descriptor: convert_desc.to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                        }
                        return Some(dest);
                    }
                }

                if let Some(jvm_class) = effective_class {
                    let is_primitive_ty = matches!(
                        &recv_ty,
                        Ty::Int | Ty::Long | Ty::Float | Ty::Double | Ty::Bool
                    );
                    let is_cross_class = jvm_method_name.contains("__on__");

                    // For instance methods on reference types, try instance lookup first.
                    if !is_primitive_ty && !is_cross_class {
                        let instance_arg_count = args.len(); // don't count receiver
                                                             // Build typed arg list (excluding the receiver) to pick the
                                                             // best overload. all_args = [receiver, ...args] so we skip 1.
                        let arg_tys: Vec<Ty> = all_args
                            .iter()
                            .skip(1)
                            .map(|a| fb.mf.locals[a.0 as usize].clone())
                            .collect();
                        // Try the JVM-renamed name first.
                        if let Some((found_class, found_method, descriptor, ret_ty)) =
                            lookup_java_instance_with_types(
                                jvm_class,
                                effective_method,
                                instance_arg_count,
                                &arg_tys,
                            )
                        {
                            // Dispatch on the receiver's static type
                            // (kotlinc emits `invokevirtual
                            // <ReceiverClass>` even when the method is
                            // declared on a parent class). The JVM's
                            // virtual dispatch finds the actual
                            // implementation at runtime, so this is
                            // semantically equivalent to dispatching
                            // on `found_class`. Use `found_class` as a
                            // fallback when `jvm_class` is `Object`
                            // (recv was `Any` / `Nullable(Any)`) and
                            // the actual method lives on a more
                            // specific JDK class.
                            let dispatch_class = if jvm_class == "java/lang/Object"
                                && found_class != "java/lang/Object"
                            {
                                found_class
                            } else {
                                jvm_class.to_string()
                            };
                            // If the lookup's fallback returned a method whose
                            // descriptor has more params than the call site
                            // provided (Kotlin default-param dispatch where the
                            // caller omitted defaulted args), pad `all_args`
                            // with type-appropriate defaults based on the
                            // descriptor's param chars. Without this, the JVM
                            // backend's arg-count check rejects the call and
                            // stubs the enclosing method body.
                            let desc_params =
                                skotch_classinfo::count_descriptor_params_pub(&descriptor);
                            let provided = all_args.len() - 1; // skip receiver
                            let mut all_args = all_args;
                            if desc_params > provided {
                                let param_descs = parse_descriptor_param_chars(&descriptor);
                                for slot in provided..desc_params {
                                    let slot_ch = param_descs.get(slot).copied().unwrap_or('L');
                                    let (slot_ty, init): (Ty, Rvalue) = match slot_ch {
                                        'I' | 'B' | 'C' | 'S' | 'Z' => {
                                            (Ty::Int, Rvalue::Const(MirConst::Int(0)))
                                        }
                                        'J' => (Ty::Long, Rvalue::Const(MirConst::Long(0))),
                                        'F' | 'D' => {
                                            (Ty::Double, Rvalue::Const(MirConst::Double(0.0)))
                                        }
                                        _ => (Ty::Any, Rvalue::Const(MirConst::Null)),
                                    };
                                    let pad_local = fb.new_local(slot_ty);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: pad_local,
                                        value: init,
                                    });
                                    all_args.push(pad_local);
                                }
                            }
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: dispatch_class,
                                        method_name: found_method,
                                        descriptor,
                                    },
                                    args: all_args,
                                },
                            });
                            return Some(dest);
                        }
                        // Try original Kotlin name.
                        if effective_method != method_name_str.as_str() {
                            if let Some((found_class, found_method, descriptor, ret_ty)) =
                                lookup_java_instance(
                                    jvm_class,
                                    &method_name_str,
                                    instance_arg_count,
                                )
                            {
                                let is_user_class =
                                    module.classes.iter().any(|c| c.name == jvm_class);
                                let dispatch_class = if is_user_class && found_class != jvm_class {
                                    jvm_class.to_string()
                                } else {
                                    found_class
                                };
                                let dest = fb.new_local(ret_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::VirtualJava {
                                            class_name: dispatch_class,
                                            method_name: found_method,
                                            descriptor,
                                        },
                                        args: all_args,
                                    },
                                });
                                return Some(dest);
                            }
                        }
                    }

                    // For static methods (primitive types, cross-class redirections).
                    let static_arg_count = args.len() + 1; // count receiver as arg
                                                           // Build typed arg list (receiver + args) for overload picking.
                    let mut static_arg_types: Vec<Ty> = Vec::with_capacity(static_arg_count);
                    static_arg_types.push(recv_ty.clone());
                    for arg_local in &all_args {
                        static_arg_types.push(fb.mf.locals[arg_local.0 as usize].clone());
                    }
                    // We pushed receiver twice (it's already in all_args at idx 0).
                    static_arg_types.remove(0);
                    if let Some((found_class, found_method, descriptor, ret_ty)) =
                        lookup_java_static_typed(
                            jvm_class,
                            effective_method,
                            static_arg_count,
                            &static_arg_types,
                        )
                    {
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: found_class,
                                    method_name: found_method,
                                    descriptor,
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                // Extension method via enclosing receiver scope. For a call
                // `dp.roundToPx()` inside `Density.measureIt`, when Dp has
                // no `roundToPx` member but Density has
                // `fun Dp.roundToPx(): Int`, kotlinc emits
                // `aload_0 (this); aload_X (dp); invoke{virtual,interface}
                // Density.roundToPx(Dp)I`. Walk the enclosing function's
                // `this` (params[0]) class hierarchy looking for an
                // extension method matching `(method_name, recv_ty)`.
                // Inside a lambda, also try the captured `$outerThis` or
                // captured `$this$<method>` extension receivers.
                {
                    let mut this_candidates: Vec<LocalId> = Vec::new();
                    if !fb.mf.params.is_empty() {
                        this_candidates.push(fb.mf.params[0]);
                    }
                    let outer_this_sym = interner.intern("$outerThis");
                    if let Some((_, outer_lid)) =
                        scope.iter().rev().find(|(s, _)| *s == outer_this_sym)
                    {
                        this_candidates.push(*outer_lid);
                    }
                    // Any captured `$this$<name>` extension receivers
                    // from enclosing functions/methods.
                    for (sym, lid) in scope.iter().rev() {
                        let s = interner.resolve(*sym);
                        if s.starts_with("$this$") && s.len() > 6 {
                            this_candidates.push(*lid);
                        }
                    }
                    let mut matched: Option<(LocalId, String, Ty, String)> = None;
                    'cand: for this_local in this_candidates {
                        let this_ty = fb.mf.locals[this_local.0 as usize].clone();
                        if let Ty::Class(enclosing_class) = &this_ty {
                            // Walk the class plus its superclass chain and
                            // implemented interfaces (extension methods may
                            // be inherited via interface, e.g.
                            // `MyDensity : Density { fun Dp.roundToPx() }`).
                            let mut to_visit: Vec<String> = vec![enclosing_class.clone()];
                            let mut visited: rustc_hash::FxHashSet<String> =
                                rustc_hash::FxHashSet::default();
                            while let Some(cn) = to_visit.pop() {
                                if !visited.insert(cn.clone()) {
                                    continue;
                                }
                                if let Some(cls) = module.classes.iter().find(|c| c.name == cn) {
                                    for m in &cls.methods {
                                        if m.name != method_name_str || m.params.len() < 2 {
                                            continue;
                                        }
                                        // params[0]=this, params[1]=ext_receiver.
                                        let ext_recv_lid = m.params[1];
                                        let ext_recv_ty =
                                            m.locals.get(ext_recv_lid.0 as usize).cloned();
                                        if ext_recv_ty.as_ref() == Some(&recv_ty)
                                            && m.params.len() == args.len() + 2
                                        {
                                            matched = Some((
                                                this_local,
                                                cls.name.clone(),
                                                m.return_ty.clone(),
                                                method_name_str.clone(),
                                            ));
                                            break 'cand;
                                        }
                                    }
                                    for iname in &cls.interfaces {
                                        to_visit.push(iname.clone());
                                    }
                                    if let Some(sc) = &cls.super_class {
                                        to_visit.push(sc.clone());
                                    }
                                }
                            }
                        }
                    }
                    if let Some((this_local, target_class, ret_ty, mname)) = matched {
                        let mut new_args = vec![this_local, recv_local];
                        for &a in all_args.iter().skip(1) {
                            new_args.push(a);
                        }
                        let dest = fb.new_local(ret_ty.clone());
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: target_class,
                                    method_name: mname,
                                },
                                args: new_args,
                            },
                        });
                        return Some(dest);
                    }
                }

                let (kind, dest_ty) = if let Ty::Class(class_name) = &recv_ty {
                    // Look up method in class, walking superclass + interfaces.
                    let mut return_ty = Ty::Unit;
                    let mut found_on_interface = false;
                    let mut found_is_suspend = false;
                    let mut iface_name = String::new();
                    // Capture param info for default-param dispatch: when the
                    // call site provides fewer args than the method declares
                    // and the missing slots have defaults, we need to pad
                    // args and route to the `name$default(...)` synthetic.
                    let mut found_param_count: usize = 0;
                    let mut found_param_defaults: Vec<Option<MirConst>> = Vec::new();
                    let mut found_param_types: Vec<Ty> = Vec::new();
                    let mut search = Some(class_name.clone());
                    'outer: while let Some(ref cname) = search {
                        if let Some(cls) = module.classes.iter().find(|c| &c.name == cname) {
                            if let Some(m) = cls.methods.iter().find(|m| m.name == method_name_str)
                            {
                                return_ty = m.return_ty.clone();
                                found_is_suspend = m.is_suspend;
                                // For class methods, params[0] is `this` (the
                                // receiver). Skip it to align with the call
                                // site's "args excluding receiver" count.
                                // Class methods: params[0]=this, params[1..]=user.
                                // param_defaults is indexed by user position
                                // (does NOT include `this`).
                                let user_param_start = if m.params.is_empty() { 0 } else { 1 };
                                found_param_count = m.params.len().saturating_sub(user_param_start);
                                found_param_defaults = m.param_defaults.clone();
                                found_param_types = m
                                    .params
                                    .iter()
                                    .skip(user_param_start)
                                    .map(|lid| {
                                        m.locals.get(lid.0 as usize).cloned().unwrap_or(Ty::Any)
                                    })
                                    .collect();
                                break;
                            }
                            // Search implemented interfaces.
                            for iname in &cls.interfaces {
                                if let Some(icls) = module.classes.iter().find(|c| &c.name == iname)
                                {
                                    if let Some(m) =
                                        icls.methods.iter().find(|m| m.name == method_name_str)
                                    {
                                        return_ty = m.return_ty.clone();
                                        found_is_suspend = m.is_suspend;
                                        found_on_interface = true;
                                        iface_name = iname.clone();
                                        break 'outer;
                                    }
                                }
                            }
                            search = cls.super_class.clone();
                        } else {
                            break;
                        }
                    }

                    // Fallback: if the method wasn't found in MIR classes,
                    // check for known Java methods.
                    if return_ty == Ty::Unit {
                        return_ty = match (method_name_str.as_str(), args.len()) {
                            ("toString", 0) => Ty::String,
                            ("hashCode", 0) => Ty::Int,
                            ("equals", 1) => Ty::Bool,
                            ("length", 0) => Ty::Int,
                            ("size", 0) => Ty::Int,
                            _ => {
                                // StringBuilder.append returns StringBuilder.
                                if class_name.contains("StringBuilder")
                                    && method_name_str == "append"
                                {
                                    Ty::Class(class_name.clone())
                                } else if let Some(d) = skotch_classinfo::lookup_method_descriptor(
                                    class_name,
                                    &method_name_str,
                                    args.len(),
                                ) {
                                    ty_from_descriptor_return(&d)
                                } else {
                                    Ty::Unit
                                }
                            }
                        };
                    }

                    // Suspend instance method calls. Append
                    // the $completion continuation and emit as VirtualJava
                    // so the state machine extractor detects it as a
                    // suspension point.
                    if found_is_suspend {
                        let cont_local = if fb.mf.is_suspend {
                            *fb.mf
                                .params
                                .last()
                                .expect("suspend fn must have $completion")
                        } else {
                            let c = fb
                                .new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                            fb.push_stmt(MStmt::Assign {
                                dest: c,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            c
                        };
                        all_args.push(cont_local);
                        // Build VirtualJava descriptor: (user_params..., Continuation)Object
                        let mut desc = String::from("(");
                        // Skip receiver (first arg) in descriptor
                        for &a in all_args.iter().skip(1) {
                            let ty = &fb.mf.locals[a.0 as usize];
                            desc.push_str(&jvm_type_string_for_ty(ty));
                        }
                        desc.push_str(")Ljava/lang/Object;");
                        let target_class = if found_on_interface {
                            iface_name
                        } else {
                            class_name.clone()
                        };
                        (
                            CallKind::VirtualJava {
                                class_name: target_class,
                                method_name: method_name_str,
                                descriptor: desc,
                            },
                            Ty::Any,
                        )
                    } else if found_on_interface {
                        // When the method comes from an interface but the
                        // receiver's static type is a concrete class
                        // implementing it, dispatch via the concrete
                        // class — kotlinc emits `invokevirtual <Class>`
                        // rather than `invokeinterface <Iface>` here.
                        let receiver_is_class = module
                            .classes
                            .iter()
                            .find(|c| &c.name == class_name)
                            .map(|c| !c.is_interface)
                            .unwrap_or(false);
                        let dispatch_class = if receiver_is_class {
                            class_name.clone()
                        } else {
                            iface_name
                        };
                        (
                            CallKind::Virtual {
                                class_name: dispatch_class,
                                method_name: method_name_str,
                            },
                            return_ty,
                        )
                    } else if let Some((_, callable_local)) = scope
                        .iter()
                        .rev()
                        .find(|(s, _)| interner.resolve(*s) == method_name_str)
                    {
                        // receiver.callable(args) where callable is a
                        // local variable of function/lambda type.
                        // Invoke as callable.invoke(receiver, args).
                        let callable_local = *callable_local;
                        let callable_ty = fb.mf.locals[callable_local.0 as usize].clone();
                        let invoke_class = match &callable_ty {
                            Ty::Class(cn) => cn.clone(),
                            Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                            _ => "java/lang/Object".to_string(),
                        };
                        let recv_arg = {
                            let widened = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: widened,
                                value: Rvalue::Local(recv_local),
                            });
                            widened
                        };
                        let mut invoke_args = vec![callable_local, recv_arg];
                        for &a in all_args.iter().skip(1) {
                            let a_ty = fb.mf.locals[a.0 as usize].clone();
                            let boxed = mir_autobox(fb, a, &a_ty);
                            invoke_args.push(boxed);
                        }
                        // FunctionN.invoke always returns Object on JVM.
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: invoke_class,
                                    method_name: "invoke".to_string(),
                                },
                                args: invoke_args,
                            },
                        });
                        return Some(dest);
                    } else if found_param_count > (all_args.len() - 1)
                        && found_param_defaults.iter().any(|d| d.is_some())
                    {
                        // Default-arg dispatch for user-class virtual method.
                        // Caller provided fewer args than the method declares
                        // AND the missing slots have defaults — pad with
                        // typed default values, set the $default mask, and
                        // emit a synthetic StaticJava call to
                        // `Class.method$default(receiver, args..., mask, marker)`.
                        // This mirrors what kotlinc generates and what the
                        // JVM backend already handles for top-level
                        // default-arg dispatch.
                        let provided = all_args.len() - 1;
                        // Trailing-lambda placement: when the user's last arg
                        // is a lambda (Function-typed) AND the method's last
                        // param is also Function-typed BUT a later position
                        // than where the lambda would land positionally,
                        // shift the lambda to the last position and default
                        // the params between. This matches Kotlin's
                        // `r.layout(w, h) { ... }` desugaring where the
                        // trailing block goes to the final Function param.
                        let is_fn_ty = |t: &Ty| {
                            matches!(t, Ty::Function { .. })
                                || matches!(t, Ty::Class(n) if n.starts_with("kotlin/jvm/functions/Function")
                                    || module.is_lambda_class(n))
                        };
                        let user_arg_tys: Vec<Ty> = all_args
                            .iter()
                            .skip(1)
                            .map(|a| fb.mf.locals[a.0 as usize].clone())
                            .collect();
                        let last_user_is_fn = user_arg_tys.last().map(is_fn_ty).unwrap_or(false);
                        let last_param_is_fn =
                            found_param_types.last().map(is_fn_ty).unwrap_or(false);
                        let lambda_landed_at = provided.saturating_sub(1);
                        let last_param_pos = found_param_count.saturating_sub(1);
                        let mut all_args = all_args;
                        if last_user_is_fn && last_param_is_fn && lambda_landed_at < last_param_pos
                        {
                            // Pop the trailing lambda — we'll re-append it
                            // after the in-between defaults are padded.
                            let _trailing = all_args.pop();
                            if let Some(trailing) = _trailing {
                                let new_provided = all_args.len() - 1;
                                let mut default_mask: u32 = 0;
                                for i in new_provided..last_param_pos {
                                    let default_const = found_param_defaults
                                        .get(i)
                                        .cloned()
                                        .flatten()
                                        .unwrap_or_else(|| match found_param_types.get(i) {
                                            Some(Ty::Int) | Some(Ty::Byte) | Some(Ty::Short)
                                            | Some(Ty::Char) | Some(Ty::Bool) => MirConst::Int(0),
                                            Some(Ty::Long) => MirConst::Long(0),
                                            Some(Ty::Double) | Some(Ty::Float) => {
                                                MirConst::Double(0.0)
                                            }
                                            _ => MirConst::Null,
                                        });
                                    let pad_ty = found_param_types
                                        .get(i)
                                        .cloned()
                                        .unwrap_or_else(|| const_ty(&default_const));
                                    let pad_local = fb.new_local(pad_ty);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: pad_local,
                                        value: Rvalue::Const(default_const),
                                    });
                                    all_args.push(pad_local);
                                    if i < 32 {
                                        default_mask |= 1u32 << i;
                                    }
                                }
                                all_args.push(trailing);
                                // Emit using the computed mask. Inline the
                                // tail of the static-default emit below.
                                let mask_local = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: mask_local,
                                    value: Rvalue::Const(MirConst::Int(default_mask as i32)),
                                });
                                all_args.push(mask_local);
                                let marker_local = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest: marker_local,
                                    value: Rvalue::Const(MirConst::Null),
                                });
                                all_args.push(marker_local);
                                let mut default_desc = String::from("(");
                                default_desc.push_str(&jvm_type_string_for_ty(&Ty::Class(
                                    class_name.clone(),
                                )));
                                for pty in &found_param_types {
                                    default_desc.push_str(&jvm_type_string_for_ty(pty));
                                }
                                default_desc.push_str("ILjava/lang/Object;)");
                                default_desc.push_str(&jvm_type_string_for_ty(&return_ty));
                                let default_method = format!("{}$default", method_name_str);
                                let dest = fb.new_local(return_ty.clone());
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::StaticJava {
                                            class_name: class_name.clone(),
                                            method_name: default_method,
                                            descriptor: default_desc,
                                        },
                                        args: all_args.clone(),
                                    },
                                });
                                return Some(dest);
                            }
                        }
                        let mut default_mask: u32 = 0;
                        for i in provided..found_param_count {
                            let default_const = found_param_defaults
                                .get(i)
                                .cloned()
                                .flatten()
                                .unwrap_or_else(|| match found_param_types.get(i) {
                                    Some(Ty::Int) | Some(Ty::Byte) | Some(Ty::Short)
                                    | Some(Ty::Char) | Some(Ty::Bool) => MirConst::Int(0),
                                    Some(Ty::Long) => MirConst::Long(0),
                                    Some(Ty::Double) | Some(Ty::Float) => MirConst::Double(0.0),
                                    _ => MirConst::Null,
                                });
                            let pad_ty = found_param_types
                                .get(i)
                                .cloned()
                                .unwrap_or_else(|| const_ty(&default_const));
                            let pad_local = fb.new_local(pad_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest: pad_local,
                                value: Rvalue::Const(default_const),
                            });
                            all_args.push(pad_local);
                            if i < 32 {
                                default_mask |= 1u32 << i;
                            }
                        }
                        // Push mask + null marker as the last two args.
                        let mask_local = fb.new_local(Ty::Int);
                        fb.push_stmt(MStmt::Assign {
                            dest: mask_local,
                            value: Rvalue::Const(MirConst::Int(default_mask as i32)),
                        });
                        all_args.push(mask_local);
                        let marker_local = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest: marker_local,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        all_args.push(marker_local);
                        // Build the $default descriptor:
                        //   (LReceiver;param0...paramN-1, I, Object)RET
                        let mut default_desc = String::from("(");
                        default_desc
                            .push_str(&jvm_type_string_for_ty(&Ty::Class(class_name.clone())));
                        for pty in &found_param_types {
                            default_desc.push_str(&jvm_type_string_for_ty(pty));
                        }
                        default_desc.push_str("ILjava/lang/Object;)");
                        default_desc.push_str(&jvm_type_string_for_ty(&return_ty));
                        let default_method = format!("{}$default", method_name_str);
                        let dest = fb.new_local(return_ty.clone());
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: class_name.clone(),
                                    method_name: default_method,
                                    descriptor: default_desc,
                                },
                                args: all_args.clone(),
                            },
                        });
                        return Some(dest);
                    } else if let Some((fc, fm, fd, rt)) =
                        dynamic_stdlib_extension(class_name.as_str(), &method_name_str)
                    {
                        // `recv.ext(args)` where `ext` is a stdlib/dep-jar
                        // extension fn on the concrete receiver class, not a
                        // member — e.g. `MutableStateFlow.asStateFlow()` →
                        // `invokestatic FlowKt.asStateFlow(MutableStateFlow)`.
                        // Without this the bare `Virtual` fallback below emits
                        // a bogus `invokevirtual <Class>.<ext>()V`.
                        let dest = fb.new_local(rt);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: fc,
                                    method_name: fm,
                                    descriptor: fd,
                                },
                                args: all_args,
                            },
                        });
                        return Some(dest);
                    } else {
                        (
                            CallKind::Virtual {
                                class_name: class_name.clone(),
                                method_name: method_name_str,
                            },
                            return_ty,
                        )
                    }
                } else if matches!(&recv_ty, Ty::Any | Ty::Nullable(_)) {
                    // Methods defined on java/lang/Object are available on
                    // every JVM type, including erased generics (Ty::Any).
                    let object_method: Option<(&str, Ty)> =
                        match (method_name_str.as_str(), args.len()) {
                            ("toString", 0) => Some(("()Ljava/lang/String;", Ty::String)),
                            ("hashCode", 0) => Some(("()I", Ty::Int)),
                            ("equals", 1) => Some(("(Ljava/lang/Object;)Z", Ty::Bool)),
                            ("getClass", 0) => Some(("()Ljava/lang/Class;", Ty::Any)),
                            _ => None,
                        };
                    if let Some((descriptor, ret_ty)) = object_method {
                        (
                            CallKind::VirtualJava {
                                class_name: "java/lang/Object".to_string(),
                                method_name: method_name_str,
                                descriptor: descriptor.to_string(),
                            },
                            ret_ty,
                        )
                    } else if let Some(fid) = name_to_func.get(&method_name) {
                        (
                            CallKind::Static(*fid),
                            module.functions[fid.0 as usize].return_ty.clone(),
                        )
                    } else {
                        // Last resort: try dynamic stdlib extension discovery.
                        let recv_ty_str2 = match &recv_ty {
                            Ty::Class(cn) => cn.as_str(),
                            Ty::String => "java/lang/String",
                            Ty::Any => "java/lang/Object",
                            _ => "",
                        };
                        if let Some((fc, fm, fd, rt)) =
                            dynamic_stdlib_extension(recv_ty_str2, &method_name_str)
                        {
                            let dest = fb.new_local(rt);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: fc,
                                        method_name: fm,
                                        descriptor: fd,
                                    },
                                    args: all_args,
                                },
                            });
                            return Some(dest);
                        }
                        // Method not found — emit null placeholder to
                        // avoid cascading errors in the rest of the function.
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        return Some(dest);
                    }
                } else if let Some(fid) = name_to_func.get(&method_name) {
                    (
                        CallKind::Static(*fid),
                        module.functions[fid.0 as usize].return_ty.clone(),
                    )
                } else if let Some((_, callable_local)) =
                    scope.iter().rev().find(|(s, _)| *s == method_name)
                {
                    // receiver.callable(args) where callable is a local
                    // variable of function type → callable.invoke(receiver, args).
                    // This handles extension function type invocations like
                    // `sb.block()` where block: StringBuilder.() -> Unit.
                    let callable_local = *callable_local;
                    let callable_ty = fb.mf.locals[callable_local.0 as usize].clone();
                    let is_callable = is_lambda_or_function_ty(&callable_ty, module)
                        || matches!(callable_ty, Ty::Any | Ty::Function { .. });
                    if is_callable {
                        let invoke_class = match &callable_ty {
                            Ty::Class(cn) => cn.clone(),
                            Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                            _ => "java/lang/Object".to_string(),
                        };
                        // Widen receiver to Any for the erased invoke signature.
                        let recv_arg = {
                            let widened = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: widened,
                                value: Rvalue::Local(recv_local),
                            });
                            widened
                        };
                        let mut invoke_args = vec![callable_local, recv_arg];
                        for &a in all_args.iter().skip(1) {
                            let a_ty = fb.mf.locals[a.0 as usize].clone();
                            let boxed = mir_autobox(fb, a, &a_ty);
                            invoke_args.push(boxed);
                        }
                        // FunctionN.invoke always returns Object on JVM.
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: invoke_class,
                                    method_name: "invoke".to_string(),
                                },
                                args: invoke_args,
                            },
                        });
                        return Some(dest);
                    }
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    return Some(dest);
                } else {
                    // Last resort before null-stubbing: resolve as a
                    // stdlib/dep-jar extension function on the receiver's type
                    // (e.g. `MutableStateFlow.asStateFlow()` →
                    // `FlowKt.asStateFlow(MutableStateFlow)`). The `Ty::Class`
                    // member-resolution branch above only handles real members,
                    // so concrete-receiver extension calls fall through to here.
                    let recv_cls = match &recv_ty {
                        Ty::Class(cn) => Some(cn.clone()),
                        Ty::String => Some("java/lang/String".to_string()),
                        _ => None,
                    };
                    if let Some(rc) = recv_cls {
                        if let Some((fc, fm, fd, rt)) =
                            dynamic_stdlib_extension(&rc, &method_name_str)
                        {
                            let dest = fb.new_local(rt);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: fc,
                                        method_name: fm,
                                        descriptor: fd,
                                    },
                                    args: all_args,
                                },
                            });
                            return Some(dest);
                        }
                    }
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    return Some(dest);
                };
                let dest = fb.new_local(dest_ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind,
                        args: all_args,
                    },
                });
                return Some(dest);
            }

            // Handle safe method calls: `receiver?.method(args)`
            // Wrap the call in a null-check: if (recv != null) recv.method(args) else null
            if let Expr::SafeCall {
                receiver: sc_receiver,
                name: sc_name,
                span: sc_span,
            } = callee.as_ref()
            {
                let recv = lower_expr(
                    sc_receiver,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )?;
                let then_block = fb.new_block();
                let else_block = fb.new_block();
                let merge_block = fb.new_block();

                let null_local = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                fb.push_stmt(MStmt::Assign {
                    dest: null_local,
                    value: Rvalue::Const(MirConst::Null),
                });
                let cmp = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: cmp,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpNe,
                        lhs: recv,
                        rhs: null_local,
                    },
                });
                let result = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: cmp,
                        then_block,
                        else_block,
                    },
                    then_block,
                );

                // then-block: unwrap and dispatch the method call via a
                // synthetic Call { callee: Field { .. } } expression.
                let recv_ty = fb.mf.locals[recv.0 as usize].clone();
                let inner_ty = intrinsics::strip_nullable(&recv_ty);
                let recv_unwrapped = if matches!(recv_ty, Ty::Nullable(_)) {
                    let uw = fb.new_local(inner_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest: uw,
                        value: Rvalue::Local(recv),
                    });
                    uw
                } else {
                    recv
                };

                // Build a synthetic Field-based call expression and lower it.
                // We use a temporary ident node whose symbol is bound to the
                // unwrapped receiver local in the scope.
                let tmp_sym = interner.intern("$safe_recv$");
                scope.push((tmp_sym, recv_unwrapped));
                let synthetic_call = Expr::Call {
                    callee: Box::new(Expr::Field {
                        receiver: Box::new(Expr::Ident(tmp_sym, *sc_span)),
                        name: *sc_name,
                        span: *sc_span,
                    }),
                    args: args.clone(),
                    type_args: type_args.clone(),
                    span: *span,
                };
                let call_result = lower_expr(
                    &synthetic_call,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                );
                scope.pop(); // remove $safe_recv$

                if let Some(cr) = call_result {
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(cr),
                    });
                }
                fb.terminate_and_switch(Terminator::Goto(merge_block), else_block);

                // else-block: result = null
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Const(MirConst::Null),
                });
                fb.terminate_and_switch(Terminator::Goto(merge_block), merge_block);

                return Some(result);
            }

            let callee_name = match callee.as_ref() {
                Expr::Ident(name, _) => *name,
                _ => {
                    diags.push(Diagnostic::error(
                        *span,
                        "only direct function calls are supported",
                    ));
                    return None;
                }
            };

            // ─── Overload resolution by user arity ───────────────────
            // The Pass-1 registration overwrites `name_to_func` per name,
            // so when a file declares both `foo(x)` and `foo(x, y, z)`,
            // the last one wins and a call `foo(x)` would dispatch to
            // the 3-arg version (verifier error). Search `module.functions`
            // for a same-name overload whose param count matches the
            // call's user-arg count and pin `name_to_func` at it for the
            // duration of this lowering. (Nested calls re-run this dance
            // for themselves, so a transient mismatch doesn't matter.)
            if let Some(&primary_fid) = name_to_func.get(&callee_name) {
                let primary_arity = module.functions[primary_fid.0 as usize].params.len();
                if primary_arity != args.len() {
                    let target_name = interner.resolve(callee_name).to_string();
                    if let Some(matching) = module
                        .functions
                        .iter()
                        .find(|f| f.name == target_name && f.params.len() == args.len())
                    {
                        name_to_func.insert(callee_name, matching.id);
                    }
                }
            }

            // ─── SAM conversion: Interface { lambda } ────────────────
            // When the callee names an interface with a single abstract
            // method, and the argument is a lambda, desugar to an
            // anonymous object implementing the interface.
            let callee_str = interner.resolve(callee_name).to_string();
            let sam_method = module
                .classes
                .iter()
                .find(|c| c.name == callee_str && c.is_interface)
                .and_then(|iface| {
                    let abstract_methods: Vec<&MirFunction> =
                        iface.methods.iter().filter(|m| m.is_abstract).collect();
                    if abstract_methods.len() == 1 {
                        Some((
                            abstract_methods[0].name.clone(),
                            abstract_methods[0].return_ty.clone(),
                            abstract_methods[0]
                                .params
                                .iter()
                                .skip(1) // skip `this`
                                .map(|p| iface.methods[0].locals[p.0 as usize].clone())
                                .collect::<Vec<Ty>>(),
                        ))
                    } else {
                        None
                    }
                });
            if let Some((sam_name, sam_ret, _sam_params)) = sam_method {
                if args.len() == 1 {
                    if let Expr::Lambda {
                        params: lparams,
                        body: lbody,
                        span: lspan,
                        ..
                    } = &args[0].expr
                    {
                        // Construct an ObjectExpr AST node and lower it.
                        let override_fn = skotch_syntax::FunDecl {
                            name: interner.intern(&sam_name),
                            name_span: *lspan,
                            type_params: Vec::new(),
                            params: lparams.clone(),
                            return_ty: None,
                            receiver_ty: None,
                            body: lbody.clone(),
                            is_open: false,
                            is_override: true,
                            is_abstract: false,
                            is_suspend: false,
                            is_inline: false,
                            is_ext_property: false,
                            visibility: skotch_syntax::Visibility::Public,
                            annotations: Vec::new(),
                            span: *lspan,
                        };
                        // If the SAM method returns non-Unit, set return type.
                        if sam_ret != Ty::Unit {
                            // Leave return_ty as None — inferred from body.
                        }
                        let obj_expr = Expr::ObjectExpr {
                            super_type: callee_name,
                            methods: vec![override_fn],
                            span: *lspan,
                        };
                        return lower_expr(
                            &obj_expr,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                }
            }

            // ─── Reified inline: `f<Type>(arg)` where f has reified T ──
            // For inline functions with reified type params, we inline the
            // `is T` check at the call site using the concrete type arg.
            // Supports multi-reified: `f<A, B>(arg)` substitutes both A and B.
            if !type_args.is_empty() {
                if let Some(fid) = name_to_func.get(&callee_name) {
                    let target = &module.functions[fid.0 as usize];
                    // Build type param → concrete type map.
                    // Use common convention: T, A, B, C... for positional params.
                    let common_params = ["T", "A", "B", "C", "R", "E", "K", "V"];
                    for (i, ta) in type_args.iter().enumerate() {
                        if i < common_params.len() {
                            let concrete = interner.resolve(ta.name).to_string();
                            fb.reified_types
                                .insert(common_params[i].to_string(), concrete.clone());
                        }
                    }
                    // Check if the function body is a single is-check pattern
                    // (the common reified use case).
                    if target.return_ty == Ty::Bool && !args.is_empty() {
                        // Use the first type arg for the simple pattern.
                        let concrete_type = interner.resolve(type_args[0].name).to_string();
                        // Lower the argument.
                        let arg_local = lower_expr(
                            &args[0].expr,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )?;
                        // The parameter type is `Any` so it's already an Object on JVM.
                        // But if the argument is a primitive, we need it autoboxed.
                        // The function's parameter is typed `Ty::Any`, so the autoboxing
                        // happens at the JVM backend level when the static call is emitted.
                        // For the inlined instanceof, we just use the arg directly —
                        // if it's a primitive, we need to box it first.
                        let obj_local = match fb.mf.locals[arg_local.0 as usize] {
                            Ty::Int | Ty::Long | Ty::Float | Ty::Double | Ty::Bool => {
                                // Box the primitive by calling it through a static valueOf.
                                let (class, desc) = match fb.mf.locals[arg_local.0 as usize] {
                                    Ty::Int => ("java/lang/Integer", "(I)Ljava/lang/Integer;"),
                                    Ty::Long => ("java/lang/Long", "(J)Ljava/lang/Long;"),
                                    Ty::Float => ("java/lang/Float", "(F)Ljava/lang/Float;"),
                                    Ty::Double => ("java/lang/Double", "(D)Ljava/lang/Double;"),
                                    Ty::Bool => ("java/lang/Boolean", "(Z)Ljava/lang/Boolean;"),
                                    _ => unreachable!(),
                                };
                                let boxed = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest: boxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::StaticJava {
                                            class_name: class.to_string(),
                                            method_name: "valueOf".to_string(),
                                            descriptor: desc.to_string(),
                                        },
                                        args: vec![arg_local],
                                    },
                                });
                                boxed
                            }
                            _ => arg_local,
                        };
                        // Emit instanceof check with the concrete type.
                        let jvm_name = intrinsics::runtime_check_jvm_class(&concrete_type)
                            .map(str::to_string)
                            .unwrap_or_else(|| concrete_type.clone());
                        let result = fb.new_local(Ty::Bool);
                        fb.push_stmt(MStmt::Assign {
                            dest: result,
                            value: Rvalue::InstanceOf {
                                obj: obj_local,
                                type_descriptor: jvm_name,
                            },
                        });
                        return Some(result);
                    }
                }
            }

            // ─── User-declared inline-fn body substitution ────────────
            // For an `inline fun foo(...)` whose body is a single basic
            // block with no lambda params and no exception handlers,
            // splice the body directly into the caller at the call site
            // (with locals/blocks renamed). This avoids the extra static
            // method call and matches kotlinc's semantic for non-HOF
            // inline functions. HOF inline fns (the
            // `let`/`apply`/`with` family) are intrinsified separately
            // and skipped here via the lambda-param gate inside
            // `try_inline_call_into_fb`. Reified-T inline fns are
            // handled by the dedicated branch above.
            if type_args.is_empty() && callee_str != fb.mf.name {
                if let Some(fid) = name_to_func.get(&callee_name) {
                    let target_idx = fid.0 as usize;
                    // Pre-check the inline gates before lowering args so
                    // we don't pollute `fb` with arg locals on the
                    // common path (a regular static call) where we'd
                    // fall through and re-lower anyway.
                    let inline_candidate = target_idx < module.functions.len() && {
                        let t = &module.functions[target_idx];
                        t.is_inline
                            && !t.is_suspend
                            && !t.is_abstract
                            && t.blocks.len() == 1
                            && t.exception_handlers.is_empty()
                            && t.suspend_state_machine.is_none()
                            && t.params.len() == args.len()
                            && !t
                                .params
                                .iter()
                                .any(|p| matches!(t.locals[p.0 as usize], Ty::Function { .. }))
                            && matches!(
                                t.blocks[0].terminator,
                                Terminator::ReturnValue(_) | Terminator::Return
                            )
                    };
                    if inline_candidate {
                        let mut ok = true;
                        let mut arg_locals: Vec<LocalId> = Vec::with_capacity(args.len());
                        for a in args {
                            match lower_expr(
                                &a.expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            ) {
                                Some(l) => arg_locals.push(l),
                                None => {
                                    ok = false;
                                    break;
                                }
                            }
                        }
                        if ok {
                            if let Some(result) =
                                try_inline_call_into_fb(target_idx, &arg_locals, fb, module)
                            {
                                return Some(result);
                            }
                        }
                    }
                }
            }

            // ─── Set reified type substitutions for IsCheck ────────
            // Store type arg names as reified substitutions so that
            // `is T` in function bodies resolves to the concrete type.
            if !type_args.is_empty() {
                // Simple heuristic: map single-letter type param names.
                // For the common case `f<String>(x)`, map T→String.
                let common_params = ["T", "A", "B", "C", "R", "E", "K", "V"];
                for (i, ta) in type_args.iter().enumerate() {
                    if i < common_params.len() {
                        let concrete = interner.resolve(ta.name).to_string();
                        fb.reified_types
                            .insert(common_params[i].to_string(), concrete);
                    }
                }
            }

            // ─── Resolve type aliases for constructor calls ─────────
            // e.g. `typealias SymbolAnnotation = Pair<...>` allows
            // `SymbolAnnotation(a, b)` which is really `Pair(a, b)`.
            let callee_str = if let Some(target) = module.type_aliases.get(&callee_str) {
                target.clone()
            } else {
                callee_str
            };

            // ─── Check for constructor call (class instantiation) ────
            let is_class = module.classes.iter().any(|c| c.name == callee_str);
            if is_class {
                // Use the fully-qualified JVM name for the class.
                let fq_name = fq_class_name(&callee_str, module);
                // Lower args first so we can choose between the class
                // constructor and a same-named top-level factory function.
                // Track each arg's name (if any) so named args can be
                // reordered to the constructor's parameter order below —
                // `Foo(b = …, a = …)` must emit `<init>(a, b)`.
                let mut named_locals: Vec<(Option<Symbol>, LocalId)> = Vec::new();
                for a in args {
                    let id = lower_expr(
                        &a.expr,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    named_locals.push((a.name, id));
                }
                // Reorder named args to match the primary constructor's
                // declared parameter order. kotlinc always emits the
                // callee's positional `<init>` descriptor; without this a
                // call like JetChat's
                // `ConversationUiState(initialMessages = …, channelName = …)`
                // emits the args in source order, mismatching the
                // constructor signature (VerifyError / NoSuchMethodError).
                let arg_locals: Vec<LocalId> = if named_locals.iter().any(|(n, _)| n.is_some()) {
                    // The constructor's value-parameter names (the
                    // `param_names` vec drops the implicit `this`).
                    let ctor_param_names: Vec<String> = module
                        .classes
                        .iter()
                        .find(|c| c.name == callee_str || c.name == fq_name)
                        .map(|c| c.constructor.param_names.clone())
                        .unwrap_or_default();
                    if ctor_param_names.is_empty() {
                        named_locals.iter().map(|(_, id)| *id).collect()
                    } else {
                        let mut reordered: Vec<Option<LocalId>> =
                            vec![None; ctor_param_names.len()];
                        let mut positional_idx = 0;
                        for (name_opt, id) in &named_locals {
                            if let Some(name_sym) = name_opt {
                                let name_str = interner.resolve(*name_sym);
                                if let Some(pos) =
                                    ctor_param_names.iter().position(|pn| pn == name_str)
                                {
                                    reordered[pos] = Some(*id);
                                    continue;
                                }
                            }
                            // Positional arg (or unknown name): fill the
                            // next free slot.
                            while positional_idx < reordered.len()
                                && reordered[positional_idx].is_some()
                            {
                                positional_idx += 1;
                            }
                            if positional_idx < reordered.len() {
                                reordered[positional_idx] = Some(*id);
                                positional_idx += 1;
                            }
                        }
                        reordered.into_iter().flatten().collect()
                    }
                } else {
                    named_locals.iter().map(|(_, id)| *id).collect()
                };
                let arg_tys: Vec<Ty> = arg_locals
                    .iter()
                    .map(|l| fb.mf.locals[l.0 as usize].clone())
                    .collect();

                // Kotlin allows a top-level factory function with the same name
                // as a class (e.g. `class Foo(s: String)` + `fun Foo(n: Int): Foo`,
                // exactly how Compose declares `RoundedCornerShape(Dp,…)` next to
                // the `RoundedCornerShape(CornerSize,…)` constructor). skotch
                // defaults an uppercase callee to the constructor, which emits a
                // type-mismatched `<init>` (VerifyError / d8 reject) when the
                // args fit the factory, not the ctor. Prefer the factory only
                // when the ctor params do NOT accept the args but the factory's
                // do — legitimate constructor calls (ctor matches) are untouched.
                let factory_fid = name_to_func.get(&interner.intern(&callee_str)).copied();
                if let Some(fid) = factory_fid {
                    let assignable = |args: &[Ty], params: &[Ty]| {
                        args.len() == params.len()
                            && args
                                .iter()
                                .zip(params)
                                .all(|(a, p)| a.assignable_to(p) || matches!(p, Ty::Any))
                    };
                    let ctor_params: Vec<Ty> = module
                        .classes
                        .iter()
                        .find(|c| c.name == callee_str)
                        .map(|c| {
                            c.constructor
                                .params
                                .iter()
                                .skip(1) // skip `this`
                                .map(|p| c.constructor.locals[p.0 as usize].clone())
                                .collect()
                        })
                        .unwrap_or_default();
                    let factory = &module.functions[fid.0 as usize];
                    let fn_params: Vec<Ty> = factory
                        .params
                        .iter()
                        .map(|p| factory.locals[p.0 as usize].clone())
                        .collect();
                    let returns_class = matches!(&factory.return_ty, Ty::Class(c) if *c == callee_str || *c == fq_name);
                    if returns_class
                        && !assignable(&arg_tys, &ctor_params)
                        && assignable(&arg_tys, &fn_params)
                    {
                        let ret_ty = factory.return_ty.clone();
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Static(fid),
                                args: arg_locals,
                            },
                        });
                        return Some(dest);
                    }
                }

                // Default: NewInstance + Constructor call.
                let dest = fb.new_local(Ty::Class(fq_name.clone()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance(fq_name.clone()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::Constructor(fq_name),
                        args: arg_locals,
                    },
                });
                return Some(dest);
            }

            // ─── Imported class constructors ─────────────────────────
            // Check import_map for Java classes: `import java.util.Random`
            // allows `Random()` as a constructor call.
            if let Some(jvm_class) = module.import_map.get(&callee_str).cloned() {
                // Check if this is a class (starts with uppercase last segment)
                // that we can construct. Check both JDK and classpath JARs.
                let last_seg = jvm_class.rsplit('/').next().unwrap_or(&jvm_class);
                let is_class = last_seg.starts_with(|c: char| c.is_uppercase());
                let class_exists = is_class
                    && (skotch_classinfo::load_jdk_class(&jvm_class).is_ok()
                        || skotch_classinfo::lookup_method_descriptor(&jvm_class, "<init>", 0)
                            .is_some());
                // Compose convention: the simple name `MaterialTheme` resolves
                // to BOTH an `object MaterialTheme` (singleton accessor for
                // `MaterialTheme.colorScheme.primary` etc.) AND a sibling top-
                // level `@Composable fun MaterialTheme(...)` in a Kt facade
                // class (`MaterialTheme_androidKt` / `MaterialThemeKt`). The
                // function is the one users invoke at composition sites.
                //
                // If a Kt facade in the same package exports a static method
                // with the same name and the imported class is a Kotlin
                // singleton (has an `INSTANCE` field), prefer the function:
                // route through the StaticJava path below instead of falling
                // into constructor dispatch, which would emit
                // `new MaterialTheme; invokespecial <init>` and crash with
                // NoSuchMethodError at runtime.
                let is_kotlin_object = class_exists
                    && skotch_classinfo::lookup_static_field_descriptor(&jvm_class, "INSTANCE")
                        .is_some();
                // Interfaces can't be instantiated by `<init>`. When the
                // imported name resolves to an interface (e.g.
                // `MutableStateFlow`, which is BOTH an interface and a
                // top-level factory function in `StateFlowKt`), we MUST
                // route to the sibling Kt facade — falling into the
                // constructor branch produces an aconst_null stub
                // because no `<init>` exists.
                let is_interface = class_exists
                    && skotch_classinfo::check_is_interface(&jvm_class).unwrap_or(false);
                let sibling_kt_fn = if is_kotlin_object || is_interface {
                    if let Some((pkg, _)) = jvm_class.rsplit_once('/') {
                        skotch_classinfo::find_wrapper_class_for_function(pkg, &callee_str)
                    } else {
                        None
                    }
                } else {
                    None
                };
                if class_exists && sibling_kt_fn.is_none() {
                    let mut arg_locals = Vec::new();
                    for a in args {
                        let id = lower_expr(
                            &a.expr,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )?;
                        arg_locals.push(id);
                    }
                    // `@JvmInline value class` detection: kotlinc emits an
                    // accessible `static <C> box-impl(<inner>)` for every
                    // value class so callers can construct a boxed instance
                    // without touching the synthetic private `<init>`.
                    // Compose uses this pattern for `Color`, `Dp`,
                    // `TextUnit`, etc. — `Color(0xFFADC6FF)` MUST go through
                    // `Color.box-impl(J)LColor;` or the JVM raises
                    // IllegalAccessError on `invokespecial Color.<init>(J)V`
                    // at runtime.
                    //
                    // The presence of `box-impl` is the cheapest reliable
                    // marker for value classes — only the inline-class
                    // compiler emits it. Routing through it also avoids
                    // emitting `new + dup` for a class whose constructor we
                    // can't actually call.
                    let box_impl_desc = skotch_classinfo::lookup_method_descriptor(
                        &jvm_class,
                        "box-impl",
                        arg_locals.len(),
                    );
                    if let Some(desc) = box_impl_desc {
                        // When the user arg types match the value-class's
                        // underlying primitive directly (e.g. `Color(longLit)`
                        // calling `Color.box-impl(J)Color`), route through
                        // box-impl as-is. When they DON'T match — the most
                        // common JetChat case is `Color(intLit)` where
                        // box-impl wants `J` — prefer the same-package
                        // factory `ColorKt.Color(I)J` and then box its long
                        // result. kotlinc generates exactly this two-call
                        // chain for `Color(0xFF6750A4)`.
                        let box_arg_tys = descriptor_arg_tys(&desc);
                        let user_arg_tys: Vec<Ty> = arg_locals
                            .iter()
                            .map(|l| fb.mf.locals[l.0 as usize].clone())
                            .collect();
                        let box_accepts = box_arg_tys.len() == user_arg_tys.len()
                            && box_arg_tys
                                .iter()
                                .zip(&user_arg_tys)
                                .all(|(p, a)| a.assignable_to(p) || matches!(p, Ty::Any));
                        // Try to locate a sibling `<Pkg>/<Name>Kt.<Name>`
                        // factory that takes the user's arg types and
                        // returns the value-class's underlying primitive.
                        let chained = if !box_accepts {
                            jvm_class.rsplit_once('/').and_then(|(pkg, _)| {
                                skotch_classinfo::find_wrapper_class_for_function(pkg, &callee_str)
                                    .and_then(|facade| {
                                        skotch_classinfo::lookup_method_descriptor(
                                            &facade,
                                            &callee_str,
                                            arg_locals.len(),
                                        )
                                        .and_then(|fd| {
                                            let fparams = descriptor_arg_tys(&fd);
                                            let fits = fparams.len() == user_arg_tys.len()
                                                && user_arg_tys.iter().zip(&fparams).all(
                                                    |(a, p)| {
                                                        a.assignable_to(p) || matches!(p, Ty::Any)
                                                    },
                                                );
                                            if fits {
                                                Some((facade, fd))
                                            } else {
                                                None
                                            }
                                        })
                                    })
                            })
                        } else {
                            None
                        };
                        if let Some((facade, fac_desc)) = chained {
                            let fac_ret_ty = ty_from_descriptor_return(&fac_desc);
                            let inner = fb.new_local(fac_ret_ty.clone());
                            fb.push_stmt(MStmt::Assign {
                                dest: inner,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: facade,
                                        method_name: callee_str.clone(),
                                        descriptor: fac_desc,
                                    },
                                    args: arg_locals,
                                },
                            });
                            let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: jvm_class,
                                        method_name: "box-impl".to_string(),
                                        descriptor: desc,
                                    },
                                    args: vec![inner],
                                },
                            });
                            return Some(dest);
                        }
                        if box_accepts {
                            let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: jvm_class,
                                        method_name: "box-impl".to_string(),
                                        descriptor: desc,
                                    },
                                    args: arg_locals,
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // Look up the actual constructor descriptor from the
                    // classpath. Use the typed lookup so overload resolution
                    // matches arg types — e.g. `File("/tmp")` picks the
                    // (String) constructor over the (URI) constructor.
                    let arg_types: Vec<Ty> = arg_locals
                        .iter()
                        .map(|l| fb.mf.locals[l.0 as usize].clone())
                        .collect();
                    // Same-named top-level factory preference (external site).
                    // Kotlin allows a top-level `fun RoundedCornerShape(Dp,Dp,
                    // Dp,Dp)` alongside `class RoundedCornerShape(CornerSize,
                    // …)`. `RoundedCornerShape(4.dp, …)` resolves to the
                    // FACTORY (its Dp/Float params match), but skotch defaults
                    // an uppercase name to the ctor and emits `new +
                    // invokespecial <init>(CornerSize,…)` with float args → d8
                    // rejects ConversationKt.<clinit>. Mirror the local-class
                    // fix (fixture 1225) at the external/classpath site: when a
                    // sibling `<pkg>/<Name>Kt.<Name>` factory's params accept
                    // the arg types but the ctor's do NOT, invokestatic the
                    // factory. The asymmetric condition keeps legitimate ctor
                    // calls (ctor matches) untouched.
                    let accepts = |params: &[Ty]| {
                        params.len() == arg_types.len()
                            && arg_types
                                .iter()
                                .zip(params)
                                .all(|(a, p)| a.assignable_to(p) || matches!(p, Ty::Any))
                    };
                    if let Some((pkg, _)) = jvm_class.rsplit_once('/') {
                        if let Some(facade) =
                            skotch_classinfo::find_wrapper_class_for_function(pkg, &callee_str)
                        {
                            if let Some(fac_desc) = skotch_classinfo::lookup_method_descriptor(
                                &facade,
                                &callee_str,
                                arg_locals.len(),
                            ) {
                                let fac_params = descriptor_arg_tys(&fac_desc);
                                let ctor_accepts =
                                    lookup_constructor(&jvm_class, arg_locals.len(), &arg_types)
                                        .or_else(|| {
                                            skotch_classinfo::lookup_method_descriptor(
                                                &jvm_class,
                                                "<init>",
                                                arg_locals.len(),
                                            )
                                        })
                                        .map(|d| accepts(&descriptor_arg_tys(&d)))
                                        .unwrap_or(false);
                                if accepts(&fac_params) && !ctor_accepts {
                                    let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                                    fb.push_stmt(MStmt::Assign {
                                        dest,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: facade,
                                                method_name: callee_str.clone(),
                                                descriptor: fac_desc,
                                            },
                                            args: arg_locals,
                                        },
                                    });
                                    return Some(dest);
                                }
                            }
                        }
                    }
                    let ctor_desc = lookup_constructor(&jvm_class, arg_locals.len(), &arg_types)
                        .or_else(|| {
                            skotch_classinfo::lookup_method_descriptor(
                                &jvm_class,
                                "<init>",
                                arg_locals.len(),
                            )
                        });
                    // Default-param dispatch for external Kotlin classes:
                    // kotlinc generates a SYNTHETIC ctor with descriptor
                    // ending in `Lkotlin/jvm/internal/DefaultConstructorMarker;)V`.
                    // Its param count is `primary_count + 2` (mask + marker).
                    // For `GoogleFont(name = "Montserrat")` user_arg=1,
                    // the primary is `<init>(String, Z)` and the synthetic
                    // is `<init>(String, Z, I, DefaultConstructorMarker)`.
                    // We pad the user's args to primary_count with 0/null,
                    // set the mask for unsupplied slots, push null marker,
                    // and invokespecial the synthetic.
                    if ctor_desc.is_none()
                        || ctor_desc
                            .as_ref()
                            .map(|d| d.contains("Lkotlin/jvm/internal/DefaultConstructorMarker;)V"))
                            .unwrap_or(false)
                    {
                        // Search for a synthetic default ctor that takes
                        // more args than the user supplied.
                        let synthetic_desc = (1..=12).find_map(|extra| {
                            skotch_classinfo::lookup_method_descriptor(
                                &jvm_class,
                                "<init>",
                                arg_locals.len() + extra,
                            )
                            .filter(|d| {
                                d.contains("Lkotlin/jvm/internal/DefaultConstructorMarker;)V")
                            })
                        });
                        if let Some(desc) = synthetic_desc {
                            let total = skotch_classinfo::count_descriptor_params_pub(&desc);
                            let primary_count = total.saturating_sub(2);
                            let user_n = arg_locals.len();
                            let param_chars = parse_descriptor_param_chars(&desc);
                            // Pad slots from user_n..primary_count with zero/null.
                            for i in user_n..primary_count {
                                let kind = param_chars.get(i).copied().unwrap_or('L');
                                let (slot_ty, value) = match kind {
                                    'I' => (Ty::Int, Rvalue::Const(MirConst::Int(0))),
                                    'J' => (Ty::Long, Rvalue::Const(MirConst::Long(0))),
                                    'F' => (Ty::Float, Rvalue::Const(MirConst::Float(0.0))),
                                    'D' => (Ty::Double, Rvalue::Const(MirConst::Double(0.0))),
                                    _ => (Ty::Any, Rvalue::Const(MirConst::Null)),
                                };
                                let pad = fb.new_local(slot_ty);
                                fb.push_stmt(MStmt::Assign { dest: pad, value });
                                arg_locals.push(pad);
                            }
                            // Mask: bit `i` set for slots not supplied by the
                            // user (the synthetic dispatcher uses these bits
                            // to know which positions need its own defaults).
                            let mut mask: i32 = 0;
                            for i in user_n..primary_count {
                                if i < 32 {
                                    mask |= 1 << i;
                                }
                            }
                            let mask_local = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: mask_local,
                                value: Rvalue::Const(MirConst::Int(mask)),
                            });
                            arg_locals.push(mask_local);
                            // DefaultConstructorMarker is always null.
                            let marker_local = fb.new_local(Ty::Class(
                                "kotlin/jvm/internal/DefaultConstructorMarker".to_string(),
                            ));
                            fb.push_stmt(MStmt::Assign {
                                dest: marker_local,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            arg_locals.push(marker_local);
                            let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::NewInstance(jvm_class.clone()),
                            });
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::ConstructorJava {
                                        class_name: jvm_class,
                                        descriptor: desc,
                                    },
                                    args: arg_locals,
                                },
                            });
                            return Some(dest);
                        }
                        // No synthetic available either — fall back to null.
                        let dest = fb.new_local(Ty::Class(jvm_class));
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        return Some(dest);
                    }
                    let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::NewInstance(jvm_class.clone()),
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: if let Some(desc) = ctor_desc {
                                CallKind::ConstructorJava {
                                    class_name: jvm_class,
                                    descriptor: desc,
                                }
                            } else {
                                CallKind::Constructor(jvm_class)
                            },
                            args: arg_locals,
                        },
                    });
                    return Some(dest);
                }
                // ─── External Kt-facade static-fn dispatch (#296) ────────
                // An uppercase callee like `Text(...)` (or `Icon`, `Surface`,
                // `Scaffold`) imports to a name that ISN'T a real class — it
                // resolves through `import_map` because Compose's @Composable
                // functions are imported by their plain name, but the JVM
                // class at `androidx/compose/material3/Text` does not exist;
                // the actual method lives on the sibling Kt facade
                // `androidx/compose/material3/TextKt`. Without this branch
                // the construction block above is skipped (`class_exists =
                // false`) and the call falls through to `None`, which drops
                // the entire enclosing function body and produces the
                // JetChat blank-UI (#358). Mirror the ctor synthetic-default
                // search above for static functions: try the exact-arity
                // descriptor first, then scan for `<name>$default` (which
                // appends `int $default_mask, Object $marker` to the primary
                // signature).
                if !class_exists {
                    if let Some((pkg, _)) = jvm_class.rsplit_once('/') {
                        if let Some(facade) =
                            skotch_classinfo::find_wrapper_class_for_function(pkg, &callee_str)
                        {
                            let mut arg_locals = Vec::new();
                            for a in args {
                                let id = lower_expr(
                                    &a.expr,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                )?;
                                arg_locals.push(id);
                            }
                            // Named-arg reordering: when the call uses named
                            // args (e.g. `darkColorScheme(primary = Blue80,
                            // onPrimary = Blue20, …)`) and the source-level
                            // order doesn't match the facade fn's param
                            // declaration order, the trailing `$default`
                            // dispatch below pads positional gaps with
                            // wrong-slot defaults and the validator rejects
                            // the call → enclosing `<clinit>` is stubbed →
                            // theme colors are null at runtime → MaterialTheme
                            // NPE. Use `@Metadata` param names to map each
                            // named arg back to its declaration position;
                            // synthesize typed defaults for any unfilled
                            // user-level slot and record the mask bits so
                            // the callee uses its own defaults for them.
                            let mut reorder_default_mask: u32 = 0;
                            let has_named = args.iter().any(|a| a.name.is_some());
                            if has_named {
                                if let Some(fn_meta) =
                                    skotch_classinfo::lookup_function_metadata(&facade, &callee_str)
                                {
                                    let param_names: Vec<&str> = fn_meta
                                        .value_params
                                        .iter()
                                        .map(|p| p.name.as_str())
                                        .collect();
                                    if !param_names.is_empty() {
                                        let mut placed: Vec<Option<LocalId>> =
                                            vec![None; param_names.len()];
                                        let mut next_positional = 0usize;
                                        let mut ok = true;
                                        for (i, a) in args.iter().enumerate() {
                                            let local = arg_locals[i];
                                            if let Some(name_sym) = a.name {
                                                let name_str = interner.resolve(name_sym);
                                                if let Some(pos) =
                                                    param_names.iter().position(|n| *n == name_str)
                                                {
                                                    if placed[pos].is_some() {
                                                        ok = false;
                                                        break;
                                                    }
                                                    placed[pos] = Some(local);
                                                } else {
                                                    ok = false;
                                                    break;
                                                }
                                            } else {
                                                while next_positional < param_names.len()
                                                    && placed[next_positional].is_some()
                                                {
                                                    next_positional += 1;
                                                }
                                                if next_positional >= param_names.len() {
                                                    ok = false;
                                                    break;
                                                }
                                                placed[next_positional] = Some(local);
                                                next_positional += 1;
                                            }
                                        }
                                        if ok {
                                            // Find the highest filled
                                            // position; expand arg_locals up
                                            // to that point, filling internal
                                            // gaps with descriptor-typed
                                            // defaults. Bits for the
                                            // synthesized defaults go in
                                            // `reorder_default_mask`, which
                                            // the padding logic below ORs
                                            // into the `$default` mask.
                                            let last_filled =
                                                placed.iter().rposition(|p| p.is_some());
                                            if let Some(last) = last_filled {
                                                // Look up the descriptor we'll
                                                // use to type each synthesized
                                                // default. Prefer the exact-
                                                // arity descriptor; fall back
                                                // to scanning for a $default
                                                // overload.
                                                let desc_for_types =
                                                    skotch_classinfo::lookup_method_descriptor(
                                                        &facade,
                                                        &callee_str,
                                                        placed.len(),
                                                    )
                                                    .or_else(|| {
                                                        (1..=8usize).find_map(|extra| {
                                                        skotch_classinfo::lookup_method_descriptor(
                                                            &facade,
                                                            &format!("{callee_str}$default"),
                                                            placed.len() + extra,
                                                        )
                                                    })
                                                    });
                                                let desc_param_tys = desc_for_types
                                                    .as_deref()
                                                    .map(param_tys_from_descriptor)
                                                    .unwrap_or_default();
                                                let mut new_arg_locals: Vec<LocalId> =
                                                    Vec::with_capacity(last + 1);
                                                for (slot, slot_local) in
                                                    placed.iter().take(last + 1).enumerate()
                                                {
                                                    if let Some(local) = slot_local {
                                                        new_arg_locals.push(*local);
                                                    } else {
                                                        if slot < 32 {
                                                            reorder_default_mask |= 1u32 << slot;
                                                        }
                                                        let slot_ty = desc_param_tys
                                                            .get(slot)
                                                            .cloned()
                                                            .unwrap_or(Ty::Any);
                                                        let pad = fb.new_local(slot_ty.clone());
                                                        let init = match &slot_ty {
                                                            Ty::Int
                                                            | Ty::Byte
                                                            | Ty::Short
                                                            | Ty::Char => {
                                                                Rvalue::Const(MirConst::Int(0))
                                                            }
                                                            Ty::Long => {
                                                                Rvalue::Const(MirConst::Long(0))
                                                            }
                                                            Ty::Float => {
                                                                Rvalue::Const(MirConst::Float(0.0))
                                                            }
                                                            Ty::Double => {
                                                                Rvalue::Const(MirConst::Double(0.0))
                                                            }
                                                            Ty::Bool => {
                                                                Rvalue::Const(MirConst::Bool(false))
                                                            }
                                                            _ => Rvalue::Const(MirConst::Null),
                                                        };
                                                        fb.push_stmt(MStmt::Assign {
                                                            dest: pad,
                                                            value: init,
                                                        });
                                                        new_arg_locals.push(pad);
                                                    }
                                                }
                                                arg_locals = new_arg_locals;
                                            }
                                        }
                                    }
                                }
                            }
                            let user_n = arg_locals.len();
                            // Exact-arity match: user supplied all params (no
                            // defaults needed). Common when the fn has no
                            // defaults, or the user wrote every arg.
                            if let Some(desc) = skotch_classinfo::lookup_method_descriptor(
                                &facade,
                                &callee_str,
                                user_n,
                            ) {
                                let ret_ty = ty_from_descriptor_return(&desc);
                                let dest = fb.new_local(ret_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::StaticJava {
                                            class_name: facade,
                                            method_name: callee_str.to_string(),
                                            descriptor: desc,
                                        },
                                        args: arg_locals,
                                    },
                                });
                                return Some(dest);
                            }
                            // Search for `<name>$default` with arity
                            // `user_n + extra` for `extra` in 1..=32. The
                            // synthetic's `primary_count` is `total - 2`
                            // (mask + Object). 32 is sufficient for compose
                            // signatures, which can be deep but rarely
                            // exceed ~24 primary params.
                            let default_name = format!("{callee_str}$default");
                            let mut synthetic_name = default_name.clone();
                            let mut synthetic = (1..=32usize).find_map(|extra| {
                                skotch_classinfo::lookup_method_descriptor(
                                    &facade,
                                    &default_name,
                                    user_n + extra,
                                )
                            });
                            // Fallback: mangled `<name>-<hash>$default` for
                            // overloads that take inline value-class params
                            // (Color/Dp/TextUnit/etc.), where kotlinc
                            // mangles the JVM name. The whole material3
                            // surface (Text/Surface/most Icon overloads)
                            // emits ONLY mangled `$default` synthetics —
                            // their source-level `<name>$default` does not
                            // exist as a JVM method. We can't widen
                            // `matches_mangled` to accept this pattern in
                            // the general lookup because multiple mangled
                            // overloads may share an arity but differ in
                            // their param types — naive arity-only matching
                            // picks the wrong one and corrupts the call's
                            // descriptor (iter 22/23 hit a TypographyKt
                            // VerifyError when `Font-<resId>$default` won
                            // for a `Font(GoogleFont, ...)` call site).
                            // Instead, enumerate all candidates and choose
                            // the one whose param types are assignable from
                            // the user's arg types.
                            if synthetic.is_none() {
                                let arg_tys: Vec<Ty> = arg_locals
                                    .iter()
                                    .map(|l| fb.mf.locals[l.0 as usize].clone())
                                    .collect();
                                let stem_dash = format!("{callee_str}-");
                                // Compose's `@JvmInline value class` types
                                // erase to primitives on the JVM (Color→long,
                                // Dp→float, TextUnit→long, etc.). The user-
                                // level Ty for `Color.Red` is
                                // `Ty::Class("androidx/compose/ui/graphics/
                                // Color")`, but the descriptor param for a
                                // color slot is `J`. Strict
                                // `Ty::assignable_to` rejects that match, so
                                // composables that take Color/Dp/TextUnit
                                // params (Text/Surface/Scaffold overloads)
                                // never find a compatible mangled-`$default`
                                // candidate and the enclosing function's
                                // body drops (#358). Accept the match when
                                // the user arg is one of these known value
                                // classes and the descriptor expects the
                                // corresponding primitive.
                                let value_class_jvm_ty = |c: &str| -> Option<Ty> {
                                    match c {
                                        // Color: value class around ULong → J on the JVM.
                                        "androidx/compose/ui/graphics/Color"
                                        // Compose unit/text value classes (long-erased).
                                        | "androidx/compose/ui/unit/TextUnit"
                                        | "androidx/compose/ui/unit/DpOffset"
                                        | "androidx/compose/ui/unit/DpSize"
                                        | "androidx/compose/ui/unit/IntOffset"
                                        | "androidx/compose/ui/unit/IntSize"
                                        // Compose geometry value classes — these live in
                                        // `geometry/`, NOT `unit/` (an earlier iter-26 cut
                                        // had the wrong package prefix and never matched).
                                        | "androidx/compose/ui/geometry/Size"
                                        | "androidx/compose/ui/geometry/Offset" => Some(Ty::Long),
                                        // Dp is the lone Float-backed value class in the
                                        // common compose-unit surface.
                                        "androidx/compose/ui/unit/Dp" => Some(Ty::Float),
                                        _ => None,
                                    }
                                };
                                let mut best: Option<(String, String, usize)> = None;
                                for (mname, mdesc) in skotch_classinfo::iter_class_methods(&facade)
                                {
                                    if !mname.starts_with(&stem_dash)
                                        || !mname.ends_with("$default")
                                    {
                                        continue;
                                    }
                                    let total =
                                        skotch_classinfo::count_descriptor_params_pub(&mdesc);
                                    if total <= user_n + 1 {
                                        continue;
                                    }
                                    let dparams = descriptor_arg_tys(&mdesc);
                                    if dparams.len() < user_n {
                                        continue;
                                    }
                                    let mut compat = true;
                                    let mut score = 0usize;
                                    for (i, ut) in arg_tys.iter().enumerate() {
                                        let pt = &dparams[i];
                                        let value_class_match = if let Ty::Class(c) = ut {
                                            value_class_jvm_ty(c).is_some_and(|j| j == *pt)
                                        } else {
                                            false
                                        };
                                        if matches!(pt, Ty::Any)
                                            || ut.assignable_to(pt)
                                            || value_class_match
                                        {
                                            if !matches!(pt, Ty::Any) {
                                                score += 1;
                                            }
                                        } else {
                                            compat = false;
                                            break;
                                        }
                                    }
                                    if !compat {
                                        continue;
                                    }
                                    if best.as_ref().is_none_or(|(_, _, s)| score > *s) {
                                        best = Some((mname.clone(), mdesc.clone(), score));
                                    }
                                }
                                if let Some((mname, mdesc, _)) = best {
                                    synthetic_name = mname;
                                    synthetic = Some(mdesc);
                                }
                            }
                            if let Some(desc) = synthetic {
                                let total = skotch_classinfo::count_descriptor_params_pub(&desc);
                                let primary_count = total.saturating_sub(2);
                                let param_chars = parse_descriptor_param_chars(&desc);
                                // For an external `@Composable` synthetic,
                                // kotlinc's primary signature ends with
                                // `..., Composer, $changed` (Compose
                                // transform), then `$default_mask, Object`
                                // (default-param wrapper). The mask bits
                                // index ONLY the user-level params — they
                                // do NOT cover `Composer`/`$changed`, which
                                // the caller must always supply. Detect the
                                // Composer slot and bound the user-pad +
                                // mask there; everything past it is the
                                // Compose-injected tail (#358).
                                let composer_sym = interner.intern("$composer");
                                let changed_sym = interner.intern("$changed");
                                let scope_composer = scope
                                    .iter()
                                    .rev()
                                    .find(|(s, _)| *s == composer_sym)
                                    .map(|(_, id)| *id);
                                let scope_changed = scope
                                    .iter()
                                    .rev()
                                    .find(|(s, _)| *s == changed_sym)
                                    .map(|(_, id)| *id);
                                let composer_abs_pos = composer_position_in_descriptor(&desc);
                                let user_count_total = composer_abs_pos.unwrap_or(primary_count);
                                // Pad user-omitted user-level slots with
                                // zero/null per the descriptor's primitive
                                // kind, and set the mask bits for those
                                // positions only.
                                let mut mask: i32 = reorder_default_mask as i32;
                                for i in user_n..user_count_total {
                                    let kind = param_chars.get(i).copied().unwrap_or('L');
                                    let (slot_ty, value) = match kind {
                                        'I' => (Ty::Int, Rvalue::Const(MirConst::Int(0))),
                                        'J' => (Ty::Long, Rvalue::Const(MirConst::Long(0))),
                                        'F' => (Ty::Float, Rvalue::Const(MirConst::Float(0.0))),
                                        'D' => (Ty::Double, Rvalue::Const(MirConst::Double(0.0))),
                                        'Z' => (Ty::Bool, Rvalue::Const(MirConst::Int(0))),
                                        _ => (Ty::Any, Rvalue::Const(MirConst::Null)),
                                    };
                                    let pad = fb.new_local(slot_ty);
                                    fb.push_stmt(MStmt::Assign { dest: pad, value });
                                    arg_locals.push(pad);
                                    if i < 32 {
                                        mask |= 1 << i;
                                    }
                                }
                                // For `@Composable` external calls, inject
                                // the enclosing scope's `$composer` (and
                                // `$changed` int) at their dedicated slots
                                // BEFORE the `$default_mask`. Without this
                                // the call lands `aconst_null` in the
                                // Composer slot and the Compose runtime
                                // short-circuits the body — that's why the
                                // UI was blank after iter 18 wired up the
                                // `$default` dispatch (#358).
                                if composer_abs_pos.is_some() {
                                    if let Some(cid) = scope_composer {
                                        arg_locals.push(cid);
                                    } else {
                                        let composer_local = fb.new_local(Ty::Class(
                                            "androidx/compose/runtime/Composer".to_string(),
                                        ));
                                        fb.push_stmt(MStmt::Assign {
                                            dest: composer_local,
                                            value: Rvalue::Const(MirConst::Null),
                                        });
                                        arg_locals.push(composer_local);
                                    }
                                    if let Some(cid) = scope_changed {
                                        arg_locals.push(cid);
                                    } else {
                                        let changed_local = fb.new_local(Ty::Int);
                                        fb.push_stmt(MStmt::Assign {
                                            dest: changed_local,
                                            value: Rvalue::Const(MirConst::Int(0)),
                                        });
                                        arg_locals.push(changed_local);
                                    }
                                }
                                let mask_local = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: mask_local,
                                    value: Rvalue::Const(MirConst::Int(mask)),
                                });
                                arg_locals.push(mask_local);
                                // The trailing `Object` marker is always
                                // null in Kotlin's `$default` calling
                                // convention.
                                let marker_local =
                                    fb.new_local(Ty::Class("java/lang/Object".to_string()));
                                fb.push_stmt(MStmt::Assign {
                                    dest: marker_local,
                                    value: Rvalue::Const(MirConst::Null),
                                });
                                arg_locals.push(marker_local);
                                let ret_ty = ty_from_descriptor_return(&desc);
                                let dest = fb.new_local(ret_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::StaticJava {
                                            class_name: facade,
                                            method_name: synthetic_name,
                                            descriptor: desc,
                                        },
                                        args: arg_locals,
                                    },
                                });
                                return Some(dest);
                            }
                        }
                    }
                }
            }

            // ─── Cross-file class constructor ─────────────────────────
            // If the callee matches a cross-file user class (registered via
            // PackageSymbolTable), emit NewInstance + Constructor.
            if let Some((jvm_class, _, _)) = module
                .cross_file_classes
                .get(&callee_str.to_string())
                .cloned()
            {
                // Reorder named args (`Foo(name = ..., other = ...)`) to
                // positional order using the stub MirClass's
                // `param_names`. Cross-file classes never participated in
                // named-arg reordering before this — call sites went out
                // in source order — and that broke data classes whose
                // declaration order didn't match the source order at the
                // call site (e.g. `ConversationUiState(initialMessages =
                // ..., channelName = ..., channelMembers = ...)` was
                // emitting `<init>(Object, String, int)` against a
                // declared `<init>(String, int, List)`, triggering a
                // verifier reject).
                let stub_ctor_names: Vec<String> = module
                    .classes
                    .iter()
                    .find(|c| c.name == jvm_class)
                    .map(|c| c.constructor.param_names.clone())
                    .unwrap_or_default();
                let has_named = args.iter().any(|a| a.name.is_some());
                let ordered_args: Vec<&skotch_syntax::CallArg> =
                    if has_named && !stub_ctor_names.is_empty() {
                        let mut by_name: Vec<Option<&skotch_syntax::CallArg>> =
                            vec![None; stub_ctor_names.len()];
                        let mut positional_cursor = 0usize;
                        let mut failed = false;
                        for a in args {
                            if let Some(label_sym) = a.name {
                                let label = interner.resolve(label_sym);
                                if let Some(idx) =
                                    stub_ctor_names.iter().position(|n| n.as_str() == label)
                                {
                                    by_name[idx] = Some(a);
                                } else {
                                    failed = true;
                                    break;
                                }
                            } else {
                                while positional_cursor < by_name.len()
                                    && by_name[positional_cursor].is_some()
                                {
                                    positional_cursor += 1;
                                }
                                if positional_cursor < by_name.len() {
                                    by_name[positional_cursor] = Some(a);
                                    positional_cursor += 1;
                                } else {
                                    failed = true;
                                    break;
                                }
                            }
                        }
                        if failed {
                            args.iter().collect()
                        } else {
                            by_name.into_iter().flatten().collect()
                        }
                    } else {
                        args.iter().collect()
                    };
                let mut arg_locals = Vec::new();
                for a in &ordered_args {
                    let id = lower_expr(
                        &a.expr,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    arg_locals.push(id);
                }
                let dest = fb.new_local(Ty::Class(jvm_class.clone()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance(jvm_class.clone()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::Constructor(jvm_class),
                        args: arg_locals,
                    },
                });
                return Some(dest);
            }

            // ─── Special form: println(<string template>) ───────────
            if interner.resolve(callee_name) == "println"
                && args.len() == 1
                && matches!(&args[0].expr, Expr::StringTemplate(_, _))
            {
                if let Expr::StringTemplate(parts, _) = &args[0].expr {
                    // Constant folding: if the entire template is a
                    // compile-time constant, lower as `println(<folded>)`
                    // with a regular string literal argument. Matches kotlinc.
                    if let Some(folded) = try_const_fold_template(parts, interner) {
                        let sid = module.intern_string(&folded);
                        let arg_local = fb.new_local(Ty::String);
                        fb.push_stmt(MStmt::Assign {
                            dest: arg_local,
                            value: Rvalue::Const(MirConst::String(sid)),
                        });
                        let dest = fb.new_local(Ty::Unit);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Println,
                                args: vec![arg_local],
                            },
                        });
                        return Some(dest);
                    }
                    let mut arg_locals = Vec::with_capacity(parts.len());
                    for part in parts {
                        let id = lower_template_part(
                            part,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                        )?;
                        arg_locals.push(id);
                    }
                    let dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::PrintlnConcat,
                            args: arg_locals,
                        },
                    });
                    return Some(dest);
                }
            }

            // For `with(receiver) { ... }`, set the lambda receiver
            // type after lowering the first (receiver) arg.
            let is_with_call = callee_str == "with";

            // If the callee is a coroutine builder, set a flag so
            // trailing lambda args are created as SuspendLambda.
            let is_coroutine_builder = callee_str == "runBlocking"
                || callee_str == "launch"
                || callee_str == "async"
                || callee_str == "withContext"
                || callee_str == "coroutineScope"
                || callee_str == "supervisorScope"
                || callee_str == "withTimeout"
                || callee_str == "withTimeoutOrNull";
            if is_coroutine_builder {
                module.force_suspend_lambda = true;
            }

            // Well-known functions that take a trailing lambda with receiver.
            // The receiver type is set just before lowering the LAST lambda
            // arg so earlier lambdas (e.g. `content` in Layout) don't consume it.
            let known_trailing_receiver: Option<&str> = match callee_str.as_str() {
                "buildAnnotatedString" => Some("androidx/compose/ui/text/AnnotatedString$Builder"),
                "buildString" => Some("java/lang/StringBuilder"),
                "buildList" | "buildMutableList" => Some("java/util/ArrayList"),
                "buildMap" | "buildMutableMap" => Some("java/util/LinkedHashMap"),
                "buildSet" | "buildMutableSet" => Some("java/util/LinkedHashSet"),
                "Layout" => Some("androidx/compose/ui/layout/MeasureScope"),
                _ => None,
            };
            // Find the index of the last lambda arg so we can set the
            // receiver type just before lowering it (not before earlier lambdas).
            let last_lambda_idx = if known_trailing_receiver.is_some() {
                args.iter()
                    .rposition(|a| matches!(&a.expr, Expr::Lambda { .. }))
            } else {
                None
            };

            // Lower arguments. If any are named, we'll reorder after.
            let has_named = args.iter().any(|a| a.name.is_some());
            let mut named_pairs: Vec<(Option<Symbol>, LocalId)> = Vec::new();
            // Look up param_receiver_types for the target function so
            // we can set lambda_receiver_type before lowering lambda args.
            let param_recv_types: Vec<(usize, String)> = name_to_func
                .get(&callee_name)
                .map(|fid| {
                    module.functions[fid.0 as usize]
                        .param_receiver_types
                        .clone()
                })
                .unwrap_or_default();
            // Get the parameter types of the target so we can expand
            // callable-reference desugars (e.g. `::inflate` lambdas need
            // to match a Function3 slot, not Function1).
            let mut param_tys: Vec<Ty> = name_to_func
                .get(&callee_name)
                .map(|fid| {
                    let f = &module.functions[fid.0 as usize];
                    f.params
                        .iter()
                        .map(|p| f.locals[p.0 as usize].clone())
                        .collect()
                })
                .unwrap_or_default();
            // External static functions (e.g. imported Kotlin Kt-facade
            // calls) aren't in `name_to_func`, but we can still recover
            // their param types from the classinfo descriptor.
            if param_tys.is_empty() {
                if let Some(desc) =
                    find_external_static_descriptor(callee_str.as_str(), module, args.len())
                {
                    param_tys = descriptor_arg_tys(&desc);
                }
            }
            for (arg_idx, a) in args.iter().enumerate() {
                // If this arg position has a receiver type and the arg
                // is a lambda, set the receiver type flag.
                if let Some((_, recv_ty)) = param_recv_types.iter().find(|(idx, _)| *idx == arg_idx)
                {
                    if matches!(&a.expr, Expr::Lambda { .. }) {
                        module.lambda_receiver_type = Some(recv_ty.clone());
                    }
                }
                // For well-known functions with trailing lambda receiver,
                // set the receiver type just before the last lambda arg.
                if Some(arg_idx) == last_lambda_idx {
                    if let Some(recv_class) = known_trailing_receiver {
                        module.lambda_receiver_type = Some(recv_class.to_string());
                    }
                }
                // If the arg is a single-param lambda passed to a `(T) -> R`
                // slot, propagate `T` so the lambda helper's invoke descriptor
                // uses the primitive/concrete type (matches kotlinc; otherwise
                // we'd erase to Object and emit an unbox in the helper body).
                if matches!(&a.expr, Expr::Lambda { .. }) {
                    // First try the structured `Ty::Function` form. If the
                    // callee's param was erased to
                    // `kotlin/jvm/functions/FunctionN` at decl-lowering
                    // time, recover the original lambda param types from
                    // `local_generic_args` (preserved in `lower_fun_decl`).
                    let recovered: Option<Vec<Ty>> = match param_tys.get(arg_idx) {
                        Some(Ty::Function { params: fp, .. }) => Some(fp.clone()),
                        _ => name_to_func.get(&callee_name).and_then(|fid| {
                            let target = &module.functions[fid.0 as usize];
                            target
                                .params
                                .get(arg_idx)
                                .and_then(|pid| target.local_generic_args.get(&pid.0).cloned())
                        }),
                    };
                    if let Some(fparams) = recovered {
                        if fparams.len() == 1 && !matches!(fparams[0], Ty::Any) {
                            module.lambda_param_type = Some(fparams[0].clone());
                        }
                    }
                }
                // If the arg is a callable-reference desugar and the
                // target expects a higher-arity FunctionN, expand it.
                let expanded_arg = param_tys.get(arg_idx).and_then(|expected_ty| {
                    maybe_expand_callable_ref(&a.expr, expected_ty, interner)
                });
                let arg_expr_ref: &Expr = expanded_arg.as_ref().unwrap_or(&a.expr);
                let id = lower_expr(
                    arg_expr_ref,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    loop_ctx,
                )?;
                named_pairs.push((a.name, id));
                // For `with(receiver, lambda)`: after lowering the first
                // (receiver) arg, set the receiver type for the lambda.
                if is_with_call && arg_idx == 0 {
                    let arg_ty = &fb.mf.locals[id.0 as usize];
                    if let Ty::Class(cn) = arg_ty {
                        module.lambda_receiver_type = Some(cn.clone());
                    }
                }
            }
            // Clear the force flag in case it wasn't consumed
            // (e.g. the lambda was a capture, not a literal).
            module.force_suspend_lambda = false;
            // Clear lambda param/receiver-type channels in case the lambda
            // arg took a non-metafactory path that didn't consume them.
            module.lambda_param_type = None;
            module.lambda_receiver_type = None;

            // Reorder named arguments to match parameter order.
            let mut arg_locals: Vec<LocalId> = if has_named {
                // Look up the function's parameter names from the MIR module.
                let param_name_strs: Vec<String> = name_to_func
                    .get(&callee_name)
                    .map(|fid| module.functions[fid.0 as usize].param_names.clone())
                    .unwrap_or_default();

                if param_name_strs.is_empty() {
                    // No param names found — keep positional order.
                    named_pairs.iter().map(|(_, id)| *id).collect()
                } else {
                    let mut reordered = vec![None; param_name_strs.len()];
                    let mut positional_idx = 0;
                    for (name_opt, id) in &named_pairs {
                        if let Some(name_sym) = name_opt {
                            let name_str = interner.resolve(*name_sym);
                            if let Some(pos) = param_name_strs.iter().position(|pn| pn == name_str)
                            {
                                reordered[pos] = Some(*id);
                            } else {
                                // Unknown param name — keep in order.
                                if positional_idx < reordered.len() {
                                    reordered[positional_idx] = Some(*id);
                                    positional_idx += 1;
                                }
                            }
                        } else {
                            // Positional arg: fill the next unfilled slot.
                            while positional_idx < reordered.len()
                                && reordered[positional_idx].is_some()
                            {
                                positional_idx += 1;
                            }
                            if positional_idx < reordered.len() {
                                reordered[positional_idx] = Some(*id);
                                positional_idx += 1;
                            }
                        }
                    }
                    reordered.into_iter().flatten().collect()
                }
            } else {
                named_pairs.iter().map(|(_, id)| *id).collect()
            };

            // If fewer args provided than params, inject default values
            // and track which positions came from defaults so the JVM
            // backend can route the call through `name$default(...)`.
            let mut default_mask: u32 = 0;
            if let Some(fid) = name_to_func.get(&callee_name) {
                let defaults = module.functions[fid.0 as usize].param_defaults.clone();
                let total_params = defaults.len();
                if !defaults.is_empty() && arg_locals.len() < total_params {
                    for i in arg_locals.len()..total_params {
                        if let Some(Some(default_const)) = defaults.get(i) {
                            let ty = const_ty(default_const);
                            let id = fb.new_local(ty);
                            fb.push_stmt(MStmt::Assign {
                                dest: id,
                                value: Rvalue::Const(default_const.clone()),
                            });
                            arg_locals.push(id);
                            if i < 32 {
                                default_mask |= 1u32 << i;
                            }
                        }
                    }
                }
            }

            // ─── Vararg packing ──────────────────────────────────────
            // If the target function has a vararg parameter, pack all
            // arguments from that index onward into a single IntArray.
            if let Some(fid) = name_to_func.get(&callee_name) {
                let vi = module.functions[fid.0 as usize].vararg_index;
                if let Some(va_idx) = vi {
                    if arg_locals.len() >= va_idx {
                        let vararg_args: Vec<LocalId> = arg_locals.drain(va_idx..).collect();
                        // Spread optimization: if there's exactly one arg and
                        // it's already an IntArray, pass it directly (no repack).
                        // This handles `sum(*intArrayOf(1,2,3))` and `sum(*arr)`.
                        let is_spread = vararg_args.len() == 1
                            && matches!(
                                fb.mf.locals[vararg_args[0].0 as usize],
                                Ty::IntArray
                                    | Ty::LongArray
                                    | Ty::DoubleArray
                                    | Ty::BooleanArray
                                    | Ty::ByteArray
                            );
                        if is_spread {
                            arg_locals.push(vararg_args[0]);
                        } else {
                            let count = vararg_args.len();
                            let count_local = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest: count_local,
                                value: Rvalue::Const(MirConst::Int(count as i32)),
                            });
                            let arr = fb.new_local(Ty::IntArray);
                            fb.push_stmt(MStmt::Assign {
                                dest: arr,
                                value: Rvalue::NewIntArray(count_local),
                            });
                            for (i, elem) in vararg_args.iter().enumerate() {
                                let idx_local = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: idx_local,
                                    value: Rvalue::Const(MirConst::Int(i as i32)),
                                });
                                let store_dest = fb.new_local(Ty::Unit);
                                fb.push_stmt(MStmt::Assign {
                                    dest: store_dest,
                                    value: Rvalue::ArrayStore {
                                        array: arr,
                                        index: idx_local,
                                        value: *elem,
                                    },
                                });
                            }
                            arg_locals.push(arr);
                        }
                    }
                }
            }

            let callee_str = callee_str.as_str();

            // ── `runBlocking { }` ──────────────────────────
            //
            // `fun main() = runBlocking { delay(10); println("done") }`
            //
            // kotlinc compiles this as:
            //   aconst_null                       // CoroutineContext arg (null → default)
            //   new Lambda; dup; aconst_null
            //   invokespecial Lambda.<init>(Continuation)V
            //   checkcast Function2
            //   iconst_1                          // default-mask (bit 0 = context defaulted)
            //   aconst_null                       // unused handler
            //   invokestatic BuildersKt.runBlocking$default(
            //       CoroutineContext, Function2, int, Object)Object
            //   pop                               // result is Unit
            //
            // The trailing lambda has already been lowered as a suspend lambda
            // class with arity 2 (CoroutineScope + Continuation → Function2).
            // The `arg_locals` at this point contain the lambda instance.
            if callee_str == "runBlocking" && arg_locals.len() == 1 {
                let lambda_local = arg_locals[0];

                // The trailing lambda for runBlocking has type
                // `suspend CoroutineScope.() -> T`, which is
                // `Function2<CoroutineScope, Continuation<T>, Object>`.
                // The MIR lowerer created it as a suspend lambda with
                // arity 1 (Function1). We need to bump it to arity 2
                // (Function2) so that `runBlocking$default` can call it.
                //
                // Find the lambda class by type and patch its interfaces.
                let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                if let Ty::Class(ref lambda_class_name) = lambda_ty {
                    if let Some(cls) = module
                        .classes
                        .iter_mut()
                        .find(|c| &c.name == lambda_class_name)
                    {
                        // Replace any FunctionN → Function2 in interfaces.
                        for iface in cls.interfaces.iter_mut() {
                            if iface.starts_with("kotlin/jvm/functions/Function") {
                                *iface = "kotlin/jvm/functions/Function2".to_string();
                            }
                        }
                    }
                }

                // Push null for CoroutineContext (defaulted).
                let null_ctx =
                    fb.new_local(Ty::Class("kotlin/coroutines/CoroutineContext".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: null_ctx,
                    value: Rvalue::Const(MirConst::Null),
                });

                // Cast lambda to Function2.
                let func2_local =
                    fb.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: func2_local,
                    value: Rvalue::CheckCast {
                        obj: lambda_local,
                        target_class: "kotlin/jvm/functions/Function2".to_string(),
                    },
                });

                // Push iconst_1 (default mask: bit 0 → context is defaulted).
                let mask_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: mask_local,
                    value: Rvalue::Const(MirConst::Int(1)),
                });

                // Push null for the unused handler arg.
                let null_handler = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: null_handler,
                    value: Rvalue::Const(MirConst::Null),
                });

                // Call BuildersKt.runBlocking$default(
                //     CoroutineContext, Function2, int, Object)Object
                let result = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlinx/coroutines/BuildersKt".to_string(),
                            method_name: "runBlocking$default".to_string(),
                            descriptor: "(Lkotlin/coroutines/CoroutineContext;Lkotlin/jvm/functions/Function2;ILjava/lang/Object;)Ljava/lang/Object;".to_string(),
                        },
                        args: vec![null_ctx, func2_local, mask_local, null_handler],
                    },
                });
                return Some(result);
            }

            // ── `launch { }` and `async { }` builders ────
            //
            // `launch { body }` and `async { body }` are coroutine
            // builders from kotlinx-coroutines. For simplicity we use
            // `GlobalScope.launch$default` / `GlobalScope.async$default`
            // rather than threading the CoroutineScope from
            // `runBlocking`'s lambda receiver. This means these launches
            // are NOT structured (GlobalScope never cancels), but it
            // produces correct runtime behavior for basic patterns.
            //
            // kotlinc reference call site:
            //   getstatic GlobalScope.INSTANCE:GlobalScope
            //   aconst_null                // CoroutineContext (default)
            //   aconst_null                // CoroutineStart  (default)
            //   new Lambda; dup; aconst_null; invokespecial <init>
            //   checkcast Function2
            //   iconst_3                   // default mask (bits 0+1)
            //   aconst_null                // unused handler
            //   invokestatic BuildersKt.launch$default(
            //       CoroutineScope, CoroutineContext, CoroutineStart,
            //       Function2, int, Object)Job
            //
            // `async` is identical but returns `Deferred` instead of `Job`.
            if (callee_str == "launch" || callee_str == "async") && arg_locals.len() == 1 {
                let lambda_local = arg_locals[0];

                // The trailing lambda for launch/async has type
                // `suspend CoroutineScope.() -> T`, i.e.
                // `Function2<CoroutineScope, Continuation<T>, Object>`.
                // Patch any FunctionN → Function2 and mark as suspend lambda
                // so the JVM backend emits the SuspendLambda shell.
                //
                // IMPORTANT: lambda_local is in the CURRENT FnBuilder (fb).
                // When inside a suspend lambda's invoke body, fb is the
                // invoke FnBuilder, not the top-level one. The local's type
                // is the inner lambda's class name.
                let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                if let Ty::Class(ref lambda_class_name) = lambda_ty {
                    if let Some(cls) = module
                        .classes
                        .iter_mut()
                        .find(|c| &c.name == lambda_class_name)
                    {
                        for iface in cls.interfaces.iter_mut() {
                            if iface.starts_with("kotlin/jvm/functions/Function") {
                                *iface = "kotlin/jvm/functions/Function2".to_string();
                            }
                        }
                        // Force SuspendLambda even if body has no suspend calls
                        // (the lambda is being passed to a coroutine builder).
                        if !cls.is_suspend_lambda {
                            cls.is_suspend_lambda = true;
                            cls.super_class =
                                Some("kotlin/coroutines/jvm/internal/SuspendLambda".to_string());
                        }
                    }
                }

                // Structured concurrency — use the enclosing
                // CoroutineScope from this.p$0 if available (set by the
                // SuspendLambda shell's create method). Fall back to
                // GlobalScope for non-lambda contexts.
                let this_sym = interner.intern("this");
                let scope_local = if let Some((_, this_local)) =
                    scope.iter().rev().find(|(s, _)| *s == this_sym)
                {
                    let this_ty = &fb.mf.locals[this_local.0 as usize];
                    // All suspend lambda classes get a p$0 field (added
                    // at finalization). Check if this class IS a suspend
                    // lambda by looking for the field OR by class name
                    // pattern (the field may not exist yet on the placeholder).
                    let has_scope_field = if let Ty::Class(cls_name) = this_ty {
                        module
                            .classes
                            .iter()
                            .find(|c| &c.name == cls_name)
                            .map(|c| {
                                c.fields.iter().any(|f| f.name == "p$0") || c.is_suspend_lambda
                            })
                            .unwrap_or(false)
                    } else {
                        false
                    };
                    if has_scope_field {
                        let cls_name = if let Ty::Class(n) = this_ty {
                            n.clone()
                        } else {
                            unreachable!()
                        };
                        // Load the scope from this.p$0 and cast to CoroutineScope.
                        let raw_scope = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest: raw_scope,
                            value: Rvalue::GetField {
                                receiver: *this_local,
                                class_name: cls_name,
                                field_name: "p$0".to_string(),
                            },
                        });
                        let cast_scope = fb
                            .new_local(Ty::Class("kotlinx/coroutines/CoroutineScope".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: cast_scope,
                            value: Rvalue::CheckCast {
                                obj: raw_scope,
                                target_class: "kotlinx/coroutines/CoroutineScope".to_string(),
                            },
                        });
                        cast_scope
                    } else {
                        // No p$0 field — use GlobalScope.
                        let gs =
                            fb.new_local(Ty::Class("kotlinx/coroutines/GlobalScope".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: gs,
                            value: Rvalue::GetStaticField {
                                class_name: "kotlinx/coroutines/GlobalScope".to_string(),
                                field_name: "INSTANCE".to_string(),
                                descriptor: "Lkotlinx/coroutines/GlobalScope;".to_string(),
                            },
                        });
                        gs
                    }
                } else {
                    let gs = fb.new_local(Ty::Class("kotlinx/coroutines/GlobalScope".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: gs,
                        value: Rvalue::GetStaticField {
                            class_name: "kotlinx/coroutines/GlobalScope".to_string(),
                            field_name: "INSTANCE".to_string(),
                            descriptor: "Lkotlinx/coroutines/GlobalScope;".to_string(),
                        },
                    });
                    gs
                };

                // null CoroutineContext (defaulted)
                let null_ctx =
                    fb.new_local(Ty::Class("kotlin/coroutines/CoroutineContext".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: null_ctx,
                    value: Rvalue::Const(MirConst::Null),
                });

                // null CoroutineStart (defaulted)
                let null_start =
                    fb.new_local(Ty::Class("kotlinx/coroutines/CoroutineStart".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: null_start,
                    value: Rvalue::Const(MirConst::Null),
                });

                // Cast lambda to Function2
                let func2_local =
                    fb.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: func2_local,
                    value: Rvalue::CheckCast {
                        obj: lambda_local,
                        target_class: "kotlin/jvm/functions/Function2".to_string(),
                    },
                });

                // iconst_3 (default mask: bits 0+1 = context + start defaulted)
                let mask_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: mask_local,
                    value: Rvalue::Const(MirConst::Int(3)),
                });

                // null handler arg
                let null_handler = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: null_handler,
                    value: Rvalue::Const(MirConst::Null),
                });

                if callee_str == "launch" {
                    // Call BuildersKt.launch$default(
                    //     CoroutineScope, CoroutineContext, CoroutineStart,
                    //     Function2, int, Object)Job
                    let result = fb.new_local(Ty::Class("kotlinx/coroutines/Job".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlinx/coroutines/BuildersKt".to_string(),
                                method_name: "launch$default".to_string(),
                                descriptor: "(Lkotlinx/coroutines/CoroutineScope;Lkotlin/coroutines/CoroutineContext;Lkotlinx/coroutines/CoroutineStart;Lkotlin/jvm/functions/Function2;ILjava/lang/Object;)Lkotlinx/coroutines/Job;".to_string(),
                            },
                            args: vec![scope_local, null_ctx, null_start, func2_local, mask_local, null_handler],
                        },
                    });
                    return Some(result);
                } else {
                    // async: same args, returns Deferred
                    let result = fb.new_local(Ty::Class("kotlinx/coroutines/Deferred".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlinx/coroutines/BuildersKt".to_string(),
                                method_name: "async$default".to_string(),
                                descriptor: "(Lkotlinx/coroutines/CoroutineScope;Lkotlin/coroutines/CoroutineContext;Lkotlinx/coroutines/CoroutineStart;Lkotlin/jvm/functions/Function2;ILjava/lang/Object;)Lkotlinx/coroutines/Deferred;".to_string(),
                            },
                            args: vec![scope_local, null_ctx, null_start, func2_local, mask_local, null_handler],
                        },
                    });
                    return Some(result);
                }
            }

            // ── `withContext(Dispatchers.X) { body }` ───
            //
            // `withContext` is an inline suspend function from
            // kotlinx-coroutines:
            //   kotlinx/coroutines/WithContextKt.withContext(
            //       CoroutineContext, Function2, Continuation)Object
            //
            // It takes a CoroutineContext as its first argument and a
            // suspend lambda block as its second. The lambda is a
            // `suspend CoroutineScope.() -> T` (Function2).
            //
            // Usage: withContext(Dispatchers.IO) { ... }
            //        withContext(Dispatchers.Default) { ... }
            if callee_str == "withContext" && arg_locals.len() == 2 {
                let ctx_local = arg_locals[0];
                let lambda_local = arg_locals[1];

                // Patch lambda to Function2 + SuspendLambda
                let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                if let Ty::Class(ref lambda_class_name) = lambda_ty {
                    if let Some(cls) = module
                        .classes
                        .iter_mut()
                        .find(|c| &c.name == lambda_class_name)
                    {
                        for iface in cls.interfaces.iter_mut() {
                            if iface.starts_with("kotlin/jvm/functions/Function") {
                                *iface = "kotlin/jvm/functions/Function2".to_string();
                            }
                        }
                        if !cls.is_suspend_lambda {
                            cls.is_suspend_lambda = true;
                            cls.super_class =
                                Some("kotlin/coroutines/jvm/internal/SuspendLambda".to_string());
                        }
                    }
                }

                // Cast lambda to Function2
                let func2_local =
                    fb.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: func2_local,
                    value: Rvalue::CheckCast {
                        obj: lambda_local,
                        target_class: "kotlin/jvm/functions/Function2".to_string(),
                    },
                });

                // withContext is a suspend function — emit as Static(stub)
                // so the state machine extractor detects it as a
                // suspension point and threads the continuation properly.
                let wc_sym = interner.intern("withContext");
                let wc_fid = *name_to_func
                    .get(&wc_sym)
                    .expect("withContext stub must be pre-registered");

                let cont_local = if fb.mf.is_suspend {
                    *fb.mf
                        .params
                        .last()
                        .expect("suspend fn must have $completion")
                } else {
                    let c = fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    c
                };

                let result = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::Static(wc_fid),
                        args: vec![ctx_local, func2_local, cont_local],
                    },
                });
                return Some(result);
            }

            // ── `coroutineScope { body }` ──────────────
            //
            // `coroutineScope` is an inline suspend function:
            //   kotlinx/coroutines/CoroutineScopeKt.coroutineScope(
            //       Function2, Continuation)Object
            //
            // The lambda is `suspend CoroutineScope.() -> R` (Function2).
            // `supervisorScope` has the same signature but lives in
            // SupervisorKt.
            if (callee_str == "coroutineScope" || callee_str == "supervisorScope")
                && arg_locals.len() == 1
            {
                let lambda_local = arg_locals[0];

                // Patch lambda to Function2 + SuspendLambda
                let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                if let Ty::Class(ref lambda_class_name) = lambda_ty {
                    if let Some(cls) = module
                        .classes
                        .iter_mut()
                        .find(|c| &c.name == lambda_class_name)
                    {
                        for iface in cls.interfaces.iter_mut() {
                            if iface.starts_with("kotlin/jvm/functions/Function") {
                                *iface = "kotlin/jvm/functions/Function2".to_string();
                            }
                        }
                        if !cls.is_suspend_lambda {
                            cls.is_suspend_lambda = true;
                            cls.super_class =
                                Some("kotlin/coroutines/jvm/internal/SuspendLambda".to_string());
                        }
                    }
                }

                // Cast lambda to Function2
                let func2_local =
                    fb.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: func2_local,
                    value: Rvalue::CheckCast {
                        obj: lambda_local,
                        target_class: "kotlin/jvm/functions/Function2".to_string(),
                    },
                });

                // coroutineScope/supervisorScope are suspend functions —
                // emit as Static(stub) for state machine detection.
                let stub_sym = interner.intern(callee_str);
                let stub_fid = *name_to_func
                    .get(&stub_sym)
                    .expect("coroutineScope/supervisorScope stub must be pre-registered");

                let cont_local = if fb.mf.is_suspend {
                    *fb.mf
                        .params
                        .last()
                        .expect("suspend fn must have $completion")
                } else {
                    let c = fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    c
                };

                let result = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::Static(stub_fid),
                        args: vec![func2_local, cont_local],
                    },
                });
                return Some(result);
            }

            // ── `withTimeout(ms) { body }` ────────────
            //
            // `withTimeout` and `withTimeoutOrNull` are suspend functions:
            //   kotlinx/coroutines/TimeoutKt.withTimeout(J, Function2, Continuation)Object
            //   kotlinx/coroutines/TimeoutKt.withTimeoutOrNull(J, Function2, Continuation)Object
            //
            // First arg is Long (millis), second is suspend lambda.
            if (callee_str == "withTimeout" || callee_str == "withTimeoutOrNull")
                && arg_locals.len() == 2
            {
                let ms_arg = arg_locals[0];
                let lambda_local = arg_locals[1];

                // Promote Int to Long if needed (same pattern as delay)
                let ms_local = {
                    let arg_ty = fb.mf.locals[ms_arg.0 as usize].clone();
                    if arg_ty == Ty::Int {
                        let mut promoted = false;
                        for stmt in fb.mf.blocks[fb.cur_block as usize].stmts.iter_mut().rev() {
                            let MStmt::Assign { dest, value } = stmt;
                            if *dest == ms_arg {
                                if let Rvalue::Const(MirConst::Int(v)) = value {
                                    let v_long = *v as i64;
                                    *value = Rvalue::Const(MirConst::Long(v_long));
                                    fb.mf.locals[ms_arg.0 as usize] = Ty::Long;
                                    promoted = true;
                                }
                                break;
                            }
                        }
                        if promoted {
                            ms_arg
                        } else {
                            let long_local = fb.new_local(Ty::Long);
                            fb.push_stmt(MStmt::Assign {
                                dest: long_local,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: "$i2l$".to_string(),
                                        method_name: "$i2l$".to_string(),
                                        descriptor: "(I)J".to_string(),
                                    },
                                    args: vec![ms_arg],
                                },
                            });
                            long_local
                        }
                    } else {
                        ms_arg
                    }
                };

                // Patch lambda to Function2 + SuspendLambda
                let lambda_ty = fb.mf.locals[lambda_local.0 as usize].clone();
                if let Ty::Class(ref lambda_class_name) = lambda_ty {
                    if let Some(cls) = module
                        .classes
                        .iter_mut()
                        .find(|c| &c.name == lambda_class_name)
                    {
                        for iface in cls.interfaces.iter_mut() {
                            if iface.starts_with("kotlin/jvm/functions/Function") {
                                *iface = "kotlin/jvm/functions/Function2".to_string();
                            }
                        }
                        if !cls.is_suspend_lambda {
                            cls.is_suspend_lambda = true;
                            cls.super_class =
                                Some("kotlin/coroutines/jvm/internal/SuspendLambda".to_string());
                        }
                    }
                }

                // Cast lambda to Function2
                let func2_local =
                    fb.new_local(Ty::Class("kotlin/jvm/functions/Function2".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: func2_local,
                    value: Rvalue::CheckCast {
                        obj: lambda_local,
                        target_class: "kotlin/jvm/functions/Function2".to_string(),
                    },
                });

                // Continuation
                let cont_local = if fb.mf.is_suspend {
                    *fb.mf
                        .params
                        .last()
                        .expect("suspend fn must have $completion")
                } else {
                    let c = fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    c
                };

                // withTimeout/withTimeoutOrNull are suspend functions —
                // emit as Static(stub) for state machine detection.
                let stub_sym = interner.intern(callee_str);
                let stub_fid = *name_to_func
                    .get(&stub_sym)
                    .expect("withTimeout stub must be pre-registered");

                let result = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::Static(stub_fid),
                        args: vec![ms_local, func2_local, cont_local],
                    },
                });
                return Some(result);
            }

            // ── `yield()` inside suspend context ───────
            //
            // `yield` is a suspend function from kotlinx-coroutines:
            //   kotlinx/coroutines/YieldKt.yield(Continuation)Object
            //
            // It yields the current coroutine's thread to allow other
            // coroutines to run (cooperative multitasking).
            if callee_str == "yield" && arg_locals.is_empty() {
                let yield_sym = interner.intern("yield");
                let yield_fid = *name_to_func
                    .get(&yield_sym)
                    .expect("yield stub must be pre-registered");

                let cont_local = if fb.mf.is_suspend {
                    *fb.mf
                        .params
                        .last()
                        .expect("suspend fn must have $completion")
                } else {
                    let c = fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    c
                };

                let dest = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::Static(yield_fid),
                        args: vec![cont_local],
                    },
                });
                return Some(dest);
            }

            // ── `delay(ms)` inside suspend context ──────
            //
            // `delay` is a kotlinx-coroutines suspend function:
            //   kotlinx/coroutines/DelayKt.delay(J, Continuation)Object
            //
            // The Int literal argument is promoted to Long. The
            // Continuation arg is the enclosing suspend function's
            // `$completion` (for named funs) or `this` (for suspend
            // lambdas, where the lambda IS the continuation).
            //
            // This call is a SUSPENSION POINT — it must be recognized
            // by the state machine extractor. We emit it as a
            // StaticJava call but also register a synthetic function
            // in the module so the extractor can match it.
            if callee_str == "delay" {
                // Promote Int arg to Long if needed. `delay` takes a
                // `Long` parameter, but Kotlin auto-promotes `Int`
                // literals. We scan backwards through the block for the
                // assignment that produced the arg local, and if it's a
                // `Const(Int(v))` we replace it in-place with
                // `Const(Long(v))` and retype the local. For non-literal
                // ints we emit a fresh Long local via `i2l`.
                let ms_local = if !arg_locals.is_empty() {
                    let arg = arg_locals[0];
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    if arg_ty == Ty::Int {
                        // Try to find the Const(Int) assignment to this local
                        // and promote it to Long in place.
                        let mut promoted = false;
                        for stmt in fb.mf.blocks[fb.cur_block as usize].stmts.iter_mut().rev() {
                            let MStmt::Assign { dest, value } = stmt;
                            if *dest == arg {
                                if let Rvalue::Const(MirConst::Int(v)) = value {
                                    let v_long = *v as i64;
                                    *value = Rvalue::Const(MirConst::Long(v_long));
                                    fb.mf.locals[arg.0 as usize] = Ty::Long;
                                    promoted = true;
                                }
                                break;
                            }
                        }
                        if promoted {
                            arg
                        } else {
                            // General case: emit i2l conversion via StaticJava stub.
                            // The JVM backend handles this by emitting the `i2l` opcode.
                            let long_local = fb.new_local(Ty::Long);
                            fb.push_stmt(MStmt::Assign {
                                dest: long_local,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: "$i2l$".to_string(),
                                        method_name: "$i2l$".to_string(),
                                        descriptor: "(I)J".to_string(),
                                    },
                                    args: vec![arg],
                                },
                            });
                            long_local
                        }
                    } else {
                        arg
                    }
                } else {
                    // delay() with no args — shouldn't happen, but
                    // default to 0L.
                    let zero_long = fb.new_local(Ty::Long);
                    fb.push_stmt(MStmt::Assign {
                        dest: zero_long,
                        value: Rvalue::Const(MirConst::Long(0)),
                    });
                    zero_long
                };

                // The `delay` stub was pre-registered in `lower_file`'s
                // Pass 1 so that `body_contains_suspend_call` can
                // detect it during suspend-lambda analysis. Look it up.
                let delay_sym = interner.intern("delay");
                let delay_fid = *name_to_func
                    .get(&delay_sym)
                    .expect("delay stub must be pre-registered");

                // Now emit the call as a Static call to the delay stub.
                // The state machine extractor will pick up that it's a
                // suspend call because delay_fid.is_suspend == true.
                //
                // Append the continuation (last param of enclosing fn if
                // suspend, else null).
                let cont_local = if fb.mf.is_suspend {
                    *fb.mf
                        .params
                        .last()
                        .expect("suspend fn must have $completion")
                } else {
                    let c = fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    c
                };

                let dest = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::Static(delay_fid),
                        args: vec![ms_local, cont_local],
                    },
                });
                return Some(dest);
            }

            // `listOf(...)` — call the real Kotlin stdlib
            // `kotlin/collections/CollectionsKt.listOf([Ljava/lang/Object;)Ljava/util/List;`.
            // We create an Object[] array, autobox + store each element, then invoke the stdlib.
            if callee_str == "listOf" {
                let arg_count = arg_locals.len();

                // Single-arg listOf: kotlinc dispatches to the
                // `listOf(T): List<T>` overload (descriptor
                // `(Ljava/lang/Object;)Ljava/util/List;`) rather than
                // the vararg form. Match that shape — no array
                // allocation, just box the element if primitive and
                // hand it directly to the single-arg overload.
                if arg_count == 1 {
                    let arg = arg_locals[0];
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    // Suspend functions use Boxing.boxXxx for primitive
                    // autoboxing (kotlinc convention); non-suspend
                    // functions use Integer.valueOf etc.
                    let boxed = if fb.mf.is_suspend {
                        mir_autobox_suspend(fb, arg, &arg_ty)
                    } else {
                        mir_autobox(fb, arg, &arg_ty)
                    };
                    let result = fb.new_local(Ty::Class("java/util/List".to_string()));
                    fb.mf
                        .local_generic_args
                        .insert(result.0, vec![arg_ty.clone()]);
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlin/collections/CollectionsKt".to_string(),
                                method_name: "listOf".to_string(),
                                descriptor: "(Ljava/lang/Object;)Ljava/util/List;".to_string(),
                            },
                            args: vec![boxed],
                        },
                    });
                    return Some(result);
                }

                // If all args share the same concrete class (`String`, a
                // user class, etc.), allocate a typed array
                // `anewarray Class(<element_class>)` — kotlinc does this
                // even though `listOf` is declared `<T> vararg T → List<T>`
                // (the descriptor is still `([Ljava/lang/Object;)`). The
                // typed allocation is just a bytecode-shape match; the
                // method signature stays Object[]. Falls back to
                // `NewObjectArray` if args are heterogeneous or primitive.
                let inferred_element_class: Option<String> = arg_locals
                    .first()
                    .and_then(|first| match &fb.mf.locals[first.0 as usize] {
                        Ty::Class(name) => Some(name.clone()),
                        Ty::String => Some("java/lang/String".to_string()),
                        _ => None,
                    })
                    .filter(|cls| {
                        arg_locals
                            .iter()
                            .all(|a| match &fb.mf.locals[a.0 as usize] {
                                Ty::Class(n) => n == cls,
                                Ty::String => cls == "java/lang/String",
                                _ => false,
                            })
                    });

                // Create the array of the right size.
                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                let array_rvalue = match &inferred_element_class {
                    Some(cls) => Rvalue::NewTypedObjectArray {
                        size: count_local,
                        element_class: cls.clone(),
                    },
                    None => Rvalue::NewObjectArray(count_local),
                };
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: array_rvalue,
                });

                // Store each arg into the Object[] (autoboxing primitives).
                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = mir_autobox(fb, arg, &arg_ty);
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                // Call kotlin/collections/CollectionsKt.listOf(Object[])List
                //
                // Type the result as the erased `Ty::Class("java/util/List")`
                // (downstream `.size`/`.add`/etc. dispatch matches on
                // class names containing "List"). Record the element
                // type in `local_generic_args` so the call-site lambda
                // param inference (`.filter { it.foo }`) can recover it
                // without changing the local's nominal type.
                let elem_ty = arg_locals
                    .first()
                    .map(|a| fb.mf.locals[a.0 as usize].clone())
                    .unwrap_or(Ty::Any);
                let result = fb.new_local(Ty::Class("java/util/List".to_string()));
                fb.mf.local_generic_args.insert(result.0, vec![elem_ty]);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/CollectionsKt".to_string(),
                            method_name: "listOf".to_string(),
                            descriptor: "([Ljava/lang/Object;)Ljava/util/List;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `mutableListOf(...)` — same pattern as listOf, but returns
            // `java/util/ArrayList` via
            // `kotlin/collections/CollectionsKt.mutableListOf([Object;)ArrayList`.
            if callee_str == "mutableListOf" {
                let arg_count = arg_locals.len();

                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: Rvalue::NewObjectArray(count_local),
                });

                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = mir_autobox(fb, arg, &arg_ty);
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                // Return type is java/util/List at JVM level. Keep the
                // erased Ty::Class and record element type in
                // local_generic_args (same approach as listOf above).
                let elem_ty = arg_locals
                    .first()
                    .map(|a| fb.mf.locals[a.0 as usize].clone())
                    .unwrap_or(Ty::Any);
                let result = fb.new_local(Ty::Class("java/util/List".to_string()));
                fb.mf.local_generic_args.insert(result.0, vec![elem_ty]);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/CollectionsKt".to_string(),
                            method_name: "mutableListOf".to_string(),
                            descriptor: "([Ljava/lang/Object;)Ljava/util/List;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `mapOf(pair1, pair2, ...)` — create Pair[] array, call
            // `kotlin/collections/MapsKt.mapOf([Lkotlin/Pair;)Ljava/util/Map;`.
            if callee_str == "mapOf" {
                let arg_count = arg_locals.len();

                // Create kotlin/Pair[] of the right size (must be Pair[], not Object[]).
                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: Rvalue::NewTypedObjectArray {
                        size: count_local,
                        element_class: "kotlin/Pair".to_string(),
                    },
                });

                // Store each Pair arg into the array.
                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = mir_autobox(fb, arg, &arg_ty);
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                // Call kotlin/collections/MapsKt.mapOf([Lkotlin/Pair;)Ljava/util/Map;
                let result = fb.new_local(Ty::Class("java/util/Map".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/MapsKt".to_string(),
                            method_name: "mapOf".to_string(),
                            descriptor: "([Lkotlin/Pair;)Ljava/util/Map;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `mutableMapOf(pair1, pair2, ...)` — same pattern as mapOf but
            // calls `MapsKt.mutableMapOf`.
            if callee_str == "mutableMapOf" {
                let arg_count = arg_locals.len();

                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: Rvalue::NewTypedObjectArray {
                        size: count_local,
                        element_class: "kotlin/Pair".to_string(),
                    },
                });

                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = mir_autobox(fb, arg, &arg_ty);
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                let result = fb.new_local(Ty::Class("java/util/Map".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/MapsKt".to_string(),
                            method_name: "mutableMapOf".to_string(),
                            descriptor: "([Lkotlin/Pair;)Ljava/util/Map;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `setOf(elements...)` — mirror the listOf treatment above:
            // single-arg → `setOf(Object)Set` overload; multi-arg → typed
            // `anewarray <ElemClass>` when all elements share a class,
            // else `Object[]`. Both forward to kotlin/collections/SetsKt.
            if callee_str == "setOf" {
                let arg_count = arg_locals.len();

                if arg_count == 1 {
                    let arg = arg_locals[0];
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = if fb.mf.is_suspend {
                        mir_autobox_suspend(fb, arg, &arg_ty)
                    } else {
                        mir_autobox(fb, arg, &arg_ty)
                    };
                    let result = fb.new_local(Ty::Class("java/util/Set".to_string()));
                    fb.mf.local_generic_args.insert(result.0, vec![arg_ty]);
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlin/collections/SetsKt".to_string(),
                                method_name: "setOf".to_string(),
                                descriptor: "(Ljava/lang/Object;)Ljava/util/Set;".to_string(),
                            },
                            args: vec![boxed],
                        },
                    });
                    return Some(result);
                }

                // Detect when every arg shares a concrete class (boxed
                // primitives count: Int → Integer, etc.) and use
                // `anewarray <ElemClass>` like kotlinc. Falls back to
                // Object[] for heterogeneous shapes.
                let elem_class_of = |ty: &Ty| -> Option<String> {
                    match ty {
                        Ty::Class(name) => Some(name.clone()),
                        Ty::String => Some("java/lang/String".to_string()),
                        Ty::Int => Some("java/lang/Integer".to_string()),
                        Ty::Long => Some("java/lang/Long".to_string()),
                        Ty::Double => Some("java/lang/Double".to_string()),
                        Ty::Float => Some("java/lang/Float".to_string()),
                        Ty::Bool => Some("java/lang/Boolean".to_string()),
                        Ty::Byte => Some("java/lang/Byte".to_string()),
                        Ty::Short => Some("java/lang/Short".to_string()),
                        Ty::Char => Some("java/lang/Character".to_string()),
                        _ => None,
                    }
                };
                let inferred_element_class: Option<String> = arg_locals
                    .first()
                    .and_then(|first| elem_class_of(&fb.mf.locals[first.0 as usize]))
                    .filter(|cls| {
                        arg_locals.iter().all(|a| {
                            elem_class_of(&fb.mf.locals[a.0 as usize]).as_ref() == Some(cls)
                        })
                    });

                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                let array_rvalue = match &inferred_element_class {
                    Some(cls) => Rvalue::NewTypedObjectArray {
                        size: count_local,
                        element_class: cls.clone(),
                    },
                    None => Rvalue::NewObjectArray(count_local),
                };
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: array_rvalue,
                });

                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = if fb.mf.is_suspend {
                        mir_autobox_suspend(fb, arg, &arg_ty)
                    } else {
                        mir_autobox(fb, arg, &arg_ty)
                    };
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                let elem_ty = arg_locals
                    .first()
                    .map(|a| fb.mf.locals[a.0 as usize].clone())
                    .unwrap_or(Ty::Any);
                let result = fb.new_local(Ty::Class("java/util/Set".to_string()));
                fb.mf.local_generic_args.insert(result.0, vec![elem_ty]);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/SetsKt".to_string(),
                            method_name: "setOf".to_string(),
                            descriptor: "([Ljava/lang/Object;)Ljava/util/Set;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `mutableSetOf(elements...)` — same pattern as setOf but calls
            // `SetsKt.mutableSetOf`.
            if callee_str == "mutableSetOf" {
                let arg_count = arg_locals.len();

                let count_local = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: count_local,
                    value: Rvalue::Const(MirConst::Int(arg_count as i32)),
                });
                let array_local = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: array_local,
                    value: Rvalue::NewObjectArray(count_local),
                });

                for (i, &arg) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                    let boxed = mir_autobox(fb, arg, &arg_ty);
                    let store_dest = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: store_dest,
                        value: Rvalue::ObjectArrayStore {
                            array: array_local,
                            index: idx,
                            value: boxed,
                        },
                    });
                }

                let result = fb.new_local(Ty::Class("java/util/Set".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "kotlin/collections/SetsKt".to_string(),
                            method_name: "mutableSetOf".to_string(),
                            descriptor: "([Ljava/lang/Object;)Ljava/util/Set;".to_string(),
                        },
                        args: vec![array_local],
                    },
                });
                return Some(result);
            }

            // `Pair(a, b)` — new kotlin/Pair(boxed_a, boxed_b).
            if callee_str == "Pair"
                && arg_locals.len() == 2
                && !module.classes.iter().any(|c| c.name == "Pair")
            {
                let a_ty = fb.mf.locals[arg_locals[0].0 as usize].clone();
                let b_ty = fb.mf.locals[arg_locals[1].0 as usize].clone();
                let a_boxed = mir_autobox(fb, arg_locals[0], &a_ty);
                let b_boxed = mir_autobox(fb, arg_locals[1], &b_ty);
                let dest = fb.new_local(Ty::Class("kotlin/Pair".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance("kotlin/Pair".to_string()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::ConstructorJava {
                            class_name: "kotlin/Pair".to_string(),
                            descriptor: "(Ljava/lang/Object;Ljava/lang/Object;)V".to_string(),
                        },
                        args: vec![a_boxed, b_boxed],
                    },
                });
                return Some(dest);
            }

            // `Triple(a, b, c)` — new kotlin/Triple(boxed_a, boxed_b, boxed_c).
            if callee_str == "Triple"
                && arg_locals.len() == 3
                && !module.classes.iter().any(|c| c.name == "Triple")
            {
                let a_ty = fb.mf.locals[arg_locals[0].0 as usize].clone();
                let b_ty = fb.mf.locals[arg_locals[1].0 as usize].clone();
                let c_ty = fb.mf.locals[arg_locals[2].0 as usize].clone();
                let a_boxed = mir_autobox(fb, arg_locals[0], &a_ty);
                let b_boxed = mir_autobox(fb, arg_locals[1], &b_ty);
                let c_boxed = mir_autobox(fb, arg_locals[2], &c_ty);
                let dest = fb.new_local(Ty::Class("kotlin/Triple".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance("kotlin/Triple".to_string()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::ConstructorJava {
                            class_name: "kotlin/Triple".to_string(),
                            descriptor: "(Ljava/lang/Object;Ljava/lang/Object;Ljava/lang/Object;)V"
                                .to_string(),
                        },
                        args: vec![a_boxed, b_boxed, c_boxed],
                    },
                });
                return Some(dest);
            }

            // `StringBuilder()` — new java.lang.StringBuilder().
            if callee_str == "StringBuilder" && arg_locals.is_empty() {
                let dest = fb.new_local(Ty::Class("java/lang/StringBuilder".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance("java/lang/StringBuilder".to_string()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::ConstructorJava {
                            class_name: "java/lang/StringBuilder".to_string(),
                            descriptor: "()V".to_string(),
                        },
                        args: vec![],
                    },
                });
                return Some(dest);
            }

            // Exception constructors: `IllegalStateException("msg")` etc.
            // The Kotlin → JVM name map lives in one place (intrinsics §7).
            let exception_class = intrinsics::kotlin_exception_class(callee_str);
            if let Some(jvm_class) = exception_class {
                // Use ClasspathIndex to find the correct constructor overload.
                let arg_types: Vec<Ty> = arg_locals
                    .iter()
                    .map(|l| fb.mf.locals[l.0 as usize].clone())
                    .collect();
                let descriptor = lookup_constructor(jvm_class, arg_locals.len(), &arg_types)
                    .unwrap_or_else(|| {
                        if arg_locals.is_empty() {
                            "()V".to_string()
                        } else {
                            "(Ljava/lang/String;)V".to_string()
                        }
                    });
                let dest = fb.new_local(Ty::Class(jvm_class.to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::NewInstance(jvm_class.to_string()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::ConstructorJava {
                            class_name: jvm_class.to_string(),
                            descriptor: descriptor.to_string(),
                        },
                        args: arg_locals.clone(),
                    },
                });
                return Some(dest);
            }

            // `Regex(pattern)` → Pattern.compile(pattern)
            if callee_str == "Regex" && arg_locals.len() == 1 {
                let dest = fb.new_local(Ty::Class("java/util/regex/Pattern".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "java/util/regex/Pattern".to_string(),
                            method_name: "compile".to_string(),
                            descriptor: "(Ljava/lang/String;)Ljava/util/regex/Pattern;".to_string(),
                        },
                        args: arg_locals.clone(),
                    },
                });
                return Some(dest);
            }

            // `require(condition)` / `require(condition) { "msg" }`
            // → if (!condition) throw IllegalArgumentException(msg?)
            if callee_str == "require" && (arg_locals.len() == 1 || arg_locals.len() == 2) {
                let cond = arg_locals[0];
                let throw_block = fb.new_block();
                let ok_block = fb.new_block();
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond,
                        then_block: ok_block,
                        else_block: throw_block,
                    },
                    throw_block,
                );
                emit_throw_new(
                    fb,
                    module,
                    "java/lang/IllegalArgumentException",
                    if arg_locals.len() == 2 {
                        Some(arg_locals[1])
                    } else {
                        None
                    },
                );
                fb.cur_block = ok_block;
                let dest = fb.new_local(Ty::Unit);
                return Some(dest);
            }

            // `check(condition)` / `check(condition) { "msg" }`
            // → if (!condition) throw IllegalStateException(msg?)
            if callee_str == "check" && (arg_locals.len() == 1 || arg_locals.len() == 2) {
                let cond = arg_locals[0];
                let throw_block = fb.new_block();
                let ok_block = fb.new_block();
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond,
                        then_block: ok_block,
                        else_block: throw_block,
                    },
                    throw_block,
                );
                emit_throw_new(
                    fb,
                    module,
                    "java/lang/IllegalStateException",
                    if arg_locals.len() == 2 {
                        Some(arg_locals[1])
                    } else {
                        None
                    },
                );
                fb.cur_block = ok_block;
                let dest = fb.new_local(Ty::Unit);
                return Some(dest);
            }

            // `error(message)` → throw IllegalStateException(message)
            if callee_str == "error" && arg_locals.len() == 1 {
                emit_throw_new(
                    fb,
                    module,
                    "java/lang/IllegalStateException",
                    Some(arg_locals[0]),
                );
                let dest = fb.new_local(Ty::Nothing);
                return Some(dest);
            }

            // `TODO()` / `TODO(message)` → throw NotImplementedError
            if callee_str == "TODO" {
                let msg = if arg_locals.is_empty() {
                    None
                } else {
                    Some(arg_locals[0])
                };
                emit_throw_new(fb, module, "kotlin/NotImplementedError", msg);
                let dest = fb.new_local(Ty::Nothing);
                return Some(dest);
            }

            // `IntArray(size)` intrinsic — create a primitive int[].
            // Typed array constructors: IntArray(n), LongArray(n), etc.
            let typed_array_ty = match callee_str {
                "IntArray" => Some(Ty::IntArray),
                "LongArray" => Some(Ty::LongArray),
                "DoubleArray" => Some(Ty::DoubleArray),
                "BooleanArray" => Some(Ty::BooleanArray),
                "ByteArray" => Some(Ty::ByteArray),
                _ => None,
            };
            if let Some(arr_ty) = typed_array_ty {
                if !arg_locals.is_empty() {
                    let size_local = arg_locals[0];
                    let dest = fb.new_local(arr_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::NewIntArray(size_local), // reuses NewIntArray; JVM backend infers type from dest
                    });
                    return Some(dest);
                }
            }

            // `intArrayOf(...)`, `longArrayOf(...)`, etc.
            let arrayof_ty = match callee_str {
                "intArrayOf" => Some(Ty::IntArray),
                "longArrayOf" => Some(Ty::LongArray),
                "doubleArrayOf" => Some(Ty::DoubleArray),
                "booleanArrayOf" => Some(Ty::BooleanArray),
                "byteArrayOf" => Some(Ty::ByteArray),
                _ => None,
            };
            if let Some(arr_ty) = arrayof_ty {
                if !arg_locals.is_empty() {
                    let n = arg_locals.len() as i32;
                    let size = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: size,
                        value: Rvalue::Const(MirConst::Int(n)),
                    });
                    let arr = fb.new_local(arr_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest: arr,
                        value: Rvalue::NewIntArray(size),
                    });
                    // Store each element
                    for (i, &val) in arg_locals.iter().enumerate() {
                        let idx = fb.new_local(Ty::Int);
                        fb.push_stmt(MStmt::Assign {
                            dest: idx,
                            value: Rvalue::Const(MirConst::Int(i as i32)),
                        });
                        let dummy = fb.new_local(Ty::Unit);
                        fb.push_stmt(MStmt::Assign {
                            dest: dummy,
                            value: Rvalue::ArrayStore {
                                array: arr,
                                index: idx,
                                value: val,
                            },
                        });
                    }
                    return Some(arr);
                }
            }

            // `arrayOf(a, b, c)` — create Object[] with given elements.
            if callee_str == "arrayOf" && !arg_locals.is_empty() {
                let n = arg_locals.len() as i32;
                let size = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: size,
                    value: Rvalue::Const(MirConst::Int(n)),
                });
                let arr = fb.new_local(Ty::Any); // Object[]
                fb.push_stmt(MStmt::Assign {
                    dest: arr,
                    value: Rvalue::NewObjectArray(size),
                });
                for (i, &val) in arg_locals.iter().enumerate() {
                    let idx = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: idx,
                        value: Rvalue::Const(MirConst::Int(i as i32)),
                    });
                    // Autobox primitives for Object[].
                    let val_ty = fb.mf.locals[val.0 as usize].clone();
                    let boxed = mir_autobox(fb, val, &val_ty);
                    let dummy = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: dummy,
                        value: Rvalue::ObjectArrayStore {
                            array: arr,
                            index: idx,
                            value: boxed,
                        },
                    });
                }
                return Some(arr);
            }

            // `repeat(n) { body }` — execute lambda n times.
            if callee_str == "repeat" && arg_locals.len() == 2 {
                let count = arg_locals[0];
                let lambda = arg_locals[1];
                let lambda_ty = fb.mf.locals[lambda.0 as usize].clone();
                if is_lambda_or_function_ty(&lambda_ty, module) {
                    let cn = match &lambda_ty {
                        Ty::Class(n) => n.clone(),
                        Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                        _ => unreachable!(),
                    };
                    // var i = 0; while (i < n) { lambda.invoke(i); i++ }
                    let i_local = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: i_local,
                        value: Rvalue::Const(MirConst::Int(0)),
                    });
                    let cond_blk = fb.new_block();
                    let body_blk = fb.new_block();
                    let exit_blk = fb.new_block();
                    fb.terminate_and_switch(Terminator::Goto(cond_blk), cond_blk);
                    // Condition: i < n
                    let cmp = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: cmp,
                        value: Rvalue::BinOp {
                            op: skotch_mir::BinOp::CmpLt,
                            lhs: i_local,
                            rhs: count,
                        },
                    });
                    fb.terminate_and_switch(
                        Terminator::Branch {
                            cond: cmp,
                            then_block: body_blk,
                            else_block: exit_blk,
                        },
                        body_blk,
                    );
                    // Body: lambda.invoke(i)
                    // Autobox i to Object for the erased invoke signature.
                    let boxed_i = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest: boxed_i,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "java/lang/Integer".to_string(),
                                method_name: "valueOf".to_string(),
                                descriptor: "(I)Ljava/lang/Integer;".to_string(),
                            },
                            args: vec![i_local],
                        },
                    });
                    let _call_result = fb.new_local(Ty::Unit);
                    fb.push_stmt(MStmt::Assign {
                        dest: _call_result,
                        value: Rvalue::Call {
                            kind: CallKind::Virtual {
                                class_name: cn,
                                method_name: "invoke".to_string(),
                            },
                            args: vec![lambda, boxed_i],
                        },
                    });
                    // i++
                    let one = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: one,
                        value: Rvalue::Const(MirConst::Int(1)),
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest: i_local,
                        value: Rvalue::BinOp {
                            op: skotch_mir::BinOp::AddI,
                            lhs: i_local,
                            rhs: one,
                        },
                    });
                    fb.terminate_and_switch(Terminator::Goto(cond_blk), exit_blk);
                    let result = fb.new_local(Ty::Unit);
                    return Some(result);
                }
            }

            // `with(receiver, lambda)` — invoke lambda with receiver as arg.
            if callee_str == "with" && arg_locals.len() == 2 {
                let receiver = arg_locals[0];
                let lambda = arg_locals[1];
                let lambda_ty = fb.mf.locals[lambda.0 as usize].clone();
                if is_lambda_or_function_ty(&lambda_ty, module) {
                    let cn = match &lambda_ty {
                        Ty::Class(n) => n.clone(),
                        Ty::Function { params, .. } => stdlib_function_interface(params.len()),
                        _ => unreachable!(),
                    };
                    let ret = lambda_invoke_return_ty(&lambda_ty, module);
                    // Widen receiver to Ty::Any for erased invoke signature.
                    let recv_arg = {
                        let recv_ty = fb.mf.locals[receiver.0 as usize].clone();
                        match recv_ty {
                            Ty::Int => {
                                let boxed = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest: boxed,
                                    value: Rvalue::Call {
                                        kind: CallKind::StaticJava {
                                            class_name: "java/lang/Integer".to_string(),
                                            method_name: "valueOf".to_string(),
                                            descriptor: "(I)Ljava/lang/Integer;".to_string(),
                                        },
                                        args: vec![receiver],
                                    },
                                });
                                boxed
                            }
                            Ty::Any => receiver,
                            _ => {
                                let widened = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest: widened,
                                    value: Rvalue::Local(receiver),
                                });
                                widened
                            }
                        }
                    };
                    let dest = fb.new_local(ret);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Virtual {
                                class_name: cn,
                                method_name: "invoke".to_string(),
                            },
                            args: vec![lambda, recv_arg],
                        },
                    });
                    return Some(dest);
                }
            }

            // Handle stdlib top-level functions as StaticJava calls.
            // Math functions map to java.lang.Math static methods. A
            // user-defined function with the same name takes precedence —
            // skip the stdlib mapping if the callee is in `name_to_func`.
            let stdlib_call: Option<(&str, &str, &str, Ty)> =
                if name_to_func.contains_key(&callee_name) {
                    None
                } else {
                    match (callee_str, arg_locals.len()) {
                        ("maxOf", 2) => Some(("java/lang/Math", "max", "(II)I", Ty::Int)),
                        ("minOf", 2) => Some(("java/lang/Math", "min", "(II)I", Ty::Int)),
                        // kotlin.math functions
                        ("abs", 1) => {
                            let arg_ty = &fb.mf.locals[arg_locals[0].0 as usize];
                            match arg_ty {
                                Ty::Double => Some(("java/lang/Math", "abs", "(D)D", Ty::Double)),
                                Ty::Long => Some(("java/lang/Math", "abs", "(J)J", Ty::Long)),
                                _ => Some(("java/lang/Math", "abs", "(I)I", Ty::Int)),
                            }
                        }
                        ("sqrt", 1) => Some(("java/lang/Math", "sqrt", "(D)D", Ty::Double)),
                        ("ceil", 1) => Some(("java/lang/Math", "ceil", "(D)D", Ty::Double)),
                        ("floor", 1) => Some(("java/lang/Math", "floor", "(D)D", Ty::Double)),
                        ("round", 1) => Some(("java/lang/Math", "round", "(D)J", Ty::Long)),
                        ("pow", 2) => Some(("java/lang/Math", "pow", "(DD)D", Ty::Double)),
                        ("sin", 1) => Some(("java/lang/Math", "sin", "(D)D", Ty::Double)),
                        ("cos", 1) => Some(("java/lang/Math", "cos", "(D)D", Ty::Double)),
                        ("tan", 1) => Some(("java/lang/Math", "tan", "(D)D", Ty::Double)),
                        ("log", 1) => Some(("java/lang/Math", "log", "(D)D", Ty::Double)),
                        ("log10", 1) => Some(("java/lang/Math", "log10", "(D)D", Ty::Double)),
                        ("exp", 1) => Some(("java/lang/Math", "exp", "(D)D", Ty::Double)),
                        // readLine() → reads a line from stdin
                        ("readLine", 0) | ("readln", 0) => None, // handled separately below
                        _ => None,
                    }
                };
            if let Some((class, method, desc, ret_ty)) = stdlib_call {
                let dest = fb.new_local(ret_ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: class.to_string(),
                            method_name: method.to_string(),
                            descriptor: desc.to_string(),
                        },
                        args: arg_locals,
                    },
                });
                return Some(dest);
            }

            // readLine() / readln() — read a line from stdin.
            // Emits: new java.util.Scanner(System.in).nextLine()
            // The JVM backend handles the GetStaticField for System.in
            // as a special case in the Scanner constructor.
            if (callee_str == "readLine" || callee_str == "readln") && arg_locals.is_empty() {
                // We emit this as a StaticJava call to a pseudo-method
                // that the JVM backend recognizes and emits as the
                // Scanner(System.in).nextLine() pattern.
                let result = fb.new_local(Ty::String);
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "$readLine".to_string(),
                            method_name: "readLine".to_string(),
                            descriptor: "()Ljava/lang/String;".to_string(),
                        },
                        args: vec![],
                    },
                });
                return Some(result);
            }

            // Check if callee is a local variable (lambda or callable object).
            // Handles: val f = { x: Int -> x * 2 }; f(5)
            // Also: fun apply(f: (Int)->Int, x: Int) = f(x) via FunctionN interface.
            if let Some((_, local_id)) = scope.iter().rev().find(|(s, _)| *s == callee_name) {
                let local_ty = fb.mf.locals[local_id.0 as usize].clone();
                let is_lambda_class =
                    matches!(&local_ty, Ty::Class(n) if module.is_lambda_class(n));
                let is_function_interface = matches!(&local_ty, Ty::Class(n) if n.starts_with("kotlin/jvm/functions/Function"));
                // Check if this is a class with an `invoke` operator method.
                let has_invoke_method = if let Ty::Class(ref cn) = local_ty {
                    module
                        .classes
                        .iter()
                        .find(|c| &c.name == cn)
                        .map(|c| c.methods.iter().any(|m| m.name == "invoke"))
                        .unwrap_or(false)
                } else {
                    false
                };
                let is_callable = is_lambda_class
                    || is_function_interface
                    || has_invoke_method
                    || matches!(local_ty, Ty::Any | Ty::Function { .. });
                if is_callable {
                    // ── FunctionN interface dispatch ──────────────────
                    // When the local is typed as FunctionN, Ty::Any, or
                    // Ty::Function, dispatch through the erased FunctionN
                    // interface: autobox each arg to Object, call
                    // invokeinterface FunctionN.invoke(), then unbox the
                    // Object return to the expected type.
                    let use_interface_dispatch =
                        is_function_interface || matches!(local_ty, Ty::Any | Ty::Function { .. });
                    if use_interface_dispatch {
                        // ── Suspend callable parameter ────
                        // When the local is a suspend-typed function
                        // parameter inside a suspend function, the
                        // invocation becomes:
                        //   block.invoke($completion)
                        // via invokeinterface Function1.invoke(Object)Object.
                        // The $completion is the enclosing function's last
                        // param. The result is Object (no unboxing).
                        let is_suspend_call = fb.suspend_callable_locals.contains(&local_id.0);
                        if is_suspend_call && fb.mf.is_suspend {
                            // Load block + continuation → invokeinterface
                            let cont_local = *fb
                                .mf
                                .params
                                .last()
                                .expect("suspend fn must have $completion");
                            // Widen continuation to Ty::Any for the erased
                            // invoke(Object)Object descriptor.
                            let cont_widened = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: cont_widened,
                                value: Rvalue::Local(cont_local),
                            });
                            let iface_name = if let Ty::Class(ref cn) = local_ty {
                                cn.clone()
                            } else {
                                stdlib_function_interface(1)
                            };
                            let raw_result = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: raw_result,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: iface_name,
                                        method_name: "invoke".to_string(),
                                    },
                                    args: vec![*local_id, cont_widened],
                                },
                            });
                            return Some(raw_result);
                        }

                        // Args: pass primitives directly. The JVM
                        // backend force-boxes them inline at the call
                        // site for FunctionN.invoke, matching kotlinc's
                        // `aload-receiver; load-arg; valueOf; invokeinterface`
                        // order (no swap). Reference args also pass
                        // through unwidened — the call's descriptor is
                        // already forced to `(Object^N)Object;`.
                        let mut boxed_args: Vec<LocalId> = vec![*local_id];
                        for &arg in &arg_locals {
                            boxed_args.push(arg);
                        }
                        let iface_name = if let Ty::Class(ref cn) = local_ty {
                            cn.clone()
                        } else {
                            // For Ty::Any / Ty::Function, derive arity from call args.
                            let arity = arg_locals.len();
                            stdlib_function_interface(arity)
                        };
                        // The interface invoke returns Ty::Any (Object).
                        let raw_result = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest: raw_result,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: iface_name,
                                    method_name: "invoke".to_string(),
                                },
                                args: boxed_args,
                            },
                        });
                        // Use the function's declared return type to determine
                        // whether to unbox the Object result or pass it through.
                        let fn_ret = if let Ty::Function { ref ret, .. } = local_ty {
                            (**ret).clone()
                        } else {
                            // For Ty::Any or FunctionN interface types, we
                            // can't determine the return type statically.
                            // Return the raw Object; the JVM backend or
                            // smart-cast handles narrowing downstream.
                            Ty::Any
                        };
                        // Primitive returns from FunctionN.invoke (Object)
                        // unbox via `checkcast Number; <type>Value()<type>`
                        // (or `checkcast Boolean; booleanValue()Z` for Bool).
                        // Kotlinc uses the Number parent class for numeric
                        // primitives, matching bytecode exactly.
                        let unbox: Option<(&str, &str, &str, Ty)> = match &fn_ret {
                            Ty::Int => Some(("java/lang/Number", "intValue", "()I", Ty::Int)),
                            Ty::Long => Some(("java/lang/Number", "longValue", "()J", Ty::Long)),
                            Ty::Float => Some(("java/lang/Number", "floatValue", "()F", Ty::Float)),
                            Ty::Double => {
                                Some(("java/lang/Number", "doubleValue", "()D", Ty::Double))
                            }
                            Ty::Bool => {
                                Some(("java/lang/Boolean", "booleanValue", "()Z", Ty::Bool))
                            }
                            _ => None,
                        };
                        if let Some((cast_class, unbox_method, unbox_desc, unboxed_ty)) = unbox {
                            let casted = fb.new_local(Ty::Class(cast_class.to_string()));
                            fb.push_stmt(MStmt::Assign {
                                dest: casted,
                                value: Rvalue::CheckCast {
                                    obj: raw_result,
                                    target_class: cast_class.to_string(),
                                },
                            });
                            let unboxed = fb.new_local(unboxed_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest: unboxed,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: cast_class.to_string(),
                                        method_name: unbox_method.to_string(),
                                        descriptor: unbox_desc.to_string(),
                                    },
                                    args: vec![casted],
                                },
                            });
                            return Some(unboxed);
                        }
                        // For reference types (String, Any, etc.),
                        // return the Object as-is. The JVM backend
                        // handles checkcast via Rvalue::Local.
                        return Some(raw_result);
                    }

                    // ── Direct lambda / invoke-operator dispatch ──────
                    // Lower as: receiver.invoke(args)
                    // Lambda invoke methods now use erased types (Ty::Any)
                    // for FunctionN compatibility. Must autobox args and
                    // the return is Ty::Any (Object).
                    let invoke_class = if let Ty::Class(ref cn) = local_ty {
                        cn.clone()
                    } else if matches!(local_ty, Ty::Function { .. } | Ty::Any) {
                        module
                            .classes
                            .iter()
                            .rev()
                            .find(|c| c.is_lambda)
                            .map(|c| c.name.clone())
                            .unwrap_or_else(|| "java/lang/Object".to_string())
                    } else {
                        "java/lang/Object".to_string()
                    };
                    // Check if the target invoke uses erased types.
                    let target_erased = module
                        .classes
                        .iter()
                        .find(|c| c.name == invoke_class)
                        .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                        .map(|m| {
                            m.params
                                .iter()
                                .skip(1)
                                .all(|p| matches!(m.locals[p.0 as usize], Ty::Any))
                        })
                        .unwrap_or(false);
                    let mut all_args = vec![*local_id];
                    if target_erased {
                        // Autobox each arg for the erased invoke method.
                        for &arg in &arg_locals {
                            let arg_ty = fb.mf.locals[arg.0 as usize].clone();
                            match arg_ty {
                                Ty::Int => {
                                    let boxed = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: boxed,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: "java/lang/Integer".to_string(),
                                                method_name: "valueOf".to_string(),
                                                descriptor: "(I)Ljava/lang/Integer;".to_string(),
                                            },
                                            args: vec![arg],
                                        },
                                    });
                                    all_args.push(boxed);
                                }
                                Ty::Bool => {
                                    let boxed = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: boxed,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: "java/lang/Boolean".to_string(),
                                                method_name: "valueOf".to_string(),
                                                descriptor: "(Z)Ljava/lang/Boolean;".to_string(),
                                            },
                                            args: vec![arg],
                                        },
                                    });
                                    all_args.push(boxed);
                                }
                                Ty::Long => {
                                    let boxed = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: boxed,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: "java/lang/Long".to_string(),
                                                method_name: "valueOf".to_string(),
                                                descriptor: "(J)Ljava/lang/Long;".to_string(),
                                            },
                                            args: vec![arg],
                                        },
                                    });
                                    all_args.push(boxed);
                                }
                                Ty::Double => {
                                    let boxed = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: boxed,
                                        value: Rvalue::Call {
                                            kind: CallKind::StaticJava {
                                                class_name: "java/lang/Double".to_string(),
                                                method_name: "valueOf".to_string(),
                                                descriptor: "(D)Ljava/lang/Double;".to_string(),
                                            },
                                            args: vec![arg],
                                        },
                                    });
                                    all_args.push(boxed);
                                }
                                Ty::Any => all_args.push(arg),
                                _ => {
                                    // Reference type (String, Class, etc.) —
                                    // widen to Ty::Any so the descriptor uses
                                    // Ljava/lang/Object; matching the erased
                                    // invoke signature.
                                    let widened = fb.new_local(Ty::Any);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: widened,
                                        value: Rvalue::Local(arg),
                                    });
                                    all_args.push(widened);
                                }
                            }
                        }
                    } else {
                        all_args.extend_from_slice(&arg_locals);
                    }
                    // Find invoke return type from class metadata.
                    let ret_ty = if let Ty::Class(ref cn) = local_ty {
                        module
                            .classes
                            .iter()
                            .find(|c| &c.name == cn)
                            .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                            .map(|m| m.return_ty.clone())
                            .unwrap_or(Ty::Any)
                    } else if let Ty::Function { ref ret, .. } = local_ty {
                        (**ret).clone()
                    } else {
                        Ty::Any
                    };
                    let dest = fb.new_local(ret_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Virtual {
                                class_name: invoke_class,
                                method_name: "invoke".to_string(),
                            },
                            args: all_args,
                        },
                    });
                    return Some(dest);
                }
            }

            let kind = if callee_str == "println" {
                CallKind::Println
            } else if callee_str == "print" {
                CallKind::Print
            } else if let Some(fid) = name_to_func.get(&callee_name) {
                // Check if this function has capture params (local functions).
                // If the function has more params than explicit args AND it's
                // not a suspend function (which has an extra $completion param),
                // the extra leading params are captures that need to be filled.
                let target = &module.functions[fid.0 as usize];
                let target_param_count = target.params.len();
                let is_suspend_target = target.is_suspend;
                if !is_suspend_target && target_param_count > arg_locals.len() {
                    let fn_name = &module.functions[fid.0 as usize].name;
                    let capture_count = target_param_count - arg_locals.len();
                    // Only treat the missing slots as captures when at
                    // least one matching $capture$ binding exists in
                    // scope — that's the signal that the target is a
                    // LOCAL function (nested fun) with hoisted outer
                    // captures. For top-level @Composable functions
                    // with default parameters (e.g.
                    // `DividerItem(modifier: Modifier = Modifier)`),
                    // there are no captures: the missing slots are
                    // default params that the compose-transform pass
                    // fills with proper null/0 placeholders. Pre-
                    // filling them here with `Int(0)` corrupts the
                    // reference slots (the JVM emitter then chains
                    // `iconst_0; checkcast Modifier` and d8 rejects).
                    let has_captures_in_scope = scope.iter().any(|(sym, _)| {
                        let n = interner.resolve(*sym);
                        n.starts_with(&format!("$capture${fn_name}$"))
                    });
                    if has_captures_in_scope {
                        let mut capture_args = Vec::new();
                        for ci in 0..capture_count {
                            let capture_ty = module.functions[fid.0 as usize]
                                .locals
                                .get(ci)
                                .cloned()
                                .unwrap_or(Ty::Error);
                            let found = scope.iter().rev().find(|(sym, _)| {
                                let n = interner.resolve(*sym);
                                n.starts_with(&format!("$capture${fn_name}$"))
                            });
                            if let Some((_, lid)) = found {
                                capture_args.push(*lid);
                            } else {
                                let init = match &capture_ty {
                                    Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                        Rvalue::Const(MirConst::Int(0))
                                    }
                                    Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                    Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                    Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                    Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                    _ => Rvalue::Const(MirConst::Null),
                                };
                                let fallback = fb.new_local(capture_ty);
                                fb.push_stmt(MStmt::Assign {
                                    dest: fallback,
                                    value: init,
                                });
                                capture_args.push(fallback);
                            }
                        }
                        capture_args.extend_from_slice(&arg_locals);
                        arg_locals = capture_args;
                    }
                }
                CallKind::Static(*fid)
            } else {
                // Try implicit `this.method()` — if `this` is in scope
                // and its class has a matching method, emit a virtual call.
                let this_sym = interner.intern("this");
                let this_info = scope.iter().rev().find(|(s, _)| *s == this_sym);
                let mut resolved = None;
                if let Some((_sym, this_local)) = this_info {
                    let this_ty = fb.mf.locals[this_local.0 as usize].clone();
                    if let Ty::Class(class_name) = &this_ty {
                        // Look up in this class, superclasses, and interfaces.
                        let mut search_class = Some(class_name.clone());
                        'search: while let Some(ref cname) = search_class {
                            let found = module.classes.iter().find(|c| &c.name == cname);
                            if let Some(cls) = found {
                                if cls.methods.iter().any(|m| m.name == callee_str) {
                                    arg_locals.insert(0, *this_local);
                                    let ret_ty = cls
                                        .methods
                                        .iter()
                                        .find(|m| m.name == callee_str)
                                        .map(|m| m.return_ty.clone())
                                        .unwrap_or(Ty::Unit);
                                    resolved = Some((
                                        CallKind::Virtual {
                                            class_name: cname.clone(),
                                            method_name: callee_str.to_string(),
                                        },
                                        ret_ty,
                                    ));
                                    break;
                                }
                                // Search interfaces.
                                for iname in &cls.interfaces {
                                    if let Some(icls) =
                                        module.classes.iter().find(|c| &c.name == iname)
                                    {
                                        if let Some(m) =
                                            icls.methods.iter().find(|m| m.name == callee_str)
                                        {
                                            arg_locals.insert(0, *this_local);
                                            resolved = Some((
                                                CallKind::Virtual {
                                                    class_name: iname.clone(),
                                                    method_name: callee_str.to_string(),
                                                },
                                                m.return_ty.clone(),
                                            ));
                                            break 'search;
                                        }
                                    }
                                }
                                search_class = cls.super_class.clone();
                            } else {
                                break;
                            }
                        }
                        // If not found in MirClass hierarchy, try JDK
                        // class lookup for Java classes (StringBuilder,
                        // etc.). This enables implicit `this.method()`
                        // dispatch in lambda-with-receiver bodies.
                        if resolved.is_none() {
                            if let Ok(info) = skotch_classinfo::load_jdk_class(class_name) {
                                // Prefer the overload whose param count matches
                                // the call site; fall back to first by name if
                                // no exact match exists. Without the preference
                                // we'd return e.g. a 4-param `layout` for a
                                // 3-arg call site and the JVM backend stubs
                                // the whole enclosing lambda. The padding
                                // below fills missing defaulted slots.
                                let provided = arg_locals.len();
                                let exact = info.methods.iter().find(|m| {
                                    m.name == callee_str
                                        && skotch_classinfo::count_descriptor_params_pub(
                                            &m.descriptor,
                                        ) == provided
                                });
                                let m = exact
                                    .or_else(|| info.methods.iter().find(|m| m.name == callee_str));
                                if let Some(m) = m {
                                    let desc_params = skotch_classinfo::count_descriptor_params_pub(
                                        &m.descriptor,
                                    );
                                    arg_locals.insert(0, *this_local);
                                    if desc_params > provided {
                                        // Pad missing args with typed
                                        // defaults based on descriptor slots.
                                        let chars = parse_descriptor_param_chars(&m.descriptor);
                                        for slot in provided..desc_params {
                                            let ch = chars.get(slot).copied().unwrap_or('L');
                                            let (slot_ty, init): (Ty, Rvalue) = match ch {
                                                'I' | 'B' | 'C' | 'S' | 'Z' => {
                                                    (Ty::Int, Rvalue::Const(MirConst::Int(0)))
                                                }
                                                'J' => (Ty::Long, Rvalue::Const(MirConst::Long(0))),
                                                'F' | 'D' => (
                                                    Ty::Double,
                                                    Rvalue::Const(MirConst::Double(0.0)),
                                                ),
                                                _ => (Ty::Any, Rvalue::Const(MirConst::Null)),
                                            };
                                            let pad_local = fb.new_local(slot_ty);
                                            fb.push_stmt(MStmt::Assign {
                                                dest: pad_local,
                                                value: init,
                                            });
                                            arg_locals.push(pad_local);
                                        }
                                    }
                                    resolved = Some((
                                        CallKind::VirtualJava {
                                            class_name: class_name.clone(),
                                            method_name: callee_str.to_string(),
                                            descriptor: m.descriptor.clone(),
                                        },
                                        Ty::Any,
                                    ));
                                }
                            }
                        }
                        // Check callable fields: `greet()` where `greet` is
                        // a val of function type on `this`.
                        if resolved.is_none() {
                            let field_info: Option<(String, Ty)> = module
                                .classes
                                .iter()
                                .find(|c| &c.name == class_name)
                                .and_then(|cls| cls.fields.iter().find(|f| f.name == callee_str))
                                .map(|f| (f.name.clone(), f.ty.clone()));
                            if let Some((field_name, field_ty)) = field_info {
                                let this_copy = *this_local;
                                let class_copy = class_name.clone();
                                // Load the field from this.
                                let field_local = fb.new_local(field_ty.clone());
                                fb.push_stmt(MStmt::Assign {
                                    dest: field_local,
                                    value: Rvalue::GetField {
                                        receiver: this_copy,
                                        class_name: class_copy,
                                        field_name,
                                    },
                                });
                                // Invoke the callable field.
                                let (invoke_class, _invoke_ret) = if let Ty::Class(ref cn) =
                                    field_ty
                                {
                                    let ret = module
                                        .classes
                                        .iter()
                                        .find(|c| &c.name == cn)
                                        .and_then(|c| c.methods.iter().find(|m| m.name == "invoke"))
                                        .map(|m| m.return_ty.clone())
                                        .unwrap_or(Ty::Any);
                                    (cn.clone(), ret)
                                } else if let Ty::Function {
                                    ref params,
                                    ref ret,
                                    ..
                                } = field_ty
                                {
                                    // Function type: use FunctionN interface for invoke.
                                    let arity = params.len();
                                    let iface = stdlib_function_interface(arity);
                                    (iface, (**ret).clone())
                                } else {
                                    ("$Callable".to_string(), Ty::Any)
                                };
                                let mut invoke_args = vec![field_local];
                                // Box primitive args for the erased invoke signature.
                                for a in &arg_locals {
                                    let a_ty = fb.mf.locals[a.0 as usize].clone();
                                    let boxed = mir_autobox(fb, *a, &a_ty);
                                    invoke_args.push(boxed);
                                }
                                // FunctionN.invoke returns Object on JVM.
                                let dest = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::Virtual {
                                            class_name: invoke_class,
                                            method_name: "invoke".to_string(),
                                        },
                                        args: invoke_args,
                                    },
                                });
                                return Some(dest);
                            }
                        }
                    }
                }
                if let Some((k, _)) = resolved {
                    k
                } else if let Some((owner, desc, _ret_ty)) =
                    module.cross_file_fns.get(callee_str).cloned()
                {
                    // Cross-file function call. Apply the same trailing-
                    // lambda + composer/changed/default padding that the
                    // import_map branch does, so calls to in-project
                    // Composables like `JetchatTheme { ... }` route the
                    // lambda to the correct (final user-param) slot and
                    // forward $composer/$changed.
                    let desc_param_count = skotch_classinfo::count_descriptor_params_pub(&desc);
                    if arg_locals.len() < desc_param_count {
                        let composer_sym = interner.intern("$composer");
                        let changed_sym = interner.intern("$changed");
                        let scope_composer = scope
                            .iter()
                            .rev()
                            .find(|(s, _)| *s == composer_sym)
                            .map(|(_, id)| *id);
                        let scope_changed = scope
                            .iter()
                            .rev()
                            .find(|(s, _)| *s == changed_sym)
                            .map(|(_, id)| *id);
                        let composer_abs_pos = composer_position_in_descriptor(&desc);
                        let desc_param_tys = param_tys_from_descriptor(&desc);
                        let mut default_mask: u64 = 0;
                        let default_slot_idx = composer_abs_pos.map(|p| p + 2);
                        // Trailing-lambda re-positioning.
                        if let Some(composer_pos) = composer_abs_pos {
                            let user_slot_count = composer_pos;
                            let is_fn_slot = |ty: &Ty| {
                                matches!(ty, Ty::Function { .. })
                                    || matches!(ty, Ty::Class(n) if n.starts_with("kotlin/jvm/functions/Function")
                                        || module.is_lambda_class(n))
                            };
                            let last_user_slot_is_fn = composer_pos > 0
                                && desc_param_tys
                                    .get(composer_pos - 1)
                                    .map(is_fn_slot)
                                    .unwrap_or(false);
                            let last_user_arg_is_fn = arg_locals
                                .last()
                                .and_then(|l| fb.mf.locals.get(l.0 as usize))
                                .map(is_fn_slot)
                                .unwrap_or(false);
                            // Don't shift a positional first arg to the
                            // trailing slot when its arity matches slot 0
                            // better than the last slot. Example:
                            // `AndroidViewBinding(::inflate)` →
                            // arg_locals=[Function3], slot 0 is Function3,
                            // last slot is Function1. Without this check
                            // we'd null out slot 0 and put the Function3
                            // in slot 2, then crash at runtime when slot 0
                            // is invoked as the factory.
                            let fn_arity = |ty: &Ty| -> Option<usize> {
                                match ty {
                                    Ty::Function { params, .. } => Some(params.len()),
                                    Ty::Class(n) => n
                                        .strip_prefix("kotlin/jvm/functions/Function")
                                        .and_then(|s| s.parse::<usize>().ok()),
                                    _ => None,
                                }
                            };
                            let user_first_arg_arity = arg_locals
                                .first()
                                .and_then(|l| fb.mf.locals.get(l.0 as usize))
                                .and_then(fn_arity);
                            let user_first_slot_arity = desc_param_tys.first().and_then(fn_arity);
                            let user_last_slot_arity = composer_pos
                                .checked_sub(1)
                                .and_then(|i| desc_param_tys.get(i))
                                .and_then(fn_arity);
                            let positional_fit = match (
                                user_first_arg_arity,
                                user_first_slot_arity,
                                user_last_slot_arity,
                            ) {
                                (Some(a), Some(first), Some(last)) => a == first && a != last,
                                (Some(a), Some(first), None) => a == first,
                                _ => false,
                            };
                            if last_user_arg_is_fn
                                && last_user_slot_is_fn
                                && arg_locals.len() < user_slot_count
                                && user_slot_count >= 2
                                && !positional_fit
                            {
                                let trailing = arg_locals.pop().expect("non-empty checked above");
                                let pad_until = user_slot_count - 1;
                                while arg_locals.len() < pad_until {
                                    let cur = arg_locals.len();
                                    let slot_ty =
                                        desc_param_tys.get(cur).cloned().unwrap_or(Ty::Any);
                                    default_mask |= 1u64 << cur;
                                    let pad = fb.new_local(slot_ty.clone());
                                    let init = match &slot_ty {
                                        Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                            Rvalue::Const(MirConst::Int(0))
                                        }
                                        Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                        Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                        Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                        Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                        _ => Rvalue::Const(MirConst::Null),
                                    };
                                    fb.push_stmt(MStmt::Assign {
                                        dest: pad,
                                        value: init,
                                    });
                                    arg_locals.push(pad);
                                }
                                arg_locals.push(trailing);
                            }
                        }
                        while arg_locals.len() < desc_param_count {
                            let cur = arg_locals.len();
                            let slot_ty = desc_param_tys.get(cur).cloned().unwrap_or(Ty::Any);
                            let is_composer_slot = composer_abs_pos == Some(cur);
                            let is_changed_slot = composer_abs_pos == Some(cur.wrapping_sub(1));
                            let is_default_slot = Some(cur) == default_slot_idx;
                            if is_composer_slot {
                                if let Some(cid) = scope_composer {
                                    arg_locals.push(cid);
                                } else {
                                    let composer = fb.new_local(Ty::Class(
                                        "androidx/compose/runtime/Composer".to_string(),
                                    ));
                                    fb.push_stmt(MStmt::Assign {
                                        dest: composer,
                                        value: Rvalue::Const(MirConst::Null),
                                    });
                                    arg_locals.push(composer);
                                }
                            } else if is_changed_slot {
                                if let Some(cid) = scope_changed {
                                    arg_locals.push(cid);
                                } else {
                                    let changed = fb.new_local(Ty::Int);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: changed,
                                        value: Rvalue::Const(MirConst::Int(0)),
                                    });
                                    arg_locals.push(changed);
                                }
                            } else if is_default_slot {
                                let mask = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: mask,
                                    value: Rvalue::Const(MirConst::Int(default_mask as i32)),
                                });
                                arg_locals.push(mask);
                            } else {
                                if cur < composer_abs_pos.unwrap_or(usize::MAX) {
                                    default_mask |= 1u64 << cur;
                                }
                                let placeholder = fb.new_local(slot_ty.clone());
                                let init = match &slot_ty {
                                    Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                        Rvalue::Const(MirConst::Int(0))
                                    }
                                    Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                    Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                    Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                    Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                    _ => Rvalue::Const(MirConst::Null),
                                };
                                fb.push_stmt(MStmt::Assign {
                                    dest: placeholder,
                                    value: init,
                                });
                                arg_locals.push(placeholder);
                            }
                        }
                    }
                    // The actual JVM method name may be mangled
                    // (`Font-wCLgNak` for source-level `Font`) when the
                    // return type is a value class. Query for the real
                    // name so the invokestatic targets a real method.
                    let actual_method_name = skotch_classinfo::lookup_method_name_and_descriptor(
                        &owner,
                        callee_str,
                        arg_locals.len(),
                    )
                    .map(|(n, _)| n)
                    .unwrap_or_else(|| callee_str.to_string());
                    CallKind::StaticJava {
                        class_name: owner,
                        method_name: actual_method_name,
                        descriptor: desc,
                    }
                } else if let Some((class_path, method_name)) =
                    module.static_method_imports.get(callee_str).cloned()
                {
                    // Static method import: e.g. `assertTrue(...)` →
                    // `Assertions.assertTrue(...)` via
                    // `import org.junit.jupiter.api.Assertions.assertTrue`.
                    let arg_types: Vec<Ty> = arg_locals
                        .iter()
                        .map(|l| fb.mf.locals[l.0 as usize].clone())
                        .collect();
                    if let Some((_cls, _meth, descriptor, _ret)) = lookup_java_static_typed(
                        &class_path,
                        &method_name,
                        arg_locals.len(),
                        &arg_types,
                    ) {
                        CallKind::StaticJava {
                            class_name: class_path,
                            method_name,
                            descriptor,
                        }
                    } else {
                        diags.push(Diagnostic::error(
                            *span,
                            format!(
                                "static method `{}` not found on class `{}`",
                                method_name, class_path
                            ),
                        ));
                        return None;
                    }
                } else if let Some(jvm_class) = module.import_map.get(callee_str) {
                    // Imported library function/class.
                    // Only use the "append Kt" wrapper class pattern when the
                    // last segment of the JVM path is lowercase (package), meaning
                    // the import is `import pkg.functionName`. When the last segment
                    // is uppercase, it's a class import like `import pkg.ClassName`
                    // and the function is a companion/static method on that class.
                    let last_segment = jvm_class.rsplit('/').next().unwrap_or(jvm_class);
                    let wrapper_class = if last_segment.starts_with(|c: char| c.is_lowercase()) {
                        // Package-level function import like
                        // `import a.b.c.functionName` → jvm_class = "a/b/c/functionName"
                        // Strip the function name to get the package: "a/b/c"
                        let package_path = jvm_class
                            .rsplit_once('/')
                            .map(|(pkg, _)| pkg)
                            .unwrap_or(jvm_class);
                        let found = skotch_classinfo::find_wrapper_class_for_function(
                            package_path,
                            callee_str,
                        );
                        if let Some(f) = found {
                            f
                        } else {
                            // Not found in any JAR — emit null stub.
                            let dest = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            return Some(dest);
                        }
                    } else {
                        // Class-level function: try the class as wrapper
                        // first. If classinfo says the class doesn't
                        // declare this method, fall back to the Kt-
                        // facade lookup on the parent package — Pascal-
                        // cased top-level functions like @Composable
                        // `AndroidViewBinding` live in
                        // `<pkg>/AndroidViewBindingKt`, not in a class
                        // named `AndroidViewBinding`. Without this
                        // fallback we emit `invokestatic
                        // AndroidViewBinding.AndroidViewBinding(...)`
                        // which doesn't exist at runtime
                        // (NoSuchMethodError).
                        let direct = jvm_class.clone();
                        let direct_has_method = skotch_classinfo::lookup_method_descriptor(
                            &direct,
                            callee_str,
                            arg_locals.len(),
                        )
                        .is_some()
                            || (2..=8).any(|extra| {
                                skotch_classinfo::lookup_method_descriptor(
                                    &direct,
                                    callee_str,
                                    arg_locals.len() + extra,
                                )
                                .is_some()
                            });
                        if direct_has_method {
                            direct
                        } else {
                            let package_path = jvm_class
                                .rsplit_once('/')
                                .map(|(pkg, _)| pkg)
                                .unwrap_or(jvm_class);
                            skotch_classinfo::find_wrapper_class_for_function(
                                package_path,
                                callee_str,
                            )
                            .unwrap_or(direct)
                        }
                    };
                    // Look up the method descriptor, preferring composable
                    // overloads. Composable functions have extra params:
                    //   +2: $composer + $changed
                    //   +3: $composer + $changed + $default
                    //   +N: default params + $composer + $changed + $default
                    // Search with a preference for descriptors containing "Composer".
                    let lookup_desc =
                        lookup_composable_descriptor(&wrapper_class, callee_str, arg_locals.len());
                    // If classinfo can't find a real method matching the
                    // callee + arg count, refuse the call instead of
                    // falling back to a synthesized `(Object^N)Object`
                    // descriptor — that fake descriptor doesn't match any
                    // real method on the target class and produces a
                    // NoSuchMethodError at runtime (e.g. Compose's
                    // `darkColorScheme(...)` has heavily mangled
                    // value-class overloads `darkColorScheme-_VG5OTI(long
                    // × 48)` with $default suffix variants that take more
                    // args + mask + null marker — skotch can't match
                    // those without full default-param dispatch
                    // infrastructure). Returning a null placeholder
                    // keeps clinit running so later vals load.
                    if lookup_desc.is_none() {
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        return Some(dest);
                    }
                    let desc = lookup_desc.unwrap();
                    // Named-arg + defaults: when user has named args AND
                    // the descriptor has more user-slots than user-args,
                    // positional padding produces wrong-slot assignment
                    // (e.g. `MaterialTheme(colorScheme=…, typography=…,
                    // content=…)` lands `typography` in the `Shapes`
                    // slot because skotch can't reorder by name without
                    // the target's param names. Reorder via
                    // `lookup_function_metadata` (`@Metadata` param
                    // names) when available — for callees without
                    // @Metadata, fall back to the null-emit fallback
                    // below.
                    let has_named = args.iter().any(|a| a.name.is_some());
                    let composer_abs_pos = composer_position_in_descriptor(&desc);
                    let user_slot_count = composer_abs_pos
                        .unwrap_or_else(|| skotch_classinfo::count_descriptor_params_pub(&desc));
                    // Mask bits for slots we filled with synthesized
                    // defaults during named-arg reordering. Consumed by
                    // the padding path below when emitting the
                    // `$default` mask slot.
                    let mut precomputed_default_mask: u64 = 0;
                    if has_named && arg_locals.len() < user_slot_count {
                        if let Some(fn_meta) =
                            skotch_classinfo::lookup_function_metadata(&wrapper_class, callee_str)
                        {
                            let param_names: Vec<&str> = fn_meta
                                .value_params
                                .iter()
                                .map(|p| p.name.as_str())
                                .collect();
                            let metadata_matches = param_names.len() == user_slot_count;
                            if metadata_matches {
                                let mut placed: Vec<Option<LocalId>> = vec![None; user_slot_count];
                                let mut next_positional = 0usize;
                                let mut ok = true;
                                for (i, a) in args.iter().enumerate() {
                                    let local = arg_locals[i];
                                    if let Some(name_sym) = a.name {
                                        let name_str = interner.resolve(name_sym);
                                        if let Some(pos) =
                                            param_names.iter().position(|n| *n == name_str)
                                        {
                                            if placed[pos].is_some() {
                                                ok = false;
                                                break;
                                            }
                                            placed[pos] = Some(local);
                                        } else {
                                            ok = false;
                                            break;
                                        }
                                    } else {
                                        while next_positional < user_slot_count
                                            && placed[next_positional].is_some()
                                        {
                                            next_positional += 1;
                                        }
                                        if next_positional >= user_slot_count {
                                            ok = false;
                                            break;
                                        }
                                        placed[next_positional] = Some(local);
                                        next_positional += 1;
                                    }
                                }
                                // Refuse the reorder when any placed slot
                                // would need a value-class arg passed to
                                // a primitive descriptor slot (e.g.
                                // `darkColorScheme(primary = Blue40)`
                                // where Blue40 is `Color` (value class
                                // over `J`) and the descriptor expects
                                // `J`). The JVM emitter would then push
                                // a `Color` object reference into a
                                // primitive slot and the validator would
                                // stub the entire enclosing function.
                                // The downstream null-emit fallback
                                // preserves the previous behavior for
                                // these cases.
                                let desc_param_tys = param_tys_from_descriptor(&desc);
                                let primitive_value_class_mismatch =
                                    placed.iter().enumerate().any(|(slot, slot_local)| {
                                        let Some(local) = slot_local else {
                                            return false;
                                        };
                                        let arg_ty = &fb.mf.locals[local.0 as usize];
                                        let slot_ty = desc_param_tys.get(slot);
                                        matches!(slot_ty, Some(Ty::Long | Ty::Double))
                                            && matches!(arg_ty, Ty::Class(_))
                                    });
                                if ok && !primitive_value_class_mismatch {
                                    let mut new_arg_locals: Vec<LocalId> =
                                        Vec::with_capacity(user_slot_count);
                                    for (slot, slot_local) in placed.iter().enumerate() {
                                        if let Some(local) = slot_local {
                                            new_arg_locals.push(*local);
                                        } else {
                                            // Synthesized default for an
                                            // unfilled slot — record the
                                            // mask bit so the callee
                                            // ignores our null/zero and
                                            // uses its own default.
                                            precomputed_default_mask |= 1u64 << slot;
                                            let slot_ty = desc_param_tys
                                                .get(slot)
                                                .cloned()
                                                .unwrap_or(Ty::Any);
                                            let pad = fb.new_local(slot_ty.clone());
                                            let init = match &slot_ty {
                                                Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                                    Rvalue::Const(MirConst::Int(0))
                                                }
                                                Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                                Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                                Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                                Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                                _ => Rvalue::Const(MirConst::Null),
                                            };
                                            fb.push_stmt(MStmt::Assign {
                                                dest: pad,
                                                value: init,
                                            });
                                            new_arg_locals.push(pad);
                                        }
                                    }
                                    arg_locals = new_arg_locals;
                                    // Skip the null-emit fallback below;
                                    // the padding+invokestatic path
                                    // handles `$composer`, `$changed`,
                                    // and the `$default` mask.
                                }
                            }
                        }
                    }
                    let composer_abs_pos = composer_position_in_descriptor(&desc);
                    let user_slot_count = composer_abs_pos
                        .unwrap_or_else(|| skotch_classinfo::count_descriptor_params_pub(&desc));
                    if has_named && arg_locals.len() < user_slot_count {
                        // Tactical fallback: if one of the named args is
                        // called "content" and points at a Function2-shaped
                        // lambda (the conventional Compose content slot),
                        // invoke it with placeholder $composer/$changed
                        // before we give up on the wrapped call.
                        //
                        // The actual composer/changed locals don't exist
                        // at MIR-lower time — they're injected later by
                        // skotch-compose. We emit `MirConst::Null` and
                        // `MirConst::Int(0)` placeholders here; the
                        // existing `thread_composer_args` pass in
                        // skotch-compose patches matching call sites with
                        // the real values when it sees a VirtualJava call
                        // whose descriptor contains "Composer;".
                        //
                        // This lets the composition tree walk down even
                        // though the wrapper (MaterialTheme, Scaffold,
                        // etc.) is null-stubbed — at least some content
                        // composables get a chance to run.
                        let content_idx = args
                            .iter()
                            .position(|a| a.name.is_some_and(|n| interner.resolve(n) == "content"));
                        if let Some(idx) = content_idx {
                            if let Some(&content_local) = arg_locals.get(idx) {
                                let composer_ph = fb.new_local(Ty::Class(
                                    "androidx/compose/runtime/Composer".to_string(),
                                ));
                                fb.push_stmt(MStmt::Assign {
                                    dest: composer_ph,
                                    value: Rvalue::Const(MirConst::Null),
                                });
                                let changed_ph = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: changed_ph,
                                    value: Rvalue::Const(MirConst::Int(0)),
                                });
                                let dest = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest,
                                    value: Rvalue::Call {
                                        kind: CallKind::Virtual {
                                            class_name: "kotlin/jvm/functions/Function2"
                                                .to_string(),
                                            method_name: "invoke".to_string(),
                                        },
                                        args: vec![content_local, composer_ph, changed_ph],
                                    },
                                });
                                return Some(dest);
                            }
                        }
                        let dest = fb.new_local(Ty::Any);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        return Some(dest);
                    }
                    // Disambiguation check: when a class has only one
                    // overload matching the user's arg count, but the
                    // user's first arg type is a primitive while the
                    // descriptor's first slot is a reference type (or
                    // vice versa), it's almost certainly a wrong-import
                    // case — JetChat imports `Font` from BOTH
                    // `androidx.compose.ui.text.font` (the int-resId
                    // overload) and `androidx.compose.ui.text.googlefonts`
                    // (the GoogleFont-taking overload). Skotch's
                    // single-entry import_map routes all calls to one
                    // wrapper, then padding produces wrong-typed args
                    // that crash JVM verification. Detect the
                    // primitive-vs-reference mismatch on the first user
                    // arg and emit null. The clinit completes; the
                    // affected val ends up null at runtime.
                    let desc_param_kinds = parse_descriptor_param_chars(&desc);
                    // Extract the first slot's full descriptor name (for L
                    // params) so we can distinguish "generic T erased to
                    // Object" (autoboxing OK) from "specific reference
                    // type" (the wrong-import case we want to refuse).
                    let first_slot_class: Option<String> = {
                        let inner = desc
                            .strip_prefix('(')
                            .and_then(|s| s.split(')').next())
                            .unwrap_or("");
                        let mut chars = inner.chars();
                        match chars.next() {
                            Some('L') => {
                                let mut s = String::new();
                                for c in chars.by_ref() {
                                    if c == ';' {
                                        break;
                                    }
                                    s.push(c);
                                }
                                Some(s)
                            }
                            _ => None,
                        }
                    };
                    if let (Some(first_user), Some(first_kind)) =
                        (arg_locals.first(), desc_param_kinds.first())
                    {
                        let user_ty = &fb.mf.locals[first_user.0 as usize];
                        let user_is_int = matches!(
                            user_ty,
                            Ty::Int | Ty::Byte | Ty::Short | Ty::Char | Ty::Bool
                        );
                        let user_is_ref = matches!(user_ty, Ty::Class(_) | Ty::String | Ty::Any);
                        // Slot is "generic T erased to Object" — autoboxing
                        // is always valid. Don't refuse this case.
                        let slot_is_object_generic = first_slot_class
                            .as_deref()
                            .map(|c| {
                                c == "java/lang/Object"
                                    || c == "kotlin/Any"
                                    || c == "java/lang/Number"
                                    || c == "java/lang/Comparable"
                            })
                            .unwrap_or(false);
                        let slot_is_ref = *first_kind == 'L' && !slot_is_object_generic;
                        let slot_is_int = *first_kind == 'I';
                        if (user_is_int && slot_is_ref) || (user_is_ref && slot_is_int) {
                            let dest = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Const(MirConst::Null),
                            });
                            return Some(dest);
                        }
                    }
                    // Vararg wrapping: when the descriptor's last param is
                    // an array (`[L<elem>;`) and the user supplied
                    // individual element-typed args (not an array),
                    // collect those trailing args into a freshly built
                    // `<elem>[N]` and replace them in `arg_locals`.
                    // Without this, calls like `bundleOf("k" to v)` emit
                    // a single `Pair` where `Pair[]` is required —
                    // VerifyError at class load.
                    if let Some(elem_class) = vararg_element_class(&desc) {
                        let desc_pc = skotch_classinfo::count_descriptor_params_pub(&desc);
                        if desc_pc >= 1 && arg_locals.len() >= desc_pc {
                            let fixed_count = desc_pc - 1;
                            let extras_start = fixed_count;
                            let extras_count = arg_locals.len() - extras_start;
                            // Skip if a single trailing arg is already
                            // an array reference matching the element
                            // class (user used spread syntax).
                            let already_array = extras_count == 1 && {
                                let id = arg_locals[extras_start];
                                matches!(
                                    fb.mf.locals.get(id.0 as usize),
                                    Some(Ty::Any) | Some(Ty::Class(_))
                                ) && {
                                    let ty = fb.mf.locals[id.0 as usize].clone();
                                    matches!(&ty, Ty::Class(c) if c.starts_with('['))
                                }
                            };
                            if !already_array {
                                let size_local = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: size_local,
                                    value: Rvalue::Const(MirConst::Int(extras_count as i32)),
                                });
                                let arr_local = fb.new_local(Ty::Any);
                                fb.push_stmt(MStmt::Assign {
                                    dest: arr_local,
                                    value: Rvalue::NewTypedObjectArray {
                                        size: size_local,
                                        element_class: elem_class.clone(),
                                    },
                                });
                                let extras_locals: Vec<LocalId> =
                                    arg_locals[extras_start..extras_start + extras_count].to_vec();
                                for (i, id) in extras_locals.iter().enumerate() {
                                    let idx_local = fb.new_local(Ty::Int);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: idx_local,
                                        value: Rvalue::Const(MirConst::Int(i as i32)),
                                    });
                                    let store_dest = fb.new_local(Ty::Unit);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: store_dest,
                                        value: Rvalue::ObjectArrayStore {
                                            array: arr_local,
                                            index: idx_local,
                                            value: *id,
                                        },
                                    });
                                }
                                arg_locals.truncate(extras_start);
                                arg_locals.push(arr_local);
                            }
                        }
                    }
                    // If the descriptor has more params than we have args
                    // (composable functions with $composer/$changed), forward
                    // the $composer/$changed from the enclosing scope.
                    let desc_param_count = skotch_classinfo::count_descriptor_params_pub(&desc);
                    if arg_locals.len() < desc_param_count {
                        // Try to find $composer in the current scope.
                        // In a @Composable function, $composer was injected
                        // by the compose transform as a parameter.
                        // In a lambda invoked as Function2, $composer is
                        // at param slot 1 (after this at slot 0).
                        let composer_sym = interner.intern("$composer");
                        let changed_sym = interner.intern("$changed");
                        let scope_composer = scope
                            .iter()
                            .rev()
                            .find(|(s, _)| *s == composer_sym)
                            .map(|(_, id)| *id);
                        let scope_changed = scope
                            .iter()
                            .rev()
                            .find(|(s, _)| *s == changed_sym)
                            .map(|(_, id)| *id);

                        // Parse the descriptor to find the Composer param's
                        // absolute position and per-slot types. Without
                        // this, calls like `rememberDrawerState(initial)`
                        // whose target is `(DrawerValue, Function1,
                        // Composer, I, I)` get the Composer placed at the
                        // wrong slot (the simple last/second-last
                        // heuristic doesn't handle the trailing `$default`
                        // mask), AND the trailing Int slots get filled
                        // with null instead of 0.
                        let composer_abs_pos = composer_position_in_descriptor(&desc);
                        let desc_param_tys = param_tys_from_descriptor(&desc);
                        // Track which slots we filled with user-default
                        // placeholders. The `$default` mask slot must have
                        // those bits set so the callee uses its own
                        // defaults instead of treating the nulls as
                        // explicit user-supplied values (e.g.
                        // `rememberCoroutineScope` would otherwise call
                        // `null.invoke()` on the missing `getContext`
                        // lambda).
                        let mut default_mask: u64 = precomputed_default_mask;
                        let default_slot_idx = composer_abs_pos.map(|p| p + 2);

                        // Trailing-lambda placement: if the user provided
                        // a Function-typed last arg AND the last user-param
                        // slot in the descriptor (just before Composer) is
                        // also Function-typed AND we don't already have the
                        // right number of user args, treat the user's last
                        // arg as the trailing lambda destined for the final
                        // user-param slot. Fill the in-between slots with
                        // defaults (mask bits set) so the call dispatches
                        // through $default-style defaults at the callee.
                        if let Some(composer_pos) = composer_abs_pos {
                            let user_slot_count = composer_pos;
                            let is_fn_slot = |ty: &Ty| {
                                matches!(ty, Ty::Function { .. })
                                    || matches!(ty, Ty::Class(n) if n.starts_with("kotlin/jvm/functions/Function")
                                        || module.is_lambda_class(n))
                            };
                            let last_user_slot_is_fn = composer_pos > 0
                                && desc_param_tys
                                    .get(composer_pos - 1)
                                    .map(is_fn_slot)
                                    .unwrap_or(false);
                            let last_user_arg_is_fn = arg_locals
                                .last()
                                .and_then(|l| fb.mf.locals.get(l.0 as usize))
                                .map(is_fn_slot)
                                .unwrap_or(false);
                            // Don't shift a positional first arg to the
                            // trailing slot when its arity matches slot 0
                            // better than the last slot. Example:
                            // `AndroidViewBinding(::inflate)` →
                            // arg_locals=[Function3], slot 0 is Function3,
                            // last slot is Function1. Without this check
                            // we'd null out slot 0 and put the Function3
                            // in slot 2, then crash at runtime when slot 0
                            // is invoked as the factory.
                            let fn_arity = |ty: &Ty| -> Option<usize> {
                                match ty {
                                    Ty::Function { params, .. } => Some(params.len()),
                                    Ty::Class(n) => n
                                        .strip_prefix("kotlin/jvm/functions/Function")
                                        .and_then(|s| s.parse::<usize>().ok()),
                                    _ => None,
                                }
                            };
                            let user_first_arg_arity = arg_locals
                                .first()
                                .and_then(|l| fb.mf.locals.get(l.0 as usize))
                                .and_then(fn_arity);
                            let user_first_slot_arity = desc_param_tys.first().and_then(fn_arity);
                            let user_last_slot_arity = composer_pos
                                .checked_sub(1)
                                .and_then(|i| desc_param_tys.get(i))
                                .and_then(fn_arity);
                            let positional_fit = match (
                                user_first_arg_arity,
                                user_first_slot_arity,
                                user_last_slot_arity,
                            ) {
                                (Some(a), Some(first), Some(last)) => a == first && a != last,
                                (Some(a), Some(first), None) => a == first,
                                _ => false,
                            };
                            if last_user_arg_is_fn
                                && last_user_slot_is_fn
                                && arg_locals.len() < user_slot_count
                                && user_slot_count >= 2
                                && !positional_fit
                            {
                                let trailing = arg_locals.pop().expect("non-empty checked above");
                                // Pad positions arg_locals.len()..(user_slot_count-1) with
                                // descriptor-typed defaults; record mask bits.
                                let pad_until = user_slot_count - 1;
                                while arg_locals.len() < pad_until {
                                    let cur = arg_locals.len();
                                    let slot_ty =
                                        desc_param_tys.get(cur).cloned().unwrap_or(Ty::Any);
                                    default_mask |= 1u64 << cur;
                                    let pad = fb.new_local(slot_ty.clone());
                                    let init = match &slot_ty {
                                        Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                            Rvalue::Const(MirConst::Int(0))
                                        }
                                        Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                        Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                        Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                        Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                        _ => Rvalue::Const(MirConst::Null),
                                    };
                                    fb.push_stmt(MStmt::Assign {
                                        dest: pad,
                                        value: init,
                                    });
                                    arg_locals.push(pad);
                                }
                                arg_locals.push(trailing);
                            }
                        }

                        while arg_locals.len() < desc_param_count {
                            let cur = arg_locals.len();
                            let slot_ty = desc_param_tys.get(cur).cloned().unwrap_or(Ty::Any);
                            // Only apply $composer/$changed heuristics
                            // when the descriptor actually contains a
                            // Composer param. For purely non-composable
                            // calls (e.g. `tween(durationMillis)` whose
                            // descriptor is `(IILEasing;)TweenSpec` —
                            // no Composer anywhere), the "last slot is
                            // $changed Int" heuristic mis-pads an
                            // Easing-typed slot as Int(0) and breaks
                            // JVM verification at the call site.
                            let is_composer_slot = match composer_abs_pos {
                                Some(p) => p == cur,
                                None => false,
                            };
                            let is_changed_slot = match composer_abs_pos {
                                Some(p) => p + 1 == cur,
                                None => false,
                            };
                            let is_default_slot = Some(cur) == default_slot_idx;
                            if is_composer_slot {
                                if let Some(cid) = scope_composer {
                                    arg_locals.push(cid);
                                } else {
                                    let composer = fb.new_local(Ty::Class(
                                        "androidx/compose/runtime/Composer".to_string(),
                                    ));
                                    fb.push_stmt(MStmt::Assign {
                                        dest: composer,
                                        value: Rvalue::Const(MirConst::Null),
                                    });
                                    arg_locals.push(composer);
                                }
                            } else if is_changed_slot {
                                if let Some(cid) = scope_changed {
                                    arg_locals.push(cid);
                                } else {
                                    let changed = fb.new_local(Ty::Int);
                                    fb.push_stmt(MStmt::Assign {
                                        dest: changed,
                                        value: Rvalue::Const(MirConst::Int(0)),
                                    });
                                    arg_locals.push(changed);
                                }
                            } else if is_default_slot {
                                // Emit the accumulated default-mask
                                // bitmap as an Int constant.
                                let mask = fb.new_local(Ty::Int);
                                fb.push_stmt(MStmt::Assign {
                                    dest: mask,
                                    value: Rvalue::Const(MirConst::Int(default_mask as i32)),
                                });
                                arg_locals.push(mask);
                            } else {
                                // User-default slot before the Composer
                                // (or in a no-Composer descriptor): fill
                                // with the descriptor-typed zero/null,
                                // and record that this slot used a
                                // default so the `$default` mask bit can
                                // be set.
                                if cur < composer_abs_pos.unwrap_or(usize::MAX) {
                                    default_mask |= 1u64 << cur;
                                }
                                let placeholder = fb.new_local(slot_ty.clone());
                                let init = match &slot_ty {
                                    Ty::Int | Ty::Byte | Ty::Short | Ty::Char => {
                                        Rvalue::Const(MirConst::Int(0))
                                    }
                                    Ty::Long => Rvalue::Const(MirConst::Long(0)),
                                    Ty::Float => Rvalue::Const(MirConst::Float(0.0)),
                                    Ty::Double => Rvalue::Const(MirConst::Double(0.0)),
                                    Ty::Bool => Rvalue::Const(MirConst::Bool(false)),
                                    _ => Rvalue::Const(MirConst::Null),
                                };
                                fb.push_stmt(MStmt::Assign {
                                    dest: placeholder,
                                    value: init,
                                });
                                arg_locals.push(placeholder);
                            }
                        }
                    }
                    // The actual JVM method name may be mangled like
                    // `Font-wCLgNak` (Kotlin value-class returns get a
                    // 7-char hash suffix). Query for the real name so
                    // the invokestatic targets a real method.
                    let actual_method_name = skotch_classinfo::lookup_method_name_and_descriptor(
                        &wrapper_class,
                        callee_str,
                        arg_locals.len(),
                    )
                    .map(|(n, _)| n)
                    .unwrap_or_else(|| callee_str.to_string());
                    CallKind::StaticJava {
                        class_name: wrapper_class,
                        method_name: actual_method_name,
                        descriptor: desc,
                    }
                } else {
                    // Check if it's a method on the current class or its
                    // superclass chain (e.g. setContentView from Activity,
                    // findNavController as a private method in same class).
                    let this_sym = interner.intern("this");
                    let this_id = scope
                        .iter()
                        .rev()
                        .find(|(s, _)| *s == this_sym)
                        .map(|(_, id)| *id);

                    if let Some(tid) = this_id {
                        // Identify the class that owns `tid`. Inside a
                        // lambda's invoke method, `tid` is the lambda's
                        // `this` (e.g. `Lambda$24`), NOT the outer
                        // enclosing class. Don't dispatch unqualified
                        // method calls via `tid` to the outer class:
                        // `aload <lambda this>; invokevirtual
                        // OuterClass.method` produces a VerifyError
                        // (`'this' argument 'Lambda$N' not instance of
                        // 'OuterClass'`). When the method exists only on
                        // an outer class, fall through to the
                        // "unknown call target" path; this is a
                        // diagnosed error rather than a runtime crash.
                        let tid_ty = fb.mf.locals.get(tid.0 as usize).cloned();
                        let tid_class_name = match &tid_ty {
                            Some(Ty::Class(cn)) => Some(cn.clone()),
                            _ => None,
                        };
                        let in_lambda = tid_class_name
                            .as_ref()
                            .is_some_and(|cn| module.is_lambda_class(cn));
                        // Prefer the class that matches `this`'s actual type.
                        // The previous fallback ("first non-stub class") was
                        // wrong for companion-method bodies: `this_local` is
                        // typed `Binding$Companion` but the fallback picked
                        // `Binding`, so bare `inflate(...)` self-calls inside
                        // the companion failed to resolve. Searching by
                        // `tid_class_name` correctly finds the Companion
                        // class's sibling methods.
                        let current_class = if let Some(cn) = &tid_class_name {
                            module.classes.iter().find(|c| &c.name == cn).or_else(|| {
                                if in_lambda {
                                    None
                                } else {
                                    module.classes.iter().find(|c| !c.is_cross_file_stub)
                                }
                            })
                        } else {
                            module.classes.iter().find(|c| !c.is_cross_file_stub)
                        };
                        // Side-channel for in-progress Companion classes
                        // not yet pushed to `module.classes`. If `this` is
                        // typed `<Outer>$Companion` and we have pending
                        // companion method names, treat the call as a
                        // virtual dispatch to that class.
                        let companion_self_dispatch: Option<(String, String)> = (|| {
                            let (pending_cls, pending_names) =
                                module.pending_companion_methods.as_ref()?;
                            let cn = tid_class_name.as_ref()?;
                            if cn != pending_cls {
                                return None;
                            }
                            if !pending_names.iter().any(|n| n == callee_str) {
                                return None;
                            }
                            // Build a permissive descriptor — arg-count
                            // matters for kotlinc overload resolution but
                            // the actual signature comes from the
                            // companion's own MIR (which will be
                            // re-checked when the class is finalized).
                            let mut d = String::from("(");
                            for a in &arg_locals {
                                d.push_str(&jvm_type_string_for_ty(&fb.mf.locals[a.0 as usize]));
                            }
                            d.push_str(")Ljava/lang/Object;");
                            Some((pending_cls.clone(), d))
                        })(
                        );
                        let mut resolved_desc: Option<(String, String)> = None; // (class, descriptor)

                        if let Some(cls) = current_class {
                            // Own methods (including private ones).
                            if cls.methods.iter().any(|m| m.name == callee_str) {
                                if let Some(d) = skotch_classinfo::lookup_method_descriptor(
                                    &cls.name,
                                    callee_str,
                                    arg_locals.len(),
                                ) {
                                    resolved_desc = Some((cls.name.clone(), d));
                                } else {
                                    // Build descriptor from arg types.
                                    let mut d = String::from("(");
                                    for a in &arg_locals {
                                        d.push_str(&jvm_type_string_for_ty(
                                            &fb.mf.locals[a.0 as usize],
                                        ));
                                    }
                                    d.push_str(")Ljava/lang/Object;");
                                    resolved_desc = Some((cls.name.clone(), d));
                                }
                            }
                            // Superclass methods via classpath.
                            if resolved_desc.is_none() {
                                if let Some(ref sup) = cls.super_class {
                                    if let Some(d) = skotch_classinfo::lookup_method_descriptor(
                                        sup,
                                        callee_str,
                                        arg_locals.len(),
                                    ) {
                                        resolved_desc = Some((sup.clone(), d));
                                    }
                                }
                            }
                        }
                        // Companion side-channel: if the regular class
                        // lookup didn't resolve and we have a pending
                        // companion that matches, dispatch through it.
                        if resolved_desc.is_none() {
                            if let Some(d) = companion_self_dispatch {
                                resolved_desc = Some(d);
                            }
                        }

                        if let Some((class_name, descriptor)) = resolved_desc {
                            let ret_char = descriptor
                                .rsplit(')')
                                .next()
                                .and_then(|s| s.chars().next())
                                .unwrap_or('V');
                            let dest_ty = match ret_char {
                                'V' => Ty::Unit,
                                'Z' => Ty::Bool,
                                'I' => Ty::Int,
                                'J' => Ty::Long,
                                'F' => Ty::Float,
                                'D' => Ty::Double,
                                _ => Ty::Any,
                            };
                            let mut call_args = vec![tid];
                            call_args.extend_from_slice(&arg_locals);
                            let dest = fb.new_local(dest_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name,
                                        method_name: callee_str.to_string(),
                                        descriptor,
                                    },
                                    args: call_args,
                                },
                            });
                            return Some(dest);
                        }

                        // If we're inside a lambda and the method wasn't
                        // found on the lambda class, try the captured
                        // outer `this` (Auto-injected by `Expr::Lambda`
                        // lowering when the body has unqualified calls
                        // to outer-class methods). Without this, calls
                        // like `findNavController()` inside a
                        // `setContent { ... }` lambda emit invalid
                        // bytecode (lambda's `this` as the receiver to
                        // an `OuterClass.method` invokevirtual → JVM
                        // VerifyError at class load).
                        if in_lambda {
                            let outer_this_sym = interner.intern("$outerThis");
                            let outer_lid_opt = scope
                                .iter()
                                .rev()
                                .find(|(s, _)| *s == outer_this_sym)
                                .map(|(_, lid)| *lid);
                            if let Some(outer_lid) = outer_lid_opt {
                                let outer_ty = fb.mf.locals.get(outer_lid.0 as usize).cloned();
                                if let Some(Ty::Class(outer_class_name)) = outer_ty {
                                    let mut outer_desc: Option<(String, String)> = None;
                                    if let Some(d) = skotch_classinfo::lookup_method_descriptor(
                                        &outer_class_name,
                                        callee_str,
                                        arg_locals.len(),
                                    ) {
                                        outer_desc = Some((outer_class_name.clone(), d));
                                    } else if let Some(outer_cls) =
                                        module.classes.iter().find(|c| c.name == outer_class_name)
                                    {
                                        if outer_cls.methods.iter().any(|m| m.name == callee_str) {
                                            let mut d = String::from("(");
                                            for a in &arg_locals {
                                                d.push_str(&jvm_type_string_for_ty(
                                                    &fb.mf.locals[a.0 as usize],
                                                ));
                                            }
                                            d.push_str(")Ljava/lang/Object;");
                                            outer_desc = Some((outer_class_name, d));
                                        }
                                    }
                                    if let Some((cn, descriptor)) = outer_desc {
                                        let ret_char = descriptor
                                            .rsplit(')')
                                            .next()
                                            .and_then(|s| s.chars().next())
                                            .unwrap_or('V');
                                        let dest_ty = match ret_char {
                                            'V' => Ty::Unit,
                                            'Z' => Ty::Bool,
                                            'I' => Ty::Int,
                                            'J' => Ty::Long,
                                            'F' => Ty::Float,
                                            'D' => Ty::Double,
                                            _ => Ty::Any,
                                        };
                                        let mut call_args = vec![outer_lid];
                                        call_args.extend_from_slice(&arg_locals);
                                        let dest = fb.new_local(dest_ty);
                                        fb.push_stmt(MStmt::Assign {
                                            dest,
                                            value: Rvalue::Call {
                                                kind: CallKind::VirtualJava {
                                                    class_name: cn,
                                                    method_name: callee_str.to_string(),
                                                    descriptor,
                                                },
                                                args: call_args,
                                            },
                                        });
                                        return Some(dest);
                                    }
                                }
                            }
                        }
                    }

                    // Truly unknown — emit null placeholder.
                    diags.push(Diagnostic::error(
                        *span,
                        format!("unknown call target `{}`", interner.resolve(callee_name)),
                    ));
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Const(MirConst::Null),
                    });
                    return Some(dest);
                }
            };

            // Determine return type from the call kind.
            let dest_ty = match &kind {
                CallKind::Static(fid) => {
                    let target = &module.functions[fid.0 as usize];
                    let raw_ret = target.return_ty.clone();
                    // Generic call specialization: when calling
                    // `<T> f(x: T): T` (or any generic fn returning T)
                    // with an arg of known type, the call-site result
                    // type is that arg's type. The JVM descriptor still
                    // uses Object (T erases to Object); the JVM emitter
                    // inserts checkcast/unbox after the invokestatic so
                    // the value lands in a typed slot. Mirrors
                    // kotlinc's argument-driven inference for the
                    // single-T case `fun <T> f(x: T): T`.
                    //
                    // We accept primitive AND class arg types now —
                    // previously only primitives were specialized, so
                    // `identity(Wrapper(...))` returned `Any` and
                    // `result.field` failed to resolve.
                    if matches!(raw_ret, Ty::Any) && target.has_type_params {
                        if let Some(first_arg_id) = arg_locals.first() {
                            let first_arg_ty = fb.mf.locals[first_arg_id.0 as usize].clone();
                            // Only specialize when the first formal param
                            // is also Any (T-typed). Functions whose
                            // first param is a concrete type aren't
                            // generic in their first slot.
                            let first_param_is_t = target
                                .params
                                .first()
                                .and_then(|pid| target.locals.get(pid.0 as usize))
                                .is_some_and(|t| matches!(t, Ty::Any));
                            // Avoid specializing when the arg type is
                            // unresolvable — `Ty::Any`/`Error`/Unit
                            // don't carry useful info and overriding
                            // raw_ret to them would just re-erase.
                            let arg_is_concrete = !matches!(
                                first_arg_ty,
                                Ty::Any | Ty::Error | Ty::Unit | Ty::Nothing
                            );
                            if first_param_is_t && arg_is_concrete {
                                first_arg_ty
                            } else {
                                raw_ret
                            }
                        } else {
                            raw_ret
                        }
                    } else {
                        raw_ret
                    }
                }
                CallKind::Virtual {
                    class_name,
                    method_name,
                } => {
                    let mut ret = Ty::Unit;
                    let mut search = Some(class_name.clone());
                    while let Some(ref cname) = search {
                        if let Some(cls) = module.classes.iter().find(|c| &c.name == cname) {
                            if let Some(m) = cls.methods.iter().find(|m| &m.name == method_name) {
                                ret = m.return_ty.clone();
                                break;
                            }
                            search = cls.super_class.clone();
                        } else {
                            break;
                        }
                    }
                    ret
                }
                CallKind::StaticJava {
                    ref class_name,
                    ref method_name,
                    ref descriptor,
                } => {
                    // ── Generic-signature-driven inference ────────
                    // If the target method has a `Signature` attribute
                    // (JVMS §4.7.9) AND it actually declares type
                    // parameters, parse it and run the unifier
                    // against the actual arg Tys to recover the
                    // type-variable bindings. The substituted return
                    // signature becomes the call's result Ty.
                    //
                    // This subsumes a chunk of the hardcoded method-
                    // name lists (`listOf`/`map`/`mutableStateOf`/
                    // `remember`/…) — kotlinc-compiled stdlib classes
                    // carry the unerased generic info we need.
                    let arg_tys: Vec<Ty> = arg_locals
                        .iter()
                        .map(|l| fb.mf.locals[l.0 as usize].clone())
                        .collect();
                    let sig_inferred: Option<Ty> = skotch_classinfo::lookup_method_signature(
                        class_name,
                        method_name,
                        arg_locals.len(),
                    )
                    .filter(|s| !s.type_params.is_empty())
                    .map(|s| skotch_classinfo::generic_signature::infer_return_ty(&s, &arg_tys))
                    .filter(|t| !matches!(t, Ty::Any));
                    if let Some(t) = sig_inferred {
                        t
                    } else {
                        // Fall back to the (still-needed) hardcoded
                        // lambda-return-T pattern for Compose intrinsics
                        // whose classpath signatures we don't have
                        // (e.g. private Compose runtime classes).
                        // Compose intrinsics whose result is the trailing
                        // lambda's return type (`remember`/`lazy`/…). Run the
                        // same generic unifier used for classpath signatures
                        // over an embedded canonical signature, against just
                        // the trailing lambda arg — `remember` has variadic
                        // leading `key` args, so the lambda is always last.
                        // This replaces a bespoke `match Ty::Function { ret }`
                        // with the shared inference path.
                        let lambda_ret =
                            intrinsics::compose_lambda_result_signature(method_name.as_str())
                                .and_then(
                                    skotch_classinfo::generic_signature::parse_method_signature,
                                )
                                .and_then(|sig| {
                                    arg_tys.last().map(|last| {
                                        skotch_classinfo::generic_signature::infer_return_ty(
                                            &sig,
                                            std::slice::from_ref(last),
                                        )
                                    })
                                })
                                .filter(|t| !matches!(t, Ty::Unit | Ty::Any));
                        if let Some(t) = lambda_ret {
                            t
                        } else if let Some((_, _, ret_ty)) = module.cross_file_fns.get(method_name)
                        {
                            ret_ty.clone()
                        } else {
                            match skotch_classinfo::return_type_from_descriptor(descriptor) {
                                "Unit" => Ty::Unit,
                                "Boolean" => Ty::Bool,
                                "Int" => Ty::Int,
                                "Long" => Ty::Long,
                                "Double" => Ty::Double,
                                "String" => Ty::String,
                                // The descriptor erases class/collection/
                                // nullable returns to `Object` (→ Any here).
                                // For kotlinc-compiled callees, recover the
                                // real Kotlin return type from `@Metadata`.
                                _ => metadata_return_ty(class_name, method_name).unwrap_or(Ty::Any),
                            }
                        }
                    }
                }
                _ => Ty::Unit,
            };

            // Autobox primitive args when the target parameter is Any.
            if let CallKind::Static(fid) = &kind {
                let target = &module.functions[fid.0 as usize];
                for (i, arg_id) in arg_locals.iter_mut().enumerate() {
                    if i < target.params.len() {
                        let param_ty = &target.locals[target.params[i].0 as usize];
                        let arg_ty = &fb.mf.locals[arg_id.0 as usize];
                        if matches!(param_ty, Ty::Any)
                            && !matches!(
                                arg_ty,
                                Ty::Any | Ty::String | Ty::Class(_) | Ty::Nullable(_)
                            )
                        {
                            let (box_class, box_desc) = match arg_ty {
                                Ty::Int => ("java/lang/Integer", "(I)Ljava/lang/Integer;"),
                                Ty::Bool => ("java/lang/Boolean", "(Z)Ljava/lang/Boolean;"),
                                Ty::Long => ("java/lang/Long", "(J)Ljava/lang/Long;"),
                                Ty::Double => ("java/lang/Double", "(D)Ljava/lang/Double;"),
                                _ => continue,
                            };
                            let boxed = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest: boxed,
                                value: Rvalue::Call {
                                    kind: CallKind::StaticJava {
                                        class_name: box_class.to_string(),
                                        method_name: "valueOf".to_string(),
                                        descriptor: box_desc.to_string(),
                                    },
                                    args: vec![*arg_id],
                                },
                            });
                            *arg_id = boxed;
                        }
                    }
                }
            }

            // Coroutine transform: when calling a
            // `suspend fun`, append the caller's own `$completion`
            // if the caller is itself suspend, otherwise pass
            // `null`. A real Kotlin compiler would reject the
            // non-suspend case at typeck time ("suspend function
            // can only be called from another suspend function");
            // we accept it for now so non-coroutine tests that
            // mention suspend functions still compile. The `null`
            // path will NPE at runtime if invoked.
            if let CallKind::Static(fid) = &kind {
                if module.functions[fid.0 as usize].is_suspend {
                    let cont_local = if fb.mf.is_suspend {
                        // Our last param is the incoming $completion.
                        *fb.mf
                            .params
                            .last()
                            .expect("suspend fn must have $completion")
                    } else {
                        let c =
                            fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest: c,
                            value: Rvalue::Const(MirConst::Null),
                        });
                        c
                    };
                    arg_locals.push(cont_local);
                }
            }

            // Before consuming `kind`, peek at the method name and
            // figure out whether the call's result needs an element-
            // type tag (e.g. `users.filter { ... }` is `List<User>`,
            // `users.map { it.name }` is `List<String>`). The collection
            // backbone calls go through `CollectionsKt`/`SequencesKt`
            // static methods after the receiver-method-dispatch rewrite.
            //
            // We use the side-channel `local_generic_args` rather than
            // changing the nominal `dest_ty` so the downstream type-
            // sensitive dispatchers (`.size`, `.add`, etc.) keep
            // matching on `Class(java/util/List)`. Chained calls like
            // `users.map { it.name }.filter { it.length > 0 }` work
            // because the filter dispatch reads element type from
            // `local_generic_args`.
            let result_element_ty: Option<Ty> =
                if let CallKind::StaticJava { method_name, .. } = &kind {
                    let m = method_name.as_str();
                    // The receiver's element type is tracked either in the
                    // receiver local's nominal `Ty::Generic` args or in the
                    // `local_generic_args` side channel (when the nominal Ty
                    // stays erased for downstream dispatch).
                    let receiver_elem = arg_locals.first().and_then(|&id| {
                        let recv_ty = &fb.mf.locals[id.0 as usize];
                        recv_ty.generic_args().first().cloned().or_else(|| {
                            fb.mf
                                .local_generic_args
                                .get(&id.0)
                                .and_then(|args| args.first().cloned())
                        })
                    });
                    if let Some(sig_str) = intrinsics::iterable_result_signature(m) {
                        // §6 collection methods: drive the result element type
                        // through the shared unifier over an embedded canonical
                        // signature (`filter` → List<T>, `map` → List<R>) —
                        // one signature-driven path replacing the former
                        // is_element_preserving / is_map_family branch.
                        // Reconstruct the receiver as `Iterable<elem>` (its
                        // element lives in the side channel, not the nominal
                        // Ty) so `T` binds; the remaining actuals (the lambda)
                        // pass through so `R` binds from its return type.
                        let mut actuals: Vec<Ty> = vec![Ty::Generic {
                            base: Box::new(Ty::Class("java/lang/Iterable".to_string())),
                            args: vec![receiver_elem.clone().unwrap_or(Ty::Any)],
                        }];
                        for &id in arg_locals.iter().skip(1) {
                            actuals.push(fb.mf.locals[id.0 as usize].clone());
                        }
                        skotch_classinfo::generic_signature::parse_method_signature(sig_str)
                            .map(|sig| {
                                skotch_classinfo::generic_signature::infer_return_ty(&sig, &actuals)
                            })
                            .and_then(|t| t.generic_args().first().cloned())
                            .filter(|t| !matches!(t, Ty::Any | Ty::Unit | Ty::Error))
                    } else if intrinsics::is_compose_state_holder(m) {
                        // First-arg-driven: Compose's `mutableStateOf(v)`
                        // returns `MutableState<typeof(v)>` (a §2 state holder,
                        // not a §6 iterable method, so it keeps its own rule).
                        // Recording the element on the result local lets
                        // `state.value` resolve against the right field type.
                        arg_locals
                            .first()
                            .map(|&id| fb.mf.locals[id.0 as usize].clone())
                            .filter(|t| !matches!(t, Ty::Any | Ty::Unit | Ty::Error))
                    } else {
                        None
                    }
                } else {
                    None
                };
            let dest = fb.new_local(dest_ty);
            if let Some(elem) = result_element_ty {
                fb.mf.local_generic_args.insert(dest.0, vec![elem]);
            }
            let stmt_idx = fb.mf.blocks[fb.cur_block as usize].stmts.len() as u32;
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Call {
                    kind,
                    args: arg_locals,
                },
            });
            if default_mask != 0 {
                let block_idx = fb.cur_block;
                fb.mf
                    .default_call_masks
                    .push((block_idx, stmt_idx, default_mask));
            }
            Some(dest)
        }
        Expr::StringTemplate(parts, _) => {
            // Constant folding: if all parts are compile-time constants, fold
            // the entire template to a single string literal at compile time.
            // This matches kotlinc's behavior.
            if let Some(folded) = try_const_fold_template(parts, interner) {
                let sid = module.intern_string(&folded);
                let dest = fb.new_local(Ty::String);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(MirConst::String(sid)),
                });
                return Some(dest);
            }

            // Try makeConcatWithConstants for the entire template
            // first. kotlinc collapses every Kotlin string-template
            // into a single `invokedynamic makeConcatWithConstants`
            // (JDK 9+). Build a recipe with `\u{1}` placeholders for
            // dynamic parts and gather the runtime args. Falls back to
            // a chain of ConcatStr ops when the recipe contains the
            // reserved bytes the JVM uses internally.
            {
                let mut recipe = String::new();
                let mut dyn_args: Vec<LocalId> = Vec::new();
                let mut recipe_safe = true;
                for part in parts {
                    match part {
                        skotch_syntax::TemplatePart::Text(s, _) => {
                            if s.contains('\u{1}') || s.contains('\u{2}') {
                                recipe_safe = false;
                                break;
                            }
                            recipe.push_str(s);
                        }
                        skotch_syntax::TemplatePart::Expr(e) => {
                            let id = lower_expr(
                                e,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            )?;
                            recipe.push('\u{1}');
                            dyn_args.push(id);
                        }
                        skotch_syntax::TemplatePart::IdentRef(sym, _) => {
                            let Some(local) =
                                scope.iter().rev().find(|(s, _)| s == sym).map(|(_, l)| *l)
                            else {
                                recipe_safe = false;
                                break;
                            };
                            recipe.push('\u{1}');
                            dyn_args.push(local);
                        }
                    }
                }
                if recipe_safe && !dyn_args.is_empty() {
                    let mut descriptor = String::from("(");
                    for a in &dyn_args {
                        let ty = &fb.mf.locals[a.0 as usize];
                        descriptor.push_str(&jvm_type_string_for_ty(ty));
                    }
                    descriptor.push_str(")Ljava/lang/String;");
                    let dest = fb.new_local(Ty::String);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::MakeConcatWithConstants { recipe, descriptor },
                            args: dyn_args,
                        },
                    });
                    return Some(dest);
                }
            }

            // Fallback: chain of ConcatStr operations.
            let mut result: Option<LocalId> = None;
            for part in parts {
                let part_local = lower_template_part(
                    part,
                    fb,
                    scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                )?;
                result = Some(match result {
                    None => part_local,
                    Some(prev) => {
                        let concat = fb.new_local(Ty::String);
                        fb.push_stmt(MStmt::Assign {
                            dest: concat,
                            value: Rvalue::BinOp {
                                op: MBinOp::ConcatStr,
                                lhs: prev,
                                rhs: part_local,
                            },
                        });
                        concat
                    }
                });
            }
            result
        }
        Expr::Unary { op, operand, .. } => {
            // For negation of an integer literal, fold to a negative
            // constant directly. For general expressions, emit a sub.
            match op {
                skotch_syntax::UnaryOp::Neg => {
                    // Check for constant folding: -<intlit> or -<doublelit>
                    if let Expr::IntLit(v, _) = operand.as_ref() {
                        let dest = fb.new_local(Ty::Int);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Int(-(*v as i32))),
                        });
                        return Some(dest);
                    }
                    if let Expr::LongLit(v, _) = operand.as_ref() {
                        let dest = fb.new_local(Ty::Long);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Long(-*v)),
                        });
                        return Some(dest);
                    }
                    if let Expr::DoubleLit(v, _) | Expr::FloatLit(v, _) = operand.as_ref() {
                        let dest = fb.new_local(Ty::Double);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Double(-*v)),
                        });
                        return Some(dest);
                    }
                    // General: 0 - operand
                    let val = lower_expr(
                        operand,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    let val_ty = fb.mf.locals[val.0 as usize].clone();
                    if matches!(val_ty, Ty::Long) {
                        let zero = fb.new_local(Ty::Long);
                        fb.push_stmt(MStmt::Assign {
                            dest: zero,
                            value: Rvalue::Const(MirConst::Long(0)),
                        });
                        let dest = fb.new_local(Ty::Long);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::BinOp {
                                op: MBinOp::SubL,
                                lhs: zero,
                                rhs: val,
                            },
                        });
                        return Some(dest);
                    }
                    if matches!(val_ty, Ty::Double) {
                        let zero = fb.new_local(Ty::Double);
                        fb.push_stmt(MStmt::Assign {
                            dest: zero,
                            value: Rvalue::Const(MirConst::Double(0.0)),
                        });
                        let dest = fb.new_local(Ty::Double);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::BinOp {
                                op: MBinOp::SubD,
                                lhs: zero,
                                rhs: val,
                            },
                        });
                        return Some(dest);
                    }
                    let zero = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: zero,
                        value: Rvalue::Const(MirConst::Int(0)),
                    });
                    let dest = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::BinOp {
                            op: MBinOp::SubI,
                            lhs: zero,
                            rhs: val,
                        },
                    });
                    Some(dest)
                }
                skotch_syntax::UnaryOp::Not => {
                    // !bool → (bool == 0). kotlinc emits this as a cmp +
                    // branch + iconst_0/iconst_1 materialization, which our
                    // cmp-branch fusion peephole then collapses to a single
                    // direct branch when the result is consumed by an `if`.
                    // The arithmetic `1 - bool` form is shorter but doesn't
                    // match kotlinc's emission shape.
                    let val = lower_expr(
                        operand,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    let zero = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest: zero,
                        value: Rvalue::Const(MirConst::Int(0)),
                    });
                    let dest = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpEq,
                            lhs: val,
                            rhs: zero,
                        },
                    });
                    Some(dest)
                }
            }
        }
        Expr::When {
            subject,
            branches,
            else_body,
            ..
        } => {
            // Lower `when (subject) { v1 -> e1; v2 -> e2; else -> e3 }`
            // as a chain of if-else comparisons:
            //   val tmp = subject
            //   if (tmp == v1) e1
            //   else if (tmp == v2) e2
            //   else e3
            // Detect subjectless when: subject is BoolLit(true).
            let is_subjectless = matches!(subject.as_ref(), Expr::BoolLit(true, _));
            let subj_raw = lower_expr(
                subject,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            // For reference-typed when-subjects that are bare identifiers
            // (param/local), kotlinc materializes a fresh copy in a new
            // slot so all `is`/`==` reads anchor to the same location.
            // Primitive subjects use the original slot (kotlinc emits
            // `iload_<slot>` once per branch). Detect by:
            //   1. subject AST is `Expr::Ident`
            //   2. lowered subject's MIR type is a reference (Class, Any,
            //      Nullable, String) — primitives skip materialization
            // For reference-typed when-subjects that are bare identifiers
            // (param/local), kotlinc materializes a fresh copy in a new
            // slot for `is`-check dispatch. In the BODY of each branch
            // kotlinc still uses the ORIGINAL identifier (the
            // smart-cast applies to the source variable, not the copy).
            // We therefore do NOT push the copy into scope; subsequent
            // lowering of the body's identifier reads finds the
            // original. The copy is referenced explicitly by the
            // pattern-dispatch lowering below.
            let subj = if is_subjectless {
                subj_raw
            } else {
                let raw_ty = fb.mf.locals[subj_raw.0 as usize].clone();
                let needs_copy = matches!(subject.as_ref(), Expr::Ident(_, _))
                    && matches!(
                        raw_ty,
                        Ty::Class(_) | Ty::Any | Ty::Nullable(_) | Ty::String
                    );
                if needs_copy {
                    let copy = fb.new_local(raw_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest: copy,
                        value: Rvalue::Local(subj_raw),
                    });
                    copy
                } else {
                    subj_raw
                }
            };

            // Sealed class exhaustiveness check: if the subject is a sealed
            // class, verify all subclasses are covered by `is` patterns.
            if !is_subjectless && else_body.is_none() {
                let subj_ty = &fb.mf.locals[subj.0 as usize];
                if let Ty::Class(class_name) = subj_ty {
                    let is_sealed = module
                        .classes
                        .iter()
                        .any(|c| &c.name == class_name && c.is_abstract && !c.is_interface);
                    if is_sealed {
                        // Collect all subclasses.
                        let subclasses: Vec<&str> = module
                            .classes
                            .iter()
                            .filter(|c| c.super_class.as_deref() == Some(class_name.as_str()))
                            .map(|c| c.name.as_str())
                            .collect();
                        // Collect all `is` patterns in the when branches.
                        let covered: Vec<String> = branches
                            .iter()
                            .filter_map(|b| {
                                if let Expr::IsCheck { type_name, .. } = &b.pattern {
                                    Some(interner.resolve(*type_name).to_string())
                                } else {
                                    None
                                }
                            })
                            .collect();
                        let missing: Vec<&&str> = subclasses
                            .iter()
                            .filter(|s| !covered.iter().any(|c| c == **s))
                            .collect();
                        if !missing.is_empty() {
                            let names: Vec<&str> = missing.iter().map(|s| **s).collect();
                            diags.push(Diagnostic::error(
                                subject.span(),
                                format!(
                                    "'when' on sealed class `{}` is not exhaustive. Missing: {}",
                                    class_name,
                                    names.join(", ")
                                ),
                            ));
                        }
                    }
                }
            }

            let result = fb.new_local(Ty::String); // type patched below

            // Pre-allocate ALL blocks so they're in the right order:
            // [cmp1_blk, body1_blk, cmp2_blk, body2_blk, ..., else_blk, merge_blk]
            // This ensures merge_blk has the highest index and is emitted last.
            let mut cmp_blks = Vec::new();
            let mut body_blks = Vec::new();
            for _ in branches {
                cmp_blks.push(fb.new_block());
                body_blks.push(fb.new_block());
            }
            let body_is_first: Vec<bool> = vec![true; branches.len()];
            let _ = body_is_first;
            // Always create an else block — even without an explicit else body,
            // we need it to assign a default value so the JVM verifier sees an
            // initialized result on all paths.
            let else_blk = fb.new_block();
            let merge_blk = fb.new_block();

            // First comparison block
            if !branches.is_empty() {
                fb.terminate_and_switch(Terminator::Goto(cmp_blks[0]), cmp_blks[0]);
            } else {
                fb.terminate_and_switch(Terminator::Goto(else_blk), else_blk);
            }

            for (i, branch) in branches.iter().enumerate() {
                // We're now in cmp_blks[i].
                // For `is`-check patterns when the subject was materialized
                // to a fresh local, dispatch directly off `subj` (the
                // materialized copy) rather than re-lowering the pattern's
                // cloned `Ident` (which would resolve to the original
                // parameter). This matches kotlinc's slot allocation:
                // dispatch reads the materialized slot, body reads the
                // original.
                let pattern_local = if let Expr::IsCheck {
                    type_name, negated, ..
                } = &branch.pattern
                {
                    if subj != subj_raw && !is_subjectless {
                        let raw_type_str = interner.resolve(*type_name);
                        let substituted = fb.reified_types.get(raw_type_str).cloned();
                        let type_str = substituted.as_deref().unwrap_or(raw_type_str);
                        let jvm_type = intrinsics::runtime_check_jvm_class(type_str)
                            .map(str::to_string)
                            .unwrap_or_else(|| type_str.to_string());
                        let dest = fb.new_local(Ty::Bool);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::InstanceOf {
                                obj: subj,
                                type_descriptor: jvm_type,
                            },
                        });
                        if *negated {
                            // Negate via `dest == false` — produces 1
                            // when `dest` was 0 and 0 when `dest` was 1.
                            let zero = fb.new_local(Ty::Bool);
                            fb.push_stmt(MStmt::Assign {
                                dest: zero,
                                value: Rvalue::Const(MirConst::Bool(false)),
                            });
                            let neg = fb.new_local(Ty::Bool);
                            fb.push_stmt(MStmt::Assign {
                                dest: neg,
                                value: Rvalue::BinOp {
                                    op: MBinOp::CmpEq,
                                    lhs: dest,
                                    rhs: zero,
                                },
                            });
                            neg
                        } else {
                            dest
                        }
                    } else {
                        lower_expr(
                            &branch.pattern,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )?
                    }
                } else {
                    lower_expr(
                        &branch.pattern,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?
                };

                // Determine the comparison for this branch.
                let cmp = if let Some(ref range_end_expr) = branch.range_end {
                    // Range pattern: subject >= start && subject <= end
                    let range_end_local = lower_expr(
                        range_end_expr,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )?;
                    let ge = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: ge,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpGe,
                            lhs: subj,
                            rhs: pattern_local,
                        },
                    });
                    let le = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: le,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpLe,
                            lhs: subj,
                            rhs: range_end_local,
                        },
                    });
                    // AND them together using short-circuit
                    // For simplicity, use a non-short-circuit AND:
                    // result = ge * le (both are 0/1 ints)
                    let both = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: both,
                        value: Rvalue::BinOp {
                            op: MBinOp::MulI,
                            lhs: ge,
                            rhs: le,
                        },
                    });
                    both
                } else if is_subjectless || matches!(&branch.pattern, Expr::IsCheck { .. }) {
                    // Subjectless when or `is Type` pattern: the pattern IS the condition.
                    pattern_local
                } else {
                    // Subject when: compare subject == pattern.
                    let c = fb.new_local(Ty::Bool);
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpEq,
                            lhs: subj,
                            rhs: pattern_local,
                        },
                    });
                    c
                };

                let fall_through = if i + 1 < branches.len() {
                    cmp_blks[i + 1]
                } else {
                    else_blk
                };

                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: cmp,
                        then_block: body_blks[i],
                        else_block: fall_through,
                    },
                    body_blks[i],
                );

                // Smart cast: if the branch pattern is `is Type`, narrow the
                // subject variable to that type in the branch body scope.
                // e.g. `when (obj) { is String -> obj.length }` — obj is
                // narrowed to String inside the branch.
                let smart_cast_entries = if let Expr::IsCheck {
                    expr: checked_expr,
                    type_name,
                    negated: false,
                    ..
                } = &branch.pattern
                {
                    if let Expr::Ident(var_name, _) = checked_expr.as_ref() {
                        let type_str = interner.resolve(*type_name);
                        let narrowed_ty =
                            skotch_types::ty_from_name(type_str).unwrap_or_else(|| {
                                if module.classes.iter().any(|c| c.name == type_str) {
                                    Ty::Class(type_str.to_string())
                                } else {
                                    Ty::Any
                                }
                            });
                        if let Some((_, old_local)) =
                            scope.iter().rev().find(|(s, _)| s == var_name)
                        {
                            let cast_local = fb.new_local(narrowed_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest: cast_local,
                                value: Rvalue::Local(*old_local),
                            });
                            scope.push((*var_name, cast_local));
                            1usize
                        } else {
                            0
                        }
                    } else {
                        0
                    }
                } else {
                    0
                };

                // Lower body in body_blks[i].
                // When branch bodies that are `{ stmts }` parse
                // as Expr::Lambda with no params. Inline them as blocks
                // rather than creating lambda classes — they're Kotlin block
                // expressions, not closures.
                let body_val = if let Expr::Lambda { params, body, .. } = &branch.body {
                    if params.is_empty() {
                        // Inline the block: lower each stmt, return last expr's val.
                        let mut last = None;
                        for s in &body.stmts {
                            match s {
                                skotch_syntax::Stmt::Expr(e)
                                | skotch_syntax::Stmt::Return { value: Some(e), .. } => {
                                    last = lower_expr(
                                        e,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    );
                                    // If it's a return, set the terminator.
                                    if matches!(s, skotch_syntax::Stmt::Return { .. }) {
                                        if let Some(local) = last {
                                            fb.set_terminator(Terminator::ReturnValue(local));
                                        }
                                    }
                                }
                                _ => {
                                    lower_stmt(
                                        s,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    );
                                }
                            }
                        }
                        last
                    } else {
                        lower_expr(
                            &branch.body,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )
                    }
                } else {
                    lower_expr(
                        &branch.body,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )
                };

                // Pop smart-cast scope entries.
                for _ in 0..smart_cast_entries {
                    scope.pop();
                }

                if let Some(val) = body_val {
                    if i == 0 {
                        let ty = fb.mf.locals[val.0 as usize].clone();
                        fb.mf.locals[result.0 as usize] = ty;
                    }
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(val),
                    });
                }

                // Goto merge, switch to next comparison block.
                // Don't overwrite explicit `return` terminators.
                let next = if i + 1 < branches.len() {
                    cmp_blks[i + 1]
                } else {
                    else_blk
                };
                {
                    let cur = fb.cur_block as usize;
                    if !matches!(fb.mf.blocks[cur].terminator, Terminator::ReturnValue(_)) {
                        fb.terminate_and_switch(Terminator::Goto(merge_blk), next);
                    } else {
                        fb.cur_block = next;
                    }
                }
            }

            // Else body
            if let Some(eb) = else_body {
                // We're in else_blk. Same Lambda-as-block inlining.
                let else_val = if let Expr::Lambda { params, body, .. } = eb.as_ref() {
                    if params.is_empty() {
                        let mut last = None;
                        for s in &body.stmts {
                            match s {
                                skotch_syntax::Stmt::Expr(e)
                                | skotch_syntax::Stmt::Return { value: Some(e), .. } => {
                                    last = lower_expr(
                                        e,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    );
                                    if matches!(s, skotch_syntax::Stmt::Return { .. }) {
                                        if let Some(local) = last {
                                            fb.set_terminator(Terminator::ReturnValue(local));
                                        }
                                    }
                                }
                                _ => {
                                    lower_stmt(
                                        s,
                                        fb,
                                        scope,
                                        module,
                                        name_to_func,
                                        name_to_global,
                                        interner,
                                        diags,
                                        loop_ctx,
                                    );
                                }
                            }
                        }
                        last
                    } else {
                        lower_expr(
                            eb,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        )
                    }
                } else {
                    lower_expr(
                        eb,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    )
                };
                if let Some(val) = else_val {
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(val),
                    });
                }
                {
                    let cur = fb.cur_block as usize;
                    if !matches!(fb.mf.blocks[cur].terminator, Terminator::ReturnValue(_)) {
                        fb.terminate_and_switch(Terminator::Goto(merge_blk), merge_blk);
                    } else {
                        fb.cur_block = merge_blk;
                    }
                }
            } else {
                // No else body. Detect "exhaustive when on a sealed
                // class" (every direct subclass appears as an `is`
                // pattern). kotlinc throws `NoWhenBranchMatchedException`
                // for that path; otherwise we fall back to a default
                // value (matches kotlinc for non-exhaustive whens too).
                let throws_no_branch = !is_subjectless && {
                    let subj_ty = fb.mf.locals[subj.0 as usize].clone();
                    if let Ty::Class(class_name) = subj_ty {
                        let is_sealed = module
                            .classes
                            .iter()
                            .any(|c| c.name == class_name && c.is_abstract && !c.is_interface);
                        if is_sealed {
                            let subclasses: Vec<String> = module
                                .classes
                                .iter()
                                .filter(|c| c.super_class.as_deref() == Some(class_name.as_str()))
                                .map(|c| c.name.clone())
                                .collect();
                            let covered: rustc_hash::FxHashSet<String> = branches
                                .iter()
                                .filter_map(|b| {
                                    if let Expr::IsCheck { type_name, .. } = &b.pattern {
                                        Some(interner.resolve(*type_name).to_string())
                                    } else {
                                        None
                                    }
                                })
                                .collect();
                            !subclasses.is_empty()
                                && subclasses.iter().all(|s| covered.contains(s.as_str()))
                        } else {
                            false
                        }
                    } else {
                        false
                    }
                };

                if throws_no_branch {
                    let exc_class = "kotlin/NoWhenBranchMatchedException".to_string();
                    let exc = fb.new_local(Ty::Class(exc_class.clone()));
                    fb.push_stmt(MStmt::Assign {
                        dest: exc,
                        value: Rvalue::NewInstance(exc_class.clone()),
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest: exc,
                        value: Rvalue::Call {
                            kind: CallKind::ConstructorJava {
                                class_name: exc_class,
                                descriptor: "()V".to_string(),
                            },
                            args: vec![],
                        },
                    });
                    // Set terminator on the current (else) block; do NOT
                    // switch to merge — the throw is the path's terminus.
                    fb.set_terminator(Terminator::Throw(exc));
                    // Switch to merge_blk so the trailing fix-up below
                    // operates on the correct block.
                    fb.cur_block = merge_blk;
                } else {
                    let result_ty = &fb.mf.locals[result.0 as usize];
                    let default_val = match result_ty {
                        Ty::Int | Ty::Byte | Ty::Short | Ty::Char | Ty::Bool | Ty::Float => {
                            MirConst::Int(0)
                        }
                        Ty::Long => MirConst::Long(0),
                        Ty::Double => MirConst::Double(0.0),
                        _ => MirConst::Null,
                    };
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Const(default_val),
                    });
                    fb.terminate_and_switch(Terminator::Goto(merge_blk), merge_blk);
                }
            }

            // If the merge block is unreachable (all branches
            // returned explicitly) and the method returns non-void, the
            // merge block needs a valid return. Only fix non-void methods;
            // void methods' bare `Return` is correct.
            {
                let merge = merge_blk as usize;
                let result_ty = &fb.mf.locals[result.0 as usize];
                if matches!(fb.mf.blocks[merge].terminator, Terminator::Return)
                    && !matches!(result_ty, Ty::Unit)
                {
                    fb.mf.blocks[merge].terminator = Terminator::ReturnValue(result);
                }
            }

            Some(result)
        }
        Expr::Index {
            receiver,
            index,
            span: _,
        } => {
            let arr = lower_expr(
                receiver,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let idx = lower_expr(
                index,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let arr_ty = fb.mf.locals[arr.0 as usize].clone();
            match &arr_ty {
                Ty::IntArray | Ty::BooleanArray | Ty::ByteArray => {
                    let elem_ty = match &arr_ty {
                        Ty::BooleanArray => Ty::Bool,
                        Ty::ByteArray => Ty::Byte,
                        _ => Ty::Int,
                    };
                    let dest = fb.new_local(elem_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::ArrayLoad {
                            array: arr,
                            index: idx,
                        },
                    });
                    Some(dest)
                }
                Ty::LongArray => {
                    let dest = fb.new_local(Ty::Long);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::ArrayLoad {
                            array: arr,
                            index: idx,
                        },
                    });
                    Some(dest)
                }
                Ty::DoubleArray => {
                    let dest = fb.new_local(Ty::Double);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::ArrayLoad {
                            array: arr,
                            index: idx,
                        },
                    });
                    Some(dest)
                }
                Ty::Class(cn) if cn.contains("ArrayList") || cn.contains("List") => {
                    // List[index] → invokeinterface java/util/List.get(I)Object
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/util/List".to_string(),
                                method_name: "get".to_string(),
                                descriptor: "(I)Ljava/lang/Object;".to_string(),
                            },
                            args: vec![arr, idx],
                        },
                    });
                    Some(dest)
                }
                Ty::Class(cn) if cn.contains("Map") => {
                    // Map[key] → invokeinterface java/util/Map.get(Object)Object
                    let idx_ty = fb.mf.locals[idx.0 as usize].clone();
                    let boxed_key = mir_autobox(fb, idx, &idx_ty);
                    let dest = fb.new_local(Ty::Any);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/util/Map".to_string(),
                                method_name: "get".to_string(),
                                descriptor: "(Ljava/lang/Object;)Ljava/lang/Object;".to_string(),
                            },
                            args: vec![arr, boxed_key],
                        },
                    });
                    Some(dest)
                }
                Ty::String => {
                    // String[index] → invokevirtual String.charAt(I)C
                    let dest = fb.new_local(Ty::Char);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/String".to_string(),
                                method_name: "charAt".to_string(),
                                descriptor: "(I)C".to_string(),
                            },
                            args: vec![arr, idx],
                        },
                    });
                    Some(dest)
                }
                Ty::Class(cn) => {
                    // Check for operator fun get() on the class (own module).
                    let get_method = module
                        .classes
                        .iter()
                        .find(|c| &c.name == cn)
                        .and_then(|cls| cls.methods.iter().find(|m| m.name == "get"))
                        .map(|m| m.return_ty.clone());
                    if let Some(ret_ty) = get_method {
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Virtual {
                                    class_name: cn.clone(),
                                    method_name: "get".to_string(),
                                },
                                args: vec![arr, idx],
                            },
                        });
                        Some(dest)
                    } else if let Some(desc) =
                        skotch_classinfo::lookup_method_descriptor(cn, "get", 1)
                    {
                        // External class (Android SDK / JDK) with operator
                        // `fun get(...)`. Example: `Placeable[FirstBaseline]`
                        // on `androidx/compose/ui/layout/Placeable` — the
                        // index is an `AlignmentLine`, not an int, so the
                        // generic `ArrayLoad` path is wrong. Emit a virtual
                        // call with the real descriptor instead.
                        let ret_ty = ty_from_descriptor_return(&desc);
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: cn.clone(),
                                    method_name: "get".to_string(),
                                    descriptor: desc,
                                },
                                args: vec![arr, idx],
                            },
                        });
                        Some(dest)
                    } else {
                        diags.push(Diagnostic::error(
                            receiver.span(),
                            format!("no operator fun get() on class `{cn}`"),
                        ));
                        None
                    }
                }
                Ty::Any => {
                    // Lambda-receiver / generic-erased List: when the type
                    // resolves to `Any` (e.g. `measurables: List<Measurable>`
                    // inside a `Layout { measurables, constraints -> ... }`
                    // body, where the generic parameter gets erased), the
                    // call `measurables[0]` should compile to
                    // `List.get(0)`, NOT `aaload`. Object[] indexing is
                    // rare in idiomatic Kotlin code and is handled via the
                    // typed `Ty::IntArray`/`Ty::LongArray`/etc. paths.
                    // Defaulting to List.get matches the common case and
                    // unblocks JetChat's IconAndTextRow.
                    // If the source `arr` local had its type args recorded
                    // (e.g. `measurables: List<Measurable>`), pick up the
                    // element type so the result local carries it instead
                    // of the erased Any. Downstream calls then resolve
                    // the right method overload.
                    let elem_ty = fb
                        .mf
                        .local_generic_args
                        .get(&arr.0)
                        .and_then(|args| args.first().cloned())
                        .unwrap_or(Ty::Any);
                    let dest = fb.new_local(elem_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/util/List".to_string(),
                                method_name: "get".to_string(),
                                descriptor: "(I)Ljava/lang/Object;".to_string(),
                            },
                            args: vec![arr, idx],
                        },
                    });
                    Some(dest)
                }
                _ => {
                    diags.push(Diagnostic::error(
                        receiver.span(),
                        "index operator is only supported on String, IntArray, List, Map, Array, and classes with operator fun get()",
                    ));
                    None
                }
            }
        }
        Expr::Field {
            receiver,
            name,
            span,
        } => {
            // Nested static field access: `OuterClass.NestedClass.FIELD`
            //
            // Pattern matches when receiver is itself an Expr::Field with an
            // Ident inner receiver — i.e. a three-segment dotted path. This
            // covers `android.os.Build.VERSION.SDK_INT` (imported as
            // `import android.os.Build`, then referenced as
            // `Build.VERSION.SDK_INT`) and `Build.VERSION_CODES.S`-style
            // constants used widely in Android theme code.
            //
            // Without this, MIR-lower's recursive Field-evaluation cannot
            // resolve the inner `Build.VERSION` (Build is not a class in
            // module.classes; VERSION is not a function or global) and
            // returns None, dropping the entire enclosing statement.
            if let Expr::Field {
                receiver: inner_receiver,
                name: inner_name,
                ..
            } = receiver.as_ref()
            {
                if let Expr::Ident(outer_sym, _) = inner_receiver.as_ref() {
                    let outer_str = interner.resolve(*outer_sym).to_string();
                    let mid_str = interner.resolve(*inner_name).to_string();
                    let field_str = interner.resolve(*name).to_string();
                    // Resolve outer simple name through the import map.
                    if let Some(outer_jvm) = module.import_map.get(&outer_str).cloned() {
                        let nested_class = format!("{outer_jvm}${mid_str}");
                        // Hardcoded descriptors for the small set of Android
                        // Build nested-static fields actually used by sample
                        // apps. The JVM emitter just needs the descriptor +
                        // result type; we list the ones JetChat exercises.
                        let known: Option<(Ty, &str)> =
                            match (outer_jvm.as_str(), mid_str.as_str(), field_str.as_str()) {
                                ("android/os/Build", "VERSION", "SDK_INT") => Some((Ty::Int, "I")),
                                ("android/os/Build", "VERSION", "RELEASE") => {
                                    Some((Ty::String, "Ljava/lang/String;"))
                                }
                                ("android/os/Build", "VERSION", "CODENAME") => {
                                    Some((Ty::String, "Ljava/lang/String;"))
                                }
                                // Build.VERSION_CODES.* — all Int level constants
                                // (BASE=1 through current). We don't enumerate
                                // every code; match by mid-segment and accept any
                                // FIELD name as Int.
                                ("android/os/Build", "VERSION_CODES", _) => Some((Ty::Int, "I")),
                                _ => None,
                            };
                        if let Some((ty, desc)) = known {
                            let dest = fb.new_local(ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::GetStaticField {
                                    class_name: nested_class,
                                    field_name: field_str,
                                    descriptor: desc.to_string(),
                                },
                            });
                            return Some(dest);
                        }
                        // Android R class — `R.<type>.<name>` always
                        // resolves to a static `int` constant on
                        // `<Pkg>/R$<type>.<name>:I`. The R classes
                        // themselves are generated during the build
                        // pipeline so classinfo can't find them yet —
                        // hardcode the descriptor based on the well-known
                        // Android resource-type taxonomy. `styleable` is
                        // the exception (int[] arrays) but those aren't
                        // accessed as `R.styleable.X` in this form (those
                        // appear as `R.styleable.AppCompatTheme_X` and
                        // are still ints).
                        if outer_jvm.ends_with("/R") || outer_jvm == "R" {
                            let dest = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::GetStaticField {
                                    class_name: nested_class,
                                    field_name: field_str,
                                    descriptor: "I".to_string(),
                                },
                            });
                            return Some(dest);
                        }
                        // Generic nested-static lookup via classinfo.
                        // Covers JDK enum-style inner classes whose
                        // fields actually exist in the loaded class
                        // registry (e.g. `KeyEvent.KEYCODE.X`).
                        if let Some(field_desc) = skotch_classinfo::lookup_static_field_descriptor(
                            &nested_class,
                            &field_str,
                        ) {
                            let field_ty = ty_from_descriptor_return(&field_desc);
                            let dest = fb.new_local(field_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::GetStaticField {
                                    class_name: nested_class,
                                    field_name: field_str,
                                    descriptor: field_desc,
                                },
                            });
                            return Some(dest);
                        }
                    }
                }
            }
            // Companion property access: `OuterClass.PROP` →
            // `getstatic Outer.Companion; invokevirtual
            //  Outer$Companion.get<PROP>()`. Matches kotlinc's emission.
            if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                let recv_str = interner.resolve(*recv_sym).to_string();
                let field_str = interner.resolve(*name).to_string();
                let getter_name = format!(
                    "get{}{}",
                    field_str
                        .chars()
                        .next()
                        .map(|c| c.to_uppercase().to_string())
                        .unwrap_or_default(),
                    &field_str[field_str.chars().next().map(char::len_utf8).unwrap_or(0)..]
                );
                let companion_hit: Option<(String, String, Ty)> = module
                    .classes
                    .iter()
                    .find(|c| c.name == recv_str && c.companion_class_name.is_some())
                    .and_then(|outer| {
                        let cn = outer.companion_class_name.clone().unwrap();
                        let comp = module.classes.iter().find(|c| c.name == cn)?;
                        let m = comp.methods.iter().find(|m| m.name == getter_name)?;
                        Some((outer.name.clone(), cn, m.return_ty.clone()))
                    });
                if let Some((outer_name, comp_name, ret_ty)) = companion_hit {
                    let instance_local = fb.new_local(Ty::Class(comp_name.clone()));
                    fb.push_stmt(MStmt::Assign {
                        dest: instance_local,
                        value: Rvalue::GetStaticField {
                            class_name: outer_name,
                            field_name: "Companion".to_string(),
                            descriptor: format!("L{};", comp_name),
                        },
                    });
                    let dest = fb.new_local(ret_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Virtual {
                                class_name: comp_name,
                                method_name: getter_name,
                            },
                            args: vec![instance_local],
                        },
                    });
                    return Some(dest);
                }
            }
            // Companion object property access: ClassName.PROP → global constant lookup.
            if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                let recv_str = interner.resolve(*recv_sym).to_string();
                let field_str = interner.resolve(*name).to_string();
                let is_class = module.classes.iter().any(|c| c.name == recv_str);
                if is_class {
                    let companion_sym = interner.intern(&field_str);
                    if let Some(constant) = name_to_global.get(&companion_sym).cloned() {
                        let ty = const_ty(&constant);
                        let dest = fb.new_local(ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(constant),
                        });
                        return Some(dest);
                    }
                }
            }

            // Well-known Kotlin/Java stdlib constants:
            // Long.MAX_VALUE, Long.MIN_VALUE, Int.MAX_VALUE, Int.MIN_VALUE
            if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                let recv_str = interner.resolve(*recv_sym);
                let field_str = interner.resolve(*name);
                let constant: Option<(Ty, MirConst)> = match (recv_str, field_str) {
                    ("Long", "MAX_VALUE") => Some((Ty::Long, MirConst::Long(i64::MAX))),
                    ("Long", "MIN_VALUE") => Some((Ty::Long, MirConst::Long(i64::MIN))),
                    ("Int", "MAX_VALUE") => Some((Ty::Int, MirConst::Int(i32::MAX))),
                    ("Int", "MIN_VALUE") => Some((Ty::Int, MirConst::Int(i32::MIN))),
                    ("Double", "MAX_VALUE") => Some((Ty::Double, MirConst::Double(f64::MAX))),
                    ("Double", "MIN_VALUE") => {
                        Some((Ty::Double, MirConst::Double(f64::MIN_POSITIVE)))
                    }
                    ("Float", "MAX_VALUE") => Some((Ty::Float, MirConst::Float(f32::MAX))),
                    ("Byte", "MAX_VALUE") => Some((Ty::Byte, MirConst::Int(i8::MAX as i32))),
                    ("Byte", "MIN_VALUE") => Some((Ty::Byte, MirConst::Int(i8::MIN as i32))),
                    ("Short", "MAX_VALUE") => Some((Ty::Short, MirConst::Int(i16::MAX as i32))),
                    ("Short", "MIN_VALUE") => Some((Ty::Short, MirConst::Int(i16::MIN as i32))),
                    _ => None,
                };
                if let Some((ty, val)) = constant {
                    let dest = fb.new_local(ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Const(val),
                    });
                    return Some(dest);
                }
            }

            // Dispatchers.IO / .Default / .Main / .Unconfined
            //
            // `Dispatchers` is a Kotlin object. Each dispatcher property
            // is exposed as a static getter method on the JVM:
            //   Dispatchers.IO → invokestatic Dispatchers.getIO()
            //   Dispatchers.Default → invokestatic Dispatchers.getDefault()
            //   Dispatchers.Unconfined → invokestatic Dispatchers.getUnconfined()
            //   Dispatchers.Main → invokestatic Dispatchers.getMain()
            if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                let recv_str = interner.resolve(*recv_sym);
                let field_str = interner.resolve(*name);
                if recv_str == "Dispatchers" {
                    let getter = match field_str {
                        "IO" => Some("getIO"),
                        "Default" => Some("getDefault"),
                        "Unconfined" => Some("getUnconfined"),
                        "Main" => Some("getMain"),
                        _ => None,
                    };
                    if let Some(getter_name) = getter {
                        let dest = fb
                            .new_local(Ty::Class("kotlin/coroutines/CoroutineContext".to_string()));
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: "kotlinx/coroutines/Dispatchers".to_string(),
                                    method_name: getter_name.to_string(),
                                    descriptor: "()Lkotlinx/coroutines/CoroutineDispatcher;"
                                        .to_string(),
                                },
                                args: vec![],
                            },
                        });
                        return Some(dest);
                    }
                }
            }

            // Compose UI numeric → unit-value extension properties:
            //   `32.dp`   → Dp(32.toFloat())   — erased to float
            //   `32.sp`   → TextUnit(...)      — also float-erased
            //   `32.em`   → TextUnit(...)      — also float-erased
            //
            // These are `inline val Int.dp: Dp = Dp(toFloat())` style
            // declarations on `androidx.compose.ui.unit.*`. Without
            // inlining, skotch resolves the property to `null` and the
            // surrounding expression (often a Composable lambda body)
            // gets a broken `aconst_null; areturn` shape that d8 then
            // rejects. Since `Dp` and `TextUnit` are `@JvmInline value
            // class`es over `Float`/`Long`, the JVM-erased value IS the
            // primitive. We emit a simple numeric→Float convert at the
            // call site by routing through `.toFloat()` (which the JVM
            // backend handles via `i2f`/`l2f`/`d2f`).
            {
                let field_str = interner.resolve(*name);
                if intrinsics::is_compose_unit_prop(field_str) {
                    // Build a synthetic `<receiver>.toFloat()` call and
                    // recurse via lower_expr so the existing primitive-
                    // conversion path handles the actual numeric coerce.
                    let to_float_sym = interner.intern("toFloat");
                    let synth = skotch_syntax::Expr::Call {
                        callee: Box::new(skotch_syntax::Expr::Field {
                            receiver: receiver.clone(),
                            name: to_float_sym,
                            span: *span,
                        }),
                        args: Vec::new(),
                        type_args: Vec::new(),
                        span: *span,
                    };
                    if let Some(synth_local) = lower_expr(
                        &synth,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    ) {
                        return Some(synth_local);
                    }
                }
            }

            // Qualified enum-member access: `InputSelector.EMOJI`.
            // Skotch compiles enum constants as zero-arg static methods
            // on the wrapper class (e.g. `Direction.NORTH()` returns
            // a `Direction` instance), not as static fields. The
            // generic `name_to_func.get(name)` fallback below resolves
            // ENUM-MEMBER references through this synthesized method,
            // but when two enums in the same file share a member name
            // (JetChat: both `InputSelector.EMOJI` and
            // `EmojiStickerSelector.EMOJI`) only one wins the lookup,
            // and the wrong one is selected. Disambiguate by looking
            // up the receiver-qualified accessor name (e.g.
            // `InputSelector$EMOJI`) first.
            if let Expr::Ident(recv_sym, _) = receiver.as_ref() {
                let recv_str = interner.resolve(*recv_sym).to_string();
                let is_enum_simple = module.enum_names.contains(&recv_str);
                let is_enum_fq = module
                    .enum_names
                    .iter()
                    .any(|n| n.rsplit('/').next() == Some(recv_str.as_str()));
                if is_enum_simple || is_enum_fq {
                    let field_str = interner.resolve(*name).to_string();
                    let qualified = format!("{recv_str}${field_str}");
                    let qualified_sym = interner.intern(&qualified);
                    if let Some(&fid) = name_to_func.get(&qualified_sym) {
                        let ret_ty = module.functions[fid.0 as usize].return_ty.clone();
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Static(fid),
                                args: vec![],
                            },
                        });
                        return Some(dest);
                    }
                }
            }

            // Check if this is an enum/object constant access (Color.RED)
            // or an extension property access (receiver.extProp).
            if let Some(&fid) = name_to_func.get(name) {
                let ret_ty = module.functions[fid.0 as usize].return_ty.clone();
                let params_len = module.functions[fid.0 as usize].params.len();
                if params_len == 0 {
                    // Zero-arg function (enum constant or companion method).
                    let dest = fb.new_local(ret_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Static(fid),
                            args: vec![],
                        },
                    });
                    return Some(dest);
                }
                if params_len == 1 {
                    // Extension property: lower receiver, call with it.
                    if let Some(recv_local) = lower_expr(
                        receiver,
                        fb,
                        scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        loop_ctx,
                    ) {
                        let dest = fb.new_local(ret_ty);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::Static(fid),
                                args: vec![recv_local],
                            },
                        });
                        return Some(dest);
                    }
                }
            }

            // Try to lower as a field access on a class instance.
            if let Some(recv_local) = lower_expr(
                receiver,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            ) {
                let recv_ty = fb.mf.locals[recv_local.0 as usize].clone();
                // A parameterized collection (`Ty::Generic { base: List, .. }`)
                // has the same instance-member surface as its erased base, so
                // unwrap it to the base class before member resolution. The two
                // type-inference paths disagree on representation: a local from
                // `listOf(...)` is typed `Ty::Class` by the call-lowering path,
                // but a top-level-val `listOf(...)` is typed `Ty::Generic` by
                // `infer_top_level_val_ty`. Without this unwrap, `.size` (and
                // every other `Ty::Class`-keyed member below) on a top-level-val
                // List falls through to `None`, which drops the whole enclosing
                // function body (#354).
                let recv_ty = match recv_ty {
                    Ty::Generic { base, .. } => *base,
                    other => other,
                };
                if let Ty::Class(class_name) = recv_ty {
                    let field_name = interner.resolve(*name).to_string();
                    // Walk the inheritance chain to find the declaring class.
                    let mut declaring_class = class_name.clone();
                    let mut field_ty = Ty::Any;
                    let mut search = Some(class_name.clone());
                    while let Some(ref cname) = search {
                        if let Some(cls) = module.classes.iter().find(|c| &c.name == cname) {
                            if let Some(f) = cls.fields.iter().find(|f| f.name == field_name) {
                                declaring_class = cname.clone();
                                field_ty = f.ty.clone();
                                break;
                            }
                            search = cls.super_class.clone();
                        } else {
                            break;
                        }
                    }
                    // Check if this is a computed property (getter method).
                    // For inheritance, dispatch on the receiver's static type
                    // (`class_name`) rather than the declaring class — kotlinc
                    // emits `invokevirtual Child.getX()` even when `x` is
                    // declared on `Base`. The JVM resolves the inherited
                    // getter at runtime.
                    let getter_name =
                        format!("get{}{}", &field_name[..1].to_uppercase(), &field_name[1..]);
                    if let Some(cls) = module.classes.iter().find(|c| c.name == declaring_class) {
                        if let Some(getter) = cls.methods.iter().find(|m| m.name == getter_name) {
                            let ret_ty = getter.return_ty.clone();
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::Virtual {
                                        class_name: class_name.clone(),
                                        method_name: getter_name,
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // JDK class property-as-method: sb.length → length()
                    // Many JVM classes expose properties as methods.
                    if declaring_class.contains('/') {
                        // Try the field name directly as a 0-arg method.
                        if let Some((_, found_method, desc, ret_ty)) =
                            lookup_java_instance(&declaring_class, &field_name, 0)
                        {
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: declaring_class.clone(),
                                        method_name: found_method,
                                        descriptor: desc,
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                        // Try getXxx() pattern.
                        let jvm_getter =
                            format!("get{}{}", &field_name[..1].to_uppercase(), &field_name[1..]);
                        if let Some((_, found_method, desc, ret_ty)) =
                            lookup_java_instance(&declaring_class, &jvm_getter, 0)
                        {
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: declaring_class.clone(),
                                        method_name: found_method,
                                        descriptor: desc,
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                        // Mangled getter pattern for value-class returns:
                        // `ColorScheme.background` → real JVM method
                        // `getBackground-0d7_KjU()J`. The two
                        // `lookup_java_instance` lookups above use exact
                        // name matching, so they miss any mangled
                        // method. Route through the mangle-aware
                        // `lookup_method_name_and_descriptor` for the
                        // `getXxx` shape, which is how every Compose
                        // value-class-returning property is named.
                        // Without this, `MaterialTheme.colorScheme.background`
                        // (a long pattern in JetChat theming) returns None
                        // from this whole field path, drops the parent
                        // call's arg, and the surrounding `ModalDrawerSheet`
                        // call collapses to a silent empty body.
                        if let Some((actual_method, getter_desc)) =
                            skotch_classinfo::lookup_method_name_and_descriptor(
                                &declaring_class,
                                &jvm_getter,
                                0,
                            )
                        {
                            let ret_ty = ty_from_descriptor_return(&getter_desc);
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: declaring_class.clone(),
                                        method_name: actual_method,
                                        descriptor: getter_desc,
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // List .size → invokeinterface java/util/List.size()I
                    if field_name == "size"
                        && (declaring_class.contains("ArrayList")
                            || declaring_class.contains("List"))
                    {
                        let dest = fb.new_local(Ty::Int);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/util/List".to_string(),
                                    method_name: "size".to_string(),
                                    descriptor: "()I".to_string(),
                                },
                                args: vec![recv_local],
                            },
                        });
                        return Some(dest);
                    }
                    // Map .size / .keys / .values / .entries
                    if declaring_class.contains("Map") {
                        let map_prop: Option<(&str, &str, Ty)> = match field_name.as_str() {
                            "size" => Some(("size", "()I", Ty::Int)),
                            "keys" => Some((
                                "keySet",
                                "()Ljava/util/Set;",
                                Ty::Class("java/util/Set".into()),
                            )),
                            "values" => Some((
                                "values",
                                "()Ljava/util/Collection;",
                                Ty::Class("java/util/Collection".into()),
                            )),
                            "entries" => Some((
                                "entrySet",
                                "()Ljava/util/Set;",
                                Ty::Class("java/util/Set".into()),
                            )),
                            _ => None,
                        };
                        if let Some((jvm_method, descriptor, ret_ty)) = map_prop {
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "java/util/Map".to_string(),
                                        method_name: jvm_method.to_string(),
                                        descriptor: descriptor.to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // Set .size
                    if declaring_class.contains("Set") && field_name == "size" {
                        let dest = fb.new_local(Ty::Int);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/util/Set".to_string(),
                                    method_name: "size".to_string(),
                                    descriptor: "()I".to_string(),
                                },
                                args: vec![recv_local],
                            },
                        });
                        return Some(dest);
                    }
                    // Pair .first / .second → invoke getFirst() / getSecond()
                    // Only for kotlin/Pair, NOT user-defined classes named *Pair*.
                    if declaring_class == "kotlin/Pair" {
                        let (getter, desc) = match field_name.as_str() {
                            "first" => ("getFirst", "()Ljava/lang/Object;"),
                            "second" => ("getSecond", "()Ljava/lang/Object;"),
                            _ => ("", ""),
                        };
                        if !getter.is_empty() {
                            let dest = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "kotlin/Pair".to_string(),
                                        method_name: getter.to_string(),
                                        descriptor: desc.to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // Triple .first / .second / .third → getFirst/getSecond/getThird
                    if declaring_class.contains("Triple") || declaring_class == "kotlin/Triple" {
                        let (getter, desc) = match field_name.as_str() {
                            "first" => ("getFirst", "()Ljava/lang/Object;"),
                            "second" => ("getSecond", "()Ljava/lang/Object;"),
                            "third" => ("getThird", "()Ljava/lang/Object;"),
                            _ => ("", ""),
                        };
                        if !getter.is_empty() {
                            let dest = fb.new_local(Ty::Any);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "kotlin/Triple".to_string(),
                                        method_name: getter.to_string(),
                                        descriptor: desc.to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // IntRange .first / .last → getFirst() / getLast()
                    if declaring_class.contains("IntRange") {
                        let range_prop: Option<(&str, &str)> = match field_name.as_str() {
                            "first" => Some(("getFirst", "()I")),
                            "last" => Some(("getLast", "()I")),
                            _ => None,
                        };
                        if let Some((getter, desc)) = range_prop {
                            let dest = fb.new_local(Ty::Int);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: "kotlin/ranges/IntRange".to_string(),
                                        method_name: getter.to_string(),
                                        descriptor: desc.to_string(),
                                    },
                                    args: vec![recv_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    // Exception .message → Throwable.getMessage()
                    // Handles all JVM exception types (they all inherit from Throwable).
                    if field_name == "message"
                        && (declaring_class.contains("Exception")
                            || declaring_class.contains("Error")
                            || declaring_class.contains("Throwable"))
                    {
                        let dest = fb.new_local(Ty::String);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Throwable".to_string(),
                                    method_name: "getMessage".to_string(),
                                    descriptor: "()Ljava/lang/String;".to_string(),
                                },
                                args: vec![recv_local],
                            },
                        });
                        return Some(dest);
                    }
                    // External class companion-property access: e.g.
                    // `Color.White` lowers to
                    //   `getstatic Color.Companion:Color$Companion;
                    //    invokevirtual Color$Companion.getWhite-0d7_KjU()J`
                    // when `Color` is an external class whose companion
                    // declares the property as a getter. The getter may be
                    // mangled (`getWhite-XXXXXXX`) for value-class returns,
                    // so route through the mangled-aware helper. Without
                    // this, we fall to the generic `Rvalue::GetField`
                    // below and emit `getfield Color.White:Object` on a
                    // null receiver — runtime fails with `NoSuchFieldError`.
                    //
                    // Two shapes:
                    // - receiver is `Color` → declaring_class == "Color",
                    //   need to dereference through Color.Companion.
                    // - receiver is already `Color.Companion` (the bare-
                    //   Ident lowering at lower_expr:7132 emits
                    //   `getstatic Color.Companion`) →
                    //   declaring_class == "Color$Companion". Look up the
                    //   getter on the declaring class directly; recv_local
                    //   already holds the Companion instance.
                    if declaring_class.contains('/') {
                        let already_companion = declaring_class.ends_with("$Companion");
                        let companion_class = if already_companion {
                            declaring_class.clone()
                        } else {
                            format!("{declaring_class}$Companion")
                        };
                        let getter_name =
                            format!("get{}{}", &field_name[..1].to_uppercase(), &field_name[1..]);
                        if let Some((actual_method, getter_desc)) =
                            skotch_classinfo::lookup_method_name_and_descriptor(
                                &companion_class,
                                &getter_name,
                                0,
                            )
                        {
                            let ret_ty = ty_from_descriptor_return(&getter_desc);
                            let companion_local = if already_companion {
                                recv_local
                            } else {
                                let local = fb.new_local(Ty::Class(companion_class.clone()));
                                fb.push_stmt(MStmt::Assign {
                                    dest: local,
                                    value: Rvalue::GetStaticField {
                                        class_name: declaring_class.clone(),
                                        field_name: "Companion".to_string(),
                                        descriptor: format!("L{companion_class};"),
                                    },
                                });
                                local
                            };
                            let dest = fb.new_local(ret_ty);
                            fb.push_stmt(MStmt::Assign {
                                dest,
                                value: Rvalue::Call {
                                    kind: CallKind::VirtualJava {
                                        class_name: companion_class,
                                        method_name: actual_method,
                                        descriptor: getter_desc,
                                    },
                                    args: vec![companion_local],
                                },
                            });
                            return Some(dest);
                        }
                    }
                    let dest = fb.new_local(field_ty);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::GetField {
                            receiver: recv_local,
                            class_name: declaring_class,
                            field_name,
                        },
                    });
                    return Some(dest);
                }
                // Handle built-in type properties.
                let field_name = interner.resolve(*name).to_string();
                if matches!(recv_ty, Ty::String) && field_name == "length" {
                    // String.length → invokevirtual String.length()I
                    let dest = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::Call {
                            kind: CallKind::Virtual {
                                class_name: "java/lang/String".to_string(),
                                method_name: "length".to_string(),
                            },
                            args: vec![recv_local],
                        },
                    });
                    return Some(dest);
                }
                // IntArray.size → arraylength
                if matches!(
                    recv_ty,
                    Ty::IntArray
                        | Ty::LongArray
                        | Ty::DoubleArray
                        | Ty::BooleanArray
                        | Ty::ByteArray
                ) && field_name == "size"
                {
                    let dest = fb.new_local(Ty::Int);
                    fb.push_stmt(MStmt::Assign {
                        dest,
                        value: Rvalue::ArrayLength(recv_local),
                    });
                    return Some(dest);
                }
            }
            // Receiver couldn't be lowered — return None.
            let _ = (name_to_func, *span);
            None
        }
        Expr::ElvisOp { lhs, rhs, .. } => {
            // lhs ?: rhs → if (lhs != null) lhs else rhs
            let l = lower_expr(
                lhs,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let then_block = fb.new_block();
            let else_block = fb.new_block();
            let merge_block = fb.new_block();

            // null check: compare lhs to null
            let null_local = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
            fb.push_stmt(MStmt::Assign {
                dest: null_local,
                value: Rvalue::Const(MirConst::Null),
            });
            let cmp = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: cmp,
                value: Rvalue::BinOp {
                    op: MBinOp::CmpNe,
                    lhs: l,
                    rhs: null_local,
                },
            });
            fb.terminate_and_switch(
                Terminator::Branch {
                    cond: cmp,
                    then_block,
                    else_block,
                },
                then_block,
            );

            // Type the result with the lhs's non-nullable inner type
            // when lhs is Nullable(T). This lets follow-on code skip a
            // checkcast that would otherwise narrow Object → T at the
            // use site. If rhs's type diverges, fall back to Ty::Any.
            let lhs_ty = fb.mf.locals[l.0 as usize].clone();
            let initial_result_ty = match &lhs_ty {
                Ty::Nullable(inner) => (**inner).clone(),
                _ => Ty::Any,
            };
            let result = fb.new_local(initial_result_ty.clone());
            // When lhs is Nullable(primitive), the JVM-loaded value is the
            // boxed wrapper (Integer, Long, …) but the result slot is the
            // primitive. Unbox before storing so both branches converge at
            // the primitive type. Mirrors kotlinc's elvis shape for
            // `Int? ?: 0` (intValue() on the non-null path).
            let then_value: LocalId = match (&lhs_ty, &initial_result_ty) {
                (Ty::Nullable(inner), prim)
                    if matches!(prim, Ty::Int | Ty::Long | Ty::Double | Ty::Float | Ty::Bool)
                        && **inner == *prim =>
                {
                    let (class_name, method_name, descriptor) = match prim {
                        Ty::Int => ("java/lang/Integer", "intValue", "()I"),
                        Ty::Long => ("java/lang/Long", "longValue", "()J"),
                        Ty::Double => ("java/lang/Double", "doubleValue", "()D"),
                        Ty::Float => ("java/lang/Float", "floatValue", "()F"),
                        Ty::Bool => ("java/lang/Boolean", "booleanValue", "()Z"),
                        _ => unreachable!(),
                    };
                    let unboxed = fb.new_local(prim.clone());
                    fb.push_stmt(MStmt::Assign {
                        dest: unboxed,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: class_name.to_string(),
                                method_name: method_name.to_string(),
                                descriptor: descriptor.to_string(),
                            },
                            args: vec![l],
                        },
                    });
                    unboxed
                }
                _ => l,
            };
            fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Local(then_value),
            });
            fb.terminate_and_switch(Terminator::Goto(merge_block), else_block);

            // else: result = rhs
            let r = lower_expr(
                rhs,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            // If rhs's type diverges from the chosen result type, widen
            // to Any so the verifier accepts both paths.
            let r_ty = fb.mf.locals[r.0 as usize].clone();
            if r_ty != initial_result_ty {
                fb.mf.locals[result.0 as usize] = Ty::Any;
            }
            fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Local(r),
            });
            fb.terminate_and_switch(Terminator::Goto(merge_block), merge_block);

            Some(result)
        }
        Expr::Throw { expr: thrown, .. } => {
            // Lower the exception expression and terminate with Throw.
            // The result type is Nothing (throw never returns).
            let exc_local = lower_expr(
                thrown,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            fb.set_terminator(Terminator::Throw(exc_local));
            // Return a Nothing-typed local so the expression has a value
            // (though it's unreachable).
            let dest = fb.new_local(Ty::Nothing);
            Some(dest)
        }
        Expr::Try {
            body,
            catch_param,
            catch_type,
            catch_body,
            finally_body,
            ..
        } => {
            // ── try-as-expression lowering ──────────────────────────
            //
            // Layout (with catch):
            //   current_block → goto try_block
            //   try_block: <try body> last-expr → result; goto after_block
            //   catch_block: astore param; <catch body> last-expr → result; goto after_block
            //   after_block: result is available
            //
            // Without catch: just execute body and use last expression.
            if catch_body.is_some() {
                let try_block = fb.new_block();
                let catch_block = fb.new_block();
                let after_block = fb.new_block();

                // Pre-allocate result local (type patched below).
                let result = fb.new_local(Ty::Int);

                fb.terminate_and_switch(Terminator::Goto(try_block), try_block);

                // Lower try body: all statements, last one provides the value.
                let mut try_val = None;
                for (i, stmt) in body.stmts.iter().enumerate() {
                    if i == body.stmts.len() - 1 {
                        // Try to extract as expression for the result value.
                        if let Stmt::Expr(expr) = stmt {
                            try_val = lower_expr(
                                expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        } else {
                            lower_stmt(
                                stmt,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        }
                    } else {
                        lower_stmt(
                            stmt,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                }
                if let Some(tv) = try_val {
                    let ty = fb.mf.locals[tv.0 as usize].clone();
                    fb.mf.locals[result.0 as usize] = ty;
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(tv),
                    });
                }
                fb.terminate_and_switch(Terminator::Goto(after_block), catch_block);

                // Catch handler: store exception param.
                if let Some(param_sym) = catch_param {
                    let exc_local = fb.new_local(Ty::Any);
                    scope.push((*param_sym, exc_local));
                    fb.push_stmt(MStmt::Assign {
                        dest: exc_local,
                        value: Rvalue::Const(MirConst::Null),
                    });
                }

                // Lower catch body.
                let mut catch_val = None;
                if let Some(cb) = catch_body {
                    for (i, stmt) in cb.stmts.iter().enumerate() {
                        if i == cb.stmts.len() - 1 {
                            if let Stmt::Expr(expr) = stmt {
                                catch_val = lower_expr(
                                    expr,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                );
                            } else {
                                lower_stmt(
                                    stmt,
                                    fb,
                                    scope,
                                    module,
                                    name_to_func,
                                    name_to_global,
                                    interner,
                                    diags,
                                    loop_ctx,
                                );
                            }
                        } else {
                            lower_stmt(
                                stmt,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        }
                    }
                }
                if let Some(cv) = catch_val {
                    fb.push_stmt(MStmt::Assign {
                        dest: result,
                        value: Rvalue::Local(cv),
                    });
                }
                fb.terminate_and_switch(Terminator::Goto(after_block), after_block);

                // Exception handler entry.
                let jvm_catch_type =
                    catch_type.map(|sym| intrinsics::catch_type_to_jvm(interner.resolve(sym)));

                fb.mf.exception_handlers.push(ExceptionHandler {
                    try_start_block: try_block,
                    try_end_block: catch_block,
                    handler_block: catch_block,
                    catch_type: jvm_catch_type,
                });

                // Finally body (inlined unconditionally).
                if let Some(fb_block) = finally_body {
                    for stmt in &fb_block.stmts {
                        let terminated = lower_stmt(
                            stmt,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        if terminated {
                            break;
                        }
                    }
                }

                Some(result)
            } else {
                // No catch — just execute body, use last expression as result.
                let mut last_val = None;
                for (i, stmt) in body.stmts.iter().enumerate() {
                    if i == body.stmts.len() - 1 {
                        if let Stmt::Expr(expr) = stmt {
                            last_val = lower_expr(
                                expr,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        } else {
                            lower_stmt(
                                stmt,
                                fb,
                                scope,
                                module,
                                name_to_func,
                                name_to_global,
                                interner,
                                diags,
                                loop_ctx,
                            );
                        }
                    } else {
                        lower_stmt(
                            stmt,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                    }
                }
                if let Some(fb_block) = finally_body {
                    for stmt in &fb_block.stmts {
                        let terminated = lower_stmt(
                            stmt,
                            fb,
                            scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            loop_ctx,
                        );
                        if terminated {
                            break;
                        }
                    }
                }
                last_val
            }
        }
        Expr::SafeCall { receiver, name, .. } => {
            // receiver?.name → if (receiver != null) receiver.name else null
            let recv = lower_expr(
                receiver,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let then_block = fb.new_block();
            let else_block = fb.new_block();
            let merge_block = fb.new_block();

            let null_local = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
            fb.push_stmt(MStmt::Assign {
                dest: null_local,
                value: Rvalue::Const(MirConst::Null),
            });
            let cmp = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: cmp,
                value: Rvalue::BinOp {
                    op: MBinOp::CmpNe,
                    lhs: recv,
                    rhs: null_local,
                },
            });
            let result = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
            fb.terminate_and_switch(
                Terminator::Branch {
                    cond: cmp,
                    then_block,
                    else_block,
                },
                then_block,
            );

            // then: dispatch the property access on the non-null receiver.
            // Unwrap the nullable type to get the inner type for dispatch.
            let recv_ty = fb.mf.locals[recv.0 as usize].clone();
            let inner_ty = intrinsics::strip_nullable(&recv_ty);
            let field_name = interner.resolve(*name).to_string();

            // Create a non-nullable alias so JVM dispatch sees the right type.
            let recv_unwrapped = if matches!(recv_ty, Ty::Nullable(_)) {
                let uw = fb.new_local(inner_ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: uw,
                    value: Rvalue::Local(recv),
                });
                uw
            } else {
                recv
            };

            // Dispatch built-in properties (String.length, IntArray.size, etc.)
            let field_val = if matches!(inner_ty, Ty::String) && field_name == "length" {
                let d = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::Call {
                        kind: CallKind::Virtual {
                            class_name: "java/lang/String".to_string(),
                            method_name: "length".to_string(),
                        },
                        args: vec![recv_unwrapped],
                    },
                });
                d
            } else if matches!(
                inner_ty,
                Ty::IntArray | Ty::LongArray | Ty::DoubleArray | Ty::BooleanArray | Ty::ByteArray
            ) && field_name == "size"
            {
                let d = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::ArrayLength(recv_unwrapped),
                });
                d
            } else if let Ty::Class(ref class_name) = inner_ty {
                // Look up field in user-defined class.
                let mut declaring_class = class_name.clone();
                let mut field_ty = Ty::Any;
                let mut search = Some(class_name.clone());
                while let Some(ref cname) = search {
                    if let Some(cls) = module.classes.iter().find(|c| &c.name == cname) {
                        if let Some(f) = cls.fields.iter().find(|f| f.name == field_name) {
                            declaring_class = cname.clone();
                            field_ty = f.ty.clone();
                            break;
                        }
                        search = cls.super_class.clone();
                    } else {
                        break;
                    }
                }
                let d = fb.new_local(field_ty);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::GetField {
                        receiver: recv_unwrapped,
                        class_name: declaring_class,
                        field_name,
                    },
                });
                d
            } else if field_name == "length" {
                // When the inner type is erased to Any (e.g. from a
                // preceding safe-call chain), `.length` most likely
                // targets String.length(). Dispatch as a virtual call
                // instead of emitting a broken empty-class GetField.
                let d = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::Call {
                        kind: CallKind::Virtual {
                            class_name: "java/lang/String".to_string(),
                            method_name: "length".to_string(),
                        },
                        args: vec![recv_unwrapped],
                    },
                });
                d
            } else if field_name == "size" {
                // Similarly, `.size` on Any likely targets a collection.
                let d = fb.new_local(Ty::Int);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "java/util/Collection".to_string(),
                            method_name: "size".to_string(),
                            descriptor: "()I".to_string(),
                        },
                        args: vec![recv_unwrapped],
                    },
                });
                d
            } else {
                // For scope function names (let, also, run, apply), the
                // actual dispatch happens at the Call level. Just pass
                // through the receiver value — don't emit a broken
                // empty-class GetField.
                let d = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: d,
                    value: Rvalue::Local(recv_unwrapped),
                });
                d
            };
            // Box primitive results so they fit in the Nullable(Any) result
            // local (which is a JVM reference slot).
            let field_val_ty = fb.mf.locals[field_val.0 as usize].clone();
            let boxed_val = mir_autobox(fb, field_val, &field_val_ty);
            fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Local(boxed_val),
            });
            fb.terminate_and_switch(Terminator::Goto(merge_block), else_block);

            // else: result = null
            fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Const(MirConst::Null),
            });
            fb.terminate_and_switch(Terminator::Goto(merge_block), merge_block);

            Some(result)
        }
        Expr::IsCheck {
            expr: checked,
            type_name,
            negated,
            ..
        } => {
            let obj = lower_expr(
                checked,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let raw_type_str = interner.resolve(*type_name);
            // Substitute reified type parameters if active.
            let substituted = fb.reified_types.get(raw_type_str).cloned();
            let type_str = substituted.as_deref().unwrap_or(raw_type_str);
            // Map Kotlin type names to JVM internal names for instanceof.
            // User-defined classes pass through as-is (single-segment name).
            let jvm_type = intrinsics::runtime_check_jvm_class(type_str).unwrap_or(type_str);
            // Const-fold when `obj`'s static or last-assigned type
            // already matches the checked type — kotlinc emits
            // `iconst_1` for an `is` against the same class. Only
            // applies when the local has a single producer in the
            // current block (no later overwrite or join), so the type
            // narrowing is unambiguous.
            if !*negated {
                let obj_ty = fb.mf.locals[obj.0 as usize].clone();
                let mut obj_class: Option<String> = match &obj_ty {
                    Ty::Class(n) => Some(n.clone()),
                    Ty::String if jvm_type == "java/lang/String" => {
                        Some("java/lang/String".to_string())
                    }
                    _ => None,
                };
                // If the static type is a different class, see whether
                // the most recent assignment to `obj`'s local was a
                // `NewInstance`/`Constructor` of a more specific class.
                // This catches `val r: Result = Ok(42); r is Ok` where
                // r's declared type is `Result` but we just stored an
                // `Ok` instance into it.
                if obj_class.as_deref() != Some(jvm_type) {
                    // Walk the producer chain backwards through copies
                    // and `CheckCast` widenings to find the underlying
                    // class of the object stored into `obj`. Stops at
                    // a `NewInstance` (definitive class) or a non-copy
                    // assignment (gives up).
                    let blk = &fb.mf.blocks[fb.cur_block as usize];
                    let mut current = obj.0;
                    for _ in 0..16 {
                        // bound the chain walk to avoid pathological cases
                        let mut stepped = false;
                        for stmt in blk.stmts.iter().rev() {
                            let MStmt::Assign { dest, value } = stmt;
                            if dest.0 != current {
                                continue;
                            }
                            match value {
                                Rvalue::NewInstance(name) => {
                                    obj_class = Some(name.clone());
                                }
                                Rvalue::Local(src) => {
                                    current = src.0;
                                    stepped = true;
                                }
                                Rvalue::CheckCast { obj: src, .. } => {
                                    current = src.0;
                                    stepped = true;
                                }
                                Rvalue::Call {
                                    kind: CallKind::Constructor(name),
                                    ..
                                } => {
                                    obj_class = Some(name.clone());
                                }
                                _ => {}
                            }
                            break;
                        }
                        if !stepped {
                            break;
                        }
                    }
                }
                if let Some(class) = obj_class {
                    if class == jvm_type {
                        let dest = fb.new_local(Ty::Bool);
                        fb.push_stmt(MStmt::Assign {
                            dest,
                            value: Rvalue::Const(MirConst::Bool(true)),
                        });
                        return Some(dest);
                    }
                }
            }
            let dest = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::InstanceOf {
                    obj,
                    type_descriptor: jvm_type.to_string(),
                },
            });
            if *negated {
                // `!is` — negate the result: dest_neg = (dest == 0)
                let zero = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: zero,
                    value: Rvalue::Const(MirConst::Bool(false)),
                });
                let neg = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: neg,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpEq,
                        lhs: dest,
                        rhs: zero,
                    },
                });
                Some(neg)
            } else {
                Some(dest)
            }
            // TODO: smart casts — narrow obj's type in the then-branch
        }
        Expr::AsCast {
            expr: casted,
            type_name,
            safe,
            ..
        } => {
            let obj = lower_expr(
                casted,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let type_str = interner.resolve(*type_name);
            // Resolve `as <Type>` against the file's imports so that an
            // imported FQ name like `import android.widget.FrameLayout` lets
            // `as FrameLayout` produce `Ty::Class("android/widget/FrameLayout")`
            // instead of falling back to `Ty::Any`. The fallback erases the
            // dest local's type, which then forces every downstream user
            // (constructor call sites, descriptor inference, etc.) to use
            // `Ljava/lang/Object;` and breaks `<init>` lookups at runtime.
            let imported_fq = module.import_map.get(type_str).cloned();
            let target_ty = skotch_types::ty_from_name(type_str).unwrap_or_else(|| {
                if module.classes.iter().any(|c| c.name == type_str) {
                    Ty::Class(type_str.to_string())
                } else if let Some(fq) = &imported_fq {
                    Ty::Class(fq.clone())
                } else {
                    Ty::Any
                }
            });
            // Boxed JVM class for the runtime cast; unknown types fall
            // back to the import map, then to the bare name.
            let default_jvm: String = intrinsics::runtime_check_jvm_class(type_str)
                .map(str::to_string)
                .unwrap_or_else(|| imported_fq.clone().unwrap_or_else(|| type_str.to_string()));
            let jvm_type = default_jvm.as_str();
            if *safe {
                // `as?` — emit instanceof check: returns T? (null if not match)
                let check = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: check,
                    value: Rvalue::InstanceOf {
                        obj,
                        type_descriptor: jvm_type.to_string(),
                    },
                });
                let then_block = fb.new_block();
                let else_block = fb.new_block();
                let merge_block = fb.new_block();
                let result = fb.new_local(Ty::Nullable(Box::new(target_ty.clone())));
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: check,
                        then_block,
                        else_block,
                    },
                    then_block,
                );
                // then: cast succeeded — copy obj as target type
                let cast_local = fb.new_local(target_ty);
                fb.push_stmt(MStmt::Assign {
                    dest: cast_local,
                    value: Rvalue::Local(obj),
                });
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Local(cast_local),
                });
                fb.terminate_and_switch(Terminator::Goto(merge_block), else_block);
                // else: cast failed — result = null
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Const(MirConst::Null),
                });
                fb.terminate_and_switch(Terminator::Goto(merge_block), merge_block);
                Some(result)
            } else {
                // `as` — just retype (JVM backend emits checkcast from the
                // Rvalue::Local copy when dest type is narrower than source).
                let dest = fb.new_local(target_ty);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Local(obj),
                });
                Some(dest)
            }
        }
        Expr::NotNullAssert { expr: asserted, .. } => {
            // x!! → null check + unwrap. If null, throw KotlinNullPointerException.
            let inner = lower_expr(
                asserted,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                loop_ctx,
            )?;
            let inner_ty = fb.mf.locals[inner.0 as usize].clone();
            if let Ty::Nullable(unwrapped) = inner_ty {
                // Emit null check: if (inner == null) throw NPE
                let null_val = fb.new_local(Ty::Nullable(Box::new(Ty::Any)));
                fb.push_stmt(MStmt::Assign {
                    dest: null_val,
                    value: Rvalue::Const(MirConst::Null),
                });
                let is_null = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: is_null,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpEq,
                        lhs: inner,
                        rhs: null_val,
                    },
                });
                let throw_block = fb.new_block();
                let ok_block = fb.new_block();
                fb.terminate_and_switch(
                    Terminator::Branch {
                        cond: is_null,
                        then_block: throw_block,
                        else_block: ok_block,
                    },
                    throw_block,
                );
                // throw block: new NullPointerException + athrow
                let npe = fb.new_local(Ty::Class("java/lang/NullPointerException".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: npe,
                    value: Rvalue::NewInstance("java/lang/NullPointerException".to_string()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest: npe,
                    value: Rvalue::Call {
                        kind: CallKind::ConstructorJava {
                            class_name: "java/lang/NullPointerException".to_string(),
                            descriptor: "()V".to_string(),
                        },
                        args: vec![],
                    },
                });
                fb.set_terminator(Terminator::Throw(npe));
                fb.cur_block = ok_block;
                // ok block: unwrap to non-nullable type
                let dest = fb.new_local(*unwrapped);
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Local(inner),
                });
                Some(dest)
            } else {
                Some(inner)
            }
        }

        Expr::Lambda {
            params,
            body,
            is_suspend: ast_is_suspend,
            ..
        } => {
            // ── Suspend lambda detection ────────────────────────────
            // A lambda is a suspend lambda if either:
            //   1. The AST flagged it (future: `suspend {}` syntax or
            //      inferred from function-type-parameter context)
            //   2. The body contains a call to a suspend function
            // Detection flows through to MIR so the codegen layer
            // can generate SuspendLambda-extending classes.
            // Currently lambdas with suspend bodies still compile as
            // regular $Lambda$N classes — this means calling them from
            // real coroutine builders won't work at runtime. Full
            // SuspendLambda codegen is a follow-up.
            // Check the force flag FIRST, then AST flag, then body scan.
            let forced = module.force_suspend_lambda;
            if forced {
                module.force_suspend_lambda = false; // consume the flag
            }
            let is_suspend_lambda = forced
                || *ast_is_suspend
                || body_contains_suspend_call(body, module, interner, name_to_func);

            // ── Capture analysis ────────────────────────────────────
            let param_names: Vec<Symbol> = params.iter().map(|p| p.name).collect();
            let mut free_vars: Vec<(Symbol, LocalId, Ty)> =
                collect_free_vars(body, &param_names, scope, fb, interner);

            // Auto-capture outer `this` when the body has unqualified
            // method calls that resolve to methods on the enclosing
            // class. Without this, the lambda's invoke method would
            // emit `aload <lambda this>; invokevirtual OuterClass.foo`
            // which fails JVM verification (`'this' argument
            // 'Lambda$N' not instance of 'OuterClass'`). The captured
            // outer-this is loaded from a synthetic `$outerThis` field
            // and used as the receiver for those calls (see the
            // `$outerThis` lookup in `Expr::Call` lowering).
            //
            // For NESTED lambdas, the outer scope's `this` is itself a
            // lambda class. We then look for an existing `$outerThis`
            // binding in scope — propagated up the chain so deeply-
            // nested closures can still reach the real enclosing class.
            let this_sym = interner.intern("this");
            let outer_this_sym = interner.intern("$outerThis");
            // Prefer an existing $outerThis from outer scope (nested
            // lambdas), falling back to the closest non-lambda `this`.
            let outer_this_lid_and_ty: Option<(LocalId, Ty)> = scope
                .iter()
                .rev()
                .find_map(|(s, lid)| {
                    if *s == outer_this_sym {
                        let ty = fb.mf.locals.get(lid.0 as usize).cloned()?;
                        Some((*lid, ty))
                    } else {
                        None
                    }
                })
                .or_else(|| {
                    scope.iter().rev().find_map(|(s, lid)| {
                        if *s == this_sym {
                            let ty = fb.mf.locals.get(lid.0 as usize).cloned()?;
                            if matches!(&ty, Ty::Class(cn) if !module.is_lambda_class(cn) && !cn.contains("$Callable")) {
                                Some((*lid, ty))
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    })
                });
            if let Some((outer_lid, outer_ty)) = outer_this_lid_and_ty {
                let outer_class_name = match &outer_ty {
                    Ty::Class(c) => c.clone(),
                    _ => String::new(),
                };
                let needs_outer_this = !outer_class_name.is_empty()
                    && body_needs_outer_this(body, &outer_class_name, module, interner);
                if needs_outer_this {
                    let already = free_vars.iter().any(|(s, _, _)| *s == outer_this_sym);
                    if !already {
                        free_vars.push((outer_this_sym, outer_lid, outer_ty));
                    }
                }
            }
            // Extension-receiver capture: when the enclosing function is
            // an extension on some interface (e.g. `fun MeasureScope.measure`),
            // a lambda inside the body that calls extension methods on
            // that receiver (e.g. `dp.roundToPx()` resolving via
            // `MeasureScope: Density`) needs to capture the extension
            // receiver too. Scope holds it as `$this$<methodName>` per
            // the class-method lower fix.
            for (sym, lid) in scope.iter().rev() {
                let s = interner.resolve(*sym).to_string();
                if !s.starts_with("$this$") || s == "$this" {
                    continue;
                }
                let ext_ty = fb.mf.locals.get(lid.0 as usize).cloned();
                let Some(Ty::Class(ext_class_name)) = ext_ty.clone() else {
                    continue;
                };
                if module.is_lambda_class(&ext_class_name) || ext_class_name.contains("$Callable") {
                    continue;
                }
                let ext_sym = interner.intern(&s);
                let already = free_vars.iter().any(|(s2, _, _)| *s2 == ext_sym);
                if already {
                    continue;
                }
                if body_needs_outer_this(body, &ext_class_name, module, interner) {
                    free_vars.push((ext_sym, *lid, ext_ty.unwrap()));
                }
            }
            let free_vars = free_vars;

            // ── Simple-case metafactory path ───────────────────────
            // No-capture, non-suspend lambdas with all-reference param
            // and return types lower to a static helper method on the
            // wrapper class plus an `invokedynamic` LambdaMetafactory
            // call producing a `kotlin/jvm/functions/FunctionN`
            // instance. Matches kotlinc's emission shape.
            //
            // Both primitive and reference param/return types are
            // handled: the helper's specialized descriptor preserves
            // primitives (e.g. `(I)I`), and the JVM's LambdaMetafactory
            // generates the box/unbox adapter automatically.
            // For now: take the metafactory path only for no-capture
            // lambdas. Capturing-lambda support requires the helper's
            // implicit-return inference to be reliable for non-Unit
            // and non-primitive results, which it isn't yet (fixture
            // 363's `{ x -> { y -> x + y } }` body returns a Function1
            // but our inference says Unit).
            // For 0-arg lambdas, only take the metafactory path when the
            // body has no free-floating method calls — receiver lambdas
            // (`StringBuilder.() -> Unit`) need scope set up to resolve
            // unqualified calls like `append("x")` against the receiver.
            let zero_arg_safe = params.is_empty()
                && !body_has_unresolved_unqualified_call(
                    body,
                    scope,
                    module,
                    name_to_func,
                    interner,
                );
            if free_vars.is_empty() && !is_suspend_lambda && (!params.is_empty() || zero_arg_safe) {
                let arity = params.len() as u8;
                let outer_name = fb.mf.name.clone();
                // DEX format only allows angle brackets in the special
                // method names `<init>` and `<clinit>` themselves — any
                // other method whose name contains `<` or `>` makes d8
                // reject the whole class with "cannot be represented in
                // dex format". Strip the brackets when the enclosing
                // function is `<clinit>` (or another special name) so the
                // synthesized helper still d8s cleanly.
                let sanitized_outer = outer_name.trim_matches(|c| c == '<' || c == '>');
                let helper_prefix = format!("{sanitized_outer}$lambda$");
                let inner_idx = module
                    .functions
                    .iter()
                    .filter(|f| f.name.starts_with(&helper_prefix))
                    .count();
                let helper_name = format!("{}{}", helper_prefix, inner_idx);
                let lambda_idx = module.functions.len();
                let mut helper_fb = FnBuilder::new(lambda_idx, helper_name.clone(), Ty::Any);
                // Visibility: ACC_PRIVATE only when the metafactory call
                // site lives in the same class as the helper (typically a
                // top-level function on the wrapper class). When the
                // metafactory is emitted INSIDE another skotch-synthesized
                // class (a `<Wrapper>$Lambda$N.invoke()` body), the helper
                // still lands on the wrapper but the invokedynamic
                // references it across class boundaries. d8 desugars that
                // invokedynamic into a sibling synthetic class (e.g.
                // `Wrapper$Lambda$N$$ExternalSyntheticLambda0`) which is
                // NOT a nest member of the wrapper and cannot access the
                // private helper at runtime (java.lang.IllegalAccessError
                // — JetChat hit this on `NavActivityKt.invoke$lambda$1`
                // being inaccessible to `NavActivityKt$Lambda$36$$ExternalSyntheticLambda1`).
                //
                // Heuristic: if `outer_name` is `invoke` (the standard
                // name for a Function.invoke method on a Lambda$N class),
                // leave the helper public so the cross-class dispatch
                // works after d8 desugaring. Top-level fns (`main`, user
                // fns) keep ACC_PRIVATE to match kotlinc-parity.
                let inside_synthetic_lambda = sanitized_outer == "invoke";
                helper_fb.mf.is_private = !inside_synthetic_lambda;
                let mut helper_scope: Vec<(Symbol, LocalId)> = Vec::new();
                // Capture params come first.
                for (sym, _outer_lid, ty) in &free_vars {
                    let pid = helper_fb.new_local(ty.clone());
                    helper_fb.mf.params.push(pid);
                    helper_scope.push((*sym, pid));
                }
                // Then user-declared params. For a single un-annotated
                // explicit param (common case: parser-injected implicit
                // `it: Any` from `{ it.foo }`), consume the call site's
                // `lambda_param_type` so the param picks up the
                // receiver's element type.
                let override_first_meta: Option<Ty> = if params.len() == 1 {
                    let first_resolved = resolve_type(interner.resolve(params[0].ty.name), module);
                    if matches!(first_resolved, Ty::Any) {
                        module
                            .lambda_param_type
                            .take()
                            .filter(|t| !matches!(t, Ty::Any))
                    } else {
                        None
                    }
                } else {
                    None
                };
                for (param_idx, p) in params.iter().enumerate() {
                    let ty = if param_idx == 0 && override_first_meta.is_some() {
                        override_first_meta.clone().unwrap()
                    } else {
                        resolve_type(interner.resolve(p.ty.name), module)
                    };
                    let pid = helper_fb.new_local(ty);
                    helper_fb.mf.params.push(pid);
                    helper_scope.push((p.name, pid));
                }
                // Emit `Intrinsics.checkNotNullParameter(p, "p")` for
                // each non-null reference USER param, matching kotlinc's
                // null-safety preamble on lambda invoke methods.
                // Skip captures — they're already validated at the outer
                // function's checkNotNullParameter site.
                let user_scope_start = free_vars.len();
                for (sym, pid) in helper_scope.iter().skip(user_scope_start) {
                    let pty = helper_fb.mf.locals[pid.0 as usize].clone();
                    let is_nonnull_ref = matches!(&pty, Ty::String | Ty::Class(_));
                    if !is_nonnull_ref {
                        continue;
                    }
                    let name_str = interner.resolve(*sym).to_string();
                    let name_local = helper_fb.new_local(Ty::String);
                    let name_id = module.intern_string(&name_str);
                    helper_fb.push_stmt(MStmt::Assign {
                        dest: name_local,
                        value: Rvalue::Const(MirConst::String(name_id)),
                    });
                    let unit_local = helper_fb.new_local(Ty::Unit);
                    helper_fb.push_stmt(MStmt::Assign {
                        dest: unit_local,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "kotlin/jvm/internal/Intrinsics".to_string(),
                                method_name: "checkNotNullParameter".to_string(),
                                descriptor: "(Ljava/lang/Object;Ljava/lang/String;)V".to_string(),
                            },
                            args: vec![*pid, name_local],
                        },
                    });
                }
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        &mut helper_fb,
                        &mut helper_scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        None,
                    );
                }
                // For Unit-returning lambdas the helper must return
                // `Lkotlin/Unit;` (not V) so the metafactory's bridge
                // type-checks against the SAM's Object return. Replace
                // any Return / ReturnValue(Unit) with an explicit
                // `getstatic kotlin/Unit.INSTANCE; areturn` sequence.
                let locals_snapshot = helper_fb.mf.locals.clone();
                let mut body_returns_unit = true;
                for block in &helper_fb.mf.blocks {
                    match &block.terminator {
                        Terminator::Return => {}
                        Terminator::ReturnValue(l) if locals_snapshot[l.0 as usize] != Ty::Unit => {
                            body_returns_unit = false;
                            break;
                        }
                        _ => {}
                    }
                }
                if body_returns_unit {
                    let unit_cls = Ty::Class("kotlin/Unit".to_string());
                    for bi in 0..helper_fb.mf.blocks.len() {
                        let term = helper_fb.mf.blocks[bi].terminator.clone();
                        match term {
                            Terminator::Return => {
                                let unit_local = helper_fb.new_local(unit_cls.clone());
                                helper_fb.mf.blocks[bi].stmts.push(MStmt::Assign {
                                    dest: unit_local,
                                    value: Rvalue::GetStaticField {
                                        class_name: "kotlin/Unit".to_string(),
                                        field_name: "INSTANCE".to_string(),
                                        descriptor: "Lkotlin/Unit;".to_string(),
                                    },
                                });
                                helper_fb.mf.blocks[bi].terminator =
                                    Terminator::ReturnValue(unit_local);
                            }
                            Terminator::ReturnValue(l)
                                if locals_snapshot[l.0 as usize] == Ty::Unit =>
                            {
                                let unit_local = helper_fb.new_local(unit_cls.clone());
                                helper_fb.mf.blocks[bi].stmts.push(MStmt::Assign {
                                    dest: unit_local,
                                    value: Rvalue::GetStaticField {
                                        class_name: "kotlin/Unit".to_string(),
                                        field_name: "INSTANCE".to_string(),
                                        descriptor: "Lkotlin/Unit;".to_string(),
                                    },
                                });
                                helper_fb.mf.blocks[bi].terminator =
                                    Terminator::ReturnValue(unit_local);
                            }
                            _ => {}
                        }
                    }
                }
                let helper_ret_ty = {
                    let last_block = helper_fb.mf.blocks.last().unwrap();
                    match &last_block.terminator {
                        Terminator::ReturnValue(l) => helper_fb.mf.locals[l.0 as usize].clone(),
                        Terminator::Return => Ty::Unit,
                        _ => Ty::Any,
                    }
                };
                // Allow both reference and primitive return types —
                // the metafactory generates the box/unbox adapter.
                let return_is_supported = !matches!(&helper_ret_ty, Ty::Error);
                if return_is_supported {
                    helper_fb.mf.return_ty = helper_ret_ty.clone();
                    // The IMPL descriptor includes captures + user params.
                    let mut spec_desc = String::from("(");
                    for pid in helper_fb.mf.params.iter() {
                        let pt = &helper_fb.mf.locals[pid.0 as usize];
                        spec_desc.push_str(&jvm_type_string_for_ty(pt));
                    }
                    spec_desc.push(')');
                    spec_desc.push_str(&jvm_type_string_for_ty(&helper_ret_ty));
                    // The INSTANTIATED method-type is the SAM's specialized
                    // form — user params ONLY (captures are excluded
                    // because they're baked in by the metafactory).
                    let mut inst_user_desc = String::from("(");
                    for pid in helper_fb.mf.params.iter().skip(free_vars.len()) {
                        let pt = &helper_fb.mf.locals[pid.0 as usize];
                        inst_user_desc.push_str(&jvm_type_string_for_ty(pt));
                    }
                    inst_user_desc.push(')');
                    inst_user_desc.push_str(&jvm_type_string_for_ty(&helper_ret_ty));
                    let impl_class = module.wrapper_class.clone();

                    // Capture user-param types BEFORE finish() so we can
                    // type the lambda local accordingly.
                    let user_param_tys: Vec<Ty> = helper_fb
                        .mf
                        .params
                        .iter()
                        .skip(free_vars.len())
                        .map(|pid| helper_fb.mf.locals[pid.0 as usize].clone())
                        .collect();
                    module.add_function(helper_fb.finish());

                    // Type the lambda local as `Ty::Function { ... }`
                    // (not `Ty::Class`) so the existing invocation
                    // dispatch can extract the specialized return type
                    // and unbox primitives at the call site.
                    let lambda_inst = fb.new_local(Ty::Function {
                        params: user_param_tys,
                        ret: Box::new(helper_ret_ty.clone()),
                        is_suspend: false,
                        is_composable: false,
                    });
                    fb.push_stmt(MStmt::Assign {
                        dest: lambda_inst,
                        value: Rvalue::Call {
                            kind: CallKind::LambdaMetafactory {
                                arity,
                                method_name: helper_name,
                                specialized_descriptor: spec_desc,
                                instantiated_descriptor: inst_user_desc,
                                impl_class,
                            },
                            // Pass captured locals from the OUTER scope
                            // as bootstrap args to the metafactory; the
                            // metafactory bakes them into the Function
                            // instance's invoke method.
                            args: free_vars
                                .iter()
                                .map(|(_, outer_lid, _)| *outer_lid)
                                .collect(),
                        },
                    });
                    return Some(lambda_inst);
                }
                // Else: fall through to synthetic-class path.
            }

            // Detect which captures need Ref boxing: any `var` declaration
            // that's captured needs boxing so mutations are visible across
            // the lambda boundary (both inner writes and outer writes).
            let mutated: rustc_hash::FxHashSet<Symbol> = free_vars
                .iter()
                .filter(|(sym, _, _)| fb.var_syms.contains(sym))
                .map(|(sym, _, _)| *sym)
                .collect();

            // For each mutated capture, generate a $Ref class and box the var
            // in the outer scope so mutations are visible across the boundary.
            let mut ref_class_names: rustc_hash::FxHashMap<Symbol, String> =
                rustc_hash::FxHashMap::default();
            for (sym, outer_lid, ty) in &free_vars {
                if !mutated.contains(sym) {
                    continue;
                }
                let ref_class_name = format!("$Ref${}", module.classes.len());
                ref_class_names.insert(*sym, ref_class_name.clone());

                // Generate synthetic $Ref class with `element` field.
                let mut ref_init = MirFunction {
                    id: FuncId(0),
                    name: "<init>".to_string(),
                    params: Vec::new(),
                    locals: Vec::new(),
                    blocks: vec![BasicBlock {
                        stmts: Vec::new(),
                        terminator: Terminator::Return,
                    }],
                    return_ty: Ty::Unit,
                    required_params: 0,
                    param_names: Vec::new(),
                    param_defaults: Vec::new(),
                    param_receiver_types: Vec::new(),
                    is_abstract: false,
                    exception_handlers: Vec::new(),
                    vararg_index: None,
                    is_suspend: false,
                    is_inline: false,
                    has_type_params: false,
                    suspend_original_return_ty: None,
                    suspend_state_machine: None,
                    annotations: Vec::new(),
                    named_locals: Vec::new(),
                    is_private: false,
                    is_static: false,
                    default_call_masks: Vec::new(),
                    needs_leading_nop: false,
                    local_generic_args: rustc_hash::FxHashMap::default(),
                };
                let ref_this = ref_init.new_local(Ty::Class(ref_class_name.clone()));
                ref_init.params.push(ref_this);
                let ref_val_param = ref_init.new_local(ty.clone());
                ref_init.params.push(ref_val_param);
                ref_init.blocks[0].stmts.push(MStmt::Assign {
                    dest: ref_this,
                    value: Rvalue::Call {
                        kind: CallKind::Constructor("java/lang/Object".to_string()),
                        args: vec![ref_this],
                    },
                });
                ref_init.blocks[0].stmts.push(MStmt::Assign {
                    dest: ref_this,
                    value: Rvalue::PutField {
                        receiver: ref_this,
                        class_name: ref_class_name.clone(),
                        field_name: "element".to_string(),
                        value: ref_val_param,
                    },
                });

                module.classes.push(MirClass {
                    name: ref_class_name.clone(),
                    super_class: None,
                    is_open: false,
                    is_abstract: false,
                    is_interface: false,
                    interfaces: Vec::new(),
                    fields: vec![MirField {
                        name: "element".to_string(),
                        ty: ty.clone(),
                        is_jvm_field: false,
                    }],
                    methods: Vec::new(),
                    constructor: ref_init,
                    secondary_constructors: Vec::new(),
                    is_lambda: false,
                    is_suspend_lambda: false,
                    is_cross_file_stub: false,
                    annotations: Vec::new(),
                    has_type_params: false,
                    is_object_singleton: false,
                    companion_class_name: None,
                    static_fields: Vec::new(),
                    clinit: None,
                });

                // In the outer scope, wrap the var into a $Ref instance.
                let ref_inst = fb.new_local(Ty::Class(ref_class_name.clone()));
                fb.push_stmt(MStmt::Assign {
                    dest: ref_inst,
                    value: Rvalue::NewInstance(ref_class_name.clone()),
                });
                fb.push_stmt(MStmt::Assign {
                    dest: ref_inst,
                    value: Rvalue::Call {
                        kind: CallKind::Constructor(ref_class_name.clone()),
                        args: vec![*outer_lid],
                    },
                });
                // Replace the outer scope binding: var now points to the $Ref.
                // Add the $ref$ holder so Stmt::Assign can find it.
                let ref_holder_sym = interner.intern(&format!("$ref${}", interner.resolve(*sym)));
                scope.push((ref_holder_sym, ref_inst));
                if let Some(entry) = scope.iter_mut().rev().find(|(s, _)| s == sym) {
                    entry.1 = ref_inst;
                }
            }

            // Fields for captured variables — use $Ref type for mutated captures.
            // Substitute Ty::Unit with Ty::Any so JVM doesn't emit a `V`
            // descriptor for the field (which is invalid for fields).
            // Unit-typed captures arise when an unresolved value is closed
            // over; the runtime field will hold null/Unit.INSTANCE.
            let capture_fields: Vec<MirField> = free_vars
                .iter()
                .map(|(sym, _, ty)| {
                    let field_ty = if let Some(ref_name) = ref_class_names.get(sym) {
                        Ty::Class(ref_name.clone())
                    } else if matches!(ty, Ty::Unit) {
                        Ty::Any
                    } else {
                        ty.clone()
                    };
                    MirField {
                        name: interner.resolve(*sym).to_string(),
                        ty: field_ty,
                        is_jvm_field: false,
                    }
                })
                .collect();

            // Pre-register the lambda class so nested lambdas get unique indices.
            // (Recalculate lambda_idx since $Ref classes may have been added above.)
            let lambda_idx = module.classes.len();
            // kotlinc names lambdas `<wrapper>$<enclosingFn>$<local_idx>`
            // where `local_idx` is 1-based per enclosing function. The
            // `<clinit>`/`<init>` names get sanitized to `__clinit__`/
            // `__init__` since `<` and `>` are illegal in class names.
            // Skip indices already claimed by a state-machine class
            // (e.g. for a suspend fn `run_`, `InputKt$run_$1` is the
            // ContinuationImpl shell, so the first lambda inside `run_`
            // gets `$2`).
            let enclosing_fn_for_name = match fb.mf.name.as_str() {
                "<init>" => "__init__".to_string(),
                "<clinit>" => "__clinit__".to_string(),
                other => other.to_string(),
            };
            let lambda_class_name = loop {
                fb.lambda_count += 1;
                let candidate = format!(
                    "{}${}${}",
                    module.wrapper_class, enclosing_fn_for_name, fb.lambda_count
                );
                if !module.classes.iter().any(|c| c.name == candidate) {
                    break candidate;
                }
            };
            module.classes.push(MirClass {
                name: lambda_class_name.clone(),
                super_class: None,
                is_open: false,
                is_abstract: false,
                is_interface: false,
                interfaces: Vec::new(),
                fields: capture_fields.clone(),
                methods: Vec::new(),
                constructor: MirFunction {
                    id: FuncId(0),
                    name: "<init>".to_string(),
                    params: Vec::new(),
                    locals: Vec::new(),
                    blocks: Vec::new(),
                    return_ty: Ty::Unit,
                    required_params: 0,
                    param_names: Vec::new(),
                    param_defaults: Vec::new(),
                    param_receiver_types: Vec::new(),
                    is_abstract: false,
                    exception_handlers: Vec::new(),
                    vararg_index: None,
                    is_suspend: false,
                    is_inline: false,
                    has_type_params: false,
                    suspend_original_return_ty: None,
                    suspend_state_machine: None,
                    annotations: Vec::new(),
                    named_locals: Vec::new(),
                    is_private: false,
                    is_static: false,
                    default_call_masks: Vec::new(),
                    needs_leading_nop: false,
                    local_generic_args: rustc_hash::FxHashMap::default(),
                },
                secondary_constructors: Vec::new(),
                is_lambda: true,
                is_suspend_lambda,
                is_cross_file_stub: false,
                annotations: Vec::new(),
                has_type_params: false,
                is_object_singleton: false,
                companion_class_name: None,
                static_fields: Vec::new(),
                clinit: None,
            });

            // ── Invoke method ───────────────────────────────────────
            let mut invoke_fn = {
                let fn_idx = module.functions.len() + 1000 + lambda_idx;
                let mut invoke_fb = FnBuilder::new(fn_idx, "invoke".to_string(), Ty::Int);
                let this_local = invoke_fb.new_local(Ty::Class(lambda_class_name.clone()));
                invoke_fb.mf.params.push(this_local);

                let mut invoke_scope: Vec<(Symbol, LocalId)> = Vec::new();
                // Bind `this` in scope so nested launch/async can find
                // the lambda's p$0 field for CoroutineScope threading.
                let this_sym = interner.intern("this");
                invoke_scope.push((this_sym, this_local));
                // Load captured fields into locals.
                for (sym, _, ty) in &free_vars {
                    let is_ref_boxed = ref_class_names.contains_key(sym);
                    let field_ty = if let Some(ref_name) = ref_class_names.get(sym) {
                        Ty::Class(ref_name.clone())
                    } else {
                        ty.clone()
                    };
                    let local = invoke_fb.new_local(field_ty);
                    invoke_fb.push_stmt(MStmt::Assign {
                        dest: local,
                        value: Rvalue::GetField {
                            receiver: this_local,
                            class_name: lambda_class_name.clone(),
                            field_name: interner.resolve(*sym).to_string(),
                        },
                    });
                    if is_ref_boxed {
                        // For Ref-boxed captures, read the element into a local
                        // and put the $Ref local + element local both in scope.
                        // The $Ref local is stored so Stmt::Assign can PutField.
                        let ref_class = ref_class_names[sym].clone();
                        let elem = invoke_fb.new_local(ty.clone());
                        invoke_fb.push_stmt(MStmt::Assign {
                            dest: elem,
                            value: Rvalue::GetField {
                                receiver: local,
                                class_name: ref_class,
                                field_name: "element".to_string(),
                            },
                        });
                        // Push a special scope entry: the $Ref holder is stored
                        // under a mangled name so Stmt::Assign can find it.
                        let ref_holder_sym =
                            interner.intern(&format!("$ref${}", interner.resolve(*sym)));
                        invoke_scope.push((ref_holder_sym, local));
                        invoke_scope.push((*sym, elem));
                    } else {
                        invoke_scope.push((*sym, local));
                    }
                }
                // For SuspendLambda, the CoroutineScope
                // receiver is accessible at runtime but doesn't need
                // to be a MIR param (the SuspendLambda shell handles
                // the invoke→create→invokeSuspend delegation). We just
                // add a scope marker so nested launch/async can find it.
                // The actual CoroutineScope local comes from the scope
                // chain — `this` (the lambda) implements Function2 and
                // receives the scope as arg1 at runtime.

                // Lambda parameters — use Ty::Any for the method param
                // so the invoke descriptor matches FunctionN.invoke(Object...).
                // Then immediately unbox/cast to the annotated type in
                // a body-local so method resolution and arithmetic work.
                //
                // If the lambda has exactly one explicit param with no
                // annotation (`Ty::Any` after resolve), consume
                // `module.lambda_param_type` set by the call site (e.g.
                // `.filter`/`.map` on a `List<T>`). This covers both
                // the parser's auto-injected `it: Any` for `{ ... }`
                // bodies and user-written `{ x -> ... }` lambdas where
                // `x` has no type annotation.
                let mut consumed_lambda_param = false;
                let override_first_param_ty: Option<Ty> = if params.len() == 1 {
                    let first_resolved = resolve_type(interner.resolve(params[0].ty.name), module);
                    if matches!(first_resolved, Ty::Any) {
                        if let Some(ty) = module.lambda_param_type.take() {
                            if !matches!(ty, Ty::Any) {
                                consumed_lambda_param = true;
                                Some(ty)
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    } else {
                        None
                    }
                } else {
                    None
                };
                for (param_idx, p) in params.iter().enumerate() {
                    let erased_pid = invoke_fb.new_local(Ty::Any);
                    invoke_fb.mf.params.push(erased_pid);
                    let annotated_ty = if param_idx == 0 && override_first_param_ty.is_some() {
                        override_first_param_ty.clone().unwrap()
                    } else {
                        resolve_type(interner.resolve(p.ty.name), module)
                    };
                    let _ = consumed_lambda_param;
                    if annotated_ty != Ty::Any {
                        // Cast/unbox from Object to the annotated type.
                        let cast_rvalue = match &annotated_ty {
                            Ty::Int => Some(Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Integer".to_string(),
                                    method_name: "intValue".to_string(),
                                    descriptor: "()I".to_string(),
                                },
                                args: vec![erased_pid],
                            }),
                            Ty::Bool => Some(Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Boolean".to_string(),
                                    method_name: "booleanValue".to_string(),
                                    descriptor: "()Z".to_string(),
                                },
                                args: vec![erased_pid],
                            }),
                            Ty::Long => Some(Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Long".to_string(),
                                    method_name: "longValue".to_string(),
                                    descriptor: "()J".to_string(),
                                },
                                args: vec![erased_pid],
                            }),
                            Ty::Double => Some(Rvalue::Call {
                                kind: CallKind::VirtualJava {
                                    class_name: "java/lang/Double".to_string(),
                                    method_name: "doubleValue".to_string(),
                                    descriptor: "()D".to_string(),
                                },
                                args: vec![erased_pid],
                            }),
                            _ => {
                                // Reference type — use a local-copy typed
                                // as the annotated type so method resolution
                                // works (e.g., String.uppercase()).
                                Some(Rvalue::Local(erased_pid))
                            }
                        };
                        if let Some(rv) = cast_rvalue {
                            let typed_local = invoke_fb.new_local(annotated_ty);
                            invoke_fb.push_stmt(MStmt::Assign {
                                dest: typed_local,
                                value: rv,
                            });
                            invoke_scope.push((p.name, typed_local));
                            // Record generic args from the lambda param's
                            // declared TypeRef so element-type recovery
                            // works on this local (e.g. List<Measurable>
                            // for `Layout { measurables, _ -> measurables[0] }`).
                            if !p.ty.type_args.is_empty() {
                                let arg_tys: Vec<Ty> =
                                    p.ty.type_args
                                        .iter()
                                        .map(|tr| resolve_type_ref(tr, interner, module))
                                        .collect();
                                invoke_fb
                                    .mf
                                    .local_generic_args
                                    .insert(typed_local.0, arg_tys);
                            }
                        } else {
                            invoke_scope.push((p.name, erased_pid));
                            if !p.ty.type_args.is_empty() {
                                let arg_tys: Vec<Ty> =
                                    p.ty.type_args
                                        .iter()
                                        .map(|tr| resolve_type_ref(tr, interner, module))
                                        .collect();
                                invoke_fb
                                    .mf
                                    .local_generic_args
                                    .insert(erased_pid.0, arg_tys);
                            }
                        }
                    } else {
                        invoke_scope.push((p.name, erased_pid));
                        if !p.ty.type_args.is_empty() {
                            let arg_tys: Vec<Ty> =
                                p.ty.type_args
                                    .iter()
                                    .map(|tr| resolve_type_ref(tr, interner, module))
                                    .collect();
                            invoke_fb
                                .mf
                                .local_generic_args
                                .insert(erased_pid.0, arg_tys);
                        }
                    }
                }
                // Implicit `it` for single-param or no-param lambdas:
                // When a lambda has no explicit params, the scope function
                // passes the receiver as the first invoke arg. Add `it` to
                // scope pointing to that arg.
                if params.is_empty() && invoke_fb.mf.params.len() > 1 {
                    // params[0] is `this`, params[1] is the implicit `it`
                    let it_sym = interner.intern("it");
                    let it_local = invoke_fb.mf.params[1];
                    // Override `it`'s type if the call site set
                    // lambda_param_type (e.g. filter on List<T>).
                    if let Some(ty) = module.lambda_param_type.take() {
                        if !matches!(ty, Ty::Any) {
                            invoke_fb.mf.locals[it_local.0 as usize] = ty;
                        }
                    }
                    invoke_scope.push((it_sym, it_local));
                } else if params.is_empty()
                    && invoke_fb.mf.params.len() == 1
                    && body_references_ident(body, interner.intern("it"))
                {
                    // No explicit params, no implicit `it` from the
                    // FunctionN invoke shape — but the body uses `it`,
                    // meaning the surrounding context expects a
                    // `(T) -> R` (Function1). Add an invoke param so
                    // the lambda's runtime arity matches Function1
                    // (`invoke(Object): Object`). Without this, the
                    // class only implements Function0 and the
                    // call-site `checkcast Function1` fails (e.g.
                    // JetChat's `onChatClicked = { ... selectedMenu
                    // = it }` lambdas).
                    //
                    // Consume `module.lambda_param_type` (set by the
                    // call site for collection methods like `filter`/
                    // `map`) so `it`'s type matches the receiver's
                    // element type — `it.author` resolves against the
                    // right class instead of falling back to `Any`.
                    let it_ty = module.lambda_param_type.take().unwrap_or(Ty::Any);
                    let it_local = invoke_fb.new_local(it_ty);
                    invoke_fb.mf.params.push(it_local);
                    let it_sym = interner.intern("it");
                    invoke_scope.push((it_sym, it_local));
                }
                // Lambda-with-receiver: if the caller set a receiver type
                // (e.g., apply/run/with scope functions), bind the first
                // invoke arg as `this` with the receiver type so bare
                // calls like `append("Hello")` resolve as this.append().
                if let Some(recv_type) = module.lambda_receiver_type.take() {
                    // Add an invoke parameter for the receiver and bind
                    // it as `this` in scope. The invoke method becomes
                    // invoke(Object receiver, ...) matching FunctionN.
                    let recv_param = invoke_fb.new_local(Ty::Any);
                    invoke_fb.mf.params.push(recv_param);
                    {
                        let raw_param = recv_param;
                        let typed_recv = invoke_fb.new_local(Ty::Class(recv_type));
                        invoke_fb.push_stmt(MStmt::Assign {
                            dest: typed_recv,
                            value: Rvalue::Local(raw_param),
                        });
                        let this_sym = interner.intern("this");
                        // Replace the lambda-self `this` with the receiver.
                        if let Some(pos) = invoke_scope.iter().position(|(s, _)| *s == this_sym) {
                            invoke_scope[pos] = (this_sym, typed_recv);
                        } else {
                            invoke_scope.push((this_sym, typed_recv));
                        }
                    }
                }
                for s in &body.stmts {
                    lower_stmt(
                        s,
                        &mut invoke_fb,
                        &mut invoke_scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        None,
                    );
                }
                invoke_fb.finish()
            };
            invoke_fn.is_abstract = false;
            let mut found_return_value = false;
            // Find the block with ReturnValue and determine if we need
            // to autobox the return for the erased FunctionN interface.
            let mut autobox_info: Option<(usize, LocalId, Ty)> = None;
            for (bi, block) in invoke_fn.blocks.iter().enumerate() {
                if let Terminator::ReturnValue(local) = &block.terminator {
                    let ret_ty = invoke_fn.locals[local.0 as usize].clone();
                    if ret_ty == Ty::Unit {
                        // Will convert to plain Return below.
                    } else {
                        autobox_info = Some((bi, *local, ret_ty));
                    }
                    found_return_value = true;
                    break;
                }
            }
            if let Some((bi, local, ret_ty)) = autobox_info {
                // Autobox the return value so the erased invoke
                // descriptor `()Ljava/lang/Object;` matches the
                // FunctionN interface. E.g. int -> Integer.valueOf.
                let box_rvalue = match &ret_ty {
                    Ty::Int => Some(Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "java/lang/Integer".to_string(),
                            method_name: "valueOf".to_string(),
                            descriptor: "(I)Ljava/lang/Integer;".to_string(),
                        },
                        args: vec![local],
                    }),
                    Ty::Bool => Some(Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "java/lang/Boolean".to_string(),
                            method_name: "valueOf".to_string(),
                            descriptor: "(Z)Ljava/lang/Boolean;".to_string(),
                        },
                        args: vec![local],
                    }),
                    Ty::Long => Some(Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "java/lang/Long".to_string(),
                            method_name: "valueOf".to_string(),
                            descriptor: "(J)Ljava/lang/Long;".to_string(),
                        },
                        args: vec![local],
                    }),
                    Ty::Double => Some(Rvalue::Call {
                        kind: CallKind::StaticJava {
                            class_name: "java/lang/Double".to_string(),
                            method_name: "valueOf".to_string(),
                            descriptor: "(D)Ljava/lang/Double;".to_string(),
                        },
                        args: vec![local],
                    }),
                    _ => None, // already a reference type
                };
                if let Some(rv) = box_rvalue {
                    let b = invoke_fn.new_local(Ty::Any);
                    invoke_fn.blocks[bi]
                        .stmts
                        .push(MStmt::Assign { dest: b, value: rv });
                    invoke_fn.blocks[bi].terminator = Terminator::ReturnValue(b);
                }
                invoke_fn.return_ty = Ty::Any;
            } else if found_return_value {
                // ReturnValue with Ty::Unit — convert to plain Return.
                for block in &mut invoke_fn.blocks {
                    if let Terminator::ReturnValue(local) = &block.terminator {
                        let ret_ty = invoke_fn.locals[local.0 as usize].clone();
                        if ret_ty == Ty::Unit {
                            block.terminator = Terminator::Return;
                        }
                    }
                }
                invoke_fn.return_ty = Ty::Unit;
            }
            if !found_return_value {
                // No ReturnValue found — the lambda body is all statements
                // (e.g. assignments). The return type is Unit.
                invoke_fn.return_ty = Ty::Unit;
            }

            // ── Attach state machine for suspend lambdas ──
            //
            // The invoke body we just built contains every inner suspend
            // call in its MIR. Run the same extractor the named-suspend-
            // fun path uses, but override the continuation class to be
            // the lambda class itself — kotlinc emits the state machine
            // directly on the SuspendLambda subclass (it IS the
            // continuation) rather than generating a separate
            // `InputKt$fn$1` companion. The JVM backend reads this
            // marker from the invoke method to generate the real
            // `invokeSuspend(Object)Object` body, replacing the
            // `IllegalStateException` stub.
            //
            // Currently we only support 0 or 1
            // suspension points. Multi-suspension, captures that span
            // suspend boundaries, and local-variable spilling inside
            // suspend lambdas are tracked as follow-ups.
            // Extra MIR fields to attach to the lambda class for its
            // state-machine spill slots (I$0, I$1, L$0, …). Mirrors the
            // list `build_continuation_class` adds to the named-function
            // continuation class, but placed directly on the lambda
            // (which IS the continuation).
            let mut lambda_extra_fields: Vec<MirField> = Vec::new();
            if is_suspend_lambda {
                let lambda_sm = extract_suspend_state_machine_with_cont(
                    &invoke_fn,
                    module,
                    &module.wrapper_class,
                    &lambda_class_name,
                    lambda_class_name.clone(),
                );
                match lambda_sm {
                    SuspendSitesResult::Zero => {
                        // No suspend calls in the body; invokeSuspend
                        // degenerates to `throwOnFailure($result); <body
                        // value>; areturn`. The backend currently
                        // requires a state machine, so we don't emit
                        // one — the backend falls back to a tail
                        // emitter for zero-site suspend lambdas.
                    }
                    SuspendSitesResult::Found(sm) => {
                        // Materialize one field per spill
                        // slot directly on the lambda class. The JVM
                        // backend's multi-suspend emitter addresses
                        // these via `getfield/putfield <lambda>.I$n:I`,
                        // using `aload_0` as the receiver (since the
                        // lambda IS the continuation, unlike named
                        // suspend funs which stash the continuation
                        // in a local slot).
                        for slot in &sm.spill_layout {
                            lambda_extra_fields.push(MirField {
                                name: slot.name.clone(),
                                ty: match slot.kind {
                                    SpillKind::Int => Ty::Int,
                                    SpillKind::Long => Ty::Long,
                                    SpillKind::Float => Ty::Int, // unused in this session
                                    SpillKind::Double => Ty::Double,
                                    SpillKind::Ref => Ty::Any,
                                },
                                is_jvm_field: false,
                            });
                        }
                        invoke_fn.is_suspend = true;
                        invoke_fn.suspend_state_machine = Some(sm);
                    }
                    SuspendSitesResult::Unsupported(reason) => {
                        diags.push(Diagnostic::error(
                            body.span,
                            format!(
                                "suspend lambda has an unsupported shape: {reason}; the skotch \
                                 CPS transform currently supports straight-line bodies with \
                                 suspend calls that take only the implicit `$completion`"
                            ),
                        ));
                    }
                }
            }

            // ── Constructor (takes captured values) ─────────────────
            let mut init_fn = MirFunction {
                id: FuncId(0),
                name: "<init>".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Unit,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: false,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let init_this = init_fn.new_local(Ty::Class(lambda_class_name.clone()));
            init_fn.params.push(init_this);
            init_fn.blocks[0].stmts.push(MStmt::Assign {
                dest: init_this,
                value: Rvalue::Call {
                    kind: CallKind::Constructor("java/lang/Object".to_string()),
                    args: vec![init_this],
                },
            });
            // Constructor params for captures → field assignments.
            for (sym, _, ty) in &free_vars {
                let field_ty = if let Some(ref_name) = ref_class_names.get(sym) {
                    Ty::Class(ref_name.clone())
                } else {
                    ty.clone()
                };
                let param_id = init_fn.new_local(field_ty);
                init_fn.params.push(param_id);
                init_fn.blocks[0].stmts.push(MStmt::Assign {
                    dest: init_this,
                    value: Rvalue::PutField {
                        receiver: init_this,
                        class_name: lambda_class_name.clone(),
                        field_name: interner.resolve(*sym).to_string(),
                        value: param_id,
                    },
                });
            }

            // Make the lambda class implement kotlin/jvm/functions/FunctionN
            // so it can be passed to Kotlin stdlib HOFs and user-defined HOFs.
            //
            // Suspend lambdas follow kotlinc's convention of bumping the
            // Function arity by 1: the implicit trailing `Continuation`
            // parameter of the CPS-rewritten lambda counts against the
            // `FunctionN` interface. So `{ yield_() }` (0 user params,
            // 1 suspend call) implements `Function1<Continuation, Object>`
            // rather than `Function0<Object>`.
            // Receiver-bearing lambdas have an extra invoke param for
            // the receiver, so the FunctionN arity is +1.
            let has_lambda_recv = invoke_fn.params.len() > params.len() + 1;
            let lambda_arity = params.len()
                + if is_suspend_lambda { 1 } else { 0 }
                + if has_lambda_recv { 1 } else { 0 };
            let iface_name = stdlib_function_interface(lambda_arity);

            // Suspend lambdas extend SuspendLambda instead of
            // Object. Their `<init>(Continuation)V`, `invokeSuspend`,
            // `create`, `invoke(Continuation)`, and erased
            // `invoke(Object)` bridge methods are synthesized by the
            // JVM backend directly from the `is_suspend_lambda` marker —
            // see `crates/skotch-backend-jvm/src/class_writer.rs::
            // emit_suspend_lambda_shell` for the bytecode recipe.
            //
            // The MIR constructor we just built is replaced with a
            // `(Continuation)V` stub below (the real super-ctor wiring
            // lives inline in `emit_suspend_lambda_shell`). The
            // `invoke_fn` is KEPT — the state-machine attachment above
            // populated its `suspend_state_machine` marker so the
            // backend can emit the real CPS state-machine body on
            // `invokeSuspend` (replacing the earlier
            // `IllegalStateException` stub).
            //
            // Non-suspend lambdas keep the `$Lambda$N`
            // shape (Function1-only, direct invoke) byte-stable.
            let (super_class, interfaces, final_init_fn) = if is_suspend_lambda {
                // Suspend lambda constructor takes capture
                // args BEFORE the Continuation param, matching kotlinc's
                // `<init>(capture1, ..., captureN, Continuation)V`.
                // Each capture is stored into its corresponding field on
                // `this` before the super-ctor call (the JVM backend's
                // `emit_suspend_lambda_shell` handles the actual super-
                // ctor delegation; the MIR params here drive the
                // descriptor and call-site argument count).
                let mut susp_init = MirFunction {
                    id: FuncId(0),
                    name: "<init>".to_string(),
                    params: Vec::new(),
                    locals: Vec::new(),
                    blocks: vec![BasicBlock {
                        stmts: Vec::new(),
                        terminator: Terminator::Return,
                    }],
                    return_ty: Ty::Unit,
                    required_params: 0,
                    param_names: Vec::new(),
                    param_defaults: Vec::new(),
                    param_receiver_types: Vec::new(),
                    is_abstract: false,
                    exception_handlers: Vec::new(),
                    vararg_index: None,
                    is_suspend: false,
                    is_inline: false,
                    has_type_params: false,
                    suspend_original_return_ty: None,
                    suspend_state_machine: None,
                    annotations: Vec::new(),
                    named_locals: Vec::new(),
                    is_private: false,
                    is_static: false,
                    default_call_masks: Vec::new(),
                    needs_leading_nop: false,
                    local_generic_args: rustc_hash::FxHashMap::default(),
                };
                let susp_this = susp_init.new_local(Ty::Class(lambda_class_name.clone()));
                susp_init.params.push(susp_this);
                // Capture params — one per free variable.
                for (sym, _, ty) in &free_vars {
                    let field_ty = if let Some(ref_name) = ref_class_names.get(sym) {
                        Ty::Class(ref_name.clone())
                    } else {
                        ty.clone()
                    };
                    let cap_param = susp_init.new_local(field_ty);
                    susp_init.params.push(cap_param);
                    susp_init.blocks[0].stmts.push(MStmt::Assign {
                        dest: susp_this,
                        value: Rvalue::PutField {
                            receiver: susp_this,
                            class_name: lambda_class_name.clone(),
                            field_name: interner.resolve(*sym).to_string(),
                            value: cap_param,
                        },
                    });
                }
                let susp_completion =
                    susp_init.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                susp_init.params.push(susp_completion);
                (
                    Some("kotlin/coroutines/jvm/internal/SuspendLambda".to_string()),
                    vec![iface_name],
                    susp_init,
                )
            } else {
                (None, vec![iface_name], init_fn)
            };

            // Suspend lambdas with multi-suspension bodies
            // spill live locals to synthetic fields on themselves (the
            // lambda IS the continuation). The list we built above is
            // appended AFTER the real captures so field ordering is
            // stable wrt `capture_fields` for zero-/one-suspension
            // fixtures that never populated `lambda_extra_fields`.
            let mut final_fields = capture_fields;
            final_fields.extend(lambda_extra_fields);

            // Add p$0 field for CoroutineScope receiver on
            // ALL suspend lambdas. The interface might be Function1 at
            // this point (patched to Function2 later by the builder handler).
            if is_suspend_lambda {
                final_fields.push(MirField {
                    name: "p$0".to_string(),
                    ty: Ty::Any,
                    is_jvm_field: false,
                });
            }

            // Replace the pre-registered stub with the real class.
            module.classes[lambda_idx] = MirClass {
                name: lambda_class_name.clone(),
                super_class,
                is_open: false,
                is_abstract: false,
                is_interface: false,
                interfaces,
                fields: final_fields,
                methods: vec![invoke_fn],
                constructor: final_init_fn,
                secondary_constructors: Vec::new(),
                is_lambda: true,
                is_suspend_lambda,
                is_cross_file_stub: false,
                annotations: Vec::new(),
                has_type_params: false,
                is_object_singleton: false,
                companion_class_name: None,
                static_fields: Vec::new(),
                clinit: None,
            };

            // ── Instantiate at definition site ──────────────────────
            let inst = fb.new_local(Ty::Class(lambda_class_name.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::NewInstance(lambda_class_name.clone()),
            });
            // Pass captured values as constructor args.
            // For ref-boxed captures, pass the $Ref instance (which is now
            // the outer scope binding after we replaced it above).
            let ctor_args: Vec<LocalId> = if is_suspend_lambda {
                // Suspend lambda's constructor is
                // `(capture1, ..., captureN, Continuation)V`. Pass
                // captured locals first, then null Continuation.
                let mut args: Vec<LocalId> = free_vars
                    .iter()
                    .map(|(sym, orig_lid, _)| {
                        if ref_class_names.contains_key(sym) {
                            scope
                                .iter()
                                .rev()
                                .find(|(s, _)| s == sym)
                                .map(|(_, lid)| *lid)
                                .unwrap_or(*orig_lid)
                        } else {
                            *orig_lid
                        }
                    })
                    .collect();
                let null_cont =
                    fb.new_local(Ty::Class("kotlin/coroutines/Continuation".to_string()));
                fb.push_stmt(MStmt::Assign {
                    dest: null_cont,
                    value: Rvalue::Const(MirConst::Null),
                });
                args.push(null_cont);
                args
            } else {
                free_vars
                    .iter()
                    .map(|(sym, orig_lid, _)| {
                        if ref_class_names.contains_key(sym) {
                            // The outer scope now points to the $Ref instance.
                            scope
                                .iter()
                                .rev()
                                .find(|(s, _)| s == sym)
                                .map(|(_, lid)| *lid)
                                .unwrap_or(*orig_lid)
                        } else {
                            *orig_lid
                        }
                    })
                    .collect()
            };
            fb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::Call {
                    kind: CallKind::Constructor(lambda_class_name),
                    args: ctor_args,
                },
            });
            Some(inst)
        }

        Expr::ObjectExpr {
            super_type,
            methods,
            ..
        } => {
            let super_name = interner.resolve(*super_type).to_string();
            // kotlinc names anonymous object expressions
            // `<Wrapper>$<EnclosingFn>$<varName>$<idx>`. Use the var
            // hint when one is set (by `lower_val_stmt`), otherwise fall
            // back to `$<EnclosingFn>$<idx>`. This matches kotlinc's
            // output for `val g = object : T { ... }` patterns.
            let enclosing_fn = fb.mf.name.clone();
            let wrapper = if module.wrapper_class.is_empty() {
                "InputKt".to_string()
            } else {
                module.wrapper_class.clone()
            };
            let var_hint = OBJECT_EXPR_VAR_HINT.with(|cell| cell.borrow().clone());
            // Sequential index per (enclosing_fn, var) within the file.
            let obj_idx = module
                .classes
                .iter()
                .filter(|c| c.name.starts_with(&format!("{wrapper}${enclosing_fn}$")))
                .count()
                + 1;
            let obj_class_name = if let Some(var) = var_hint {
                format!("{wrapper}${enclosing_fn}${var}${obj_idx}")
            } else {
                format!("{wrapper}${enclosing_fn}${obj_idx}")
            };

            // Lower each method.
            let mut mir_methods = Vec::new();
            for method in methods {
                let method_name = interner.resolve(method.name).to_string();
                let return_ty = method
                    .return_ty
                    .as_ref()
                    .map(|tr| {
                        let resolved = resolve_type(interner.resolve(tr.name), module);
                        resolved
                    })
                    .unwrap_or(Ty::Unit);
                let fn_idx = module.functions.len() + mir_methods.len();
                let mut mfb = FnBuilder::new(fn_idx, method_name, return_ty);
                let this_local = mfb.new_local(Ty::Class(obj_class_name.clone()));
                mfb.mf.params.push(this_local);
                let mut mscope: Vec<(Symbol, LocalId)> = Vec::new();
                for p in &method.params {
                    let ty = resolve_type(interner.resolve(p.ty.name), module);
                    let pid = mfb.new_local(ty);
                    mfb.mf.params.push(pid);
                    mscope.push((p.name, pid));
                }
                for s in &method.body.stmts {
                    lower_stmt(
                        s,
                        &mut mfb,
                        &mut mscope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        None,
                    );
                }
                let mut finished = mfb.finish();
                // Patch Unit-returning methods: convert ReturnValue to Return.
                for block in &mut finished.blocks {
                    if let Terminator::ReturnValue(local) = &block.terminator {
                        if finished.locals[local.0 as usize] == Ty::Unit {
                            block.terminator = Terminator::Return;
                            finished.return_ty = Ty::Unit;
                        } else {
                            finished.return_ty = finished.locals[local.0 as usize].clone();
                        }
                    }
                }
                mir_methods.push(finished);
            }

            // Determine if super is an interface or class.
            let is_iface = module
                .classes
                .iter()
                .any(|c| c.name == super_name && c.is_interface);
            let (super_class, ifaces) = if is_iface {
                (None, vec![super_name.clone()])
            } else {
                (Some(super_name.clone()), vec![])
            };

            // Build constructor.
            let mut init_fn = MirFunction {
                id: FuncId(0),
                name: "<init>".to_string(),
                params: Vec::new(),
                locals: Vec::new(),
                blocks: vec![BasicBlock {
                    stmts: Vec::new(),
                    terminator: Terminator::Return,
                }],
                return_ty: Ty::Unit,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: false,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let init_this = init_fn.new_local(Ty::Class(obj_class_name.clone()));
            init_fn.params.push(init_this);
            let super_ctor = if is_iface {
                "java/lang/Object".to_string()
            } else {
                super_name.clone()
            };
            init_fn.blocks[0].stmts.push(MStmt::Assign {
                dest: init_this,
                value: Rvalue::Call {
                    kind: CallKind::Constructor(super_ctor),
                    args: vec![init_this],
                },
            });

            module.classes.push(MirClass {
                name: obj_class_name.clone(),
                super_class,
                is_open: false,
                is_abstract: false,
                is_interface: false,
                interfaces: ifaces,
                fields: Vec::new(),
                methods: mir_methods,
                constructor: init_fn,
                secondary_constructors: Vec::new(),
                is_lambda: false,
                is_suspend_lambda: false,
                is_cross_file_stub: false,
                annotations: Vec::new(),
                has_type_params: false,
                is_object_singleton: false,
                companion_class_name: None,
                static_fields: Vec::new(),
                clinit: None,
            });

            // Instantiate. Type as the synthetic anonymous class so
            // method dispatch goes through the concrete class
            // (matching kotlinc's `invokevirtual InputKt$main$g$1.method`).
            let inst = fb.new_local(Ty::Class(obj_class_name.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::NewInstance(obj_class_name.clone()),
            });
            fb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::Call {
                    kind: CallKind::Constructor(obj_class_name),
                    args: vec![],
                },
            });
            let _ = super_name;
            Some(inst)
        }
    }
}

/// Lower one template part to a local.
#[allow(clippy::too_many_arguments)]
fn lower_template_part(
    part: &skotch_syntax::TemplatePart,
    fb: &mut FnBuilder,
    scope: &mut Vec<(Symbol, LocalId)>,
    module: &mut MirModule,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) -> Option<LocalId> {
    use skotch_syntax::TemplatePart;
    match part {
        TemplatePart::Text(s, _) => {
            let sid = module.intern_string(s);
            let dest = fb.new_local(Ty::String);
            fb.push_stmt(MStmt::Assign {
                dest,
                value: Rvalue::Const(MirConst::String(sid)),
            });
            Some(dest)
        }
        TemplatePart::IdentRef(name, span) => {
            let synthetic = Expr::Ident(*name, *span);
            lower_expr(
                &synthetic,
                fb,
                scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                None,
            )
        }
        TemplatePart::Expr(inner) => lower_expr(
            inner,
            fb,
            scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
            None,
        ),
    }
}

fn lookup_java_static_typed(
    class_name: &str,
    method_name: &str,
    arg_count: usize,
    arg_types: &[Ty],
) -> Option<(String, String, String, Ty)> {
    let resolved = if class_name.contains('.') {
        class_name.replace('.', "/")
    } else {
        class_name.to_string()
    };
    lookup_java_static_with_types(&resolved, method_name, arg_count, arg_types)
}

/// Look up an instance (non-static) method on a JVM class.
fn lookup_java_instance(
    class_name: &str,
    method_name: &str,
    arg_count: usize,
) -> Option<(String, String, String, Ty)> {
    if class_name.contains('/') {
        return lookup_java_instance_from_jdk(class_name, method_name, arg_count);
    }
    if class_name.contains('.') {
        let jvm_path = class_name.replace('.', "/");
        return lookup_java_instance_from_jdk(&jvm_path, method_name, arg_count);
    }
    let simple = class_name;
    lookup_java_instance_from_jdk(simple, method_name, arg_count)
}

/// Look up a static method from the JDK's actual class files.
/// Count parameters in a JVM method descriptor.
fn count_descriptor_params(desc: &str) -> usize {
    let inner = desc.split(')').next().unwrap_or("").trim_start_matches('(');
    let mut count = 0;
    let mut chars = inner.chars();
    while let Some(c) = chars.next() {
        match c {
            'B' | 'C' | 'D' | 'F' | 'I' | 'J' | 'S' | 'Z' => count += 1,
            'L' => {
                // Skip to ';'
                for sc in chars.by_ref() {
                    if sc == ';' {
                        break;
                    }
                }
                count += 1;
            }
            '[' => {} // array prefix, don't count yet
            _ => {}
        }
    }
    count
}

/// Look up a static method with type-aware overload resolution.
/// `arg_types` is a hint for picking the best overload when multiple
/// methods match the same name and parameter count.
fn lookup_java_static_with_types(
    class_name: &str,
    method_name: &str,
    arg_count: usize,
    arg_types: &[Ty],
) -> Option<(String, String, String, Ty)> {
    ensure_class_loaded(class_name);

    with_registry(|reg| {
        let class_info = reg.get(class_name)?;
        let candidates: Vec<&skotch_classinfo::MethodInfo> = class_info
            .methods
            .iter()
            .filter(|m| {
                m.name == method_name
                    && m.is_static()
                    && m.is_public()
                    && count_descriptor_params(&m.descriptor) == arg_count
            })
            .collect();

        let method = if candidates.len() <= 1 {
            candidates.into_iter().next()
        } else {
            // Multiple overloads — pick the best match using arg types.
            pick_best_overload(&candidates, arg_types)
        };

        // Fallback: just match by name if no count match.
        let method = method.or_else(|| {
            class_info
                .methods
                .iter()
                .find(|m| m.name == method_name && m.is_static() && m.is_public())
        })?;

        Some(make_lookup_result(&class_info.name, method))
    })?
}

/// Like `lookup_java_static_from_jdk` but for instance methods (not static).
fn lookup_java_instance_from_jdk(
    class_name: &str,
    method_name: &str,
    arg_count: usize,
) -> Option<(String, String, String, Ty)> {
    lookup_java_instance_with_types(class_name, method_name, arg_count, &[])
}

fn lookup_java_instance_with_types(
    class_name: &str,
    method_name: &str,
    arg_count: usize,
    arg_types: &[Ty],
) -> Option<(String, String, String, Ty)> {
    ensure_class_loaded(class_name);

    with_registry(|reg| {
        // Walk the superclass chain to find the method.
        let mut search_class = Some(class_name.to_string());
        while let Some(ref cname) = search_class {
            if !reg.contains_key(cname.as_str()) {
                let jvm_path = if cname.contains('/') {
                    cname.clone()
                } else {
                    format!("java/lang/{cname}")
                };
                if let Ok(info) = skotch_classinfo::load_jdk_class(&jvm_path) {
                    reg.insert(cname.clone(), info);
                } else {
                    break;
                }
            }
            if let Some(ci) = reg.get(cname.as_str()) {
                let candidates: Vec<&skotch_classinfo::MethodInfo> = ci
                    .methods
                    .iter()
                    .filter(|m| {
                        m.name == method_name
                            && !m.is_static()
                            && m.is_public()
                            && count_descriptor_params(&m.descriptor) == arg_count
                    })
                    .collect();

                let method = if candidates.len() <= 1 {
                    candidates.into_iter().next()
                } else {
                    pick_best_overload(&candidates, arg_types)
                };
                let method = method.or_else(|| {
                    ci.methods
                        .iter()
                        .find(|m| m.name == method_name && !m.is_static() && m.is_public())
                });
                if let Some(m) = method {
                    return Some(make_lookup_result(&ci.name, m));
                }
                search_class = ci.super_class.clone();
            } else {
                break;
            }
        }
        None
    })?
}

/// Look up a constructor on a JVM class with type-aware overload resolution.
pub fn lookup_constructor(class_name: &str, arg_count: usize, arg_types: &[Ty]) -> Option<String> {
    ensure_class_loaded(class_name);
    with_registry(|reg| {
        let ci = reg.get(class_name)?;
        let candidates: Vec<&skotch_classinfo::MethodInfo> = ci
            .methods
            .iter()
            .filter(|m| {
                m.name == "<init>"
                    && m.is_public()
                    && count_descriptor_params(&m.descriptor) == arg_count
            })
            .collect();
        let method = if candidates.len() <= 1 {
            candidates.into_iter().next()
        } else {
            pick_best_overload(&candidates, arg_types)
        };
        method.map(|m| m.descriptor.clone())
    })?
}

fn make_lookup_result(
    class_name: &str,
    method: &skotch_classinfo::MethodInfo,
) -> (String, String, String, Ty) {
    let return_ty = match skotch_classinfo::return_type_from_descriptor(&method.descriptor) {
        "Unit" => Ty::Unit,
        "Boolean" => Ty::Bool,
        "Int" => Ty::Int,
        "Char" => Ty::Char,
        "Long" => Ty::Long,
        "Double" => Ty::Double,
        "String" => Ty::String,
        _ => Ty::Any,
    };
    (
        class_name.to_string(),
        method.name.clone(),
        method.descriptor.clone(),
        return_ty,
    )
}

/// Pick the best overload from multiple candidates using argument types.
///
/// Scoring: each parameter gets a score based on type compatibility:
///  - Exact match (Int→I, String→Ljava/lang/String;, Bool→Z): 3
///  - Compatible (any→Ljava/lang/Object;): 1
///  - Mismatch (String→I): 0
///
/// Best total score wins. Ties prefer the overload with Object params
/// (most general).
fn pick_best_overload<'a>(
    candidates: &[&'a skotch_classinfo::MethodInfo],
    arg_types: &[Ty],
) -> Option<&'a skotch_classinfo::MethodInfo> {
    if candidates.is_empty() {
        return None;
    }
    if arg_types.is_empty() {
        // No type info — prefer the most general overload (all Object params).
        let best = candidates
            .iter()
            .max_by_key(|m| (generality_score(&m.descriptor), -bridge_penalty(m)));
        return best.copied();
    }
    let best = candidates
        .iter()
        .max_by_key(|m| (overload_score(&m.descriptor, arg_types), -bridge_penalty(m)));
    best.copied()
}

/// Penalize synthetic bridge methods so that the covariant override is
/// picked first. JVM's `ACC_BRIDGE` is 0x0040.
fn bridge_penalty(m: &skotch_classinfo::MethodInfo) -> i32 {
    if m.access_flags & 0x0040 != 0 {
        1
    } else {
        0
    }
}

/// Score how well a descriptor matches the given argument types.
fn overload_score(descriptor: &str, arg_types: &[Ty]) -> i32 {
    let params = parse_descriptor_param_types(descriptor);
    let mut score = 0i32;
    for (i, param_jvm) in params.iter().enumerate() {
        let arg_ty = arg_types.get(i);
        score += match (arg_ty, param_jvm.as_str()) {
            (Some(Ty::Int), "I") => 3,
            (Some(Ty::Long), "J") => 3,
            (Some(Ty::Double), "D") | (Some(Ty::Double), "F") => 3,
            (Some(Ty::Bool), "Z") => 3,
            (Some(Ty::String), "Ljava/lang/String;") => 3,
            (Some(Ty::Int), "J") => 2, // int widens to long (preferred)
            (Some(Ty::Int), "D") | (Some(Ty::Int), "F") => 1, // int widens to double/float (less preferred)
            (Some(Ty::Long), "D") => 1,                       // long widens to double
            (Some(Ty::String), "Ljava/lang/Object;") => 2,
            (Some(Ty::Int), "Ljava/lang/Object;") => 1, // autobox
            (Some(Ty::Long), "Ljava/lang/Object;") => 1,
            (Some(Ty::Bool), "Ljava/lang/Object;") => 1,
            (Some(Ty::Double), "Ljava/lang/Object;") => 1,
            (_, "Ljava/lang/Object;") => 1, // Object accepts anything
            _ => 0,
        };
    }
    score
}

/// Score how "general" a descriptor is (higher = more Object params).
fn generality_score(descriptor: &str) -> i32 {
    let params = parse_descriptor_param_types(descriptor);
    params
        .iter()
        .map(|p| if p == "Ljava/lang/Object;" { 1 } else { 0 })
        .sum()
}

/// Parse a JVM descriptor into its parameter type strings.
/// E.g. "(ILjava/lang/String;Z)V" → ["I", "Ljava/lang/String;", "Z"]
fn parse_descriptor_param_types(desc: &str) -> Vec<String> {
    let inner = desc.split(')').next().unwrap_or("").trim_start_matches('(');
    let mut params = Vec::new();
    let mut chars = inner.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            'B' | 'C' | 'D' | 'F' | 'I' | 'J' | 'S' | 'Z' => {
                params.push(c.to_string());
            }
            'L' => {
                let mut s = String::from("L");
                for sc in chars.by_ref() {
                    s.push(sc);
                    if sc == ';' {
                        break;
                    }
                }
                params.push(s);
            }
            '[' => {
                let mut s = String::from("[");
                // Consume the element type
                if let Some(&next) = chars.peek() {
                    if next == 'L' {
                        chars.next();
                        s.push('L');
                        for sc in chars.by_ref() {
                            s.push(sc);
                            if sc == ';' {
                                break;
                            }
                        }
                    } else {
                        s.push(chars.next().unwrap_or('I'));
                    }
                }
                params.push(s);
            }
            _ => {}
        }
    }
    params
}

/// Try to lower a method call as a Java static call. Returns Some(dest_local) if successful.
#[allow(clippy::too_many_arguments)]
fn try_java_static_call(
    receiver: &Expr,
    method_name: Symbol,
    args: &[skotch_syntax::CallArg],
    fb: &mut FnBuilder,
    scope: &mut Vec<(Symbol, LocalId)>,
    module: &mut MirModule,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    interner: &mut Interner,
    diags: &mut Diagnostics,
    loop_ctx: LoopCtx,
) -> Option<LocalId> {
    // Extract the class name from the receiver expression.
    // Supports: `System` (simple), `java.lang.System` (qualified).
    let class_name = extract_qualified_name(receiver, interner)?;

    let method_str = interner.resolve(method_name).to_string();
    // Resolve through import_map if the simple name is imported.
    let resolved_class = module
        .import_map
        .get(&class_name)
        .cloned()
        .unwrap_or_else(|| class_name.clone());

    // Lower arguments first so we can use their types for overload resolution.
    let mut arg_locals = Vec::new();
    for a in args {
        let id = lower_expr(
            &a.expr,
            fb,
            scope,
            module,
            name_to_func,
            name_to_global,
            interner,
            diags,
            loop_ctx,
        )?;
        arg_locals.push(id);
    }
    let arg_types: Vec<Ty> = arg_locals
        .iter()
        .map(|l| fb.mf.locals[l.0 as usize].clone())
        .collect();

    let (jvm_class, jvm_method, descriptor, return_ty) =
        lookup_java_static_typed(&resolved_class, &method_str, args.len(), &arg_types)?;

    let dest = fb.new_local(return_ty);
    fb.push_stmt(MStmt::Assign {
        dest,
        value: Rvalue::Call {
            kind: CallKind::StaticJava {
                class_name: jvm_class,
                method_name: jvm_method,
                descriptor,
            },
            args: arg_locals,
        },
    });
    Some(dest)
}

/// Extract a qualified name from a chain of Field expressions.
/// `java.lang.System` → "java.lang.System"
/// `System` → "System"
fn extract_qualified_name(expr: &Expr, interner: &Interner) -> Option<String> {
    match expr {
        Expr::Ident(sym, _) => Some(interner.resolve(*sym).to_string()),
        Expr::Field { receiver, name, .. } => {
            let prefix = extract_qualified_name(receiver, interner)?;
            let segment = interner.resolve(*name);
            Some(format!("{prefix}.{segment}"))
        }
        _ => None,
    }
}

/// Lower an `object` declaration to a MirClass with static-like methods.
/// The object compiles to a regular class with an empty constructor.
/// Methods are instance methods (the JVM INSTANCE field dispatches to them).
/// Lower an `enum class` to top-level constant functions.
/// Each enum entry becomes a function returning its name as a String.
/// `Color.RED` resolves to calling the `RED` function which returns `"RED"`.
/// `.name` returns the string; `.ordinal` returns the index.
fn lower_enum(
    e: &skotch_syntax::EnumDecl,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    _name_to_global: &mut FxHashMap<Symbol, MirConst>,
    module: &mut MirModule,
    interner: &mut Interner,
) {
    let enum_name = interner.resolve(e.name).to_string();

    // ── Build enum as a real MirClass ───────────────────────────────────
    //
    // Every enum class has an implicit `name` field (the entry name as a
    // String), plus any user-declared constructor params as additional
    // fields. The <init> takes (name: String, ...params) and stores them.
    //
    // Each entry (e.g., Color.RED) becomes a top-level function that
    // creates and returns a new instance: `new Color("RED", 16711680)`.

    // Fields: name (implicit) + constructor params.
    let mut fields = vec![MirField {
        name: "name".to_string(),
        ty: Ty::String,
        is_jvm_field: false,
    }];
    for param in &e.constructor_params {
        let ty = resolve_type(interner.resolve(param.ty.name), module);
        fields.push(MirField {
            name: interner.resolve(param.name).to_string(),
            ty,
            is_jvm_field: false,
        });
    }

    // Enum entries become `public static final <Enum> ENTRY;` singleton
    // fields, each constructed exactly once in the class `<clinit>` (built
    // below). kotlinc does the same so that reference equality on entries
    // (`V.A == V.A`, and `it == V.A` after `pick { ... }`) holds — Kotlin
    // specifies enum entries are singletons (fixtures 65/427/995 et al.).
    // The per-entry `ENTRY()` accessor functions then just read the field
    // (`getstatic`) instead of constructing a fresh instance.
    let enum_desc = format!("L{};", enum_name);
    let static_fields: Vec<MirField> = e
        .entries
        .iter()
        .map(|entry| MirField {
            name: interner.resolve(entry.name).to_string(),
            ty: Ty::Class(enum_name.clone()),
            is_jvm_field: false,
        })
        .collect();

    // <init>(this, name: String, ...params)
    let mut init_fn = MirFunction {
        id: FuncId(0),
        name: "<init>".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::Unit,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    // this
    let this_id = init_fn.new_local(Ty::Class(enum_name.clone()));
    init_fn.params.push(this_id);
    // Super call: java/lang/Object.<init>()V
    init_fn.blocks[0].stmts.push(MStmt::Assign {
        dest: this_id,
        value: Rvalue::Call {
            kind: CallKind::Constructor("java/lang/Object".to_string()),
            args: vec![this_id],
        },
    });
    // name param
    let name_param = init_fn.new_local(Ty::String);
    init_fn.params.push(name_param);
    init_fn.blocks[0].stmts.push(MStmt::Assign {
        dest: this_id,
        value: Rvalue::PutField {
            receiver: this_id,
            class_name: enum_name.clone(),
            field_name: "name".to_string(),
            value: name_param,
        },
    });
    // Constructor params
    for param in &e.constructor_params {
        let ty = resolve_type(interner.resolve(param.ty.name), module);
        let pid = init_fn.new_local(ty);
        init_fn.params.push(pid);
        init_fn.blocks[0].stmts.push(MStmt::Assign {
            dest: this_id,
            value: Rvalue::PutField {
                receiver: this_id,
                class_name: enum_name.clone(),
                field_name: interner.resolve(param.name).to_string(),
                value: pid,
            },
        });
    }

    // toString() method → returns this.name
    let mut ts_fn = MirFunction {
        id: FuncId(0),
        name: "toString".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::String,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    let ts_this = ts_fn.new_local(Ty::Class(enum_name.clone()));
    ts_fn.params.push(ts_this);
    let ts_name = ts_fn.new_local(Ty::String);
    ts_fn.blocks[0].stmts.push(MStmt::Assign {
        dest: ts_name,
        value: Rvalue::GetField {
            receiver: ts_this,
            class_name: enum_name.clone(),
            field_name: "name".to_string(),
        },
    });
    ts_fn.blocks[0].terminator = Terminator::ReturnValue(ts_name);

    // ── Abstract method dispatch ──────────────────────────────────────
    //
    // For each abstract method declared on the enum class, we generate a
    // concrete instance method that dispatches based on `this.name`.
    // For each abstract method, generate a dispatch function as a
    // top-level function (not a class method) so the JVM backend's
    // walk_block path handles StackMapTable correctly. The function
    // takes (this: EnumClass, params...) and dispatches on this.name.
    let class_methods = vec![ts_fn];

    for abs_method in &e.methods {
        if !abs_method.is_abstract {
            continue;
        }
        let method_name_str = interner.resolve(abs_method.name).to_string();
        let ret_ty = abs_method
            .return_ty
            .as_ref()
            .map(|tr| resolve_type(interner.resolve(tr.name), module))
            .unwrap_or(Ty::Unit);

        let fn_idx = module.functions.len();
        let fn_id = FuncId(fn_idx as u32);
        // Register under "EnumName$methodName" so call sites can find it.
        let dispatch_name = format!("{}${}", enum_name, method_name_str);
        let dispatch_sym = interner.intern(&dispatch_name);
        name_to_func.insert(dispatch_sym, fn_id);

        let mut fb = FnBuilder::new(fn_idx, dispatch_name, ret_ty.clone());

        // this parameter
        let this_local = fb.new_local(Ty::Class(enum_name.clone()));
        fb.mf.params.push(this_local);
        // user params
        let mut param_locals = Vec::new();
        for p in &abs_method.params {
            let pty = resolve_type(interner.resolve(p.ty.name), module);
            let pid = fb.new_local(pty);
            fb.mf.params.push(pid);
            param_locals.push((p.name, pid));
        }

        // Get this.name for dispatch
        let name_field = fb.new_local(Ty::String);
        fb.push_stmt(MStmt::Assign {
            dest: name_field,
            value: Rvalue::GetField {
                receiver: this_local,
                class_name: enum_name.clone(),
                field_name: "name".to_string(),
            },
        });

        // For each entry with an override of this method, generate an
        // if-branch comparing this.name == "ENTRY_NAME".
        let scope: Vec<(Symbol, LocalId)> = param_locals.clone();

        for entry in &e.entries {
            let override_method = entry
                .methods
                .iter()
                .find(|m| interner.resolve(m.name) == interner.resolve(abs_method.name));
            let Some(om) = override_method else {
                continue;
            };

            let entry_name_str = interner.resolve(entry.name).to_string();
            let entry_name_sid = module.intern_string(&entry_name_str);
            let entry_name_local = fb.new_local(Ty::String);
            fb.push_stmt(MStmt::Assign {
                dest: entry_name_local,
                value: Rvalue::Const(MirConst::String(entry_name_sid)),
            });

            // Compare name_field == entry_name_str
            let cmp = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: cmp,
                value: Rvalue::BinOp {
                    op: MBinOp::CmpEq,
                    lhs: name_field,
                    rhs: entry_name_local,
                },
            });

            let then_block = fb.new_block();
            let next_block = fb.new_block();
            fb.set_terminator(Terminator::Branch {
                cond: cmp,
                then_block,
                else_block: next_block,
            });

            // Then block: inline the override body
            fb.cur_block = then_block;
            let mut entry_scope = scope.clone();
            let mut diags = Diagnostics::new();
            for stmt in &om.body.stmts {
                lower_stmt(
                    stmt,
                    &mut fb,
                    &mut entry_scope,
                    module,
                    name_to_func,
                    _name_to_global,
                    interner,
                    &mut diags,
                    None,
                );
            }
            if !matches!(
                fb.mf.blocks[fb.cur_block as usize].terminator,
                Terminator::ReturnValue(_) | Terminator::Return
            ) {
                fb.set_terminator(Terminator::Return);
            }

            fb.cur_block = next_block;
        }

        // Fallback: return default value (shouldn't be reached)
        if ret_ty == Ty::Int {
            let zero = fb.new_local(Ty::Int);
            fb.push_stmt(MStmt::Assign {
                dest: zero,
                value: Rvalue::Const(MirConst::Int(0)),
            });
            fb.set_terminator(Terminator::ReturnValue(zero));
        } else {
            fb.set_terminator(Terminator::Return);
        }

        module.add_function(fb.finish());
    }

    // ── <clinit>: construct each entry singleton exactly once ───────────
    //
    // For each entry: `new V; invokespecial V.<init>("NAME", ...args);
    // putstatic V.ENTRY`. Emitted as ordinary MIR so every backend reuses
    // its existing NewInstance / Constructor / PutStaticField lowering —
    // this is the same NewInstance+Constructor sequence the per-entry
    // accessors used to produce, now storing into the static field instead
    // of returning a fresh instance. The first `getstatic V.ENTRY` (from an
    // accessor) triggers this `<clinit>`, initializing all entries together.
    let clinit_fn = {
        let mut cb = FnBuilder::new(module.functions.len(), "<clinit>".to_string(), Ty::Unit);
        for entry in &e.entries {
            let entry_name_str = interner.resolve(entry.name).to_string();
            let inst = cb.new_local(Ty::Class(enum_name.clone()));
            cb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::NewInstance(enum_name.clone()),
            });
            // Constructor args: ["ENTRY_NAME", ...const entry args]. `inst`
            // is intentionally omitted — NewInstance already left new+dup on
            // the stack for the invokespecial.
            let name_sid = module.intern_string(&entry_name_str);
            let name_local = cb.new_local(Ty::String);
            cb.push_stmt(MStmt::Assign {
                dest: name_local,
                value: Rvalue::Const(MirConst::String(name_sid)),
            });
            let mut ctor_args = vec![name_local];
            for arg_expr in &entry.args {
                if let Some(c) = lower_const_init(arg_expr, module) {
                    let ty = const_ty(&c);
                    let arg_local = cb.new_local(ty);
                    cb.push_stmt(MStmt::Assign {
                        dest: arg_local,
                        value: Rvalue::Const(c),
                    });
                    ctor_args.push(arg_local);
                }
            }
            cb.push_stmt(MStmt::Assign {
                dest: inst,
                value: Rvalue::Call {
                    kind: CallKind::Constructor(enum_name.clone()),
                    args: ctor_args,
                },
            });
            let sink = cb.new_local(Ty::Unit);
            cb.push_stmt(MStmt::Assign {
                dest: sink,
                value: Rvalue::PutStaticField {
                    class_name: enum_name.clone(),
                    field_name: entry_name_str,
                    descriptor: enum_desc.clone(),
                    value: inst,
                },
            });
        }
        cb.set_terminator(Terminator::Return);
        cb.finish()
    };

    module.classes.push(MirClass {
        name: enum_name.clone(),
        super_class: None,
        is_open: false,
        is_abstract: false,
        is_interface: false,
        interfaces: Vec::new(),
        fields,
        methods: class_methods,
        constructor: init_fn,
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: false,
        is_object_singleton: false,
        companion_class_name: None,
        static_fields,
        clinit: Some(clinit_fn),
    });

    // ── Entry functions ─────────────────────────────────────────────────
    //
    // Each entry becomes a top-level function:
    //   fun RED(): Color = Color("RED", 16711680)
    for entry in &e.entries {
        let entry_name = interner.resolve(entry.name).to_string();
        let fn_idx = module.functions.len();
        let fn_id = FuncId(fn_idx as u32);
        name_to_func.insert(entry.name, fn_id);
        // Also register under the qualified name `EnumName$EntryName`
        // so receiver-qualified accesses (`InputSelector.EMOJI`) can
        // disambiguate when two enums in the same file share a member
        // name. The `Expr::Field` lowering checks this qualified key
        // BEFORE the bare `name_to_func.get(entry.name)` fallback.
        let qualified_name = format!("{enum_name}${entry_name}");
        let qualified_sym = interner.intern(&qualified_name);
        name_to_func.insert(qualified_sym, fn_id);
        // Record (enum_class, entry_name) so call-site lowering can emit
        // `getstatic Color.RED:LColor;` directly (matching kotlinc) and
        // the JVM backend can skip the synthesized accessor method.
        module
            .enum_entry_funcs
            .insert(fn_idx as u32, (enum_name.clone(), entry_name.clone()));

        let mut fb = FnBuilder::new(fn_idx, entry_name.clone(), Ty::Class(enum_name.clone()));

        // Read the singleton from the static field that `<clinit>`
        // initialized (`getstatic V.ENTRY`). Returning the shared instance —
        // rather than constructing a fresh one per call — is what makes
        // reference equality on entries (`it == V.A`) behave correctly.
        let inst = fb.new_local(Ty::Class(enum_name.clone()));
        fb.push_stmt(MStmt::Assign {
            dest: inst,
            value: Rvalue::GetStaticField {
                class_name: enum_name.clone(),
                field_name: entry_name.clone(),
                descriptor: enum_desc.clone(),
            },
        });
        fb.set_terminator(Terminator::ReturnValue(inst));
        module.add_function(fb.finish());
    }

    // ── values() function ──────────────────────────────────────────────
    //
    // Returns an ArrayList<EnumClass> containing all entries.
    // Desugars to: ArrayList() + add(RED()) + add(GREEN()) + ... → return list
    {
        let values_fn_name = format!("{}$values", enum_name);
        let fn_idx = module.functions.len();
        let fn_id = FuncId(fn_idx as u32);
        let values_sym = interner.intern(&values_fn_name);
        name_to_func.insert(values_sym, fn_id);

        let list_ty = Ty::Class("java/util/ArrayList".to_string());
        let mut fb = FnBuilder::new(fn_idx, values_fn_name, list_ty.clone());

        // Create ArrayList.
        let list_local = fb.new_local(list_ty.clone());
        fb.push_stmt(MStmt::Assign {
            dest: list_local,
            value: Rvalue::NewInstance("java/util/ArrayList".to_string()),
        });
        fb.push_stmt(MStmt::Assign {
            dest: list_local,
            value: Rvalue::Call {
                kind: CallKind::Constructor("java/util/ArrayList".to_string()),
                args: vec![],
            },
        });

        // Add each entry.
        for entry in &e.entries {
            let entry_fid = *name_to_func.get(&entry.name).unwrap();
            let entry_local = fb.new_local(Ty::Class(enum_name.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: entry_local,
                value: Rvalue::Call {
                    kind: CallKind::Static(entry_fid),
                    args: vec![],
                },
            });
            let _add_result = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: _add_result,
                value: Rvalue::Call {
                    kind: CallKind::VirtualJava {
                        class_name: "java/util/ArrayList".to_string(),
                        method_name: "add".to_string(),
                        descriptor: "(Ljava/lang/Object;)Z".to_string(),
                    },
                    args: vec![list_local, entry_local],
                },
            });
        }

        fb.set_terminator(Terminator::ReturnValue(list_local));
        module.add_function(fb.finish());
    }

    // ── valueOf(name: String) function ─────────────────────────────────
    //
    // Compares the string argument against each entry name. Returns the
    // first match. If none match, returns the first entry (fallback).
    // Layout:
    //   block0: load arg → check entry0 name → branch
    //   check_N: if (arg == "NAME") goto match_N else goto check_N+1
    //   match_N: return EntryN()
    //   fallback: return Entry0()   (Kotlin would throw, we simplify)
    {
        let valueof_fn_name = format!("{}$valueOf", enum_name);
        let fn_idx = module.functions.len();
        let fn_id = FuncId(fn_idx as u32);
        let valueof_sym = interner.intern(&valueof_fn_name);
        name_to_func.insert(valueof_sym, fn_id);

        let entry_ty = Ty::Class(enum_name.clone());
        let mut fb = FnBuilder::new(fn_idx, valueof_fn_name, entry_ty.clone());

        // Parameter: name string.
        let name_param = fb.new_local(Ty::String);
        fb.mf.params.push(name_param);
        fb.mf.required_params = 1;
        fb.mf.param_names.push("name".to_string());

        // For each entry, create check + match blocks.
        let entry_count = e.entries.len();
        if entry_count == 0 {
            // No entries — just return null-ish (shouldn't happen in practice).
            let null_local = fb.new_local(entry_ty);
            fb.push_stmt(MStmt::Assign {
                dest: null_local,
                value: Rvalue::Const(MirConst::Null),
            });
            fb.set_terminator(Terminator::ReturnValue(null_local));
        } else {
            // Build chain: check0 → match0 | check1 → match1 | ... | fallback
            let fallback_block = fb.new_block();
            let mut next_check = fallback_block;

            // Build in reverse so each check can branch to the next.
            for i in (0..entry_count).rev() {
                let entry = &e.entries[i];
                let entry_name_str = interner.resolve(entry.name).to_string();
                let entry_fid = *name_to_func.get(&entry.name).unwrap();

                let check_block = if i == 0 { 0 } else { fb.new_block() };
                let match_block = fb.new_block();

                // In check_block: compare name_param with entry name string.
                let saved = fb.cur_block;
                fb.cur_block = check_block;

                let name_sid = module.intern_string(&entry_name_str);
                let name_const = fb.new_local(Ty::String);
                fb.push_stmt(MStmt::Assign {
                    dest: name_const,
                    value: Rvalue::Const(MirConst::String(name_sid)),
                });
                let cmp = fb.new_local(Ty::Bool);
                fb.push_stmt(MStmt::Assign {
                    dest: cmp,
                    value: Rvalue::BinOp {
                        op: MBinOp::CmpEq,
                        lhs: name_param,
                        rhs: name_const,
                    },
                });
                fb.mf.blocks[check_block as usize].terminator = Terminator::Branch {
                    cond: cmp,
                    then_block: match_block,
                    else_block: next_check,
                };

                // In match_block: call entry function, return result.
                fb.cur_block = match_block;
                let result = fb.new_local(Ty::Class(enum_name.clone()));
                fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Call {
                        kind: CallKind::Static(entry_fid),
                        args: vec![],
                    },
                });
                fb.mf.blocks[match_block as usize].terminator = Terminator::ReturnValue(result);

                fb.cur_block = saved;
                next_check = check_block;
            }

            // Fallback: return first entry.
            fb.cur_block = fallback_block;
            let first_entry_fid = *name_to_func.get(&e.entries[0].name).unwrap();
            let fallback_result = fb.new_local(Ty::Class(enum_name.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: fallback_result,
                value: Rvalue::Call {
                    kind: CallKind::Static(first_entry_fid),
                    args: vec![],
                },
            });
            fb.mf.blocks[fallback_block as usize].terminator =
                Terminator::ReturnValue(fallback_result);
        }

        module.add_function(fb.finish());
    }
}

/// Lower an `object` declaration to a MirClass with an INSTANCE
/// singleton field. Methods become virtual methods on the class with
/// `this` as their first parameter. Call sites for `Object.method()`
/// detect the singleton at lowering time and emit `getstatic INSTANCE;
/// invokevirtual method` (see the Call lowering code path that walks
/// `module.classes` for `is_object_singleton`).
fn lower_object(
    o: &skotch_syntax::ObjectDecl,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    module: &mut MirModule,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) {
    let obj_name = interner.resolve(o.name).to_string();

    // Build the private `<init>` constructor: just call super (Object) and return.
    let mut init_fn = MirFunction {
        id: FuncId(0),
        name: "<init>".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::Unit,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: true,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    let this_id = init_fn.new_local(Ty::Class(obj_name.clone()));
    init_fn.params.push(this_id);
    // Emit super.<init>() — `aload_0; invokespecial Object.<init>()V`.
    init_fn.blocks[0].stmts.push(MStmt::Assign {
        dest: this_id,
        value: Rvalue::Call {
            kind: CallKind::Constructor("java/lang/Object".to_string()),
            args: vec![this_id],
        },
    });

    // Lower each method as a VIRTUAL method on the singleton class.
    // The first parameter is the singleton instance (`this`).
    let mut mir_methods: Vec<MirFunction> = Vec::new();
    for method in &o.methods {
        let method_name = interner.resolve(method.name).to_string();
        let return_ty = method
            .return_ty
            .as_ref()
            .map(|tr| resolve_type(interner.resolve(tr.name), module))
            .unwrap_or(Ty::Unit);

        let fn_idx = module.functions.len() + mir_methods.len();
        let mut fb = FnBuilder::new(fn_idx, method_name, return_ty);
        let this_local = fb.new_local(Ty::Class(obj_name.clone()));
        fb.mf.params.push(this_local);
        let mut scope: Vec<(Symbol, LocalId)> = Vec::new();
        for p in &method.params {
            let ty = resolve_type(interner.resolve(p.ty.name), module);
            let id = fb.new_local(ty);
            fb.mf.params.push(id);
            scope.push((p.name, id));
        }
        for s in &method.body.stmts {
            lower_stmt(
                s,
                &mut fb,
                &mut scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                None,
            );
        }
        mir_methods.push(fb.finish());
    }

    module.classes.push(MirClass {
        name: obj_name,
        super_class: None,
        is_open: false,
        is_abstract: false,
        is_interface: false,
        interfaces: Vec::new(),
        fields: Vec::new(),
        methods: mir_methods,
        constructor: init_fn,
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: false,
        is_object_singleton: true,
        companion_class_name: None,
        static_fields: Vec::new(),
        clinit: None,
    });
}

fn lower_class(
    c: &skotch_syntax::ClassDecl,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &mut FxHashMap<Symbol, MirConst>,
    module: &mut MirModule,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) {
    let class_name = interner.resolve(c.name).to_string();

    // Collect fields from constructor params (val/var) and body properties.
    let mut fields = Vec::new();
    for p in &c.constructor_params {
        if p.is_val || p.is_var {
            let ty = resolve_type_ref(&p.ty, interner, module);
            // `@JvmField val x: Int` in the primary constructor: the
            // field is exposed as a bare public member with no
            // synthesized getter, matching kotlinc's Java-interop ABI.
            let is_jvm_field = p.annotations.iter().any(|a| {
                let n = interner.resolve(a.name);
                n == "JvmField" || n == "kotlin/jvm/JvmField"
            });
            fields.push(MirField {
                name: interner.resolve(p.name).to_string(),
                ty,
                is_jvm_field,
            });
        }
    }
    // Add delegate parameters as fields (for interface delegation: `Base by b`).
    // These are constructor params that are not val/var but are referenced as
    // delegates — the delegate value must be stored in a field so forwarding
    // methods can access it.
    let delegate_param_names: rustc_hash::FxHashSet<Symbol> = c
        .interface_delegates
        .iter()
        .map(|(_, param)| *param)
        .collect();
    for p in &c.constructor_params {
        if !p.is_val && !p.is_var && delegate_param_names.contains(&p.name) {
            let ty = resolve_type(interner.resolve(p.ty.name), module);
            fields.push(MirField {
                name: interner.resolve(p.name).to_string(),
                ty,
                is_jvm_field: false,
            });
        }
    }
    for prop in &c.properties {
        let ty = if let Some(tr) = &prop.ty {
            resolve_type(interner.resolve(tr.name), module)
        } else if let Some(init_expr) = &prop.init {
            // Infer type from init expression when no explicit annotation.
            infer_property_type(init_expr, interner, module)
        } else {
            Ty::Any
        };
        // `@JvmField` (with optional use-site target like `@field:JvmField`)
        // promotes the val/var from a private-field-with-getter pair to a
        // bare public field, matching kotlinc's Java-interop ABI.
        let is_jvm_field = prop.annotations.iter().any(|a| {
            let n = interner.resolve(a.name);
            n == "JvmField" || n == "kotlin/jvm/JvmField"
        });
        fields.push(MirField {
            name: interner.resolve(prop.name).to_string(),
            ty,
            is_jvm_field,
        });
    }

    // Build the <init> constructor.
    let mut init_fn = MirFunction {
        id: FuncId(0),
        name: "<init>".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: vec![BasicBlock {
            stmts: Vec::new(),
            terminator: Terminator::Return,
        }],
        return_ty: Ty::Unit,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    // Add 'this' as local 0.
    let this_id = init_fn.new_local(Ty::Class(class_name.clone()));
    init_fn.params.push(this_id);

    // Build a scope for lowering super args (this + constructor params).
    // ALL constructor params are added as init params so they're available
    // for super-constructor delegation, e.g. `class Dog(name: String) : Animal(name)`.
    let mut ctor_param_ids: Vec<(Symbol, LocalId)> = Vec::new();
    for p in &c.constructor_params {
        let ty = resolve_type_ref(&p.ty, interner, module);
        let param_id = init_fn.new_local(ty);
        init_fn.params.push(param_id);
        ctor_param_ids.push((p.name, param_id));
    }
    // Record the value-parameter names (declaration order, excluding the
    // implicit `this`) so call sites can reorder named constructor args to
    // the declared order — `Foo(b = …, a = …)` must emit `<init>(a, b)`.
    init_fn.param_names = c
        .constructor_params
        .iter()
        .map(|p| interner.resolve(p.name).to_string())
        .collect();

    // Emit super constructor call.
    {
        let super_class_name = c
            .parent_class
            .as_ref()
            .map(|sc| {
                let simple = interner.resolve(sc.name).to_string();
                module.import_map.get(&simple).cloned().unwrap_or(simple)
            })
            .unwrap_or_else(|| "java/lang/Object".to_string());
        // Lower super args if present.
        let mut super_arg_ids = vec![this_id]; // receiver is always first
        if let Some(sc) = &c.parent_class {
            if !sc.args.is_empty() {
                // Create a temporary FnBuilder to lower the super args.
                let tmp_idx = module.functions.len() + 9000;
                let mut fb = FnBuilder::new(tmp_idx, "<super-args>".to_string(), Ty::Unit);
                // Copy locals and params from init_fn so scope resolution works.
                fb.mf.locals = init_fn.locals.clone();
                fb.mf.params = init_fn.params.clone();
                let this_sym = interner.intern("this");
                let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_id)];
                for (sym, lid) in &ctor_param_ids {
                    scope.push((*sym, *lid));
                }
                for arg in &sc.args {
                    if let Some(id) = lower_expr(
                        &arg.expr,
                        &mut fb,
                        &mut scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        None,
                    ) {
                        super_arg_ids.push(id);
                    }
                }
                // Merge any new locals/stmts back into init_fn.
                init_fn.locals = fb.mf.locals;
                for stmt in fb.mf.blocks[0].stmts.drain(..) {
                    init_fn.blocks[0].stmts.push(stmt);
                }
            }
        }
        init_fn.blocks[0].stmts.push(MStmt::Assign {
            dest: this_id, // dummy
            value: Rvalue::Call {
                kind: CallKind::Constructor(super_class_name),
                args: super_arg_ids,
            },
        });
    }

    // Add field assignments only for ctor params that actually have a
    // backing field — i.e. `val`/`var` params and interface-delegate params
    // (`Base by b`). A plain non-val/var param (e.g. ConversationUiState's
    // `initialMessages: List<Message>` feeding `_messages = …`) is an
    // ordinary local with NO field, so a `putfield` for it stores into a
    // nonexistent field → `NoSuchFieldError` at construction time. This
    // predicate must mirror the `fields` collection built above.
    for (p, (sym, param_id)) in c.constructor_params.iter().zip(&ctor_param_ids) {
        let has_field = p.is_val || p.is_var || delegate_param_names.contains(&p.name);
        if !has_field {
            continue;
        }
        let field_name = interner.resolve(*sym).to_string();
        init_fn.blocks[0].stmts.push(MStmt::Assign {
            dest: this_id, // dummy dest
            value: Rvalue::PutField {
                receiver: this_id,
                class_name: class_name.clone(),
                field_name,
                value: *param_id,
            },
        });
    }

    // (val/var constructor params already added above)
    // Initialize body properties with their initializer expressions.
    //
    // Properties with `by lazy { ... }` delegates are collected separately
    // and lowered later (the lazy delegate evaluates eagerly during
    // construction in our simplified model).
    //
    // For each `val foo = <expr>` declaration we want to run `<expr>` in
    // the constructor body and store the result via `putfield`. Literal
    // initializers (Int/Long/Bool/String/etc.) take a fast path that
    // emits a `Const` rvalue directly. Anything else — function calls,
    // qualified accesses, complex expressions — needs a full FnBuilder
    // pass through `lower_expr` so the surrounding scope (this, ctor
    // params) is visible and downstream lowering (call dispatch,
    // value-class boxing, etc.) all kicks in.
    //
    // Without this, `class MainViewModel { val flow = MutableStateFlow(false) }`
    // would leave `flow` uninitialized and every read returns null at
    // runtime — see the jetchat-vs-kotlinc diff.
    let mut delegate_props: Vec<&skotch_syntax::PropertyDecl> = Vec::new();
    let non_literal_props: Vec<&skotch_syntax::PropertyDecl> = {
        let mut out = Vec::new();
        for prop in &c.properties {
            if prop.delegate.is_some() {
                delegate_props.push(prop);
                continue;
            }
            let Some(init) = &prop.init else {
                continue;
            };
            let (val, ty) = match init {
                Expr::IntLit(v, _) => (Some(MirConst::Int(*v as i32)), Ty::Int),
                Expr::LongLit(v, _) => (Some(MirConst::Long(*v)), Ty::Long),
                Expr::DoubleLit(v, _) => (Some(MirConst::Double(*v)), Ty::Double),
                Expr::FloatLit(v, _) => (Some(MirConst::Float(*v as f32)), Ty::Float),
                Expr::BoolLit(v, _) => (Some(MirConst::Bool(*v)), Ty::Bool),
                Expr::StringLit(s, _) => {
                    let sid = module.intern_string(s);
                    (Some(MirConst::String(sid)), Ty::String)
                }
                _ => (None, Ty::Int),
            };
            if let Some(c_val) = val {
                let val_id = init_fn.new_local(ty);
                init_fn.blocks[0].stmts.push(MStmt::Assign {
                    dest: val_id,
                    value: Rvalue::Const(c_val),
                });
                let field_name = interner.resolve(prop.name).to_string();
                init_fn.blocks[0].stmts.push(MStmt::Assign {
                    dest: this_id, // dummy
                    value: Rvalue::PutField {
                        receiver: this_id,
                        class_name: class_name.clone(),
                        field_name,
                        value: val_id,
                    },
                });
            } else {
                out.push(prop);
            }
        }
        out
    };
    // Reserve this class's slot in `module.classes` (with its fields) BEFORE
    // lowering non-literal property initializers, so that a sibling-property
    // reference inside an initializer — e.g. `val x = _x.asStateFlow()` — can
    // resolve `_x` to its declared field type rather than a null placeholder
    // (otherwise the receiver is typed `Any` and the call can't resolve). The
    // slot is replaced with the fully-lowered class further below.
    let class_idx = module.classes.len();
    module.classes.push(MirClass {
        name: class_name.clone(),
        super_class: None,
        is_open: c.is_open,
        is_abstract: c.is_abstract,
        is_interface: false,
        interfaces: Vec::new(),
        fields: fields.clone(),
        methods: Vec::new(),
        constructor: init_fn.clone(),
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: !c.type_params.is_empty(),
        is_object_singleton: false,
        companion_class_name: None,
        static_fields: Vec::new(),
        clinit: None,
    });

    if !non_literal_props.is_empty() {
        let tmp_idx = module.functions.len() + 2000;
        let mut fb = FnBuilder::new(tmp_idx, "<init>".to_string(), Ty::Unit);
        fb.mf.locals = init_fn.locals.clone();
        fb.mf.params = init_fn.params.clone();
        fb.mf.blocks[0].stmts = std::mem::take(&mut init_fn.blocks[0].stmts);
        let this_sym = interner.intern("this");
        let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_id)];
        // Constructor params (val/var or plain) are in scope inside the
        // initializer of any property declared after them.
        for (param_idx, p) in (1usize..).zip(c.constructor_params.iter()) {
            if param_idx < fb.mf.params.len() {
                scope.push((p.name, fb.mf.params[param_idx]));
            }
        }
        for prop in non_literal_props {
            let Some(init) = &prop.init else { continue };
            let Some(val_id) = lower_expr(
                init,
                &mut fb,
                &mut scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                None,
            ) else {
                continue;
            };
            let field_name = interner.resolve(prop.name).to_string();
            fb.push_stmt(MStmt::Assign {
                dest: this_id, // dummy
                value: Rvalue::PutField {
                    receiver: this_id,
                    class_name: class_name.clone(),
                    field_name,
                    value: val_id,
                },
            });
        }
        init_fn.locals = fb.mf.locals;
        init_fn.blocks[0].stmts = std::mem::take(&mut fb.mf.blocks[0].stmts);
    }

    // Lower init blocks — execute statements in the constructor.
    // We need a FnBuilder-like scope for the init block body. Since init_fn
    // is a raw MirFunction (not a FnBuilder), we create a temporary FnBuilder,
    // lower the init block stmts, then merge the resulting stmts back.
    if !c.init_blocks.is_empty() {
        let init_fn_idx = module.functions.len() + 1000; // temporary index
        let mut fb = FnBuilder::new(init_fn_idx, "<init>".to_string(), Ty::Unit);
        // Transfer existing locals and stmts from init_fn into the FnBuilder.
        fb.mf.locals = init_fn.locals.clone();
        fb.mf.params = init_fn.params.clone();
        fb.mf.blocks[0].stmts = init_fn.blocks[0].stmts.clone();

        let this_sym = interner.intern("this");
        let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_id)];
        // Add constructor param names to scope.
        let mut param_idx = 1usize; // skip 'this' at 0
        for p in &c.constructor_params {
            if p.is_val || p.is_var {
                if param_idx < fb.mf.params.len() {
                    let param_local = fb.mf.params[param_idx];
                    scope.push((p.name, param_local));
                }
                param_idx += 1;
            }
        }

        for init_block in &c.init_blocks {
            for s in &init_block.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
        }

        // Transfer the results back to init_fn.
        init_fn.locals = fb.mf.locals;
        init_fn.blocks = fb.mf.blocks;
        // Ensure the last block terminates with Return.
        if let Some(last) = init_fn.blocks.last_mut() {
            last.terminator = Terminator::Return;
        }
    }

    let super_class = c.parent_class.as_ref().map(|sc| {
        let simple = interner.resolve(sc.name).to_string();
        module.import_map.get(&simple).cloned().unwrap_or(simple)
    });

    // Pre-register the class with method stubs so that implicit
    // `this.method()` resolution works during method body lowering.
    let stub_methods: Vec<MirFunction> = c
        .methods
        .iter()
        .map(|m| {
            let mname = interner.resolve(m.name).to_string();
            let rty = m
                .return_ty
                .as_ref()
                .map(|tr| {
                    let resolved = resolve_type(interner.resolve(tr.name), module);
                    resolved
                })
                .unwrap_or(Ty::Unit);
            MirFunction {
                id: FuncId(0),
                name: mname,
                params: Vec::new(),
                locals: Vec::new(),
                blocks: Vec::new(),
                return_ty: rty,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: m.is_abstract,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            }
        })
        .collect();
    // Resolve interface simple names to FQ JVM names via the import
    // map so the parent class's `interfaces` table holds the real
    // `androidx/viewbinding/ViewBinding`-style entries — without this
    // the class file's interface_table holds bare `ViewBinding` and
    // ClassLoader fails resolution at load time.
    let iface_names: Vec<String> = c
        .interfaces
        .iter()
        .map(|s| {
            let simple = interner.resolve(*s).to_string();
            if simple.contains('/') {
                simple
            } else if let Some(fq) = module.import_map.get(&simple) {
                fq.clone()
            } else if let Some((fq, _, _)) = module.cross_file_classes.get(&simple) {
                fq.clone()
            } else {
                simple
            }
        })
        .collect();
    // Replace the fields-only reservation pushed before the property-init
    // loop with the stub that now also carries the constructor + stub methods.
    module.classes[class_idx] = MirClass {
        name: class_name.clone(),
        super_class: super_class.clone(),
        is_open: c.is_open,
        is_abstract: c.is_abstract,
        is_interface: false,
        interfaces: iface_names.clone(),
        fields: fields.clone(),
        methods: stub_methods,
        constructor: init_fn.clone(),
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: !c.type_params.is_empty(),
        is_object_singleton: false,
        companion_class_name: None,
        static_fields: Vec::new(),
        clinit: None,
    };

    // Lower methods.
    let mut mir_methods = Vec::new();
    // Lower `by lazy { ... }` as truly lazy initialization.
    // For each lazy property: generate a getter method that checks an
    // `initialized` flag, runs the body on first access, and caches.
    // The eager approach has been replaced with this lazy pattern.
    if !delegate_props.is_empty() {
        for prop in &delegate_props {
            let block = prop.delegate.as_ref().unwrap();
            let field_name = interner.resolve(prop.name).to_string();
            let prop_ty = prop
                .ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Error);

            // Add a $initialized boolean field.
            let init_field_name = format!("{}$initialized", field_name);
            fields.push(MirField {
                name: init_field_name.clone(),
                ty: Ty::Bool,
                is_jvm_field: false,
            });

            // Generate getter: if (!field$initialized) { field = <body>; field$initialized = true } return field
            let fn_idx = module.functions.len() + mir_methods.len();
            let getter_name = format!("get{}{}", &field_name[..1].to_uppercase(), &field_name[1..]);
            let mut fb = FnBuilder::new(fn_idx, getter_name, prop_ty.clone());
            let this_local = fb.new_local(Ty::Class(class_name.clone()));
            fb.mf.params.push(this_local);
            let this_sym = interner.intern("this");
            let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];

            // Load fields into scope for the lazy body.
            for field in &fields {
                if field.name == field_name || field.name == init_field_name {
                    continue; // don't pre-load the lazy field itself
                }
                let fsym = interner.intern(&field.name);
                let fl = fb.new_local(field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: fl,
                    value: Rvalue::GetField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                    },
                });
                scope.push((fsym, fl));
            }

            // Check initialized flag.
            let init_flag = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: init_flag,
                value: Rvalue::GetField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: init_field_name.clone(),
                },
            });
            let init_block = fb.new_block();
            let done_block = fb.new_block();
            fb.terminate_and_switch(
                Terminator::Branch {
                    cond: init_flag,
                    then_block: done_block, // already initialized → skip
                    else_block: init_block, // not initialized → run body
                },
                init_block,
            );

            // Init block: run the lazy body.
            let mut result_local: Option<LocalId> = None;
            for (i, s) in block.stmts.iter().enumerate() {
                let is_last = i + 1 == block.stmts.len();
                if is_last {
                    if let Stmt::Expr(e) | Stmt::Return { value: Some(e), .. } = s {
                        result_local = lower_expr(
                            e,
                            &mut fb,
                            &mut scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            None,
                        );
                    } else {
                        lower_stmt(
                            s,
                            &mut fb,
                            &mut scope,
                            module,
                            name_to_func,
                            name_to_global,
                            interner,
                            diags,
                            None,
                        );
                    }
                } else {
                    lower_stmt(
                        s,
                        &mut fb,
                        &mut scope,
                        module,
                        name_to_func,
                        name_to_global,
                        interner,
                        diags,
                        None,
                    );
                }
            }
            // Store result into backing field.
            //
            // For `by lazy { body }` the body's result IS the value.
            // For `by <expr>` (e.g. `by viewModels()`) the expression
            // produces a *delegate object* (`Lazy<T>`-shaped); the
            // property's value is `delegate.getValue(...)`. Without this
            // unwrap, skotch would putfield a `Lazy<T>` into a field
            // declared as `T` and the verifier rejects the class.
            let stored_val = if prop.delegate_is_lazy_block {
                result_local
            } else if let Some(val) = result_local {
                // Call `Lazy.getValue()` to extract T from the delegate.
                // The return type is `Object`; checkcast to the property
                // type before storing so the putfield's descriptor and
                // the value's static type match (verifier requires this
                // when the field is declared as a specific class).
                let raw = fb.new_local(Ty::Any);
                fb.push_stmt(MStmt::Assign {
                    dest: raw,
                    value: Rvalue::Call {
                        kind: CallKind::VirtualJava {
                            class_name: "kotlin/Lazy".to_string(),
                            method_name: "getValue".to_string(),
                            descriptor: "()Ljava/lang/Object;".to_string(),
                        },
                        args: vec![val],
                    },
                });
                let casted = if let Ty::Class(target) = &prop_ty {
                    let c = fb.new_local(prop_ty.clone());
                    fb.push_stmt(MStmt::Assign {
                        dest: c,
                        value: Rvalue::CheckCast {
                            obj: raw,
                            target_class: target.clone(),
                        },
                    });
                    c
                } else {
                    raw
                };
                Some(casted)
            } else {
                None
            };
            if let Some(val) = stored_val {
                let dummy = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: dummy,
                    value: Rvalue::PutField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field_name.clone(),
                        value: val,
                    },
                });
            }
            // Set initialized = true.
            let true_val = fb.new_local(Ty::Bool);
            fb.push_stmt(MStmt::Assign {
                dest: true_val,
                value: Rvalue::Const(MirConst::Bool(true)),
            });
            let dummy2 = fb.new_local(Ty::Unit);
            fb.push_stmt(MStmt::Assign {
                dest: dummy2,
                value: Rvalue::PutField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: init_field_name,
                    value: true_val,
                },
            });
            fb.terminate_and_switch(Terminator::Goto(done_block), done_block);

            // Done block: load and return the cached value.
            let cached = fb.new_local(prop_ty);
            fb.push_stmt(MStmt::Assign {
                dest: cached,
                value: Rvalue::GetField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: field_name.clone(),
                },
            });
            fb.set_terminator(Terminator::ReturnValue(cached));
            mir_methods.push(fb.finish());
        }
    }
    for method in &c.methods {
        let method_name = interner.resolve(method.name).to_string();
        let declared_ret = method
            .return_ty
            .as_ref()
            .map(|tr| {
                let resolved = resolve_type(interner.resolve(tr.name), module);
                resolved
            })
            .unwrap_or(Ty::Unit);

        // Suspend instance methods get the same CPS
        // transform as top-level suspend functions — return type
        // rewritten to Object, $completion param appended.
        let return_ty = if method.is_suspend {
            Ty::Any
        } else {
            declared_ret.clone()
        };

        let fn_idx = module.functions.len() + mir_methods.len();
        let mut fb = FnBuilder::new(fn_idx, method_name.clone(), return_ty);
        fb.mf.is_suspend = method.is_suspend;
        if method.is_suspend {
            fb.mf.suspend_original_return_ty = Some(declared_ret.clone());
        }

        // Add implicit `this` parameter.
        let this_local = fb.new_local(Ty::Class(class_name.clone()));
        fb.mf.params.push(this_local);
        let this_sym = interner.intern("this");
        let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];

        // Extension method inside a class/interface
        // (`fun Dp.roundToPx()` inside `interface Density`): the
        // receiver becomes the first user param after `this`, and its
        // properties become accessible as bare identifiers in the body.
        // The implicit name kotlinc gives this slot is `$this$<method>`.
        if let Some(ext_recv) = &method.receiver_ty {
            let ext_recv_ty = resolve_type_ref(ext_recv, interner, module);
            let ext_recv_local = fb.new_local(ext_recv_ty.clone());
            fb.mf.params.push(ext_recv_local);
            let ext_recv_sym = interner.intern(&format!("$this${}", method_name));
            scope.push((ext_recv_sym, ext_recv_local));
            // Also bind any field/property on the extension receiver class
            // so a bare `value` in the body resolves to `$receiver.value`.
            if let Ty::Class(ext_class_name) = &ext_recv_ty {
                if let Some(ext_cls) = module.classes.iter().find(|c| &c.name == ext_class_name) {
                    for field in &ext_cls.fields {
                        let field_sym = interner.intern(&field.name);
                        let field_local = fb.new_local(field.ty.clone());
                        fb.push_stmt(MStmt::Assign {
                            dest: field_local,
                            value: Rvalue::GetField {
                                receiver: ext_recv_local,
                                class_name: ext_class_name.clone(),
                                field_name: field.name.clone(),
                            },
                        });
                        scope.push((field_sym, field_local));
                    }
                }
            }
        }

        // Add explicit parameters. Use resolve_type_ref so function-typed
        // params (e.g. `block: () -> Unit`) resolve to Ty::Function rather
        // than Ty::Unit (which is the bare return type's name).
        for p in &method.params {
            let ty = resolve_type_ref(&p.ty, interner, module);
            let id = fb.new_local(ty);
            fb.mf.params.push(id);
            scope.push((p.name, id));
            // Record generic args so index access / method calls on this
            // param can recover element types that would otherwise erase
            // to Ty::Any. E.g. `measurables: List<Measurable>` →
            // local_generic_args[id] = [Class("Measurable")].
            if !p.ty.type_args.is_empty() {
                let arg_tys: Vec<Ty> =
                    p.ty.type_args
                        .iter()
                        .map(|tr| resolve_type_ref(tr, interner, module))
                        .collect();
                fb.mf.local_generic_args.insert(id.0, arg_tys);
            }
        }

        // Track param defaults so cross-class call sites can route
        // through `name$default(...)` when the caller omits defaulted
        // args (e.g. `MeasureScope.layout(w, h) { }` where the
        // alignmentLines param has a default — JetChat parity).
        // Indexed by user param position (excluding `this`).
        let mut method_defaults: Vec<Option<MirConst>> = Vec::with_capacity(method.params.len());
        for p in &method.params {
            method_defaults.push(p.default.as_ref().and_then(|e| lower_const_init(e, module)));
        }
        fb.mf.param_defaults = method_defaults;

        // Suspend methods get a trailing $completion param.
        if method.is_suspend {
            let cont_ty = Ty::Class("kotlin/coroutines/Continuation".to_string());
            let cont_id = fb.new_local(cont_ty);
            fb.mf.params.push(cont_id);
        }

        // Load fields into locals so they're accessible by name in the method body.
        // Track field→local mapping for writeback after the body.
        // Also load inherited fields from superclasses (read-only).
        let mut field_locals: Vec<(String, LocalId)> = Vec::new();
        for field in &fields {
            let field_sym = interner.intern(&field.name);
            let field_local = fb.new_local(field.ty.clone());
            fb.push_stmt(MStmt::Assign {
                dest: field_local,
                value: Rvalue::GetField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });
            scope.push((field_sym, field_local));
            field_locals.push((field.name.clone(), field_local));
        }
        // Inherited fields from superclasses.
        {
            let mut parent = super_class.clone();
            while let Some(ref pname) = parent {
                if let Some(pcls) = module.classes.iter().find(|c| &c.name == pname) {
                    for pf in &pcls.fields {
                        // Skip if already shadowed by this class's field.
                        if fields.iter().any(|f| f.name == pf.name) {
                            continue;
                        }
                        let fsym = interner.intern(&pf.name);
                        let fl = fb.new_local(pf.ty.clone());
                        fb.push_stmt(MStmt::Assign {
                            dest: fl,
                            value: Rvalue::GetField {
                                receiver: this_local,
                                class_name: pname.clone(),
                                field_name: pf.name.clone(),
                            },
                        });
                        scope.push((fsym, fl));
                        // Don't add to field_locals — inherited fields aren't written back.
                    }
                    parent = pcls.super_class.clone();
                } else {
                    break;
                }
            }
        }

        // Inner class: load outer class fields via this.this$0.<field>.
        if let Some(this0_field) = fields.iter().find(|f| f.name == "this$0") {
            if let Ty::Class(ref outer_cn) = this0_field.ty {
                let outer_ref = fb.new_local(this0_field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: outer_ref,
                    value: Rvalue::GetField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: "this$0".to_string(),
                    },
                });
                let outer_fields: Vec<_> = module
                    .classes
                    .iter()
                    .find(|c| &c.name == outer_cn)
                    .map(|c| {
                        c.fields
                            .iter()
                            .map(|f| (f.name.clone(), f.ty.clone()))
                            .collect()
                    })
                    .unwrap_or_default();
                for (fname, fty) in &outer_fields {
                    if fields.iter().any(|f| f.name == *fname) && *fname != "this$0" {
                        continue;
                    }
                    let fsym = interner.intern(fname);
                    let fl = fb.new_local(fty.clone());
                    fb.push_stmt(MStmt::Assign {
                        dest: fl,
                        value: Rvalue::GetField {
                            receiver: outer_ref,
                            class_name: outer_cn.clone(),
                            field_name: fname.clone(),
                        },
                    });
                    scope.push((fsym, fl));
                }
            }
        }

        for s in &method.body.stmts {
            lower_stmt(
                s,
                &mut fb,
                &mut scope,
                module,
                name_to_func,
                name_to_global,
                interner,
                diags,
                None,
            );
        }

        // Write back all field locals to the object. This ensures that
        // mutations like `count = count + 1` persist after the method returns.
        for (field_name, field_local) in &field_locals {
            fb.push_stmt(MStmt::Assign {
                dest: this_local, // dummy dest
                value: Rvalue::PutField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: field_name.clone(),
                    value: *field_local,
                },
            });
        }

        // Suspend methods — autobox primitive returns and
        // convert bare Return → return null (same as top-level suspend fns).
        if method.is_suspend {
            for block in &mut fb.mf.blocks {
                if let Terminator::ReturnValue(local) = &block.terminator {
                    let local_ty = fb.mf.locals[local.0 as usize].clone();
                    if matches!(
                        local_ty,
                        Ty::Int | Ty::Long | Ty::Float | Ty::Double | Ty::Bool
                    ) {
                        // Autobox: insert valueOf call before return.
                        let boxed = fb.mf.locals.len() as u32;
                        fb.mf.locals.push(Ty::Any);
                        let (box_class, box_desc) = match local_ty {
                            Ty::Int => ("java/lang/Integer", "(I)Ljava/lang/Integer;"),
                            Ty::Long => ("java/lang/Long", "(J)Ljava/lang/Long;"),
                            Ty::Float => ("java/lang/Float", "(F)Ljava/lang/Float;"),
                            Ty::Double => ("java/lang/Double", "(D)Ljava/lang/Double;"),
                            Ty::Bool => ("java/lang/Boolean", "(Z)Ljava/lang/Boolean;"),
                            _ => unreachable!(),
                        };
                        let old_local = *local;
                        block.stmts.push(MStmt::Assign {
                            dest: LocalId(boxed),
                            value: Rvalue::Call {
                                kind: CallKind::StaticJava {
                                    class_name: box_class.to_string(),
                                    method_name: "valueOf".to_string(),
                                    descriptor: box_desc.to_string(),
                                },
                                args: vec![old_local],
                            },
                        });
                        block.terminator = Terminator::ReturnValue(LocalId(boxed));
                    }
                }
                if matches!(block.terminator, Terminator::Return) {
                    // return → return null (suspend Unit fns return Object)
                    let null_local = fb.mf.locals.len() as u32;
                    fb.mf.locals.push(Ty::Any);
                    block.stmts.push(MStmt::Assign {
                        dest: LocalId(null_local),
                        value: Rvalue::Const(MirConst::Null),
                    });
                    block.terminator = Terminator::ReturnValue(LocalId(null_local));
                }
            }
        }

        // Extract state machine for suspend methods.
        if method.is_suspend {
            let sm_result =
                extract_suspend_state_machine(&fb.mf, module, &class_name, &method_name);
            match sm_result {
                SuspendSitesResult::Zero => {}
                SuspendSitesResult::Found(mut state_machine) => {
                    state_machine.is_instance_method = true;
                    fb.mf.suspend_state_machine = Some(state_machine);
                }
                SuspendSitesResult::Unsupported(reason) => {
                    diags.push(Diagnostic::error(
                        method.span,
                        format!(
                            "suspend method `{class_name}.{method_name}` has an unsupported shape: {reason}"
                        ),
                    ));
                }
            }
        }

        let mut finished = fb.finish();
        finished.is_abstract = method.is_abstract;
        finished.annotations =
            lower_annotations(&method.annotations, interner, Some(&module.import_map));
        // Infer return type from body if not explicitly annotated.
        if !method.is_suspend && finished.return_ty == Ty::Unit {
            if let Some(last_block) = finished.blocks.last() {
                if let Terminator::ReturnValue(ret_local) = &last_block.terminator {
                    let inferred = finished.locals[ret_local.0 as usize].clone();
                    if inferred != Ty::Unit {
                        finished.return_ty = inferred;
                    }
                }
            }
        }
        mir_methods.push(finished);
    }

    // Synthesize default getters/setters for fields without explicit
    // accessors. kotlinc emits `getX()` for every public property
    // (val/var) and `setX(T)` for every mutable one — external code
    // reads/writes through these accessors.
    {
        // Identify which props are `var` (mutable) vs explicit getter/setter.
        let prop_meta: FxHashMap<String, (bool, bool, bool)> = c
            .properties
            .iter()
            .map(|p| {
                let name = interner.resolve(p.name).to_string();
                (name, (p.is_var, p.getter.is_some(), p.setter.is_some()))
            })
            .collect();
        let ctor_var: FxHashMap<String, bool> = c
            .constructor_params
            .iter()
            .filter(|p| p.is_val || p.is_var)
            .map(|p| (interner.resolve(p.name).to_string(), p.is_var))
            .collect();
        let mut user_method_names: rustc_hash::FxHashSet<String> = c
            .methods
            .iter()
            .map(|m| interner.resolve(m.name).to_string())
            .collect();
        // Include any synthetic methods already generated upstream (e.g.
        // `by lazy` delegate getters) so we don't duplicate them.
        for m in &mir_methods {
            user_method_names.insert(m.name.clone());
        }

        for field in &fields {
            let getter_name = format!("get{}{}", &field.name[..1].to_uppercase(), &field.name[1..]);
            let setter_name = format!("set{}{}", &field.name[..1].to_uppercase(), &field.name[1..]);
            let (is_var, has_explicit_getter, has_explicit_setter) =
                if let Some(&meta) = prop_meta.get(&field.name) {
                    meta
                } else if let Some(&v) = ctor_var.get(&field.name) {
                    (v, false, false)
                } else {
                    // Synthetic field (capture, delegate, $initialized) —
                    // skip accessor synthesis.
                    continue;
                };

            // Synthesize getX() unless the user wrote one OR a method
            // with that name already exists OR the field is `@JvmField`
            // (which exposes the field directly with no getter pair).
            if !has_explicit_getter
                && !user_method_names.contains(&getter_name)
                && !field.is_jvm_field
            {
                let fn_idx = module.functions.len() + mir_methods.len();
                let mut fb = FnBuilder::new(fn_idx, getter_name, field.ty.clone());
                let this_local = fb.new_local(Ty::Class(class_name.clone()));
                fb.mf.params.push(this_local);
                let load_local = fb.new_local(field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: load_local,
                    value: Rvalue::GetField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                    },
                });
                fb.set_terminator(Terminator::ReturnValue(load_local));
                mir_methods.push(fb.finish());
            }

            // Synthesize setX(value) for mutable properties — also
            // skipped for `@JvmField` since the field is exposed directly.
            if is_var
                && !has_explicit_setter
                && !user_method_names.contains(&setter_name)
                && !field.is_jvm_field
            {
                let fn_idx = module.functions.len() + mir_methods.len();
                let mut fb = FnBuilder::new(fn_idx, setter_name, Ty::Unit);
                let this_local = fb.new_local(Ty::Class(class_name.clone()));
                fb.mf.params.push(this_local);
                let value_local = fb.new_local(field.ty.clone());
                fb.mf.params.push(value_local);
                let unit_dest = fb.new_local(Ty::Unit);
                fb.push_stmt(MStmt::Assign {
                    dest: unit_dest,
                    value: Rvalue::PutField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                        value: value_local,
                    },
                });
                fb.set_terminator(Terminator::Return);
                mir_methods.push(fb.finish());
            }
        }
    }

    // Lower property getters as synthetic methods.
    for prop in &c.properties {
        if let Some(getter_body) = &prop.getter {
            let prop_name = interner.resolve(prop.name).to_string();
            let getter_name = format!("get{}{}", &prop_name[..1].to_uppercase(), &prop_name[1..]);
            let return_ty = prop
                .ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Error);
            let fn_idx = module.functions.len() + mir_methods.len();
            let mut fb = FnBuilder::new(fn_idx, getter_name, return_ty);
            let this_local = fb.new_local(Ty::Class(class_name.clone()));
            fb.mf.params.push(this_local);
            let this_sym = interner.intern("this");
            let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];
            // Load fields into scope.
            for field in &fields {
                let field_sym = interner.intern(&field.name);
                let field_local = fb.new_local(field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: field_local,
                    value: Rvalue::GetField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                    },
                });
                scope.push((field_sym, field_local));
            }
            for s in &getter_body.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            mir_methods.push(fb.finish());
        }
    }

    // Lower property setters as synthetic methods.
    // `var x: Int = 0; set(value) { field = value + 1 }`
    // → synthetic method `setX(value: Int): Unit`
    for prop in &c.properties {
        if let Some((setter_param, ref setter_body)) = prop.setter {
            let prop_name = interner.resolve(prop.name).to_string();
            let setter_name = format!("set{}{}", &prop_name[..1].to_uppercase(), &prop_name[1..]);
            let param_ty = prop
                .ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Error);
            let fn_idx = module.functions.len() + mir_methods.len();
            let mut fb = FnBuilder::new(fn_idx, setter_name, Ty::Unit);
            let this_local = fb.new_local(Ty::Class(class_name.clone()));
            fb.mf.params.push(this_local);
            let value_local = fb.new_local(param_ty);
            fb.mf.params.push(value_local);
            let this_sym = interner.intern("this");
            let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];
            // Load fields into scope so the setter body can reference them.
            for field in &fields {
                let field_sym = interner.intern(&field.name);
                let field_local = fb.new_local(field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: field_local,
                    value: Rvalue::GetField {
                        receiver: this_local,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                    },
                });
                scope.push((field_sym, field_local));
            }
            // Add setter parameter to scope.
            scope.push((setter_param, value_local));
            // `field` inside a setter refers to the backing field.
            // We use a copy-in/copy-out pattern: read the field into a
            // local, expose it as `field` in scope, lower the body (which
            // may assign to `field`), then write the local back.
            let field_sym = interner.intern("field");
            let backing_ty = prop
                .ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Error);
            let backing_local = fb.new_local(backing_ty);
            fb.push_stmt(MStmt::Assign {
                dest: backing_local,
                value: Rvalue::GetField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: prop_name.clone(),
                },
            });
            scope.push((field_sym, backing_local));
            for s in &setter_body.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            // Write the `field` local back to the backing field.
            let dummy = fb.new_local(Ty::Unit);
            fb.push_stmt(MStmt::Assign {
                dest: dummy,
                value: Rvalue::PutField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: prop_name.clone(),
                    value: backing_local,
                },
            });
            fb.set_terminator(Terminator::Return);
            mir_methods.push(fb.finish());
        }
    }

    // Lower companion object methods to a separate `<class>$Companion`
    // MirClass with virtual methods. The outer class gets a static
    // `Companion` field initialized in its `<clinit>`. Call sites for
    // `<ClassName>.<companionMethod>(...)` resolve to `getstatic
    // <ClassName>.Companion; invokevirtual <ClassName>$Companion.<m>`.
    let companion_class_name_opt: Option<String> =
        if !c.companion_methods.is_empty() || !c.companion_properties.is_empty() {
            Some(format!("{}$Companion", class_name))
        } else {
            None
        };
    // Wire the parent MirClass to its companion so the call-site
    // dispatcher (`OuterClass.methodOnCompanion(...)`) can find the
    // companion's MirClass via `companion_class_name`.
    if let Some(ref companion_cls) = companion_class_name_opt {
        if let Some(parent) = module.classes.get_mut(class_idx) {
            parent.companion_class_name = Some(companion_cls.clone());
        }
    }
    if let Some(ref companion_cls) = companion_class_name_opt {
        // Build private `<init>()V` constructor for the companion.
        let mut comp_init = MirFunction {
            id: FuncId(0),
            name: "<init>".to_string(),
            params: Vec::new(),
            locals: Vec::new(),
            blocks: vec![BasicBlock {
                stmts: Vec::new(),
                terminator: Terminator::Return,
            }],
            return_ty: Ty::Unit,
            required_params: 0,
            param_names: Vec::new(),
            param_defaults: Vec::new(),
            param_receiver_types: Vec::new(),
            is_abstract: false,
            exception_handlers: Vec::new(),
            vararg_index: None,
            is_suspend: false,
            is_inline: false,
            has_type_params: false,
            suspend_original_return_ty: None,
            suspend_state_machine: None,
            annotations: Vec::new(),
            named_locals: Vec::new(),
            is_private: true,
            is_static: false,
            default_call_masks: Vec::new(),
            needs_leading_nop: false,
            local_generic_args: rustc_hash::FxHashMap::default(),
        };
        let comp_this = comp_init.new_local(Ty::Class(companion_cls.clone()));
        comp_init.params.push(comp_this);
        comp_init.blocks[0].stmts.push(MStmt::Assign {
            dest: comp_this,
            value: Rvalue::Call {
                kind: CallKind::Constructor("java/lang/Object".to_string()),
                args: vec![comp_this],
            },
        });

        // Side-channel for the bare-call resolver: while the Companion's
        // method bodies are being lowered, the Companion class isn't yet
        // in `module.classes`, so the resolver at `mir-lower:15613`
        // can't find sibling overloads by name. Set
        // `pending_companion_methods` to (class_name, method_names) for
        // the duration of the loop; the resolver falls back to this when
        // `module.classes` doesn't have the class. Cleared right after.
        let companion_method_names: Vec<String> = c
            .companion_methods
            .iter()
            .map(|m| interner.resolve(m.name).to_string())
            .collect();
        module.pending_companion_methods = Some((companion_cls.clone(), companion_method_names));

        let mut comp_methods: Vec<MirFunction> = Vec::new();
        for method in &c.companion_methods {
            let m_name = interner.resolve(method.name).to_string();
            let m_ret = method
                .return_ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Unit);
            let fn_idx = module.functions.len() + comp_methods.len();
            let mut fb = FnBuilder::new(fn_idx, m_name, m_ret);
            let this_local = fb.new_local(Ty::Class(companion_cls.clone()));
            fb.mf.params.push(this_local);
            // Bind `this` in the body scope so bare-name sibling-method
            // calls (`inflate(a) = inflate(a, 0)` in the same companion)
            // can resolve via the call-site's `this_id` lookup at
            // `mir-lower:15577` and reach the Companion class's methods.
            let this_sym = interner.intern("this");
            let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];
            for p in &method.params {
                let ty = resolve_type(interner.resolve(p.ty.name), module);
                let id = fb.new_local(ty);
                fb.mf.params.push(id);
                scope.push((p.name, id));
            }
            for s in &method.body.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            let mut finished = fb.finish();
            finished.annotations =
                lower_annotations(&method.annotations, interner, Some(&module.import_map));
            comp_methods.push(finished);
        }

        // Generate JVM getter methods for each companion property —
        // `val VERSION: Int = 42` → `getVERSION()I` returning 42.
        // The getter is what kotlinc emits at every `ClassName.PROP`
        // call site (via invokevirtual on Companion).
        for prop in &c.companion_properties {
            let prop_name = interner.resolve(prop.name).to_string();
            let prop_ty = prop
                .ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Error);
            // Build initial-value constant from the init expression.
            // For non-trivial init we fall through to a Null/default.
            let init_const: Option<MirConst> = prop.init.as_ref().and_then(|e| match e {
                Expr::IntLit(v, _) => Some(MirConst::Int(*v as i32)),
                Expr::LongLit(v, _) => Some(MirConst::Long(*v)),
                Expr::FloatLit(v, _) => Some(MirConst::Float(*v as f32)),
                Expr::DoubleLit(v, _) => Some(MirConst::Double(*v)),
                Expr::BoolLit(v, _) => Some(MirConst::Bool(*v)),
                Expr::StringLit(s, _) => {
                    let sid = module.intern_string(s);
                    Some(MirConst::String(sid))
                }
                _ => None,
            });
            let getter_name = format!(
                "get{}{}",
                prop_name
                    .chars()
                    .next()
                    .map(|c| c.to_uppercase().to_string())
                    .unwrap_or_default(),
                &prop_name[prop_name.chars().next().map(char::len_utf8).unwrap_or(0)..]
            );
            let fn_idx = module.functions.len() + comp_methods.len();
            let mut fb = FnBuilder::new(fn_idx, getter_name, prop_ty.clone());
            let this_local = fb.new_local(Ty::Class(companion_cls.clone()));
            fb.mf.params.push(this_local);
            let dest = fb.new_local(prop_ty);
            if let Some(cv) = init_const {
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(cv),
                });
            } else {
                fb.push_stmt(MStmt::Assign {
                    dest,
                    value: Rvalue::Const(MirConst::Null),
                });
            }
            fb.set_terminator(Terminator::ReturnValue(dest));
            comp_methods.push(fb.finish());
        }

        // Clear the side-channel — the Companion is about to land in
        // `module.classes`, so future call sites use the real class.
        module.pending_companion_methods = None;
        module.classes.push(MirClass {
            name: companion_cls.clone(),
            super_class: None,
            is_open: false,
            is_abstract: false,
            is_interface: false,
            interfaces: Vec::new(),
            fields: Vec::new(),
            methods: comp_methods,
            constructor: comp_init,
            secondary_constructors: Vec::new(),
            is_lambda: false,
            is_suspend_lambda: false,
            is_cross_file_stub: false,
            annotations: Vec::new(),
            has_type_params: false,
            is_object_singleton: true,
            companion_class_name: None,
            static_fields: Vec::new(),
            clinit: None,
        });

        // Synthesize a `@JvmStatic` static delegate on the OUTER class for
        // each companion method tagged `@JvmStatic`. kotlinc's emission
        // pattern: the companion gets the real instance method and the
        // outer class additionally gets `public static <ret> <name>(args)`
        // that does `getstatic Outer.Companion : LOuter$Companion;` and
        // then `invokevirtual Outer$Companion.<name>(args) : <ret>`.
        // Without the static delegate, call sites that bypass the
        // companion (`Outer.method(args)` resolved as a plain static call)
        // hit NoSuchMethodError at runtime.
        for method in &c.companion_methods {
            let is_jvm_static = method
                .annotations
                .iter()
                .any(|a| interner.resolve(a.name) == "JvmStatic");
            if !is_jvm_static {
                continue;
            }
            let m_name = interner.resolve(method.name).to_string();
            let m_ret = method
                .return_ty
                .as_ref()
                .map(|tr| resolve_type(interner.resolve(tr.name), module))
                .unwrap_or(Ty::Unit);
            let fn_idx = module.functions.len() + mir_methods.len();
            let mut fb = FnBuilder::new(fn_idx, m_name.clone(), m_ret.clone());

            // Static delegate — no implicit `this`. Each user param becomes
            // a fresh local + an entry in params.
            let mut user_arg_locals: Vec<LocalId> = Vec::new();
            for p in &method.params {
                let pty = resolve_type(interner.resolve(p.ty.name), module);
                let id = fb.new_local(pty);
                fb.mf.params.push(id);
                user_arg_locals.push(id);
            }

            // Get the Companion singleton.
            let companion_local = fb.new_local(Ty::Class(companion_cls.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: companion_local,
                value: Rvalue::GetStaticField {
                    class_name: class_name.clone(),
                    field_name: "Companion".to_string(),
                    descriptor: format!("L{};", companion_cls),
                },
            });

            // invokevirtual <Companion>.method(args).
            let mut all_args = vec![companion_local];
            all_args.extend(user_arg_locals.iter().copied());
            let result_local = fb.new_local(m_ret.clone());
            fb.push_stmt(MStmt::Assign {
                dest: result_local,
                value: Rvalue::Call {
                    kind: CallKind::Virtual {
                        class_name: companion_cls.clone(),
                        method_name: m_name.clone(),
                    },
                    args: all_args,
                },
            });

            fb.set_terminator(if matches!(m_ret, Ty::Unit) {
                Terminator::Return
            } else {
                Terminator::ReturnValue(result_local)
            });

            let mut finished = fb.finish();
            finished.is_static = true;
            finished.annotations =
                lower_annotations(&method.annotations, interner, Some(&module.import_map));
            mir_methods.push(finished);
        }
    }

    // Lower companion object properties as static fields.
    // Each companion property becomes a field on the class and is
    // registered as a top-level global constant for ClassName.propName access.
    for prop in &c.companion_properties {
        let prop_name = interner.resolve(prop.name).to_string();
        let prop_ty = prop
            .ty
            .as_ref()
            .map(|tr| resolve_type(interner.resolve(tr.name), module))
            .unwrap_or(Ty::Error);
        // Add as a field on the class.
        fields.push(MirField {
            name: prop_name.clone(),
            ty: prop_ty.clone(),
            is_jvm_field: false,
        });
        // If there's an initializer, register as a global constant.
        if let Some(init) = &prop.init {
            let const_val = match init {
                Expr::IntLit(v, _) => Some(MirConst::Int(*v as i32)),
                Expr::LongLit(v, _) => Some(MirConst::Long(*v)),
                Expr::FloatLit(v, _) => Some(MirConst::Float(*v as f32)),
                Expr::DoubleLit(v, _) => Some(MirConst::Double(*v)),
                Expr::BoolLit(v, _) => Some(MirConst::Bool(*v)),
                Expr::StringLit(s, _) => {
                    let sid = module.intern_string(s);
                    Some(MirConst::String(sid))
                }
                _ => None,
            };
            if let Some(cv) = const_val {
                name_to_global.insert(prop.name, cv);
            }
        }
    }

    // Synthesize toString() for data classes.
    if c.is_data && !fields.is_empty() {
        let ts_idx = module.functions.len() + mir_methods.len();
        let mut ts_fb = FnBuilder::new(ts_idx, "toString".to_string(), Ty::String);
        let ts_this = ts_fb.new_local(Ty::Class(class_name.clone()));
        ts_fb.mf.params.push(ts_this);

        // Build the string: "ClassName(f1=v1, f2=v2)"
        // Start with "ClassName(" as a string constant.
        let prefix = format!("{}(", class_name);
        let prefix_sid = module.intern_string(&prefix);
        let result = ts_fb.new_local(Ty::String);
        ts_fb.push_stmt(MStmt::Assign {
            dest: result,
            value: Rvalue::Const(MirConst::String(prefix_sid)),
        });

        for (fi, field) in fields.iter().enumerate() {
            // For each field after the first, prepend ", "
            if fi > 0 {
                let comma_sid = module.intern_string(", ");
                let comma = ts_fb.new_local(Ty::String);
                ts_fb.push_stmt(MStmt::Assign {
                    dest: comma,
                    value: Rvalue::Const(MirConst::String(comma_sid)),
                });
                let cat = ts_fb.new_local(Ty::String);
                ts_fb.push_stmt(MStmt::Assign {
                    dest: cat,
                    value: Rvalue::BinOp {
                        op: MBinOp::ConcatStr,
                        lhs: result,
                        rhs: comma,
                    },
                });
                ts_fb.push_stmt(MStmt::Assign {
                    dest: result,
                    value: Rvalue::Local(cat),
                });
            }

            // Append "fieldName="
            let label_sid = module.intern_string(&format!("{}=", field.name));
            let label = ts_fb.new_local(Ty::String);
            ts_fb.push_stmt(MStmt::Assign {
                dest: label,
                value: Rvalue::Const(MirConst::String(label_sid)),
            });
            let cat1 = ts_fb.new_local(Ty::String);
            ts_fb.push_stmt(MStmt::Assign {
                dest: cat1,
                value: Rvalue::BinOp {
                    op: MBinOp::ConcatStr,
                    lhs: result,
                    rhs: label,
                },
            });

            // Load the field value and concat it.
            let field_val = ts_fb.new_local(field.ty.clone());
            ts_fb.push_stmt(MStmt::Assign {
                dest: field_val,
                value: Rvalue::GetField {
                    receiver: ts_this,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });
            let cat2 = ts_fb.new_local(Ty::String);
            ts_fb.push_stmt(MStmt::Assign {
                dest: cat2,
                value: Rvalue::BinOp {
                    op: MBinOp::ConcatStr,
                    lhs: cat1,
                    rhs: field_val,
                },
            });
            ts_fb.push_stmt(MStmt::Assign {
                dest: result,
                value: Rvalue::Local(cat2),
            });
        }

        // Append closing ")"
        let close_sid = module.intern_string(")");
        let close = ts_fb.new_local(Ty::String);
        ts_fb.push_stmt(MStmt::Assign {
            dest: close,
            value: Rvalue::Const(MirConst::String(close_sid)),
        });
        let final_str = ts_fb.new_local(Ty::String);
        ts_fb.push_stmt(MStmt::Assign {
            dest: final_str,
            value: Rvalue::BinOp {
                op: MBinOp::ConcatStr,
                lhs: result,
                rhs: close,
            },
        });
        ts_fb.set_terminator(Terminator::ReturnValue(final_str));
        mir_methods.push(ts_fb.finish());
    }

    // Synthesize componentN() methods for data classes.
    if c.is_data && !fields.is_empty() {
        for (i, field) in fields.iter().enumerate() {
            let method_name = format!("component{}", i + 1);
            let comp_idx = module.functions.len() + mir_methods.len();
            let mut comp_fb = FnBuilder::new(comp_idx, method_name, field.ty.clone());
            let comp_this = comp_fb.new_local(Ty::Class(class_name.clone()));
            comp_fb.mf.params.push(comp_this);

            // Load the field and return it.
            let field_val = comp_fb.new_local(field.ty.clone());
            comp_fb.push_stmt(MStmt::Assign {
                dest: field_val,
                value: Rvalue::GetField {
                    receiver: comp_this,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });
            comp_fb.set_terminator(Terminator::ReturnValue(field_val));
            mir_methods.push(comp_fb.finish());
        }
    }

    // Synthesize equals(other: Any?): Boolean for data classes.
    if c.is_data && !fields.is_empty() {
        let eq_idx = module.functions.len() + mir_methods.len();
        let mut eq_fb = FnBuilder::new(eq_idx, "equals".to_string(), Ty::Bool);
        let eq_this = eq_fb.new_local(Ty::Class(class_name.clone()));
        eq_fb.mf.params.push(eq_this);
        let eq_other = eq_fb.new_local(Ty::Any);
        eq_fb.mf.params.push(eq_other);

        // Block 0: reference equality check  (this === other)
        // Copy `this` into an Any-typed local so the JVM backend emits
        // if_acmpeq (reference identity) instead of invokevirtual equals,
        // which would cause infinite recursion.
        let this_as_any = eq_fb.new_local(Ty::Any);
        eq_fb.push_stmt(MStmt::Assign {
            dest: this_as_any,
            value: Rvalue::Local(eq_this),
        });
        let ref_eq = eq_fb.new_local(Ty::Bool);
        eq_fb.push_stmt(MStmt::Assign {
            dest: ref_eq,
            value: Rvalue::BinOp {
                op: MBinOp::CmpEq,
                lhs: this_as_any,
                rhs: eq_other,
            },
        });
        let true_block = eq_fb.new_block(); // block 1: return true
        let instanceof_block = eq_fb.new_block(); // block 2: instanceof check
        eq_fb.set_terminator(Terminator::Branch {
            cond: ref_eq,
            then_block: true_block,
            else_block: instanceof_block,
        });

        // Block 1 (true_block): return true
        eq_fb.cur_block = true_block;
        let const_true = eq_fb.new_local(Ty::Bool);
        eq_fb.push_stmt(MStmt::Assign {
            dest: const_true,
            value: Rvalue::Const(MirConst::Bool(true)),
        });
        eq_fb.set_terminator(Terminator::ReturnValue(const_true));

        // Block 2 (instanceof_block): type check
        eq_fb.cur_block = instanceof_block;
        let is_same_type = eq_fb.new_local(Ty::Bool);
        eq_fb.push_stmt(MStmt::Assign {
            dest: is_same_type,
            value: Rvalue::InstanceOf {
                obj: eq_other,
                type_descriptor: class_name.clone(),
            },
        });
        let false_block = eq_fb.new_block(); // block 3: return false
        let compare_block = eq_fb.new_block(); // block 4: field comparison
        eq_fb.set_terminator(Terminator::Branch {
            cond: is_same_type,
            then_block: compare_block,
            else_block: false_block,
        });

        // Block 3 (false_block): return false
        eq_fb.cur_block = false_block;
        let const_false = eq_fb.new_local(Ty::Bool);
        eq_fb.push_stmt(MStmt::Assign {
            dest: const_false,
            value: Rvalue::Const(MirConst::Bool(false)),
        });
        eq_fb.set_terminator(Terminator::ReturnValue(const_false));

        // Block 4 (compare_block): cast other and compare fields
        eq_fb.cur_block = compare_block;
        let casted_other = eq_fb.new_local(Ty::Class(class_name.clone()));
        eq_fb.push_stmt(MStmt::Assign {
            dest: casted_other,
            value: Rvalue::CheckCast {
                obj: eq_other,
                target_class: class_name.clone(),
            },
        });

        // Compare each field. For primitives (Int, Long, Double, Bool),
        // use CmpEq directly. For reference types (String, Class), use
        // VirtualJava Object.equals().
        let mut result_local: Option<LocalId> = None;
        for field in &fields {
            let this_field = eq_fb.new_local(field.ty.clone());
            eq_fb.push_stmt(MStmt::Assign {
                dest: this_field,
                value: Rvalue::GetField {
                    receiver: eq_this,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });
            let other_field = eq_fb.new_local(field.ty.clone());
            eq_fb.push_stmt(MStmt::Assign {
                dest: other_field,
                value: Rvalue::GetField {
                    receiver: casted_other,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });
            let fields_eq = match &field.ty {
                Ty::Int | Ty::Long | Ty::Double | Ty::Bool => {
                    let cmp = eq_fb.new_local(Ty::Bool);
                    eq_fb.push_stmt(MStmt::Assign {
                        dest: cmp,
                        value: Rvalue::BinOp {
                            op: MBinOp::CmpEq,
                            lhs: this_field,
                            rhs: other_field,
                        },
                    });
                    cmp
                }
                Ty::String => {
                    // Use String.equals(Object)
                    let cmp = eq_fb.new_local(Ty::Bool);
                    eq_fb.push_stmt(MStmt::Assign {
                        dest: cmp,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/String".to_string(),
                                method_name: "equals".to_string(),
                                descriptor: "(Ljava/lang/Object;)Z".to_string(),
                            },
                            args: vec![this_field, other_field],
                        },
                    });
                    cmp
                }
                _ => {
                    // For Class and other reference types, use Object.equals()
                    let cmp = eq_fb.new_local(Ty::Bool);
                    eq_fb.push_stmt(MStmt::Assign {
                        dest: cmp,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/Object".to_string(),
                                method_name: "equals".to_string(),
                                descriptor: "(Ljava/lang/Object;)Z".to_string(),
                            },
                            args: vec![this_field, other_field],
                        },
                    });
                    cmp
                }
            };

            result_local = Some(match result_local {
                None => fields_eq,
                Some(prev) => {
                    // AND: both must be true. We use MulI since bool is int on JVM.
                    // true(1) * true(1) = 1, true(1) * false(0) = 0
                    let and_result = eq_fb.new_local(Ty::Bool);
                    eq_fb.push_stmt(MStmt::Assign {
                        dest: and_result,
                        value: Rvalue::BinOp {
                            op: MBinOp::MulI,
                            lhs: prev,
                            rhs: fields_eq,
                        },
                    });
                    and_result
                }
            });
        }
        eq_fb.set_terminator(Terminator::ReturnValue(result_local.unwrap()));
        mir_methods.push(eq_fb.finish());
    }

    // Synthesize hashCode(): Int for data classes.
    if c.is_data && !fields.is_empty() {
        let hc_idx = module.functions.len() + mir_methods.len();
        let mut hc_fb = FnBuilder::new(hc_idx, "hashCode".to_string(), Ty::Int);
        let hc_this = hc_fb.new_local(Ty::Class(class_name.clone()));
        hc_fb.mf.params.push(hc_this);

        // result = field0.hashCode()
        // result = 31 * result + field1.hashCode()
        // ...
        let mut result: Option<LocalId> = None;
        for field in &fields {
            let field_val = hc_fb.new_local(field.ty.clone());
            hc_fb.push_stmt(MStmt::Assign {
                dest: field_val,
                value: Rvalue::GetField {
                    receiver: hc_this,
                    class_name: class_name.clone(),
                    field_name: field.name.clone(),
                },
            });

            // Compute hash for this field.
            let field_hash = match &field.ty {
                Ty::Int | Ty::Bool => {
                    // For Int, hashCode is the value itself.
                    // For Bool, true=1, false=0 — same representation.
                    field_val
                }
                Ty::Long => {
                    // Long.hashCode() in Kotlin = (value xor (value >>> 32)).toInt()
                    // Use static call: java.lang.Long.hashCode(long)
                    let h = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: h,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "java/lang/Long".to_string(),
                                method_name: "hashCode".to_string(),
                                descriptor: "(J)I".to_string(),
                            },
                            args: vec![field_val],
                        },
                    });
                    h
                }
                Ty::Double => {
                    // Double.hashCode() = java.lang.Double.hashCode(double)
                    let h = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: h,
                        value: Rvalue::Call {
                            kind: CallKind::StaticJava {
                                class_name: "java/lang/Double".to_string(),
                                method_name: "hashCode".to_string(),
                                descriptor: "(D)I".to_string(),
                            },
                            args: vec![field_val],
                        },
                    });
                    h
                }
                Ty::String => {
                    // String.hashCode()
                    let h = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: h,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/String".to_string(),
                                method_name: "hashCode".to_string(),
                                descriptor: "()I".to_string(),
                            },
                            args: vec![field_val],
                        },
                    });
                    h
                }
                _ => {
                    // For any reference type, call Object.hashCode()
                    let h = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: h,
                        value: Rvalue::Call {
                            kind: CallKind::VirtualJava {
                                class_name: "java/lang/Object".to_string(),
                                method_name: "hashCode".to_string(),
                                descriptor: "()I".to_string(),
                            },
                            args: vec![field_val],
                        },
                    });
                    h
                }
            };

            result = Some(match result {
                None => field_hash,
                Some(prev) => {
                    // result = 31 * prev + field_hash
                    let thirty_one = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: thirty_one,
                        value: Rvalue::Const(MirConst::Int(31)),
                    });
                    let mul = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: mul,
                        value: Rvalue::BinOp {
                            op: MBinOp::MulI,
                            lhs: thirty_one,
                            rhs: prev,
                        },
                    });
                    let sum = hc_fb.new_local(Ty::Int);
                    hc_fb.push_stmt(MStmt::Assign {
                        dest: sum,
                        value: Rvalue::BinOp {
                            op: MBinOp::AddI,
                            lhs: mul,
                            rhs: field_hash,
                        },
                    });
                    sum
                }
            });
        }
        hc_fb.set_terminator(Terminator::ReturnValue(result.unwrap()));
        mir_methods.push(hc_fb.finish());
    }

    // Synthesize copy(field1, field2, ...): ClassName for data classes.
    // Takes all fields as parameters — at the call site, unspecified
    // params are filled from the receiver's current field values.
    if c.is_data && !fields.is_empty() {
        let cp_idx = module.functions.len() + mir_methods.len();
        let mut cp_fb = FnBuilder::new(cp_idx, "copy".to_string(), Ty::Class(class_name.clone()));
        let cp_this = cp_fb.new_local(Ty::Class(class_name.clone()));
        cp_fb.mf.params.push(cp_this);

        // Add a parameter for each field — these are the values to use
        // in the new instance. The call site fills in defaults from
        // the receiver for any omitted named arguments.
        let mut param_locals = Vec::new();
        for field in &fields {
            let p = cp_fb.new_local(field.ty.clone());
            cp_fb.mf.params.push(p);
            param_locals.push(p);
        }

        // new ClassName
        let new_inst = cp_fb.new_local(Ty::Class(class_name.clone()));
        cp_fb.push_stmt(MStmt::Assign {
            dest: new_inst,
            value: Rvalue::NewInstance(class_name.clone()),
        });

        // Call constructor with the parameter values.
        cp_fb.push_stmt(MStmt::Assign {
            dest: new_inst,
            value: Rvalue::Call {
                kind: CallKind::Constructor(class_name.clone()),
                args: param_locals,
            },
        });

        cp_fb.set_terminator(Terminator::ReturnValue(new_inst));
        mir_methods.push(cp_fb.finish());
    }

    // Lower secondary constructors.
    let mut mir_secondary_ctors = Vec::new();
    for sec_ctor in &c.secondary_constructors {
        let mut sec_fn = MirFunction {
            id: FuncId(0),
            name: "<init>".to_string(),
            params: Vec::new(),
            locals: Vec::new(),
            blocks: vec![BasicBlock {
                stmts: Vec::new(),
                terminator: Terminator::Return,
            }],
            return_ty: Ty::Unit,
            required_params: 0,
            param_names: Vec::new(),
            param_defaults: Vec::new(),
            param_receiver_types: Vec::new(),
            is_abstract: false,
            exception_handlers: Vec::new(),
            vararg_index: None,
            is_suspend: false,
            is_inline: false,
            has_type_params: false,
            suspend_original_return_ty: None,
            suspend_state_machine: None,
            annotations: Vec::new(),
            named_locals: Vec::new(),
            is_private: false,
            is_static: false,
            default_call_masks: Vec::new(),
            needs_leading_nop: false,
            local_generic_args: rustc_hash::FxHashMap::default(),
        };
        // Add 'this' as local 0.
        let sec_this = sec_fn.new_local(Ty::Class(class_name.clone()));
        sec_fn.params.push(sec_this);

        // Add secondary constructor parameters.
        let this_sym = interner.intern("this");
        let mut sec_scope: Vec<(Symbol, LocalId)> = vec![(this_sym, sec_this)];
        for p in &sec_ctor.params {
            let ty = resolve_type(interner.resolve(p.ty.name), module);
            let param_id = sec_fn.new_local(ty);
            sec_fn.params.push(param_id);
            sec_scope.push((p.name, param_id));
            sec_fn
                .param_names
                .push(interner.resolve(p.name).to_string());
        }

        // Emit delegation call.
        if sec_ctor.has_delegation {
            // `: this(args)` — delegate to another constructor of the same class.
            let tmp_idx = module.functions.len() + 8000;
            let mut fb = FnBuilder::new(tmp_idx, "<sec-init>".to_string(), Ty::Unit);
            fb.mf.locals = sec_fn.locals.clone();
            fb.mf.params = sec_fn.params.clone();
            let mut delegate_arg_ids = vec![sec_this]; // receiver
            for arg_expr in &sec_ctor.delegate_args {
                if let Some(id) = lower_expr(
                    arg_expr,
                    &mut fb,
                    &mut sec_scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                ) {
                    delegate_arg_ids.push(id);
                }
            }
            sec_fn.locals = fb.mf.locals;
            for stmt in fb.mf.blocks[0].stmts.drain(..) {
                sec_fn.blocks[0].stmts.push(stmt);
            }
            // Call the delegate constructor (this class's <init> matching the delegate args).
            sec_fn.blocks[0].stmts.push(MStmt::Assign {
                dest: sec_this, // dummy
                value: Rvalue::Call {
                    kind: CallKind::Constructor(class_name.clone()),
                    args: delegate_arg_ids,
                },
            });
        } else {
            // No explicit delegation — call super constructor.
            let super_class_name = c
                .parent_class
                .as_ref()
                .map(|sc| {
                    let simple = interner.resolve(sc.name).to_string();
                    module.import_map.get(&simple).cloned().unwrap_or(simple)
                })
                .unwrap_or_else(|| "java/lang/Object".to_string());
            sec_fn.blocks[0].stmts.push(MStmt::Assign {
                dest: sec_this, // dummy
                value: Rvalue::Call {
                    kind: CallKind::Constructor(super_class_name),
                    args: vec![sec_this],
                },
            });
        }

        // Lower optional body.
        if let Some(body) = &sec_ctor.body {
            let tmp_idx = module.functions.len() + 8001;
            let mut fb = FnBuilder::new(tmp_idx, "<sec-init-body>".to_string(), Ty::Unit);
            fb.mf.locals = sec_fn.locals.clone();
            fb.mf.params = sec_fn.params.clone();
            fb.mf.blocks[0].stmts = sec_fn.blocks[0].stmts.clone();
            // Add fields to scope for body access, track for writeback.
            let mut field_locals: Vec<(String, LocalId)> = Vec::new();
            for field in &fields {
                let field_sym = interner.intern(&field.name);
                let fl = fb.new_local(field.ty.clone());
                fb.push_stmt(MStmt::Assign {
                    dest: fl,
                    value: Rvalue::GetField {
                        receiver: sec_this,
                        class_name: class_name.clone(),
                        field_name: field.name.clone(),
                    },
                });
                sec_scope.push((field_sym, fl));
                field_locals.push((field.name.clone(), fl));
            }
            for s in &body.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut sec_scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            // Write back fields to the object.
            for (field_name, field_local) in &field_locals {
                fb.push_stmt(MStmt::Assign {
                    dest: sec_this, // dummy dest
                    value: Rvalue::PutField {
                        receiver: sec_this,
                        class_name: class_name.clone(),
                        field_name: field_name.clone(),
                        value: *field_local,
                    },
                });
            }
            sec_fn.locals = fb.mf.locals;
            sec_fn.blocks = fb.mf.blocks;
            if let Some(last) = sec_fn.blocks.last_mut() {
                last.terminator = Terminator::Return;
            }
        }

        mir_secondary_ctors.push(sec_fn);
    }

    // Generate forwarding methods for interface delegation (`Base by b`).
    for (iface_sym, delegate_sym) in &c.interface_delegates {
        let iface_name = interner.resolve(*iface_sym).to_string();
        let delegate_field = interner.resolve(*delegate_sym).to_string();
        // Look up the interface in already-lowered MIR classes.
        let iface_methods: Vec<(String, Ty, Vec<Ty>)> = module
            .classes
            .iter()
            .find(|cls| cls.name == iface_name && cls.is_interface)
            .map(|cls| {
                cls.methods
                    .iter()
                    .map(|m| {
                        // Collect param types (skip `this` at index 0).
                        let param_tys: Vec<Ty> = m
                            .params
                            .iter()
                            .skip(1)
                            .map(|pid| m.locals[pid.0 as usize].clone())
                            .collect();
                        (m.name.clone(), m.return_ty.clone(), param_tys)
                    })
                    .collect()
            })
            .unwrap_or_default();

        for (method_name, return_ty, param_tys) in &iface_methods {
            // Skip if the class already defines this method explicitly.
            if mir_methods.iter().any(|m| m.name == *method_name) {
                continue;
            }
            let fn_idx = module.functions.len() + mir_methods.len();
            let mut fb = FnBuilder::new(fn_idx, method_name.clone(), return_ty.clone());

            // `this` parameter.
            let this_local = fb.new_local(Ty::Class(class_name.clone()));
            fb.mf.params.push(this_local);

            // Additional method parameters (mirror the interface signature).
            let mut fwd_args = Vec::new();
            for pty in param_tys {
                let pid = fb.new_local(pty.clone());
                fb.mf.params.push(pid);
                fwd_args.push(pid);
            }

            // Load the delegate field: `this.<delegate_field>`
            let delegate_local = fb.new_local(Ty::Class(iface_name.clone()));
            fb.push_stmt(MStmt::Assign {
                dest: delegate_local,
                value: Rvalue::GetField {
                    receiver: this_local,
                    class_name: class_name.clone(),
                    field_name: delegate_field.clone(),
                },
            });

            // Call the interface method on the delegate.
            let mut call_args = vec![delegate_local];
            call_args.extend(fwd_args);
            let result_local = fb.new_local(return_ty.clone());
            fb.push_stmt(MStmt::Assign {
                dest: result_local,
                value: Rvalue::Call {
                    kind: CallKind::Virtual {
                        class_name: iface_name.clone(),
                        method_name: method_name.clone(),
                    },
                    args: call_args,
                },
            });

            if *return_ty == Ty::Unit {
                fb.set_terminator(Terminator::Return);
            } else {
                fb.set_terminator(Terminator::ReturnValue(result_local));
            }

            mir_methods.push(fb.finish());
        }
    }

    // Replace the stub class with the fully-lowered version.
    let outer_name = class_name.clone();
    module.classes[class_idx] = MirClass {
        name: class_name,
        super_class,
        is_open: c.is_open,
        is_abstract: c.is_abstract,
        is_interface: false,
        interfaces: iface_names,
        fields,
        methods: mir_methods,
        constructor: init_fn,
        secondary_constructors: mir_secondary_ctors,
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: !c.type_params.is_empty(),
        is_object_singleton: false,
        companion_class_name: companion_class_name_opt.clone(),
        static_fields: Vec::new(),
        clinit: None,
    };

    // Lower nested (static inner) classes. Each nested class becomes a
    // separate top-level MirClass with a JVM-conventional mangled name:
    // `Outer$Nested`. This is a static inner class — no reference to
    // the outer instance.
    for nested in &c.nested_classes {
        let nested_name = interner.resolve(nested.name).to_string();
        let mangled = format!("{}${}", outer_name, nested_name);
        let mangled_sym = interner.intern(&mangled);
        let mut synthetic = nested.clone();
        synthetic.name = mangled_sym;

        if nested.is_inner {
            // Inner class: add `this$0` field of outer class type as the
            // first constructor parameter, so `outer.Inner(args)` passes
            // the outer reference implicitly.
            let outer_param = ConstructorParam {
                is_val: true,
                is_var: false,
                name: interner.intern("this$0"),
                ty: TypeRef {
                    name: interner.intern(&outer_name),
                    nullable: false,
                    func_params: None,
                    type_args: Vec::new(),
                    is_suspend: false,
                    is_composable: false,
                    has_receiver: false,
                    span: nested.span,
                },
                span: nested.span,
                annotations: Vec::new(),
            };
            synthetic.constructor_params.insert(0, outer_param);
        }

        lower_class(
            &synthetic,
            name_to_func,
            name_to_global,
            module,
            interner,
            diags,
        );
    }
}

fn lower_interface(
    iface: &skotch_syntax::InterfaceDecl,
    name_to_func: &mut FxHashMap<Symbol, FuncId>,
    name_to_global: &FxHashMap<Symbol, MirConst>,
    module: &mut MirModule,
    interner: &mut Interner,
    diags: &mut Diagnostics,
) {
    let iface_name = interner.resolve(iface.name).to_string();

    // Pre-register the interface with method stubs for self-resolution.
    let stub_methods: Vec<MirFunction> = iface
        .methods
        .iter()
        .map(|m| {
            let mname = interner.resolve(m.name).to_string();
            let return_ty = m
                .return_ty
                .as_ref()
                .map(|tr| {
                    let resolved = resolve_type(interner.resolve(tr.name), module);
                    resolved
                })
                .unwrap_or(Ty::Unit);
            // Build stub with correct params (needed for JVM method descriptor).
            let mut stub = MirFunction {
                id: FuncId(0),
                name: mname,
                params: Vec::new(),
                locals: Vec::new(),
                blocks: Vec::new(),
                return_ty,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: m.is_abstract,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            // Add `this` param.
            let this_id = stub.new_local(Ty::Class(iface_name.clone()));
            stub.params.push(this_id);
            // Add declared params.
            for p in &m.params {
                let ty = resolve_type(interner.resolve(p.ty.name), module);
                let pid = stub.new_local(ty);
                stub.params.push(pid);
            }
            stub
        })
        .collect();
    let dummy_init = MirFunction {
        id: FuncId(0),
        name: "<init>".to_string(),
        params: Vec::new(),
        locals: Vec::new(),
        blocks: Vec::new(),
        return_ty: Ty::Unit,
        required_params: 0,
        param_names: Vec::new(),
        param_defaults: Vec::new(),
        param_receiver_types: Vec::new(),
        is_abstract: false,
        exception_handlers: Vec::new(),
        vararg_index: None,
        is_suspend: false,
        is_inline: false,
        has_type_params: false,
        suspend_original_return_ty: None,
        suspend_state_machine: None,
        annotations: Vec::new(),
        named_locals: Vec::new(),
        is_private: false,
        is_static: false,
        default_call_masks: Vec::new(),
        needs_leading_nop: false,
        local_generic_args: rustc_hash::FxHashMap::default(),
    };
    let class_idx = module.classes.len();
    module.classes.push(MirClass {
        name: iface_name.clone(),
        super_class: None,
        is_open: true,
        is_abstract: true,
        is_interface: true,
        interfaces: Vec::new(),
        fields: Vec::new(),
        methods: stub_methods,
        constructor: dummy_init.clone(),
        secondary_constructors: Vec::new(),
        is_lambda: false,
        is_suspend_lambda: false,
        is_cross_file_stub: false,
        annotations: Vec::new(),
        has_type_params: false,
        is_object_singleton: false,
        companion_class_name: None,
        static_fields: Vec::new(),
        clinit: None,
    });

    // Lower method bodies for default methods (non-abstract).
    let mut mir_methods = Vec::new();
    for method in &iface.methods {
        let method_name = interner.resolve(method.name).to_string();
        let return_ty = method
            .return_ty
            .as_ref()
            .map(|tr| {
                let resolved = resolve_type(interner.resolve(tr.name), module);
                resolved
            })
            .unwrap_or(Ty::Unit);

        if method.is_abstract {
            // Abstract method — stub with correct params for JVM descriptor.
            let mut stub = MirFunction {
                id: FuncId(0),
                name: method_name,
                params: Vec::new(),
                locals: Vec::new(),
                blocks: Vec::new(),
                return_ty,
                required_params: 0,
                param_names: Vec::new(),
                param_defaults: Vec::new(),
                param_receiver_types: Vec::new(),
                is_abstract: true,
                exception_handlers: Vec::new(),
                vararg_index: None,
                is_suspend: false,
                is_inline: false,
                has_type_params: false,
                suspend_original_return_ty: None,
                suspend_state_machine: None,
                annotations: Vec::new(),
                named_locals: Vec::new(),
                is_private: false,
                is_static: false,
                default_call_masks: Vec::new(),
                needs_leading_nop: false,
                local_generic_args: rustc_hash::FxHashMap::default(),
            };
            let this_id = stub.new_local(Ty::Class(iface_name.clone()));
            stub.params.push(this_id);
            // Extension receiver, e.g. `fun Dp.roundToPx()` inside
            // `interface Density` adds Dp as the first user param.
            if let Some(ext_recv) = &method.receiver_ty {
                let ty = resolve_type_ref(ext_recv, interner, module);
                let pid = stub.new_local(ty);
                stub.params.push(pid);
            }
            for p in &method.params {
                let ty = resolve_type(interner.resolve(p.ty.name), module);
                let pid = stub.new_local(ty);
                stub.params.push(pid);
            }
            mir_methods.push(stub);
        } else {
            // Default method — lower the body.
            let fn_idx = module.functions.len() + mir_methods.len();
            let mut fb = FnBuilder::new(fn_idx, method_name.clone(), return_ty);
            let this_local = fb.new_local(Ty::Class(iface_name.clone()));
            fb.mf.params.push(this_local);
            let this_sym = interner.intern("this");
            let mut scope: Vec<(Symbol, LocalId)> = vec![(this_sym, this_local)];
            // Extension receiver inside an interface method, e.g.
            // `fun Dp.roundToPx()` inside `interface Density`. Add the
            // receiver as the next param and bind its fields as
            // bare-identifier locals in the body scope.
            if let Some(ext_recv) = &method.receiver_ty {
                let ext_recv_ty = resolve_type_ref(ext_recv, interner, module);
                let ext_recv_local = fb.new_local(ext_recv_ty.clone());
                fb.mf.params.push(ext_recv_local);
                let ext_recv_sym = interner.intern(&format!("$this${}", method_name));
                scope.push((ext_recv_sym, ext_recv_local));
                if let Ty::Class(ext_class_name) = &ext_recv_ty {
                    if let Some(ext_cls) = module.classes.iter().find(|c| &c.name == ext_class_name)
                    {
                        for field in &ext_cls.fields {
                            let field_sym = interner.intern(&field.name);
                            let field_local = fb.new_local(field.ty.clone());
                            fb.push_stmt(MStmt::Assign {
                                dest: field_local,
                                value: Rvalue::GetField {
                                    receiver: ext_recv_local,
                                    class_name: ext_class_name.clone(),
                                    field_name: field.name.clone(),
                                },
                            });
                            scope.push((field_sym, field_local));
                        }
                    }
                }
            }
            for p in &method.params {
                let ty = resolve_type(interner.resolve(p.ty.name), module);
                let id = fb.new_local(ty);
                fb.mf.params.push(id);
                scope.push((p.name, id));
            }
            for s in &method.body.stmts {
                lower_stmt(
                    s,
                    &mut fb,
                    &mut scope,
                    module,
                    name_to_func,
                    name_to_global,
                    interner,
                    diags,
                    None,
                );
            }
            mir_methods.push(fb.finish());
        }
    }

    // Replace stubs with real methods.
    module.classes[class_idx].methods = mir_methods;
}

/// Convert a Kotlin `@Metadata` [`skotch_classinfo::kotlin_metadata::TypeInfo`]
/// to skotch's `Ty`, for use as a call's result type.
///
/// Primitives / `String` / `Any` map to their `Ty` variants; built-in
/// collection names map to their *erased* JVM class (kept erased, not
/// `Ty::Generic`, so the value-type dispatchers that match `Ty::Class`
/// keep working); other classes pass through unchanged; a bare type
/// variable yields `None`. A nullable Kotlin type wraps in
/// `Ty::Nullable`.
fn metadata_type_to_ty(ti: &skotch_classinfo::kotlin_metadata::TypeInfo) -> Option<Ty> {
    let cn = ti.class_name.as_deref()?;
    let simple = cn.rsplit('/').next().unwrap_or(cn);
    let base = if cn.starts_with("kotlin/") {
        // Built-in: primitive/String/Any via ty_from_name, else a
        // read-only collection alias (List → java/util/List, …).
        skotch_types::ty_from_name(simple)
            .or_else(|| intrinsics::kotlin_to_jvm_class(simple).map(|j| Ty::Class(j.to_string())))
            .unwrap_or_else(|| Ty::Class(cn.to_string()))
    } else {
        Ty::Class(cn.to_string())
    };
    if ti.nullable && !matches!(base, Ty::Any | Ty::Unit | Ty::Nothing) {
        Some(Ty::Nullable(Box::new(base)))
    } else {
        Some(base)
    }
}

/// Recover a static Kotlin method's return type from its `@Metadata`.
/// Used as a last-resort refinement when descriptor-based inference
/// would otherwise yield `Ty::Any` — turning "unknown" into the real
/// (possibly nullable / collection) Kotlin return type for external
/// kotlinc-compiled callees. `None` for Java callees (no `@Metadata`),
/// absent functions, or type-variable returns.
fn metadata_return_ty(class_name: &str, method_name: &str) -> Option<Ty> {
    let f = skotch_classinfo::lookup_function_metadata(class_name, method_name)?;
    metadata_type_to_ty(f.return_type.as_ref()?)
}

#[cfg(test)]
mod tests {
    use super::*;
    use skotch_lexer::lex;
    use skotch_parser::parse_file;
    use skotch_resolve::resolve_file;
    use skotch_span::FileId;
    use skotch_typeck::type_check;

    #[test]
    fn metadata_type_to_ty_bridge() {
        use skotch_classinfo::kotlin_metadata::TypeInfo;
        let mk = |cn: &str, nullable: bool| TypeInfo {
            class_name: Some(cn.to_string()),
            nullable,
            ..Default::default()
        };
        // Primitive / String map to their Ty variants.
        assert_eq!(metadata_type_to_ty(&mk("kotlin/Int", false)), Some(Ty::Int));
        assert_eq!(
            metadata_type_to_ty(&mk("kotlin/String", false)),
            Some(Ty::String)
        );
        // Nullable wraps in Ty::Nullable.
        assert_eq!(
            metadata_type_to_ty(&mk("kotlin/String", true)),
            Some(Ty::Nullable(Box::new(Ty::String)))
        );
        // Built-in read-only collection → erased JVM class (NOT Generic,
        // so the Ty::Class value-type dispatchers keep matching).
        assert_eq!(
            metadata_type_to_ty(&mk("kotlin/collections/List", false)),
            Some(Ty::Class("java/util/List".to_string()))
        );
        // A user/library class passes through unchanged.
        assert_eq!(
            metadata_type_to_ty(&mk("com/example/Foo", false)),
            Some(Ty::Class("com/example/Foo".to_string()))
        );
        // A bare type variable (no class name) is unresolvable → None,
        // so the caller keeps its existing fallback (Ty::Any).
        assert_eq!(metadata_type_to_ty(&TypeInfo::default()), None);
    }

    fn lower(src: &str) -> (MirModule, Diagnostics) {
        let mut interner = Interner::new();
        let mut diags = Diagnostics::new();
        let lf = lex(FileId(0), src, &mut diags);
        let f = parse_file(&lf, &mut interner, &mut diags);
        let r = resolve_file(&f, &mut interner, &mut diags, None);
        let t = type_check(&f, &r, &mut interner, &mut diags, None);
        let m = lower_file(&f, &r, &t, &mut interner, &mut diags, "HelloKt", None);
        (m, diags)
    }

    #[test]
    fn lower_println_string() {
        let (m, d) = lower(r#"fun main() { println("hi") }"#);
        assert!(d.is_empty(), "{:?}", d);
        let real_fns: Vec<_> = m.functions.iter().filter(|f| !f.is_abstract).collect();
        assert_eq!(real_fns.len(), 1);
        let f = real_fns[0];
        // String pool should contain "hi".
        assert_eq!(m.strings, vec!["hi".to_string()]);
        // Body: load const string, call println, return.
        assert_eq!(f.blocks.len(), 1);
        let bb = &f.blocks[0];
        assert!(bb.stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Const(MirConst::String(_)),
                ..
            }
        )));
        assert!(bb.stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Call {
                    kind: CallKind::Println,
                    ..
                },
                ..
            }
        )));
    }

    #[test]
    fn lower_println_int() {
        let (m, d) = lower("fun main() { println(42) }");
        assert!(d.is_empty(), "{:?}", d);
        let bb = &m.functions[0].blocks[0];
        assert!(bb.stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Const(MirConst::Int(42)),
                ..
            }
        )));
    }

    #[test]
    fn lower_arithmetic() {
        let (m, d) = lower("fun main() { println(1 + 2 * 3) }");
        assert!(d.is_empty(), "{:?}", d);
        let bb = &m.functions[0].blocks[0];
        // Constant folding: 1 + 2 * 3 = 7 at compile time
        assert!(bb.stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Const(MirConst::Int(7)),
                ..
            }
        )));
    }

    #[test]
    fn lower_function_call() {
        let src = r#"
            fun greet(n: String) { println(n) }
            fun main() { greet("Kotlin") }
        "#;
        let (m, d) = lower(src);
        assert!(d.is_empty(), "{:?}", d);
        let real_fns: Vec<_> = m.functions.iter().filter(|f| !f.is_abstract).collect();
        assert_eq!(real_fns.len(), 2);
        let main_block = &real_fns[1].blocks[0];
        assert!(main_block.stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Call {
                    kind: CallKind::Static(_),
                    ..
                },
                ..
            }
        )));
    }

    #[test]
    fn lower_top_level_val_string_inlines_constant() {
        // The val should be inlined as a `Const(String)` at the
        // reference site inside `main`. The MIR should NOT contain
        // Non-`const val` top-level properties become static fields
        // initialized in `<clinit>` with public getters; references read
        // them via `GetStaticField`. Matches kotlinc's emission and lets
        // user code observe re-initialization on class reload.
        let (m, d) = lower(r#"val GREETING = "hi"; fun main() { println(GREETING) }"#);
        assert!(d.is_empty(), "{:?}", d);
        // The MIR module records the property and its initializer.
        assert_eq!(m.top_level_props.len(), 1);
        assert_eq!(m.top_level_props[0].0, "GREETING");
        // The string pool has "hi" — used by `<clinit>` to put the
        // value into the field.
        assert!(m.strings.contains(&"hi".to_string()));
        let main = m.functions.iter().find(|f| f.name == "main").unwrap();
        // The body reads the property via `GetStaticField`, NOT an
        // inlined `Const(String)`.
        assert!(main.blocks[0].stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::GetStaticField { .. },
                ..
            }
        )));
        // …followed by a Println call.
        assert!(main.blocks[0].stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Call {
                    kind: CallKind::Println,
                    ..
                },
                ..
            }
        )));
    }

    #[test]
    fn lower_top_level_val_int_inlines_constant() {
        // Same as the String case above — non-`const val` properties go
        // through `GetStaticField`. Use `const val` for inlining.
        let (m, d) = lower(r#"const val ANSWER = 42; fun main() { println(ANSWER) }"#);
        assert!(d.is_empty(), "{:?}", d);
        let main = &m.functions[0];
        assert!(main.blocks[0].stmts.iter().any(|s| matches!(
            s,
            MStmt::Assign {
                value: Rvalue::Const(MirConst::Int(42)),
                ..
            }
        )));
    }

    #[test]
    fn lower_local_shadows_top_level_val() {
        // A local with the same name as a top-level val must shadow
        // the global. The local's value (`"local"`) should be the
        // one that reaches `println`, not the global's value
        // (`"global"`).
        let src = r#"
            val X = "global"
            fun main() {
                val X = "local"
                println(X)
            }
        "#;
        let (m, d) = lower(src);
        assert!(d.is_empty(), "{:?}", d);
        // The string pool contains BOTH strings — the global is
        // interned at module-init time even though it's never read.
        assert!(m.strings.contains(&"local".to_string()));
        assert!(m.strings.contains(&"global".to_string()));
    }

    // ─── future stubs ────────────────────────────────────────────────────
    // TODO: lower_if_expression          — once Branch terminator lands
    // TODO: lower_string_template        — once Concat intrinsic lands
    // TODO: lower_local_var_reassign     — `var x = 1; x = 2`
}
